import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, QuizAttempt, Course } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getTutorResponse = async (
  userMessage: string, 
  history: ChatMessage[],
  context: { 
    courseTitle: string; 
    lessonTitle: string; 
    lessonContent: string; 
    progress: number;
    quizHistory?: Record<string, QuizAttempt>;
  },
  imageData?: string 
) => {
  try {
    const model = 'gemini-3-pro-preview'; // Use Pro for more accurate tutoring and search grounding

    let quizContext = "";
    if (context.quizHistory && Object.keys(context.quizHistory).length > 0) {
      quizContext = "\nStudent's Quiz History in this course:\n" + 
        Object.entries(context.quizHistory).map(([lessonId, attempt]) => 
          `- Lesson: ${attempt.score}/${attempt.total}`
        ).join('\n');
    }

    const systemInstruction = `
      You are an expert AI Tutor for Edu World. 
      You are currently helping a student with the course: "${context.courseTitle}" 
      The student is currently ${context.progress}% through the course.
      Specifically on the lesson: "${context.lessonTitle}".

      Lesson context: "${context.lessonContent}"
      ${quizContext}

      Instructions:
      1. Be encouraging, patient, and professional. Use the student's progress and quiz history to personalize your help.
      2. If the student sends an image, analyze it in the context of the lesson or their question.
      3. Use markdown for formatting.
      4. Do not give the answers to quizzes directly; explain concepts.
      5. Use the googleSearch tool for queries that relate to up-to-date or trending information or technical documentation that might be newer than your training data.
    `;

    const contents = history.map(msg => {
      const parts: any[] = [{ text: msg.text }];
      if (msg.image) {
        parts.push({
          inlineData: {
            mimeType: 'image/jpeg',
            data: msg.image.split(',')[1]
          }
        });
      }
      return {
        role: msg.role === 'user' ? 'user' : 'model',
        parts
      };
    });

    const currentParts: any[] = [{ text: userMessage }];
    if (imageData) {
      currentParts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: imageData.split(',')[1]
        }
      });
    }

    contents.push({ role: 'user', parts: currentParts });

    const response = await ai.models.generateContent({
      model,
      contents: contents as any,
      config: {
        systemInstruction,
        temperature: 0.7,
        tools: [{ googleSearch: {} }]
      }
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const urls = groundingChunks
      .filter((chunk: any) => chunk.web)
      .map((chunk: any) => ({
        title: chunk.web.title,
        uri: chunk.web.uri
      }));

    return {
      text: response.text || "I'm sorry, I couldn't process that request.",
      urls
    };
  } catch (error) {
    console.error("Gemini Tutor Error:", error);
    return {
      text: "I encountered an error while trying to help. Please try again later.",
      urls: []
    };
  }
};

export const generateCourseOutline = async (topic: string): Promise<Partial<Course>> => {
  try {
    const model = 'gemini-3-pro-preview';
    const response = await ai.models.generateContent({
      model,
      contents: `Generate a comprehensive high-quality online course about "${topic}". 
      The output must be a JSON object that matches the Edu World LMS format.
      Include 4-6 detailed lessons, subjects, and sub-subjects.
      Each lesson should have at least 500 words of educational content in Markdown (HTML-ready).
      Include 2-3 quiz questions per lesson.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            category: { type: Type.STRING },
            instructor: { type: Type.STRING },
            price: { type: Type.NUMBER },
            subjects: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  name: { type: Type.STRING },
                  icon: { type: Type.STRING },
                  color: { type: Type.STRING },
                  subSubjects: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        id: { type: Type.STRING },
                        name: { type: Type.STRING }
                      }
                    }
                  }
                }
              }
            },
            lessons: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING },
                  content: { type: Type.STRING },
                  duration: { type: Type.STRING },
                  subjectId: { type: Type.STRING },
                  subSubjectId: { type: Type.STRING },
                  quiz: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        id: { type: Type.STRING },
                        question: { type: Type.STRING },
                        options: { type: Type.ARRAY, items: { type: Type.STRING } },
                        correctAnswer: { type: Type.NUMBER }
                      }
                    }
                  }
                }
              }
            },
            roadmap: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  icon: { type: Type.STRING },
                  text: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Course Generation Error:", error);
    throw error;
  }
};

export const summarizeLesson = async (title: string, content: string) => {
  try {
    const model = 'gemini-3-flash-preview';
    const response = await ai.models.generateContent({
      model,
      contents: `Summarize the following lesson titled "${title}" in 3 key bullet points:\n\n${content}`,
    });
    return response.text || "Summary not available.";
  } catch (error) {
    return "Failed to generate summary.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, Course, Lesson, User } from '../types';
import { getTutorResponse } from '../services/geminiService';

interface AIAssistantProps {
  course: Course;
  lesson: Lesson;
  user: User;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ course, lesson, user }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      role: 'model', 
      text: `Hi! I'm your AI Tutor for Edu World's **${course.title}**. Ask me anything about "${lesson.title}" or share a screenshot of a problem you're stuck on!`, 
      timestamp: new Date() 
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSend = async () => {
    if ((!input.trim() && !selectedImage) || isTyping) return;

    const currentImage = selectedImage;
    const userMsg: ChatMessage = { 
      role: 'user', 
      text: input, 
      timestamp: new Date(),
      image: currentImage || undefined
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setSelectedImage(null);
    setIsTyping(true);

    const result = await getTutorResponse(
      input, 
      messages, 
      {
        courseTitle: course.title,
        lessonTitle: lesson.title,
        lessonContent: lesson.content,
        progress: course.progress || 0,
        quizHistory: user.quizScores
      },
      currentImage || undefined
    );

    const botMsg: ChatMessage = { 
      role: 'model', 
      text: result.text, 
      timestamp: new Date(),
      groundingUrls: result.urls 
    };
    setMessages(prev => [...prev, botMsg]);
    setIsTyping(false);
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden shadow-sm">
      <div className="bg-indigo-600 p-4 text-white flex items-center justify-between shadow-lg relative z-10">
        <div className="flex items-center space-x-3">
          <div className="w-9 h-9 bg-white/10 backdrop-blur-md rounded-xl flex items-center justify-center border border-white/20 shadow-inner">
            <i className="fas fa-robot text-lg"></i>
          </div>
          <div>
            <h4 className="font-black text-sm tracking-tight">Personal AI Tutor</h4>
            <div className="flex items-center space-x-2">
              <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span>
              <p className="text-[10px] text-indigo-100 font-bold uppercase tracking-widest opacity-80">Search Grounding Enabled</p>
            </div>
          </div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-950/50">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm shadow-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-slate-900 text-slate-100 border border-slate-800 rounded-tl-none'
            }`}>
              {msg.image && (
                <div className="mb-2 rounded-lg overflow-hidden border border-black/20">
                  <img src={msg.image} className="max-w-full h-auto" alt="shared content" />
                </div>
              )}
              <div className={`prose prose-sm max-w-none ${msg.role === 'user' ? 'prose-invert text-white' : 'prose-invert text-slate-100'}`}>
                {msg.text.split('\n').map((line, idx) => (
                  <p key={idx}>{line}</p>
                ))}
              </div>

              {msg.groundingUrls && msg.groundingUrls.length > 0 && (
                <div className="mt-4 pt-3 border-t border-slate-800/50">
                  <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-2">Sources:</p>
                  <div className="flex flex-wrap gap-2">
                    {msg.groundingUrls.map((link, idx) => (
                      <a 
                        key={idx} 
                        href={link.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center px-2 py-1 bg-slate-950 rounded-lg text-[10px] text-indigo-400 hover:text-white hover:bg-indigo-600 transition-all border border-slate-800"
                      >
                        <i className="fas fa-link mr-1.5 text-[8px]"></i>
                        <span className="truncate max-w-[150px]">{link.title}</span>
                      </a>
                    ))}
                  </div>
                </div>
              )}

              <span className={`text-[10px] mt-1 block font-black uppercase tracking-widest ${msg.role === 'user' ? 'text-indigo-200 text-right' : 'text-slate-500'}`}>
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-slate-900 border border-slate-800 rounded-2xl px-5 py-4 flex space-x-1.5 shadow-sm">
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-900 border-t border-slate-800">
        {selectedImage && (
          <div className="mb-3 relative inline-block group animate-in slide-in-from-bottom-2">
            <img src={selectedImage} className="h-20 w-20 object-cover rounded-xl border-2 border-indigo-600 shadow-lg" alt="preview" />
            <button 
              onClick={() => setSelectedImage(null)}
              className="absolute -top-2 -right-2 bg-slate-950 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] shadow-lg border border-slate-800"
            >
              <i className="fas fa-times"></i>
            </button>
          </div>
        )}
        <div className="flex items-center space-x-2 bg-slate-950 rounded-2xl px-4 py-2 border border-slate-800 focus-within:border-indigo-500/50 transition-all">
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="text-slate-500 hover:text-indigo-400 transition-colors p-1"
          >
            <i className="fas fa-image"></i>
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="image/*" 
            className="hidden" 
          />
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type your question..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-sm py-2 text-slate-100 font-medium placeholder:text-slate-600"
          />
          <button 
            onClick={handleSend}
            disabled={(!input.trim() && !selectedImage) || isTyping}
            className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all ${
              (input.trim() || selectedImage) && !isTyping ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'text-slate-700'
            }`}
          >
            <i className="fas fa-paper-plane-top"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect, useRef } from 'react';
import { Course, Lesson, Resource, QuizQuestion, SubjectGroup, SupplementalItem, SubSubject, RoadmapItem } from '../types';
import { generateCourseOutline } from '../services/geminiService';

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = error => reject(error);
  });
};

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
  onDeleteAll?: () => void;
}

const COLOR_PRESETS = [
  { name: 'Indigo', class: 'bg-indigo-950/30 text-indigo-400 border border-indigo-900/50' },
  { name: 'Rose', class: 'bg-rose-950/30 text-rose-400 border border-rose-900/50' },
  { name: 'Emerald', class: 'bg-emerald-950/30 text-emerald-400 border border-emerald-900/50' },
  { name: 'Amber', class: 'bg-amber-950/30 text-amber-400 border border-amber-900/50' },
  { name: 'Purple', class: 'bg-purple-950/30 text-purple-400 border border-purple-900/50' },
  { name: 'Sky', class: 'bg-sky-950/30 text-sky-400 border border-sky-900/50' },
  { name: 'Slate', class: 'bg-slate-800 text-slate-100 border border-slate-700' },
];

const ICON_PRESETS = [
  'fa-book-open', 'fa-code', 'fa-palette', 'fa-flask', 'fa-microscope', 'fa-calculus', 
  'fa-atom', 'fa-brain', 'fa-dna', 'fa-chart-line', 'fa-globe', 'fa-language',
  'fa-terminal', 'fa-database', 'fa-cloud', 'fa-graduation-cap'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse, onPreview, onDeleteAll }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeLessonExtras, setActiveLessonExtras] = useState<string | null>(null);
  const [activeLessonTab, setActiveLessonTab] = useState<'content' | 'resources' | 'quiz'>('content');
  const [activeConfigTab, setActiveConfigTab] = useState<'meta' | 'layout' | 'curriculum'>('meta');
  const [isUploadingFiles, setIsUploadingFiles] = useState(false);
  const [isUploadingThumbnail, setIsUploadingThumbnail] = useState(false);

  // AI Generation States
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const resourceFileInputRef = useRef<HTMLInputElement>(null);
  const lessonVideoInputRef = useRef<HTMLInputElement>(null);
  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const quillRef = useRef<any>(null);
  const quillContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) openEditor(course);
    }
  }, [initialEditCourseId, courses]);

  useEffect(() => {
    if (isEditing && activeLessonExtras && activeLessonTab === 'content' && quillContainerRef.current && !quillRef.current) {
      // @ts-ignore
      quillRef.current = new Quill(quillContainerRef.current, {
        theme: 'snow',
        modules: {
          toolbar: [
            [{ 'header': [1, 2, 3, false] }],
            ['bold', 'italic', 'underline'],
            [{ 'list': 'ordered'}, { 'list': 'bullet' }],
            ['code-block', 'link'],
            ['clean']
          ]
        }
      });

      const lessonId = activeLessonExtras;
      const lesson = currentCourse?.lessons?.find(l => l.id === lessonId);
      if (lesson) {
        quillRef.current.root.innerHTML = lesson.content;
      }

      quillRef.current.on('text-change', () => {
        const html = quillRef.current.root.innerHTML;
        updateLesson(lessonId, { content: html });
      });
    }

    return () => {
      if (quillRef.current) {
        quillRef.current = null;
      }
    };
  }, [isEditing, activeLessonExtras, activeLessonTab]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse({
        ...outline,
        instructorAvatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${outline.instructor || 'ai'}`,
        thumbnail: 'https://picsum.photos/seed/ai-gen/800/450',
        rating: 4.9,
        studentsCount: 0
      });
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("AI Generation failed. Please try a different prompt.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    try {
      if (currentCourse.id) {
        await onUpdateCourse(currentCourse as Course);
      } else {
        const newCourse: Course = {
          ...currentCourse as Course,
          id: Math.random().toString(36).substr(2, 9),
          instructorAvatar: currentCourse.instructorAvatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${currentCourse.instructor || 'lead'}`,
          thumbnail: currentCourse.thumbnail || 'https://picsum.photos/seed/course/800/450',
          category: currentCourse.category || 'Development'
        };
        await onAddCourse(newCourse);
      }
      setIsEditing(false);
      setCurrentCourse(null);
    } catch (err) {
      console.error(err);
      alert("Failed to publish course.");
    }
  };

  const handleThumbnailUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploadingThumbnail(true);
    try {
      const base64 = await fileToBase64(file);
      setCurrentCourse(prev => ({ ...prev!, thumbnail: base64 }));
    } catch (err) {
      alert("Image upload failed.");
    } finally {
      setIsUploadingThumbnail(false);
    }
  };

  const openEditor = (course?: Course) => {
    setCurrentCourse(course ? { ...course } : { 
      title: '', 
      description: '', 
      category: 'Development', 
      instructor: 'Lead Instructor',
      price: 49.99,
      lessons: [],
      subjects: [],
      supplementalContent: [],
      roadmap: []
    });
    setIsEditing(true);
    setActiveConfigTab('meta');
  };

  const updateLesson = (id: string, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev) return prev;
      const updatedLessons = (prev.lessons || []).map(l => l.id === id ? { ...l, ...updates } : l);
      return { ...prev, lessons: updatedLessons };
    });
  };

  const handleVideoUpload = async (lessonId: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploadingFiles(true);
    try {
      const base64 = await fileToBase64(file);
      updateLesson(lessonId, { videoUrl: base64 });
    } finally {
      setIsUploadingFiles(false);
    }
  };

  const updateSubject = (id: string, updates: Partial<SubjectGroup>) => {
    setCurrentCourse(prev => {
      if (!prev) return prev;
      const updated = (prev.subjects || []).map(s => s.id === id ? { ...s, ...updates } : s);
      return { ...prev, subjects: updated };
    });
  };

  if (isEditing && currentCourse) {
    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">
        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="flex items-center space-x-3 text-slate-500 hover:text-slate-100 font-black uppercase text-[10px] tracking-widest transition-colors">
            <i className="fas fa-arrow-left"></i>
            <span>Back to Registry</span>
          </button>
          <button type="submit" form="course-form" className="px-10 py-4 bg-indigo-600 text-white font-black text-xs uppercase tracking-widest rounded-2xl hover:bg-indigo-700 shadow-lg shadow-indigo-600/20 transition-all">
            {currentCourse.id ? 'Save Updates' : 'Deploy Course'}
          </button>
        </div>

        <div className="bg-slate-900 rounded-[40px] border border-slate-800 shadow-sm overflow-hidden">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['meta', 'layout', 'curriculum'].map((tab) => (
              <button
                key={tab}
                type="button"
                onClick={() => setActiveConfigTab(tab as any)}
                className={`flex-1 py-7 text-[10px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${
                  activeConfigTab === tab ? 'text-indigo-400 border-indigo-600 bg-slate-900' : 'text-slate-600 border-transparent hover:bg-slate-900/50'
                }`}
              >
                {tab === 'meta' ? 'Identity' : tab === 'layout' ? 'Navigation' : 'Modules'}
              </button>
            ))}
          </div>

          <form id="course-form" className="p-8 md:p-12 space-y-12" onSubmit={handleSave}>
            {activeConfigTab === 'meta' && (
              <section className="space-y-8 animate-in fade-in">
                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Program Details</label>
                  <input required type="text" value={currentCourse.title || ''} onChange={(e) => setCurrentCourse(prev => ({...prev!, title: e.target.value}))} className="w-full bg-slate-950 border-2 border-slate-800 rounded-3xl px-8 py-5 text-slate-100 font-bold" placeholder="Program Title" />
                  <textarea required rows={4} value={currentCourse.description || ''} onChange={(e) => setCurrentCourse(prev => ({...prev!, description: e.target.value}))} className="w-full bg-slate-950 border-2 border-slate-800 rounded-3xl px-8 py-5 text-slate-100" placeholder="Program Description" />
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Price ($)</label>
                    <input required type="number" step="0.01" value={currentCourse.price || 0} onChange={(e) => setCurrentCourse(prev => ({...prev!, price: parseFloat(e.target.value)}))} className="w-full bg-slate-950 border-2 border-slate-800 rounded-3xl px-8 py-4 text-slate-100" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest ml-1">Instructor</label>
                    <input required type="text" value={currentCourse.instructor || ''} onChange={(e) => setCurrentCourse(prev => ({...prev!, instructor: e.target.value}))} className="w-full bg-slate-950 border-2 border-slate-800 rounded-3xl px-8 py-4 text-slate-100" />
                  </div>
                </div>
              </section>
            )}

            {activeConfigTab === 'layout' && (
              <section className="space-y-8 animate-in fade-in">
                 <div className="flex justify-between items-center">
                    <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Navigation Groups</h3>
                    <button type="button" onClick={() => setCurrentCourse(prev => ({...prev!, subjects: [...(prev!.subjects || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Subject', icon: 'fa-book', color: COLOR_PRESETS[0].class }] }))} className="text-indigo-400 text-[10px] font-black uppercase tracking-widest">+ Add Group</button>
                 </div>
                 <div className="space-y-4">
                    {(currentCourse.subjects || []).map(subj => (
                      <div key={subj.id} className="p-6 bg-slate-950 rounded-3xl border border-slate-800 flex items-center gap-6">
                        <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl ${subj.color}`}>
                           <i className={`fas ${subj.icon}`}></i>
                        </div>
                        <input type="text" value={subj.name} onChange={(e) => updateSubject(subj.id, { name: e.target.value })} className="flex-1 bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-100" />
                        <button type="button" onClick={() => setCurrentCourse(prev => ({...prev!, subjects: prev!.subjects?.filter(s => s.id !== subj.id)}))} className="text-slate-700 hover:text-rose-500 transition-colors"><i className="fas fa-trash"></i></button>
                      </div>
                    ))}
                 </div>
              </section>
            )}

            {activeConfigTab === 'curriculum' && (
              <section className="space-y-8 animate-in fade-in">
                 <div className="flex justify-between items-center">
                    <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Learning Modules</h3>
                    <button type="button" onClick={() => setCurrentCourse(prev => ({...prev!, lessons: [...(prev!.lessons || []), { id: Math.random().toString(36).substr(2, 9), title: 'New Module', content: '', duration: '10:00' }] }))} className="px-6 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest">+ Add Module</button>
                 </div>
                 <div className="space-y-4">
                    {(currentCourse.lessons || []).map((lesson, idx) => (
                      <div key={lesson.id} className="bg-slate-950/50 rounded-3xl border border-slate-800 overflow-hidden">
                        <div className="p-6 flex items-center gap-6">
                           <span className="text-[10px] font-black text-slate-700">{idx + 1}</span>
                           <input type="text" value={lesson.title} onChange={(e) => updateLesson(lesson.id, { title: e.target.value })} className="flex-1 bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-100" />
                           <button type="button" onClick={() => setActiveLessonExtras(activeLessonExtras === lesson.id ? null : lesson.id)} className="w-10 h-10 rounded-xl bg-slate-900 flex items-center justify-center text-indigo-400 border border-slate-800">
                              <i className="fas fa-edit"></i>
                           </button>
                        </div>
                        {activeLessonExtras === lesson.id && (
                          <div className="p-8 border-t border-slate-800 space-y-8">
                             <div className="bg-slate-950 border border-slate-800 rounded-3xl overflow-hidden min-h-[300px]">
                                <div ref={quillContainerRef} className="quill-dark-editor h-[250px]"></div>
                             </div>
                             <div className="grid grid-cols-2 gap-6">
                                <div className="space-y-2">
                                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Module Duration</label>
                                  <input type="text" value={lesson.duration} onChange={(e) => updateLesson(lesson.id, { duration: e.target.value })} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-xs text-slate-200" />
                                </div>
                                <div className="space-y-2">
                                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Video Control</label>
                                  <input type="file" ref={lessonVideoInputRef} className="hidden" accept="video/*" onChange={(e) => handleVideoUpload(lesson.id, e)} />
                                  <button type="button" onClick={() => lessonVideoInputRef.current?.click()} className="w-full py-3 bg-slate-900 border border-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest text-indigo-400">
                                     {isUploadingFiles ? 'Processing...' : lesson.videoUrl ? 'Swap Video' : 'Upload Video'}
                                  </button>
                                </div>
                             </div>
                          </div>
                        )}
                      </div>
                    ))}
                 </div>
              </section>
            )}
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-10 pb-20 animate-in fade-in duration-500">

      {/* AI Modal */}
      {isAiModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl animate-in fade-in duration-200">
          <div className="bg-slate-900 w-full max-w-lg rounded-[40px] shadow-2xl border border-slate-800 p-10 space-y-8 animate-in zoom-in-95 duration-200">
            <div className="text-center space-y-3">
              <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto shadow-xl shadow-indigo-600/20">
                <i className="fas fa-wand-magic-sparkles text-white text-2xl"></i>
              </div>
              <h2 className="text-3xl font-black text-slate-100 tracking-tight">AI Program Architect</h2>
              <p className="text-slate-500 text-sm font-medium">Describe your course topic and let the system build the curriculum, modules, and quizzes instantly.</p>
            </div>

            <textarea
              value={aiPrompt}
              onChange={(e) => setAiPrompt(e.target.value)}
              placeholder="e.g. Master React and Modern Web Architecture with Advanced Patterns..."
              className="w-full bg-slate-950 border-2 border-slate-800 rounded-3xl px-6 py-4 text-slate-200 focus:border-indigo-600/30 min-h-[120px]"
            />

            <div className="flex gap-4">
              <button 
                onClick={() => setIsAiModalOpen(false)} 
                className="flex-1 py-4 bg-slate-800 text-slate-400 font-black uppercase text-[10px] tracking-widest rounded-2xl hover:bg-slate-700"
              >
                Cancel
              </button>
              <button 
                onClick={handleAiGenerate}
                disabled={!aiPrompt.trim() || isGenerating}
                className="flex-1 py-4 bg-indigo-600 text-white font-black uppercase text-[10px] tracking-widest rounded-2xl shadow-lg shadow-indigo-600/30 hover:bg-indigo-700 disabled:opacity-50"
              >
                {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : 'Begin Synthesis'}
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-8">
        <div>
          <h1 className="text-5xl font-black text-slate-100 tracking-tight">System Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px] mt-2">Manage course modules and AI synthesis</p>
        </div>
        <div className="flex gap-4">
          <button onClick={() => setIsAiModalOpen(true)} className="px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg hover:border-indigo-600/30 transition-all flex items-center">
            <i className="fas fa-wand-magic-sparkles mr-3"></i> AI Generate
          </button>
          <button onClick={() => openEditor()} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 shadow-2xl shadow-indigo-600/20 transition-all flex items-center">
            <i className="fas fa-plus mr-3"></i> Manual Create
          </button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Program</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Stats</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {courses.map((course) => (
              <tr key={course.id} className="hover:bg-slate-800/30 transition-colors group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-4">
                    <div className="w-12 h-12 bg-slate-950 rounded-xl overflow-hidden border border-slate-800">
                      <img src={course.thumbnail} className="w-full h-full object-cover opacity-60 group-hover:opacity-100" />
                    </div>
                    <div>
                      <p className="font-black text-slate-100 text-base">{course.title}</p>
                      <p className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">{course.category}</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8">
                  <span className="text-xs font-bold text-slate-400">{course.lessons.length} Modules • {course.studentsCount} Students</span>
                </td>
                <td className="px-10 py-8 text-right space-x-2">
                  <button onClick={() => openEditor(course)} className="w-10 h-10 bg-slate-950 border border-slate-800 rounded-xl text-slate-600 hover:text-indigo-400 hover:border-indigo-600 transition-all"><i className="fas fa-edit"></i></button>
                  <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 border border-slate-800 rounded-xl text-slate-600 hover:text-rose-600 hover:border-rose-600 transition-all"><i className="fas fa-trash"></i></button>
                </td>
              </tr>
            ))}
            {courses.length === 0 && (
              <tr><td colSpan={3} className="py-24 text-center text-slate-700 uppercase font-black tracking-widest text-[10px]">Registry Empty</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

