import React, { useState } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject } from '../types';

interface DashboardProps {
  onCourseClick: (id: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse 
}) => {
  const [activeSubject, setActiveSubject] = useState<SubjectGroup | null>(null);
  const [activeSubSubject, setActiveSubSubject] = useState<SubSubject | null>(null);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  const handleSubjectClick = (subj: SubjectGroup) => {
    setActiveSubject(subj);
    setActiveSubSubject(null);
  };

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[70vh] text-center p-6 bg-[#020617] animate-in fade-in duration-700">
        <div className="w-24 h-24 bg-slate-900 text-indigo-400 rounded-[40px] flex items-center justify-center mb-8 shadow-2xl shadow-indigo-500/10 border border-slate-800">
          <i className="fas fa-rocket text-3xl"></i>
        </div>
        <h2 className="text-3xl font-black text-slate-100 mb-4 tracking-tight">Ready to start learning?</h2>
        <p className="text-slate-400 text-lg max-w-md mb-10 leading-relaxed font-medium">You aren't enrolled in any programs yet. Explore our catalog to find your next goal.</p>
        <button 
          onClick={() => setRoute(AppRoute.COURSES)}
          className="px-10 py-5 bg-indigo-600 text-white rounded-[24px] font-black uppercase tracking-[0.2em] text-xs hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/30 transform hover:scale-105 active:scale-95"
        >
          Explore Courses
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-12 pb-20 animate-in fade-in duration-500">

      {/* Top Header - Program Selection */}
      <div className="flex flex-col items-center justify-center space-y-8">
        <div className="text-center space-y-3">
          <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] mb-4">Neural Interface Active</p>
          <h1 className="text-4xl md:text-6xl font-black text-slate-100 tracking-tighter leading-none">{activeCourse.title}</h1>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-xs pt-2">Currently Synchronized Pathway</p>
        </div>

        {courses.length > 1 && (
          <div className="flex items-center space-x-3 bg-slate-900/50 backdrop-blur p-2 rounded-3xl border border-slate-800 shadow-xl overflow-x-auto no-scrollbar max-w-full">
            {courses.map(c => (
              <button 
                key={c.id}
                onClick={() => onSelectCourse(c.id)}
                className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest whitespace-nowrap transition-all ${
                  selectedCourseId === c.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-800'
                }`}
              >
                {c.title}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Statistics Hub */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
         <div className="bg-slate-900 rounded-[40px] border border-slate-800 p-8 flex flex-col justify-between h-56 shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-600/5 blur-3xl rounded-full"></div>
            <div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Weekly Focus</p>
              <h4 className="text-3xl font-black text-slate-100">12.5 hrs</h4>
            </div>
            <div className="flex items-end space-x-1.5 h-16">
               {[40, 70, 45, 90, 65, 80, 55].map((h, i) => (
                 <div key={i} className="flex-1 bg-indigo-600/20 rounded-t-lg transition-all group-hover:bg-indigo-600/40" style={{ height: `${h}%` }}></div>
               ))}
            </div>
         </div>
         <div className="bg-slate-900 rounded-[40px] border border-slate-800 p-8 flex flex-col justify-between h-56 shadow-2xl overflow-hidden">
            <div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Course Progress</p>
              <h4 className="text-3xl font-black text-indigo-400">84% Complete</h4>
            </div>
            <div className="w-full h-4 bg-slate-950 rounded-full border border-slate-800 p-1">
               <div className="h-full bg-indigo-600 rounded-full shadow-lg shadow-indigo-600/20" style={{ width: '84%' }}></div>
            </div>
         </div>
         <div className="bg-slate-900 rounded-[40px] border border-slate-800 p-8 flex flex-col justify-between h-56 shadow-2xl">
            <div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Average Proficiency</p>
              <h4 className="text-3xl font-black text-emerald-400">Expert</h4>
            </div>
            <div className="flex items-center space-x-3">
               <div className="w-10 h-10 rounded-xl bg-emerald-500/10 border border-emerald-500/20 flex items-center justify-center text-emerald-500">
