      {/* Subjects Grid */}
      <div className="space-y-8">
        <h3 className="text-xs font-black text-slate-600 uppercase tracking-[0.3em] ml-2">Curriculum Map</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {(activeCourse.subjects || []).map((subj) => (
            <button
              key={subj.id}
              onClick={() => handleSubjectClick(subj)}
              className="flex items-center justify-between p-8 bg-slate-900 rounded-[32px] border-2 border-slate-800 hover:border-indigo-500/30 shadow-sm hover:shadow-2xl hover:translate-y-[-4px] transition-all group"
            >
              <div className="flex items-center space-x-6">
                <div className={`w-14 h-14 rounded-[20px] flex items-center justify-center text-2xl transition-all shadow-inner group-hover:scale-110 ${subj.color || 'bg-slate-800 text-slate-400'}`}>
                  <i className={`fas ${subj.icon}`}></i>
                </div>
                <div className="text-left">
                  <span className="text-2xl font-black text-slate-300 tracking-tight group-hover:text-indigo-400 transition-colors block">{subj.name}</span>
                  <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">8 Modules</span>
                </div>
              </div>
              <div className="text-slate-700 group-hover:text-indigo-400 group-hover:translate-x-1 transition-all">
                <i className="fas fa-chevron-right text-lg"></i>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Supplemental Content */}
      {(activeCourse.supplementalContent || []).length > 0 && (
        <div className="space-y-8 pt-6">
          <h3 className="text-xs font-black text-slate-600 uppercase tracking-[0.3em] ml-2">Additional Archives</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {activeCourse.supplementalContent!.map(item => (
              <div 
                key={item.id}
                className="bg-slate-900 rounded-[32px] border-2 border-slate-800 shadow-sm overflow-hidden group cursor-pointer hover:shadow-2xl transition-all hover:border-indigo-500/20"
              >
                <div className="aspect-[4/3] overflow-hidden">
                  <img src={item.thumbnail} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700 opacity-60 group-hover:opacity-100" alt={item.title} />
                </div>
                <div className="p-6">
                  <p className="text-sm font-black text-slate-200 line-clamp-2 leading-tight group-hover:text-indigo-400 transition-colors">{item.title}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

