            <i className="fas fa-wand-magic-sparkles mr-3"></i> AI Generate
          </button>
          <button onClick={() => openEditor()} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 shadow-2xl shadow-indigo-600/20 transition-all flex items-center">
            <i className="fas fa-plus mr-3"></i> Manual Create
          </button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Program</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Stats</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {courses.map((course) => (
              <tr key={course.id} className="hover:bg-slate-800/30 transition-colors group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-4">
                    <div className="w-12 h-12 bg-slate-950 rounded-xl overflow-hidden border border-slate-800">
                      <img src={course.thumbnail} className="w-full h-full object-cover opacity-60 group-hover:opacity-100" />
                    </div>
                    <div>
                      <p className="font-black text-slate-100 text-base">{course.title || 'Untitled Program'}</p>
                      <p className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">{course.category || 'General'}</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8">
                  <span className="text-xs font-bold text-slate-400">{(course.lessons?.length || 0)} Modules • {(course.studentsCount || 0).toLocaleString()} Students</span>
                </td>
                <td className="px-10 py-8 text-right space-x-2">
                  <button onClick={() => openEditor(course)} className="w-10 h-10 bg-slate-950 border border-slate-800 rounded-xl text-slate-600 hover:text-indigo-400 hover:border-indigo-600 transition-all"><i className="fas fa-edit"></i></button>
                  <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 border border-slate-800 rounded-xl text-slate-600 hover:text-rose-600 hover:border-rose-600 transition-all"><i className="fas fa-trash"></i></button>
                </td>
              </tr>
            ))}
            {courses.length === 0 && (
              <tr><td colSpan={3} className="py-24 text-center text-slate-700 uppercase font-black tracking-widest text-[10px]">Registry Empty</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

