            {activeCourse.supplementalContent!.map(item => (
              <div 
                key={item.id}
                className="bg-white rounded-[28px] border border-slate-100 shadow-sm overflow-hidden group cursor-pointer hover:shadow-xl transition-all hover:border-indigo-100"
              >
                <div className="aspect-[4/3] overflow-hidden">
                  <img src={item.thumbnail} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700 opacity-90 group-hover:opacity-100" alt={item.title} />
                </div>
                <div className="p-6">
                  <p className="text-sm font-bold text-slate-700 line-clamp-2 leading-tight group-hover:text-indigo-600 transition-colors">{item.title}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Explore from './components/Explore';
import CourseView from './components/CourseView';
import CourseCard from './components/CourseCard';
import AdminPanel from './components/AdminPanel';
import Profile from './components/Profile';
import Auth from './components/Auth';
import CourseDetails from './components/CourseDetails';
import { AppRoute, Course, User, QuizAttempt } from './types';
import { MOCK_COURSES } from './constants';
import { getAllCoursesFromDB, saveCourseToDB, deleteCourseFromDB, clearAllCoursesFromDB } from './services/storage';

const App: React.FC = () => {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [activeCourseId, setActiveCourseId] = useState<string | null>(null);
  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [courses, setCourses] = useState<Course[]>([]);
  const [adminPreviewMode, setAdminPreviewMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [isSwitcherOpen, setIsSwitcherOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [editingCourseId, setEditingCourseId] = useState<string | null>(null);
  const switcherRef = useRef<HTMLDivElement>(null);

  // Initialize courses from IndexedDB
  useEffect(() => {
    const loadCourses = async () => {
      try {
        const savedCourses = await getAllCoursesFromDB();
        if (savedCourses.length > 0) {
          setCourses(savedCourses);
        } else {
          // Initialize with MOCK_COURSES if empty
          for (const c of MOCK_COURSES) {
            await saveCourseToDB(c);
          }
          setCourses(MOCK_COURSES);
        }
      } catch (err) {
        console.error("Failed to load courses from IndexedDB", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadCourses();
  }, []);

  // Restore user session on mount
  useEffect(() => {
    try {
      const savedUser = localStorage.getItem('eduworld_user');
      if (savedUser) {
        setUser(JSON.parse(savedUser));
      }
    } catch (err) {
      console.error("Failed to restore user session", err);
    }
  }, []);

  // Close switcher on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (switcherRef.current && !switcherRef.current.contains(event.target as Node)) {
        setIsSwitcherOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    try {
      localStorage.setItem('eduworld_user', JSON.stringify(newUser));
    } catch (err) {
      console.error("Storage limit reached for user data.");
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('eduworld_user');
    setRoute(AppRoute.DASHBOARD);
    setIsSwitcherOpen(false);
  };

  const handleCourseClick = (id: string) => {
    setActiveCourseId(id);
    const isEnrolled = user?.enrolledCourses.includes(id);
    if (isEnrolled) {
      setRoute(AppRoute.COURSE_VIEW);
    } else {
      setRoute(AppRoute.COURSE_DETAILS);
    }
  };

  const handleEnroll = (courseId: string) => {
    if (!user) return;

    const updatedUser: User = {
      ...user,
      enrolledCourses: [...new Set([...user.enrolledCourses, courseId])]
    };

    setUser(updatedUser);
    try {
      localStorage.setItem('eduworld_user', JSON.stringify(updatedUser));

      const registeredUsers = JSON.parse(localStorage.getItem('eduworld_registered_users') || '[]');
      const updatedRegistry = registeredUsers.map((u: any) => 
        u.id === user.id ? { ...u, enrolledCourses: updatedUser.enrolledCourses } : u
      );
      localStorage.setItem('eduworld_registered_users', JSON.stringify(updatedRegistry));
    } catch (err) {
      console.error("Failed to save enrollment data.");
    }

    // Redirect to "Selected Learning Pathway" (Dashboard)
    setSelectedCourseId(courseId);
    setActiveCourseId(courseId);
    setRoute(AppRoute.DASHBOARD);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleAddCourse = async (newCourse: Course) => {
    try {
      await saveCourseToDB(newCourse);
      const updated = await getAllCoursesFromDB();
      setCourses(updated);
      if (user?.role === 'admin') {
        setRoute(AppRoute.ADMIN);
      }
    } catch (err) {
      alert("Failed to save course. IndexedDB storage might be full or blocked.");
    }
  };

  const handleUpdateCourse = async (updatedCourse: Course) => {
    try {
      await saveCourseToDB(updatedCourse);
      const updated = await getAllCoursesFromDB();
      setCourses(updated);
    } catch (err) {
      alert("Storage error: Failed to update course in IndexedDB.");
    }
  };

  const handleDeleteCourse = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this course?')) {
      try {
        await deleteCourseFromDB(id);
        const updated = await getAllCoursesFromDB();
        setCourses(updated);
      } catch (err) {
        alert("Failed to delete course.");
      }
    }
  };

  const handleDeleteAll = async () => {
    if (window.confirm('WARNING: This will permanently delete ALL courses from the global registry. Continue?')) {
      try {
        await clearAllCoursesFromDB();
        setCourses([]);
      } catch (err) {
        alert("Failed to clear course registry.");
      }
    }
  };

  const handleEnterPreview = () => {
    setAdminPreviewMode(true);
    setRoute(AppRoute.DASHBOARD);
  };

  const handleExitPreview = () => {
    setAdminPreviewMode(false);
    setRoute(AppRoute.ADMIN);
  };

  const handleQuizComplete = (lessonId: string, attempt: QuizAttempt) => {
    if (!user) return;
    const updatedUser = {
      ...user,
      quizScores: {
        ...user.quizScores,
        [lessonId]: attempt
      }
    };
    setUser(updatedUser);
    localStorage.setItem('eduworld_user', JSON.stringify(updatedUser));
  };

  const handleAdminEditCourse = (courseId: string) => {
    setEditingCourseId(courseId);
    setRoute(AppRoute.ADMIN);
    setAdminPreviewMode(false);
  };

  const activeCourse = courses.find(c => c.id === activeCourseId);
  const enrolledCourses = courses.filter(c => user?.enrolledCourses.includes(c.id));

  // Set default selection if none
  useEffect(() => {
    if (enrolledCourses.length > 0 && !selectedCourseId) {
      setSelectedCourseId(enrolledCourses[0].id);
    }
  }, [enrolledCourses, selectedCourseId]);

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  if (isLoading) {
    return (
      <div className="h-screen bg-[#f8fafc] flex flex-col items-center justify-center space-y-4">
        <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Booting Learning Core...</p>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#f8fafc] text-slate-800 overflow-hidden relative">
      {adminPreviewMode && (
        <div className="fixed top-0 left-0 right-0 h-12 bg-indigo-600 text-white z-[100] flex items-center justify-center px-4 shadow-lg animate-in slide-in-from-top duration-300">
          <div className="flex items-center space-x-4">
            <span className="text-xs font-bold uppercase tracking-widest flex items-center">
              <i className="fas fa-eye mr-2"></i> Admin Preview Mode
            </span>
            <div className="h-4 w-px bg-white/20"></div>
            <button 
              onClick={handleExitPreview}
              className="bg-white text-indigo-600 px-3 py-1 rounded-full text-[10px] font-black uppercase hover:bg-indigo-50 transition-colors"
            >
              Exit Preview & Return to Admin
            </button>
          </div>
        </div>
      )}

      {route !== AppRoute.COURSE_VIEW && (
        <Sidebar 
          currentRoute={route} 
          user={user}
          setRoute={(r) => {
            setAdminPreviewMode(false);
            setRoute(r);
            if (r !== AppRoute.ADMIN) setEditingCourseId(null);
          }} 
          onLogout={handleLogout}
        />
      )}

      <main className={`flex-1 overflow-y-auto ${adminPreviewMode ? 'pt-12' : ''} ${route !== AppRoute.COURSE_VIEW ? 'p-6 lg:p-10' : ''}`}>

        {route !== AppRoute.COURSE_VIEW && (
          <div className="md:hidden flex items-center justify-between mb-8 px-2">
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
                <i className="fas fa-graduation-cap text-white"></i>
              </div>
              <span className="text-xl font-bold text-slate-900 tracking-tight">Edu World</span>
            </div>

            <div className="relative" ref={switcherRef}>
              <button 
                onClick={() => setIsSwitcherOpen(!isSwitcherOpen)}
                className="flex items-center space-x-2 bg-white px-4 py-2 rounded-2xl border border-slate-200 shadow-sm active:scale-95 transition-all"
              >
                <i className="fas fa-layer-group text-indigo-600 text-sm"></i>
                <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Switch</span>
              </button>

              {isSwitcherOpen && (
                <div className="absolute right-0 mt-3 w-64 bg-white border border-slate-200 rounded-[32px] shadow-2xl z-[100] overflow-hidden animate-in fade-in zoom-in-95 duration-200 origin-top-right">
                  <div className="p-4 border-b border-slate-100 bg-slate-50">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Your Programs</p>
                  </div>
                  <div className="max-h-[300px] overflow-y-auto py-2">
                    {enrolledCourses.map(c => (
                      <button
                        key={c.id}
                        onClick={() => {
                          setSelectedCourseId(c.id);
                          setRoute(AppRoute.DASHBOARD);
                          setIsSwitcherOpen(false);
                        }}
                        className={`w-full flex items-center justify-between px-6 py-4 hover:bg-slate-50 transition-all group ${selectedCourseId === c.id ? 'bg-indigo-50' : ''}`}
                      >
                        <span className={`text-xs font-bold text-left truncate max-w-[140px] ${selectedCourseId === c.id ? 'text-indigo-600' : 'text-slate-600 group-hover:text-indigo-600'}`}>
                          {c.title}
                        </span>
                        {selectedCourseId === c.id && (
                          <span className="text-[8px] font-black bg-indigo-600 text-white px-2 py-0.5 rounded-full uppercase tracking-widest">Active</span>
                        )}
                      </button>
                    ))}
                  </div>
                  <div className="p-3 border-t border-slate-100 bg-slate-50">
                    <button 
                      onClick={handleLogout}
                      className="w-full flex items-center justify-center space-x-2 py-3 bg-white border border-rose-100 text-rose-500 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-50 transition-all"
                    >
                      <i className="fas fa-power-off"></i>
                      <span>Logout</span>
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {route === AppRoute.DASHBOARD && (
          <Dashboard 
            onCourseClick={handleCourseClick} 
            setRoute={setRoute} 
            courses={enrolledCourses} 
            selectedCourseId={selectedCourseId}
            onSelectCourse={setSelectedCourseId}
          />
        )}

        {route === AppRoute.COURSES && (
          <Explore 
            onCourseClick={handleCourseClick} 
            courses={courses}
          />
        )}

        {route === AppRoute.PROFILE && (
          <Profile 
            user={user}
            courses={enrolledCourses}
            onCourseClick={handleCourseClick}
            onUpdateUser={setUser}
          />
        )}

        {route === AppRoute.ADMIN && user.role === 'admin' && (
          <AdminPanel 
            courses={courses} 
            initialEditCourseId={editingCourseId}
            onAddCourse={handleAddCourse}
            onUpdateCourse={handleUpdateCourse}
            onDeleteCourse={handleDeleteCourse}
            onPreview={handleEnterPreview}
            onDeleteAll={handleDeleteAll}
          />
        )}

        {route === AppRoute.COURSE_DETAILS && activeCourse && (
          <CourseDetails 
            course={activeCourse} 
            isAdmin={user.role === 'admin'}
            isEnrolled={user.enrolledCourses.includes(activeCourse.id)}
            onEnroll={handleEnroll}
            onAdminEdit={() => handleAdminEditCourse(activeCourse.id)}
            onBack={() => setRoute(AppRoute.COURSES)}
          />
        )}

        {route === AppRoute.COURSE_VIEW && activeCourse && (
          <CourseView 
            course={activeCourse} 
            user={user}
            onBack={() => setRoute(AppRoute.DASHBOARD)} 
            onQuizComplete={handleQuizComplete}
          />
        )}
      </main>

      {route !== AppRoute.COURSE_VIEW && (
        <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur border-t border-slate-200 px-6 py-3 flex justify-between items-center z-50">
          {[
            { id: AppRoute.DASHBOARD, icon: 'fa-house', label: 'Home' },
            { id: AppRoute.COURSES, icon: 'fa-compass', label: 'Explore' },
            { id: AppRoute.PROFILE, icon: 'fa-user', label: 'Profile' },
            ...(user.role === 'admin' ? [{ id: AppRoute.ADMIN, icon: 'fa-shield-halved', label: 'Admin' }] : []),
          ].map(item => (
            <button
              key={item.id}
              onClick={() => {
                setAdminPreviewMode(false);
                setRoute(item.id as AppRoute);
                if (item.id !== AppRoute.ADMIN) setEditingCourseId(null);
              }}
              className={`flex flex-col items-center justify-center transition-all ${
                route === item.id ? 'text-indigo-600' : 'text-slate-400'
              }`}
            >
              <i className={`fas ${item.icon} text-lg mb-1`}></i>
              <span className="text-[10px] font-bold uppercase tracking-widest">{item.label}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

