import React from 'react';
import { AppRoute, User } from '../types';

interface SidebarProps {
  currentRoute: AppRoute;
  user: User;
  setRoute: (route: AppRoute) => void;
  onLogout: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentRoute, user, setRoute, onLogout }) => {
