import React, { useState, useEffect, useRef } from 'react';
import { Course, Lesson, QuizQuestion, Resource, User, QuizAttempt } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

type TabType = 'about' | 'resources' | 'notes' | 'quiz';

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(course.lessons?.[0]?.id);
  const [activeTab, setActiveTab] = useState<TabType>('about');
  const [personalNote, setPersonalNote] = useState('');

  // Video Player States
  const videoRef = useRef<HTMLVideoElement>(null);
  const [playbackSpeed, setPlaybackSpeed] = useState(1);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  const [quizState, setQuizState] = useState<{
    currentQuestionIndex: number;
    score: number;
    showResult: boolean;
    showReview: boolean;
    answers: number[];
  }>({
    currentQuestionIndex: 0,
    score: 0,
    showResult: false,
    showReview: false,
    answers: [],
  });

  // Defensive check if course has no lessons
  if (!course.lessons || course.lessons.length === 0) {
    return (
      <div className="flex flex-col h-full bg-[#f8fafc] p-20 items-center justify-center text-center">
        <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-6 text-slate-300 border border-slate-100 shadow-sm">
          <i className="fas fa-book-open text-3xl"></i>
        </div>
        <h2 className="text-2xl font-black text-slate-800">Empty Curriculum</h2>
        <p className="text-slate-500 mt-2 max-w-xs mx-auto">This course doesn't have any lessons or content published yet.</p>
        <button 
          onClick={onBack} 
          className="mt-8 px-8 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-600/20 hover:bg-indigo-700 transition-all"
        >
          Go Back
        </button>
      </div>
    );
  }

  const activeLessonIndex = course.lessons.findIndex(l => l.id === activeLessonId);
  const activeLesson = course.lessons[activeLessonIndex] || course.lessons[0];

  useEffect(() => {
    if (activeLessonId) {
      const savedNote = localStorage.getItem(`note_${activeLessonId}`);
      setPersonalNote(savedNote || '');
    }
    setQuizState({
      currentQuestionIndex: 0,
      score: 0,
      showResult: false,
      showReview: false,
      answers: [],
    });
    // Reset video when lesson changes
    if (videoRef.current) {
      videoRef.current.playbackRate = playbackSpeed;
    }
  }, [activeLessonId]);

  const saveNote = () => {
    localStorage.setItem(`note_${activeLessonId}`, personalNote);
    alert('Note saved locally!');
  };

  const goToNextLesson = () => {
    if (activeLessonIndex < course.lessons.length - 1) {
      setActiveLessonId(course.lessons[activeLessonIndex + 1].id);
      setActiveTab('about');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const goToPrevLesson = () => {
    if (activeLessonIndex > 0) {
      setActiveLessonId(course.lessons[activeLessonIndex - 1].id);
      setActiveTab('about');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleQuizAnswer = (optionIndex: number) => {
    if (!activeLesson.quiz) return;

    const isCorrect = optionIndex === activeLesson.quiz[quizState.currentQuestionIndex].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;
    const nextIndex = quizState.currentQuestionIndex + 1;

    if (nextIndex < activeLesson.quiz.length) {
      setQuizState(prev => ({
        ...prev,
        currentQuestionIndex: nextIndex,
        score: newScore,
        answers: [...prev.answers, optionIndex]
      }));
    } else {
      setQuizState(prev => ({
        ...prev,
        score: newScore,
        showResult: true,
        answers: [...prev.answers, optionIndex]
      }));

      onQuizComplete(activeLesson.id, {
        score: newScore,
        total: activeLesson.quiz.length,
        date: new Date()
      });
    }
  };

  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds.toString().padStart(2, '0')}`;
  };

  const handleSpeedChange = (speed: number) => {
    setPlaybackSpeed(speed);
    if (videoRef.current) {
      videoRef.current.playbackRate = speed;
    }
  };

  const toggleFullScreen = () => {
    if (videoRef.current) {
      if (!document.fullscreenElement) {
        videoRef.current.requestFullscreen();
      } else {
        document.exitFullscreen();
      }
    }
  };

  const renderTabContent = () => {
    switch (activeTab) {
      case 'resources':
        return (
          <div className="space-y-6 animate-in fade-in duration-300">
            <h3 className="text-xl font-black text-slate-800 tracking-tight">Downloadable Resources</h3>
            {activeLesson.resources && activeLesson.resources.length > 0 ? (
              <div className="grid grid-cols-1 gap-4">
                {activeLesson.resources.map(res => (
                  <button 
                    key={res.id} 
                    className="w-full flex items-center p-6 bg-white border border-slate-100 rounded-3xl hover:border-indigo-100 hover:shadow-xl transition-all group text-left"
                  >
                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center mr-5 shadow-sm transition-colors ${res.type === 'pdf' ? 'bg-rose-50 text-rose-500' : 'bg-indigo-50 text-indigo-600'}`}>
                      <i className={`fas ${res.type === 'link' ? 'fa-link' : (res.type === 'pdf' ? 'fa-file-pdf' : 'fa-file-zipper')}`}></i>
                    </div>
                    <div className="flex-1">
                      <p className="font-black text-slate-800 text-lg leading-tight">{res.title}</p>
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{res.type} Resource</span>
                    </div>
                    <i className="fas fa-download text-slate-300 group-hover:text-indigo-600 transition-colors"></i>
                  </button>
                ))}
              </div>
            ) : (
              <div className="py-16 text-center bg-slate-50 rounded-[40px] border-2 border-dashed border-slate-200">
                <i className="fas fa-folder-open text-3xl text-slate-200 mb-4"></i>
                <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">No resources for this module.</p>
              </div>
            )}
          </div>
        );
      case 'notes':
        return (
          <div className="space-y-6 animate-in fade-in duration-300">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Study Notes</h3>
              <button onClick={saveNote} className="px-6 py-2 bg-indigo-600 text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-600/20">Save</button>
            </div>
            <textarea 
              value={personalNote}
              onChange={(e) => setPersonalNote(e.target.value)}
              placeholder="Jot down takeaways..."
              className="w-full min-h-[400px] p-8 bg-white border-2 border-slate-100 rounded-[32px] focus:border-indigo-600/20 focus:ring-0 transition-all text-slate-700 font-medium leading-relaxed"
            />
          </div>
        );
      case 'quiz':
        return (
          <div className="space-y-8 animate-in fade-in duration-300">
            <div className="flex items-center justify-between border-b border-slate-100 pb-4">
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Knowledge Check</h3>
            </div>
            {quizState.showResult ? (
              <div className="bg-white border border-slate-100 rounded-[40px] p-12 text-center space-y-8 shadow-xl">
                <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto text-4xl mb-4 border border-indigo-100 shadow-inner">
                  <i className="fas fa-trophy"></i>
                </div>
                <div>
                  <h4 className="text-4xl font-black text-slate-800 tracking-tight">Module Mastered!</h4>
                  <p className="text-slate-500 font-medium text-lg mt-2">Score: {quizState.score} / {activeLesson.quiz?.length}</p>
                </div>
                <button 
                  onClick={() => setActiveTab('about')}
                  className="px-10 py-5 bg-indigo-600 text-white rounded-[24px] font-black uppercase tracking-[0.2em] text-xs hover:bg-indigo-700 shadow-xl"
                >
                  Continue Learning
                </button>
              </div>
            ) : (
              <div className="space-y-10">
                <h4 className="text-2xl font-black text-slate-800 leading-tight">
                  {activeLesson.quiz?.[quizState.currentQuestionIndex]?.question}
                </h4>
                <div className="grid grid-cols-1 gap-4">
                  {activeLesson.quiz?.[quizState.currentQuestionIndex]?.options.map((option, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleQuizAnswer(idx)}
                      className="w-full text-left p-6 bg-white border border-slate-100 rounded-3xl hover:border-indigo-600/40 transition-all font-bold text-slate-700 group flex items-center shadow-sm"
                    >
                      <span className="w-10 h-10 rounded-xl bg-slate-50 border border-slate-100 flex items-center justify-center text-sm mr-4 group-hover:bg-indigo-600 group-hover:text-white transition-all text-slate-400">
                        {String.fromCharCode(65 + idx)}
                      </span>
                      {option}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        );
      default:
        return (
          <div className="prose prose-slate max-w-none animate-in fade-in duration-300">
            <h3 className="text-3xl font-black text-slate-800 tracking-tight mb-8">{activeLesson.title}</h3>
            <div 
              className="text-slate-600 leading-relaxed text-lg"
              dangerouslySetInnerHTML={{ __html: activeLesson.content }}
            />
          </div>
        );
    }
  };

  return (
    <div className="flex flex-col lg:flex-row h-full bg-[#f8fafc] overflow-hidden">
      <div className="flex-1 flex flex-col h-full overflow-y-auto">
        <div className="p-4 lg:p-8 flex items-center justify-between border-b border-slate-100 sticky top-0 bg-white/80 backdrop-blur z-20">
          <div className="flex items-center space-x-4">
            <button onClick={onBack} className="w-10 h-10 rounded-full bg-white flex items-center justify-center hover:bg-slate-50 transition-colors border border-slate-100 shadow-sm">
              <i className="fas fa-arrow-left text-slate-400"></i>
            </button>
            <div>
              <h2 className="text-lg font-black text-slate-800 tracking-tight">{course.title}</h2>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{activeLesson.title}</p>
            </div>
          </div>
        </div>

        <div className="p-4 lg:p-8 space-y-10">
          <div className="relative group bg-slate-900 rounded-[40px] overflow-hidden shadow-2xl border border-slate-200">
            {activeLesson.videoUrl ? (
              <video 
                ref={videoRef}
                key={activeLesson.id}
                src={activeLesson.videoUrl} 
                controls
                className="w-full aspect-video"
              />
            ) : (
              <div className="aspect-video w-full flex flex-col items-center justify-center space-y-4 bg-slate-50">
                <i className="fas fa-play text-4xl text-slate-200"></i>
                <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Video content pending</p>
              </div>
            )}
          </div>

          <div className="max-w-5xl mx-auto space-y-10">
            <div className="flex items-center space-x-2 border-b border-slate-100 overflow-x-auto no-scrollbar">
              {[
                { id: 'about', label: 'Overview', icon: 'fa-info-circle' },
                { id: 'resources', label: 'Resources', icon: 'fa-paperclip' },
                { id: 'notes', label: 'Notes', icon: 'fa-pen-nib' },
                { id: 'quiz', label: 'Quiz', icon: 'fa-clipboard-question' },
              ].map(tab => (
                <button 
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as TabType)}
                  className={`px-8 py-5 font-black text-[10px] uppercase tracking-widest transition-all border-b-2 flex items-center ${activeTab === tab.id ? 'text-indigo-600 border-indigo-600' : 'text-slate-400 border-transparent hover:text-slate-600'}`}
                >
                  <i className={`fas ${tab.icon} mr-3 text-sm`}></i> 
                  {tab.label}
                </button>
              ))}
            </div>

            <div className="pb-24">
              {renderTabContent()}

              <div className="flex items-center justify-between pt-16 border-t border-slate-100">
                <button onClick={goToPrevLesson} disabled={activeLessonIndex === 0} className={`flex items-center space-x-3 px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${activeLessonIndex === 0 ? 'text-slate-200' : 'text-slate-600 bg-white border border-slate-100 shadow-sm hover:bg-slate-50'}`}>
                  <i className="fas fa-arrow-left"></i>
                  <span>Previous</span>
                </button>
                <button onClick={goToNextLesson} disabled={activeLessonIndex === course.lessons.length - 1} className={`flex items-center space-x-3 px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${activeLessonIndex === course.lessons.length - 1 ? 'text-slate-200' : 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/20 hover:bg-indigo-700'}`}>
                  <span>Next Module</span>
                  <i className="fas fa-arrow-right"></i>
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="w-full lg:w-[450px] border-l border-slate-100 bg-white flex flex-col h-[600px] lg:h-full overflow-hidden">
        <AIAssistant course={course} lesson={activeLesson} user={user} />
      </div>
    </div>
  );
};

