              <button
                key={tab}
                type="button"
                onClick={() => setActiveConfigTab(tab as any)}
                className={`flex-1 py-7 text-[10px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${
                  activeConfigTab === tab ? 'text-indigo-600 border-indigo-600 bg-white' : 'text-slate-400 border-transparent hover:bg-white'
                }`}
              >
                {tab === 'meta' ? 'Identity' : tab === 'layout' ? 'Navigation' : 'Modules'}
              </button>
            ))}
          </div>

          <form id="course-form" className="p-10 md:p-14 space-y-12" onSubmit={handleSave}>
            {activeConfigTab === 'meta' && (
              <section className="space-y-12 animate-in fade-in">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                   <div className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cover Preview</label>
                      <img src={currentCourse.thumbnail} className="w-full aspect-video object-cover rounded-[32px] border border-slate-100 shadow-inner" alt="Preview" />
                   </div>
                   <div className="space-y-8">
                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Program Title</label>
                        <input required type="text" value={currentCourse.title || ''} onChange={(e) => setCurrentCourse(prev => ({...prev!, title: e.target.value}))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-slate-800 font-bold focus:border-indigo-600/20" />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Category</label>
                          <input required type="text" value={currentCourse.category || ''} onChange={(e) => setCurrentCourse(prev => ({...prev!, category: e.target.value}))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-slate-800" />
                        </div>
                        <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Price ($)</label>
                          <input required type="number" value={currentCourse.price || 0} onChange={(e) => setCurrentCourse(prev => ({...prev!, price: parseFloat(e.target.value)}))} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-slate-800 font-mono" />
                        </div>
                      </div>
                   </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Full Description</label>
                  <textarea required rows={6} value={currentCourse.description || ''} onChange={(e) => setCurrentCourse(prev => ({...prev!, description: e.target.value}))} className="w-full bg-slate-50 border border-slate-100 rounded-[32px] px-8 py-6 text-slate-700 leading-relaxed" />
                </div>
              </section>
            )}

            {activeConfigTab === 'layout' && (
              <section className="space-y-10 animate-in fade-in">
                 <div className="flex justify-between items-center">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Navigation Map</h3>
                    <button type="button" onClick={() => setCurrentCourse(prev => ({...prev!, subjects: [...(prev!.subjects || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Group', icon: 'fa-book', color: COLOR_PRESETS[0].class }] }))} className="text-indigo-600 text-[10px] font-black uppercase tracking-widest">+ Create Group</button>
                 </div>
                 <div className="grid grid-cols-1 gap-6">
                    {(currentCourse.subjects || []).map(subj => (
                      <div key={subj.id} className="p-8 bg-slate-50 rounded-[32px] border border-slate-100 flex items-center gap-8">
                        <div className={`w-16 h-16 rounded-2xl flex items-center justify-center text-2xl shadow-sm ${subj.color}`}>
                           <i className={`fas ${subj.icon}`}></i>
                        </div>
                        <div className="flex-1 space-y-4">
                           <input type="text" value={subj.name} onChange={(e) => updateSubject(subj.id, { name: e.target.value })} className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold text-slate-800" />
