                        <button type="button" onClick={() => setCurrentCourse(prev => ({...prev!, subjects: prev!.subjects?.filter(s => s.id !== subj.id)}))} className="text-slate-300 hover:text-rose-500 transition-colors"><i className="fas fa-trash-alt"></i></button>
                      </div>
                    ))}
                 </div>
              </section>
            )}

            {activeConfigTab === 'curriculum' && (
              <section className="space-y-10 animate-in fade-in">
                 <div className="flex justify-between items-center">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Knowledge Modules</h3>
                    <button type="button" onClick={() => setCurrentCourse(prev => ({...prev!, lessons: [...(prev!.lessons || []), { id: Math.random().toString(36).substr(2, 9), title: 'New Lesson', content: '', duration: '10:00' }] }))} className="px-6 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-600/20">+ Add Module</button>
                 </div>
                 <div className="space-y-4">
                    {(currentCourse.lessons || []).map((lesson, idx) => (
                      <div key={lesson.id} className="bg-slate-50 rounded-3xl border border-slate-100 overflow-hidden">
