                           <span className="text-xs font-black text-slate-300">{idx + 1}</span>
                           <input type="text" value={lesson.title} onChange={(e) => updateLesson(lesson.id, { title: e.target.value })} className="flex-1 bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-800" />
                           <button type="button" onClick={() => setActiveLessonExtras(activeLessonExtras === lesson.id ? null : lesson.id)} className="w-10 h-10 rounded-xl bg-white border border-slate-100 flex items-center justify-center text-indigo-600 shadow-sm"><i className="fas fa-edit"></i></button>
                        </div>
