  }

  return (
    <div className="max-w-7xl mx-auto space-y-12 pb-24 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-5xl font-black text-slate-900 tracking-tight">System Registry</h1>
          <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px] mt-2">Manage curriculum pathways and AI synthesis</p>
        </div>
        <div className="flex gap-4">
          <button onClick={() => setIsAiModalOpen(true)} className="px-10 py-5 bg-white text-indigo-600 border border-slate-100 rounded-[24px] font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-slate-50 transition-all flex items-center">
            <i className="fas fa-wand-magic-sparkles mr-3"></i> AI Architect
          </button>
          <button onClick={() => openEditor()} className="bg-indigo-600 text-white px-10 py-5 rounded-[24px] font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 shadow-2xl shadow-indigo-600/30 transition-all flex items-center">
            <i className="fas fa-plus mr-3"></i> Manual Build
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[40px] border border-slate-100 overflow-hidden shadow-2xl shadow-slate-200/50">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-12 py-8 text-[10px] font-black text-slate-400 uppercase tracking-widest">Identity</th>
              <th className="px-12 py-8 text-[10px] font-black text-slate-400 uppercase tracking-widest">Metadata</th>
              <th className="px-12 py-8 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {courses.map((course) => (
              <tr key={course.id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-12 py-8">
                  <div className="flex items-center space-x-5">
                    <img src={course.thumbnail} className="w-14 h-14 rounded-2xl object-cover border border-slate-200" />
                    <div>
                      <p className="font-black text-slate-800 text-base">{course.title}</p>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{course.category}</p>
                    </div>
                  </div>
                </td>
                <td className="px-12 py-8">
                  <span className="text-xs font-bold text-slate-500">{course.lessons?.length || 0} Modules • {(course.studentsCount || 0).toLocaleString()} Active Users</span>
                </td>
                <td className="px-12 py-8 text-right space-x-3">
                  <button onClick={() => openEditor(course)} className="w-11 h-11 bg-white border border-slate-100 rounded-xl text-slate-400 hover:text-indigo-600 hover:border-indigo-100 shadow-sm transition-all"><i className="fas fa-edit"></i></button>
                  <button onClick={() => onDeleteCourse(course.id)} className="w-11 h-11 bg-white border border-slate-100 rounded-xl text-slate-400 hover:text-rose-500 hover:border-rose-100 shadow-sm transition-all"><i className="fas fa-trash"></i></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { User } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
}

const getUsersFromStorage = (): any[] => {
  const users = localStorage.getItem('eduworld_registered_users');
  return users ? JSON.parse(users) : [];
};

const saveUserToStorage = (user: any) => {
  const users = getUsersFromStorage();
  users.push(user);
  localStorage.setItem('eduworld_registered_users', JSON.stringify(users));
};

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!email || !password || (!isLogin && !name)) {
      setError('Required fields missing.');
      return;
    }

    if (isAdminMode) {
      if (email === 'admin@eduworld.com' && password === 'admin') {
        onLogin({
          id: 'admin-1',
          name: 'System Admin',
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=admin',
          role: 'admin',
          enrolledCourses: [],
          documents: [],
          quizScores: {}
        });
        return;
      } else {
        setError('Invalid admin credentials.');
        return;
      }
    }

    const registeredUsers = getUsersFromStorage();
    if (isLogin) {
      const userMatch = registeredUsers.find(u => u.email === email && u.password === password);
      if (userMatch) {
        onLogin({
          ...userMatch,
          role: 'student'
        });
      } else {
        setError('Identity not found.');
      }
    } else {
      const userExists = registeredUsers.some(u => u.email === email);
      if (userExists) {
        setError('Email already in network.');
        return;
      }
      const newUser = {
        id: Math.random().toString(36).substr(2, 9),
        name, email, password,
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${email}`,
        role: 'student', enrolledCourses: [], documents: [], quizScores: {}
      };
      saveUserToStorage(newUser);
      onLogin(newUser as any);
    }
  };

  return (
    <div className="min-h-screen bg-[#f1f5f9] flex items-center justify-center p-6">
      <div className="w-full max-w-md">
        <div className="text-center mb-12">
          <div className="w-20 h-20 bg-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 shadow-2xl shadow-indigo-600/30">
            <i className="fas fa-graduation-cap text-white text-4xl"></i>
          </div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tighter">Edu World</h1>
          <p className="text-slate-400 font-black uppercase tracking-[0.3em] text-[10px] mt-4 opacity-70">LEARNING CORE ACCESS</p>
        </div>

        <div className="bg-white rounded-[48px] border border-slate-100 p-10 md:p-14 shadow-2xl relative overflow-hidden">
          <div className="flex bg-slate-50 p-1.5 rounded-2xl mb-10 relative z-10 border border-slate-100 shadow-inner">
            <button
              onClick={() => { setIsLogin(true); setError(''); }}
              className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${isLogin && !isAdminMode ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-400'}`}
            >
              Log In
            </button>
            <button
              onClick={() => { setIsLogin(false); setError(''); }}
              className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${!isLogin && !isAdminMode ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-400'}`}
            >
              Sign Up
            </button>
          </div>

          <form onSubmit={handleSubmit} className="space-y-8 relative z-10">
            {!isLogin && !isAdminMode && (
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Identity Name</label>
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full bg-slate-50 border border-slate-100 rounded-3xl px-8 py-5 focus:bg-white focus:border-indigo-600/20 focus:ring-0 transition-all font-bold text-slate-800"
                  placeholder="Full name"
                />
              </div>
            )}

            <div className="space-y-3">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Secure Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-slate-50 border border-slate-100 rounded-3xl px-8 py-5 focus:bg-white focus:border-indigo-600/20 focus:ring-0 transition-all font-bold text-slate-800"
                placeholder="name@domain.com"
              />
            </div>

            <div className="space-y-3">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Access Key</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-slate-50 border border-slate-100 rounded-3xl px-8 py-5 focus:bg-white focus:border-indigo-600/20 focus:ring-0 transition-all font-bold text-slate-800"
                placeholder="••••••••"
              />
            </div>

            {error && <p className="text-[10px] font-black text-rose-500 text-center uppercase tracking-widest">{error}</p>}

            <button
              type="submit"
              className="w-full py-6 bg-indigo-600 text-white rounded-[24px] font-black text-xs uppercase tracking-[0.3em] hover:bg-indigo-700 shadow-xl shadow-indigo-600/20 transition-all transform active:scale-[0.98]"
            >
              Initialize Session
            </button>
          </form>

          <div className="mt-10 pt-10 border-t border-slate-50 text-center">
            <button
              onClick={() => { setIsAdminMode(!isAdminMode); setError(''); setIsLogin(true); }}
              className="text-[9px] font-black text-slate-300 hover:text-indigo-600 transition-all uppercase tracking-[0.3em]"
            >
              {isAdminMode ? 'Student Gateway' : 'Administrative Login'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Explore from './components/Explore';
import CourseView from './components/CourseView';
import CourseCard from './components/CourseCard';
import AdminPanel from './components/AdminPanel';
import Profile from './components/Profile';
import Auth from './components/Auth';
import CourseDetails from './components/CourseDetails';
import { AppRoute, Course, User, QuizAttempt } from './types';
import { MOCK_COURSES } from './constants';
import { getAllCoursesFromDB, saveCourseToDB, deleteCourseFromDB, clearAllCoursesFromDB } from './services/storage';

const App: React.FC = () => {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [activeCourseId, setActiveCourseId] = useState<string | null>(null);
  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [courses, setCourses] = useState<Course[]>([]);
  const [adminPreviewMode, setAdminPreviewMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [isSwitcherOpen, setIsSwitcherOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [editingCourseId, setEditingCourseId] = useState<string | null>(null);
  const switcherRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const loadCourses = async () => {
      try {
        const savedCourses = await getAllCoursesFromDB();
        if (savedCourses.length > 0) {
          setCourses(savedCourses);
        } else {
          for (const c of MOCK_COURSES) {
            await saveCourseToDB(c);
          }
          setCourses(MOCK_COURSES);
        }
      } catch (err) {
        console.error("Failed to load courses from IndexedDB", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadCourses();
  }, []);

  useEffect(() => {
    try {
      const savedUser = localStorage.getItem('eduworld_user');
      if (savedUser) {
        setUser(JSON.parse(savedUser));
      }
    } catch (err) {
      console.error("Failed to restore user session", err);
    }
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (switcherRef.current && !switcherRef.current.contains(event.target as Node)) {
        setIsSwitcherOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    try {
      localStorage.setItem('eduworld_user', JSON.stringify(newUser));
    } catch (err) {
      console.error("Storage limit reached for user data.");
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('eduworld_user');
    setRoute(AppRoute.DASHBOARD);
    setIsSwitcherOpen(false);
  };

  const handleCourseClick = (id: string) => {
    setActiveCourseId(id);
    const isEnrolled = user?.enrolledCourses.includes(id);
    if (isEnrolled) {
      setRoute(AppRoute.COURSE_VIEW);
    } else {
      setRoute(AppRoute.COURSE_DETAILS);
    }
  };

  const handleEnroll = (courseId: string) => {
    if (!user) return;
    const updatedUser: User = {
      ...user,
      enrolledCourses: [...new Set([...user.enrolledCourses, courseId])]
    };
    setUser(updatedUser);
    localStorage.setItem('eduworld_user', JSON.stringify(updatedUser));
    setSelectedCourseId(courseId);
    setActiveCourseId(courseId);
    setRoute(AppRoute.DASHBOARD);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleAddCourse = async (newCourse: Course) => {
    try {
      await saveCourseToDB(newCourse);
      const updated = await getAllCoursesFromDB();
      setCourses(updated);
      if (user?.role === 'admin') setRoute(AppRoute.ADMIN);
    } catch (err) {
      alert("Failed to save course.");
    }
  };

  const handleUpdateCourse = async (updatedCourse: Course) => {
    try {
      await saveCourseToDB(updatedCourse);
      const updated = await getAllCoursesFromDB();
      setCourses(updated);
    } catch (err) {
      alert("Failed to update course.");
    }
  };

  const handleDeleteCourse = async (id: string) => {
    if (window.confirm('Delete this course?')) {
      try {
        await deleteCourseFromDB(id);
        const updated = await getAllCoursesFromDB();
        setCourses(updated);
      } catch (err) {
        alert("Failed to delete course.");
      }
    }
  };

  const activeCourse = courses.find(c => c.id === activeCourseId);
  const enrolledCourses = courses.filter(c => user?.enrolledCourses.includes(c.id));

  useEffect(() => {
    if (enrolledCourses.length > 0 && !selectedCourseId) {
      setSelectedCourseId(enrolledCourses[0].id);
    }
  }, [enrolledCourses, selectedCourseId]);

  if (!user) return <Auth onLogin={handleLogin} />;

  if (isLoading) {
    return (
      <div className="h-screen bg-[#020617] flex flex-col items-center justify-center space-y-4">
        <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Booting Core...</p>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden relative">
      {adminPreviewMode && (
        <div className="fixed top-0 left-0 right-0 h-12 bg-indigo-600 text-white z-[100] flex items-center justify-center px-4 shadow-lg">
          <button onClick={() => setAdminPreviewMode(false)} className="bg-white text-indigo-600 px-3 py-1 rounded-full text-[10px] font-black">Exit Preview</button>
        </div>
      )}

      {route !== AppRoute.COURSE_VIEW && (
        <Sidebar currentRoute={route} user={user} setRoute={setRoute} onLogout={handleLogout} />
      )}

      <main className={`flex-1 overflow-y-auto ${adminPreviewMode ? 'pt-12' : ''} ${route !== AppRoute.COURSE_VIEW ? 'p-6 lg:p-10' : ''}`}>
        {route === AppRoute.DASHBOARD && (
          <Dashboard onCourseClick={handleCourseClick} setRoute={setRoute} courses={enrolledCourses} selectedCourseId={selectedCourseId} onSelectCourse={setSelectedCourseId} />
        )}
        {route === AppRoute.COURSES && <Explore onCourseClick={handleCourseClick} courses={courses} />}
        {route === AppRoute.PROFILE && <Profile user={user} courses={enrolledCourses} onCourseClick={handleCourseClick} onUpdateUser={setUser} />}
        {route === AppRoute.ADMIN && user.role === 'admin' && (
          <AdminPanel courses={courses} initialEditCourseId={editingCourseId} onAddCourse={handleAddCourse} onUpdateCourse={handleUpdateCourse} onDeleteCourse={handleDeleteCourse} onPreview={() => setAdminPreviewMode(true)} />
        )}
        {route === AppRoute.COURSE_DETAILS && activeCourse && (
          <CourseDetails course={activeCourse} isAdmin={user.role === 'admin'} isEnrolled={user.enrolledCourses.includes(activeCourse.id)} onEnroll={handleEnroll} onAdminEdit={() => { setEditingCourseId(activeCourse.id); setRoute(AppRoute.ADMIN); }} onBack={() => setRoute(AppRoute.COURSES)} />
        )}
        {route === AppRoute.COURSE_VIEW && activeCourse && (
          <CourseView course={activeCourse} user={user} onBack={() => setRoute(AppRoute.DASHBOARD)} onQuizComplete={(lid, att) => {
            const updatedUser = { ...user, quizScores: { ...user.quizScores, [lid]: att } };
            setUser(updatedUser);
            localStorage.setItem('eduworld_user', JSON.stringify(updatedUser));
          }} />
        )}
      </main>
    </div>
  );
};

