import React, { useState, useEffect, useRef } from 'react';
import { Course, Lesson, QuizQuestion, Resource, User, QuizAttempt } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

type TabType = 'about' | 'resources' | 'notes' | 'quiz';

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(course.lessons?.[0]?.id);
  const [activeTab, setActiveTab] = useState<TabType>('about');
  const [personalNote, setPersonalNote] = useState('');
  const [isAiOpen, setIsAiOpen] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const [playbackSpeed, setPlaybackSpeed] = useState(1);

  const [quizState, setQuizState] = useState<{
    currentQuestionIndex: number;
    score: number;
    showResult: boolean;
    showReview: boolean;
    answers: number[];
  }>({
    currentQuestionIndex: 0,
    score: 0,
    showResult: false,
    showReview: false,
    answers: [],
  });

  if (!course.lessons || course.lessons.length === 0) {
    return (
      <div className="flex flex-col h-screen bg-[#020617] p-6 items-center justify-center text-center">
        <div className="w-20 h-20 bg-slate-900 rounded-full flex items-center justify-center mb-6 text-slate-700 border border-slate-800 shadow-xl">
          <i className="fas fa-book-open text-3xl"></i>
        </div>
        <h2 className="text-2xl font-black text-slate-100">Empty Curriculum</h2>
        <button onClick={onBack} className="mt-8 px-8 py-3 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl">Go Back</button>
      </div>
    );
  }

  const activeLessonIndex = course.lessons.findIndex(l => l.id === activeLessonId);
  const activeLesson = course.lessons[activeLessonIndex] || course.lessons[0];

  useEffect(() => {
    if (activeLessonId) {
      const savedNote = localStorage.getItem(`note_${activeLessonId}`);
      setPersonalNote(savedNote || '');
    }
    setQuizState({
      currentQuestionIndex: 0,
      score: 0,
      showResult: false,
      showReview: false,
      answers: [],
    });
    if (videoRef.current) {
      videoRef.current.playbackRate = playbackSpeed;
    }
  }, [activeLessonId]);

  const saveNote = () => {
    localStorage.setItem(`note_${activeLessonId}`, personalNote);
    alert('Note saved!');
  };

  const goToNextLesson = () => {
    if (activeLessonIndex < course.lessons.length - 1) {
      setActiveLessonId(course.lessons[activeLessonIndex + 1].id);
      setActiveTab('about');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const goToPrevLesson = () => {
    if (activeLessonIndex > 0) {
      setActiveLessonId(course.lessons[activeLessonIndex - 1].id);
      setActiveTab('about');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleQuizAnswer = (optionIndex: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = optionIndex === activeLesson.quiz[quizState.currentQuestionIndex].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;
    const nextIndex = quizState.currentQuestionIndex + 1;

    if (nextIndex < activeLesson.quiz.length) {
      setQuizState(prev => ({ ...prev, currentQuestionIndex: nextIndex, score: newScore, answers: [...prev.answers, optionIndex] }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, showResult: true, answers: [...prev.answers, optionIndex] }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
    }
  };

  const renderTabContent = () => {
    switch (activeTab) {
      case 'resources':
        return (
          <div className="space-y-6">
            <h3 className="text-xl font-black text-white">Resources</h3>
            {activeLesson.resources?.map(res => (
              <button key={res.id} className="w-full flex items-center p-5 bg-slate-900 border border-slate-800 rounded-2xl hover:border-indigo-500/50 transition-all text-left group">
                <div className="w-10 h-10 rounded-xl bg-slate-950 flex items-center justify-center mr-4 text-indigo-400">
                  <i className="fas fa-file-pdf"></i>
                </div>
                <div className="flex-1">
                  <p className="font-bold text-slate-200">{res.title}</p>
                  <span className="text-[10px] text-slate-500 uppercase font-black">{res.type}</span>
                </div>
              </button>
            ))}
          </div>
        );
      case 'notes':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-black text-white">My Notes</h3>
              <button onClick={saveNote} className="px-5 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase">Save</button>
            </div>
            <textarea value={personalNote} onChange={(e) => setPersonalNote(e.target.value)} className="w-full min-h-[300px] p-6 bg-slate-900 border border-slate-800 rounded-3xl text-slate-200" />
          </div>
        );
      case 'quiz':
        return (
          <div className="space-y-8">
            {quizState.showResult ? (
              <div className="bg-slate-900 border border-slate-800 rounded-3xl p-10 text-center space-y-6">
                <h4 className="text-2xl font-black text-white">Score: {quizState.score}/{activeLesson.quiz?.length}</h4>
                <button onClick={() => setActiveTab('about')} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase">Finish</button>
              </div>
            ) : (
              <div className="space-y-6">
                <h4 className="text-xl font-black text-white">{activeLesson.quiz?.[quizState.currentQuestionIndex].question}</h4>
                {activeLesson.quiz?.[quizState.currentQuestionIndex].options.map((opt, i) => (
                  <button key={i} onClick={() => handleQuizAnswer(i)} className="w-full p-5 bg-slate-900 border border-slate-800 rounded-2xl text-left hover:border-indigo-500/50 transition-all text-slate-300">{opt}</button>
                ))}
              </div>
            )}
          </div>
        );
      default:
        return (
          <div className="prose prose-invert max-w-none">
            <h3 className="text-2xl font-black text-white mb-6">{activeLesson.title}</h3>
            <div dangerouslySetInnerHTML={{ __html: activeLesson.content }} className="text-slate-400" />
          </div>
        );
    }
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden relative">
      <div className="flex-1 flex flex-col h-full overflow-y-auto">
        <div className="p-4 lg:p-6 flex items-center justify-between border-b border-slate-800 bg-slate-950/80 backdrop-blur sticky top-0 z-30">
          <div className="flex items-center space-x-3">
            <button onClick={onBack} className="w-9 h-9 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500">
              <i className="fas fa-arrow-left"></i>
            </button>
            <div className="truncate max-w-[150px] sm:max-w-xs">
              <h2 className="text-sm font-black text-white truncate">{course.title}</h2>
              <p className="text-[10px] text-slate-500 font-bold uppercase truncate">{activeLesson.title}</p>
            </div>
          </div>
          <button onClick={() => setIsAiOpen(!isAiOpen)} className="lg:hidden w-9 h-9 rounded-xl bg-indigo-600 text-white flex items-center justify-center shadow-lg">
            <i className={`fas ${isAiOpen ? 'fa-times' : 'fa-robot'}`}></i>
          </button>
        </div>

        <div className="p-4 lg:p-8 space-y-8">
          <div className="bg-black rounded-2xl sm:rounded-[32px] overflow-hidden border border-slate-800 shadow-2xl">
            {activeLesson.videoUrl ? (
              <video ref={videoRef} key={activeLesson.id} src={activeLesson.videoUrl} controls className="w-full aspect-video" />
            ) : (
              <div className="aspect-video w-full flex flex-col items-center justify-center bg-slate-900">
                <i className="fas fa-play text-4xl text-slate-800 mb-4"></i>
                <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Video Pending</p>
              </div>
            )}
          </div>

          <div className="max-w-4xl mx-auto space-y-8">
            <div className="flex items-center space-x-1 border-b border-slate-800 overflow-x-auto no-scrollbar scroll-smooth">
              {[
                { id: 'about', label: 'Info', icon: 'fa-info' },
                { id: 'resources', label: 'Docs', icon: 'fa-paperclip' },
                { id: 'notes', label: 'Notes', icon: 'fa-pen' },
                { id: 'quiz', label: 'Quiz', icon: 'fa-question' },
              ].map(tab => (
                <button key={tab.id} onClick={() => setActiveTab(tab.id as TabType)} className={`px-5 py-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap border-b-2 transition-all flex items-center ${activeTab === tab.id ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}>
                  <i className={`fas ${tab.icon} mr-2`}></i> {tab.label}
                </button>
              ))}
            </div>

            <div className="pb-24 lg:pb-10">
              {renderTabContent()}
              <div className="flex items-center justify-between pt-12 border-t border-slate-900">
                <button onClick={goToPrevLesson} disabled={activeLessonIndex === 0} className="px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest bg-slate-900 text-slate-500 disabled:opacity-20 transition-all border border-slate-800">Prev</button>
                <button onClick={goToNextLesson} disabled={activeLessonIndex === course.lessons.length - 1} className="px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest bg-indigo-600 text-white shadow-xl shadow-indigo-600/20 disabled:opacity-20 transition-all">Next</button>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className={`fixed inset-0 lg:relative lg:inset-auto z-40 lg:w-[400px] bg-slate-950/95 lg:bg-transparent backdrop-blur-sm lg:backdrop-blur-none transition-all duration-300 ${isAiOpen ? 'translate-y-0 opacity-100' : 'translate-y-full lg:translate-y-0 opacity-0 lg:opacity-100 invisible lg:visible'}`}>
        <div className="h-full pt-16 lg:pt-0">
          <AIAssistant course={course} lesson={activeLesson} user={user} />
        </div>
      </div>
    </div>
  );
};

