const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse, onPreview, onDeleteAll }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeLessonExtras, setActiveLessonExtras] = useState<string | null>(null);
  const [activeConfigTab, setActiveConfigTab] = useState<'meta' | 'layout' | 'curriculum'>('meta');
  const [isUploadingFiles, setIsUploadingFiles] = useState(false);
  const [isUploadingThumbnail, setIsUploadingThumbnail] = useState(false);
  const [activeSubgroupEditor, setActiveSubgroupEditor] = useState<string | null>(null);

  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const lessonVideoInputRef = useRef<HTMLInputElement>(null);
  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const quillContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) openEditor(course);
    }
  }, [initialEditCourseId, courses]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse({
        ...outline,
        instructorAvatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${outline.instructor || 'ai'}`,
        thumbnail: 'https://picsum.photos/seed/ai-gen/800/450',
        rating: 4.9,
        studentsCount: 0,
        roadmap: outline.roadmap || [],
        subjects: outline.subjects || []
      });
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Synthesis failed.");
    } finally { setIsGenerating(false); }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;
    try {
      if (currentCourse.id) { await onUpdateCourse(currentCourse as Course); }
      else {
        const newCourse: Course = {
          ...currentCourse as Course,
          id: Math.random().toString(36).substr(2, 9),
          instructorAvatar: currentCourse.instructorAvatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${currentCourse.instructor || 'lead'}`,
          thumbnail: currentCourse.thumbnail || 'https://picsum.photos/seed/course/800/450',
          category: currentCourse.category || 'Development',
          studentsCount: 0, rating: 5.0, roadmap: currentCourse.roadmap || [], subjects: currentCourse.subjects || []
        };
        await onAddCourse(newCourse);
      }
      setIsEditing(false);
      setCurrentCourse(null);
    } catch (err) { alert("Deploy failed."); }
  };

  const openEditor = (course?: Course) => {
    setCurrentCourse(course ? { ...course } : { title: '', description: '', category: 'General', instructor: 'Instructor', price: 49.99, rating: 5.0, studentsCount: 0, lessons: [], subjects: [], supplementalContent: [], roadmap: [] });
    setIsEditing(true);
    setActiveConfigTab('meta');
  };

  const updateLesson = (id: string, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev) return prev;
      return { ...prev, lessons: (prev.lessons || []).map(l => l.id === id ? { ...l, ...updates } : l) };
    });
  };

  const updateSubject = (id: string, updates: Partial<SubjectGroup>) => {
    setCurrentCourse(prev => {
      if (!prev) return prev;
      return { ...prev, subjects: (prev.subjects || []).map(s => s.id === id ? { ...s, ...updates } : s) };
    });
  };

  if (isEditing && currentCourse) {
    return (
      <div className="max-w-5xl mx-auto space-y-6 lg:space-y-8 pb-24 animate-in fade-in duration-500">
        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="flex items-center space-x-2 text-slate-500 hover:text-white font-black uppercase text-[10px] tracking-widest transition-all">
            <i className="fas fa-arrow-left"></i> <span>Back</span>
          </button>
          <button type="submit" form="course-form" className="px-6 py-3 bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest rounded-xl shadow-lg">Save Program</button>
        </div>

        <div className="bg-slate-900 rounded-3xl border border-slate-800 overflow-hidden">
          <div className="flex border-b border-slate-800 bg-slate-950/50 overflow-x-auto no-scrollbar">
            {['meta', 'layout', 'curriculum'].map((tab) => (
              <button key={tab} type="button" onClick={() => setActiveConfigTab(tab as any)} className={`flex-1 min-w-[100px] py-6 text-[9px] font-black uppercase tracking-widest transition-all border-b-2 ${activeConfigTab === tab ? 'text-indigo-400 border-indigo-600 bg-slate-900' : 'text-slate-600 border-transparent'}`}>
                {tab === 'meta' ? 'Identity' : tab === 'layout' ? 'Nav' : 'Modules'}
              </button>
            ))}
          </div>

          <form id="course-form" className="p-6 md:p-10 space-y-10" onSubmit={handleSave}>
            {activeConfigTab === 'meta' && (
              <section className="space-y-8 animate-in fade-in">
                <div className="flex flex-col md:flex-row gap-6 lg:gap-10">
                   <div className="w-full md:w-64 aspect-video bg-slate-950 rounded-2xl border-2 border-slate-800 overflow-hidden relative group">
                     <img src={currentCourse.thumbnail} className="w-full h-full object-cover opacity-60" alt="Preview" />
                   </div>
                   <div className="flex-1 space-y-6">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Title</label>
                        <input required type="text" value={currentCourse.title || ''} onChange={(e) => setCurrentCourse(prev => ({...prev!, title: e.target.value}))} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white font-bold" />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                          <input required type="text" value={currentCourse.category || ''} onChange={(e) => setCurrentCourse(prev => ({...prev!, category: e.target.value}))} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-slate-200" />
                        </div>
                        <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Fee ($)</label>
                          <input required type="number" step="0.01" value={currentCourse.price || 0} onChange={(e) => setCurrentCourse(prev => ({...prev!, price: parseFloat(e.target.value)}))} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-slate-200 font-mono" />
                        </div>
                      </div>
                   </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Summary</label>
                  <textarea required rows={4} value={currentCourse.description || ''} onChange={(e) => setCurrentCourse(prev => ({...prev!, description: e.target.value}))} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-slate-300" />
                </div>
              </section>
            )}

            {activeConfigTab === 'layout' && (
              <section className="space-y-8 animate-in fade-in">
                 <div className="flex justify-between items-center">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nav Groups</h3>
                    <button type="button" onClick={() => setCurrentCourse(prev => ({...prev!, subjects: [...(prev!.subjects || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Group', icon: 'fa-book-open', color: COLOR_PRESETS[0].class, subSubjects: [] }] }))} className="text-indigo-400 text-[9px] font-black uppercase tracking-widest">+ Group</button>
                 </div>
                 <div className="space-y-4">
                    {(currentCourse.subjects || []).map(subj => (
                      <div key={subj.id} className="bg-slate-950 rounded-2xl border border-slate-800 p-4 lg:p-6 flex items-center gap-4 lg:gap-6">
