                           <i className={`fas ${subj.icon}`}></i>
                        </div>
                        <input type="text" value={subj.name} onChange={(e) => updateSubject(subj.id, { name: e.target.value })} className="flex-1 bg-transparent border-none focus:ring-0 text-xs lg:text-sm font-black text-slate-100" />
                        <button type="button" onClick={() => setCurrentCourse(prev => ({...prev!, subjects: prev!.subjects?.filter(s => s.id !== subj.id)}))} className="text-slate-700 hover:text-rose-500"><i className="fas fa-trash-alt"></i></button>
                      </div>
                    ))}
                 </div>
              </section>
            )}

            {activeConfigTab === 'curriculum' && (
              <section className="space-y-8 animate-in fade-in">
                 <div className="flex justify-between items-center">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Modules</h3>
                    <button type="button" onClick={() => setCurrentCourse(prev => ({...prev!, lessons: [...(prev!.lessons || []), { id: Math.random().toString(36).substr(2, 9), title: 'New Module', content: '', duration: '10:00' }] }))} className="px-5 py-2 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest">+ Module</button>
                 </div>
                 <div className="space-y-4">
                    {(currentCourse.lessons || []).map((lesson, idx) => (
                      <div key={lesson.id} className="bg-slate-950 border border-slate-800 rounded-2xl p-4 flex items-center gap-4">
                         <span className="text-[10px] font-black text-slate-700">{idx + 1}</span>
                         <input type="text" value={lesson.title} onChange={(e) => updateLesson(lesson.id, { title: e.target.value })} className="flex-1 bg-transparent border-none focus:ring-0 text-xs font-bold text-slate-100" />
                         <button type="button" onClick={() => setActiveLessonExtras(activeLessonExtras === lesson.id ? null : lesson.id)} className="w-9 h-9 bg-slate-900 border border-slate-800 rounded-xl text-indigo-400 flex items-center justify-center"><i className="fas fa-edit"></i></button>
                      </div>
                    ))}
                 </div>
              </section>
            )}
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-8 lg:space-y-12 pb-24 animate-in fade-in duration-500">
      {isAiModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-xl animate-in fade-in">
          <div className="bg-slate-900 w-full max-w-lg rounded-3xl border border-slate-800 p-6 md:p-10 space-y-6">
            <h2 className="text-2xl font-black text-white text-center">AI Architect</h2>
            <textarea value={aiPrompt} onChange={(e) => setAiPrompt(e.target.value)} placeholder="Course topic..." className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 text-slate-200 min-h-[100px]" />
            <div className="flex gap-3">
