import React, { useState, useEffect, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Explore from './components/Explore';
import CourseView from './components/CourseView';
import CourseCard from './components/CourseCard';
import AdminPanel from './components/AdminPanel';
import Profile from './components/Profile';
import Auth from './components/Auth';
import CourseDetails from './components/CourseDetails';
import { AppRoute, Course, User, QuizAttempt } from './types';
import { MOCK_COURSES } from './constants';
import { getAllCoursesFromDB, saveCourseToDB, deleteCourseFromDB, clearAllCoursesFromDB } from './services/storage';

const App: React.FC = () => {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [activeCourseId, setActiveCourseId] = useState<string | null>(null);
  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [courses, setCourses] = useState<Course[]>([]);
  const [adminPreviewMode, setAdminPreviewMode] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [isSwitcherOpen, setIsSwitcherOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [editingCourseId, setEditingCourseId] = useState<string | null>(null);
  const switcherRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const loadCourses = async () => {
      try {
        const savedCourses = await getAllCoursesFromDB();
        if (savedCourses.length > 0) {
          setCourses(savedCourses);
        } else {
          for (const c of MOCK_COURSES) {
            await saveCourseToDB(c);
          }
          setCourses(MOCK_COURSES);
        }
      } catch (err) {
        console.error("Failed to load courses from IndexedDB", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadCourses();
  }, []);

  useEffect(() => {
    try {
      const savedUser = localStorage.getItem('eduworld_user');
      if (savedUser) {
        setUser(JSON.parse(savedUser));
      }
    } catch (err) {
      console.error("Failed to restore user session", err);
    }
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (switcherRef.current && !switcherRef.current.contains(event.target as Node)) {
        setIsSwitcherOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    try {
      localStorage.setItem('eduworld_user', JSON.stringify(newUser));
    } catch (err) {
      console.error("Storage limit reached for user data.");
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('eduworld_user');
    setRoute(AppRoute.DASHBOARD);
    setIsSwitcherOpen(false);
  };

  const handleCourseClick = (id: string) => {
    setActiveCourseId(id);
    const isEnrolled = user?.enrolledCourses.includes(id);
    if (isEnrolled) {
      setRoute(AppRoute.COURSE_VIEW);
    } else {
      setRoute(AppRoute.COURSE_DETAILS);
    }
  };

  const handleEnroll = (courseId: string) => {
    if (!user) return;
    const updatedUser: User = {
      ...user,
      enrolledCourses: [...new Set([...user.enrolledCourses, courseId])]
    };
    setUser(updatedUser);
    localStorage.setItem('eduworld_user', JSON.stringify(updatedUser));
    setSelectedCourseId(courseId);
    setActiveCourseId(courseId);
    setRoute(AppRoute.DASHBOARD);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleAddCourse = async (newCourse: Course) => {
    try {
      await saveCourseToDB(newCourse);
      const updated = await getAllCoursesFromDB();
      setCourses(updated);
      if (user?.role === 'admin') setRoute(AppRoute.ADMIN);
    } catch (err) {
      alert("Failed to save course.");
    }
  };

  const handleUpdateCourse = async (updatedCourse: Course) => {
    try {
      await saveCourseToDB(updatedCourse);
      const updated = await getAllCoursesFromDB();
      setCourses(updated);
    } catch (err) {
      alert("Failed to update course.");
    }
  };

  const handleDeleteCourse = async (id: string) => {
    if (window.confirm('Delete this course?')) {
      try {
        await deleteCourseFromDB(id);
        const updated = await getAllCoursesFromDB();
        setCourses(updated);
      } catch (err) {
        alert("Failed to delete course.");
      }
    }
  };

  const handleAdminEditCourse = (courseId: string) => {
    setEditingCourseId(courseId);
    setRoute(AppRoute.ADMIN);
    setAdminPreviewMode(false);
  };

  const activeCourse = courses.find(c => c.id === activeCourseId);
  const enrolledCourses = courses.filter(c => user?.enrolledCourses.includes(c.id));

  useEffect(() => {
    if (enrolledCourses.length > 0 && !selectedCourseId) {
      setSelectedCourseId(enrolledCourses[0].id);
    }
  }, [enrolledCourses, selectedCourseId]);

  if (!user) return <Auth onLogin={handleLogin} />;

  if (isLoading) {
    return (
      <div className="h-screen bg-[#020617] flex flex-col items-center justify-center space-y-4">
        <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Booting Core...</p>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden relative">
      {adminPreviewMode && (
        <div className="fixed top-0 left-0 right-0 h-12 bg-indigo-600 text-white z-[100] flex items-center justify-center px-4 shadow-lg animate-in slide-in-from-top duration-300">
          <div className="flex items-center space-x-4">
            <span className="text-[10px] font-black uppercase tracking-widest flex items-center">
              <i className="fas fa-eye mr-2"></i> Preview Mode
            </span>
            <button 
              onClick={() => setAdminPreviewMode(false)} 
              className="bg-white text-indigo-600 px-3 py-1 rounded-full text-[9px] font-black uppercase"
            >
              Exit
            </button>
          </div>
        </div>
      )}

      {route !== AppRoute.COURSE_VIEW && (
        <Sidebar 
          currentRoute={route} 
          user={user} 
          setRoute={(r) => {
            setAdminPreviewMode(false);
            setRoute(r);
            if (r !== AppRoute.ADMIN) setEditingCourseId(null);
          }} 
          onLogout={handleLogout} 
        />
      )}

      <main className={`flex-1 overflow-y-auto ${adminPreviewMode ? 'pt-12' : ''} ${route !== AppRoute.COURSE_VIEW ? 'p-6 lg:p-10 pb-24 md:pb-10' : ''}`}>
        {route === AppRoute.DASHBOARD && (
          <Dashboard 
            onCourseClick={handleCourseClick} 
            setRoute={setRoute} 
            courses={enrolledCourses} 
            selectedCourseId={selectedCourseId} 
            onSelectCourse={setSelectedCourseId} 
          />
        )}
        {route === AppRoute.COURSES && <Explore onCourseClick={handleCourseClick} courses={courses} />}
        {route === AppRoute.PROFILE && <Profile user={user} courses={enrolledCourses} onCourseClick={handleCourseClick} onUpdateUser={setUser} />}
        {route === AppRoute.ADMIN && user.role === 'admin' && (
          <AdminPanel 
            courses={courses} 
            initialEditCourseId={editingCourseId} 
            onAddCourse={handleAddCourse} 
            onUpdateCourse={handleUpdateCourse} 
            onDeleteCourse={handleDeleteCourse} 
            onPreview={() => setAdminPreviewMode(true)} 
          />
        )}
        {route === AppRoute.COURSE_DETAILS && activeCourse && (
          <CourseDetails 
            course={activeCourse} 
            isAdmin={user.role === 'admin'} 
            isEnrolled={user.enrolledCourses.includes(activeCourse.id)} 
            onEnroll={handleEnroll} 
            onAdminEdit={() => handleAdminEditCourse(activeCourse.id)} 
            onBack={() => setRoute(AppRoute.COURSES)} 
          />
        )}
        {route === AppRoute.COURSE_VIEW && activeCourse && (
          <CourseView 
            course={activeCourse} 
            user={user} 
            onBack={() => setRoute(AppRoute.DASHBOARD)} 
            onQuizComplete={(lid, att) => {
              const updatedUser = { ...user, quizScores: { ...user.quizScores, [lid]: att } };
              setUser(updatedUser);
              localStorage.setItem('eduworld_user', JSON.stringify(updatedUser));
            }} 
          />
        )}
      </main>

      {/* Mobile Bottom Bar - Optimized for Dark UI */}
      {route !== AppRoute.COURSE_VIEW && (
        <div className="md:hidden fixed bottom-0 left-0 right-0 bg-slate-950/90 backdrop-blur-xl border-t border-slate-800 px-6 py-4 flex justify-between items-center z-[50] shadow-[0_-10px_30px_rgba(0,0,0,0.5)]">
          {[
            { id: AppRoute.DASHBOARD, icon: 'fa-house', label: 'Home' },
            { id: AppRoute.COURSES, icon: 'fa-compass', label: 'Explore' },
            { id: AppRoute.PROFILE, icon: 'fa-user', label: 'Profile' },
            ...(user.role === 'admin' ? [{ id: AppRoute.ADMIN, icon: 'fa-shield-halved', label: 'Admin' }] : []),
          ].map(item => (
            <button
              key={item.id}
              onClick={() => {
                setAdminPreviewMode(false);
                setRoute(item.id as AppRoute);
                if (item.id !== AppRoute.ADMIN) setEditingCourseId(null);
              }}
              className={`flex flex-col items-center justify-center transition-all ${
                route === item.id ? 'text-indigo-400 scale-110' : 'text-slate-600'
              }`}
            >
              <i className={`fas ${item.icon} text-lg mb-1`}></i>
              <span className="text-[8px] font-black uppercase tracking-widest">{item.label}</span>
              {route === item.id && (
                <div className="w-1 h-1 bg-indigo-400 rounded-full mt-1"></div>
              )}
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

