import React, { useState } from 'react';
import { User } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
}

const getUsersFromStorage = (): any[] => {
  const users = localStorage.getItem('eduworld_registered_users');
  return users ? JSON.parse(users) : [];
};

const saveUserToStorage = (user: any) => {
  const users = getUsersFromStorage();
  users.push(user);
  localStorage.setItem('eduworld_registered_users', JSON.stringify(users));
};

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!email || !password || (!isLogin && !name)) {
      setError('Required fields missing.');
      return;
    }

    if (isAdminMode) {
      if (email === 'admin@eduworld.com' && password === 'admin') {
        onLogin({
          id: 'admin-1',
          name: 'System Admin',
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=admin',
          role: 'admin',
          enrolledCourses: [],
          documents: [],
          quizScores: {}
        });
        return;
      } else {
        setError('Invalid admin credentials.');
        return;
      }
    }

    const registeredUsers = getUsersFromStorage();
    if (isLogin) {
      const userMatch = registeredUsers.find(u => u.email === email && u.password === password);
      if (userMatch) {
        onLogin({
          ...userMatch,
          role: 'student'
        });
      } else {
        setError('Identity not found.');
      }
    } else {
      const userExists = registeredUsers.some(u => u.email === email);
      if (userExists) {
        setError('Email already in network.');
        return;
      }
      const newUser = {
        id: Math.random().toString(36).substr(2, 9),
        name, email, password,
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${email}`,
        role: 'student', enrolledCourses: [], documents: [], quizScores: {}
      };
      saveUserToStorage(newUser);
      onLogin(newUser as any);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] flex items-center justify-center p-6 text-slate-100">
      <div className="w-full max-w-md animate-in fade-in zoom-in duration-500">
        <div className="text-center mb-12">
          <div className="w-20 h-20 bg-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 shadow-2xl shadow-indigo-600/30">
            <i className="fas fa-graduation-cap text-white text-4xl"></i>
          </div>
          <h1 className="text-4xl font-black text-white tracking-tighter">Edu World</h1>
          <p className="text-slate-500 font-black uppercase tracking-[0.3em] text-[10px] mt-4 opacity-70">NEURAL LEARNING CORE</p>
        </div>

        <div className="bg-slate-900 rounded-[48px] border border-slate-800 p-10 md:p-14 shadow-2xl relative overflow-hidden">
          <div className="flex bg-slate-950 p-1.5 rounded-2xl mb-10 relative z-10 border border-slate-800">
            <button
              onClick={() => { setIsLogin(true); setError(''); }}
              className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${isLogin && !isAdminMode ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500'}`}
            >
              Log In
            </button>
            <button
              onClick={() => { setIsLogin(false); setError(''); }}
              className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${!isLogin && !isAdminMode ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500'}`}
            >
              Sign Up
            </button>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6 relative z-10">
            {!isLogin && !isAdminMode && (
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Identity Name</label>
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-4 focus:bg-slate-900 focus:border-indigo-600/50 focus:ring-0 transition-all font-bold text-white placeholder:text-slate-700"
                  placeholder="Full name"
                />
              </div>
            )}

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Secure Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-4 focus:bg-slate-900 focus:border-indigo-600/50 focus:ring-0 transition-all font-bold text-white placeholder:text-slate-700"
                placeholder="name@domain.com"
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Access Key</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-4 focus:bg-slate-900 focus:border-indigo-600/50 focus:ring-0 transition-all font-bold text-white placeholder:text-slate-700"
                placeholder="••••••••"
              />
            </div>

            {error && <p className="text-[10px] font-black text-rose-500 text-center uppercase tracking-widest animate-pulse">{error}</p>}

            <button
              type="submit"
              className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.3em] hover:bg-indigo-700 shadow-xl shadow-indigo-600/20 transition-all transform active:scale-[0.98]"
            >
              Initialize Session
            </button>
          </form>

          <div className="mt-10 pt-10 border-t border-slate-800 text-center">
            <button
              onClick={() => { setIsAdminMode(!isAdminMode); setError(''); setIsLogin(true); }}
              className="text-[9px] font-black text-slate-600 hover:text-indigo-400 transition-all uppercase tracking-[0.3em]"
            >
              {isAdminMode ? 'Return to Student Hub' : 'System Administration'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

