import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, QuizAttempt, Course } from "../types";

// Always initialize with the environment key
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getTutorResponse = async (
  userMessage: string, 
  history: ChatMessage[],
  context: { 
    courseTitle: string; 
    lessonTitle: string; 
    lessonContent: string; 
    progress: number;
    quizHistory?: Record<string, QuizAttempt>;
  },
  imageData?: string 
) => {
  try {
    // Using Gemini 3 Pro for advanced reasoning and grounding
    const model = 'gemini-3-pro-preview';

    let quizContext = "";
    if (context.quizHistory && Object.keys(context.quizHistory).length > 0) {
      quizContext = "\nStudent's Quiz History in this course:\n" + 
        Object.entries(context.quizHistory).map(([lessonId, attempt]) => 
          `- Lesson Attempt: ${attempt.score}/${attempt.total} correct.`
        ).join('\n');
    }

    const systemInstruction = `
      You are "Aris", the Lead AI Tutor at Edu World. 
      You are currently assisting a student in the course: "${context.courseTitle}" (Progress: ${context.progress}%).
      Current Module: "${context.lessonTitle}".

      Lesson Content Overview: "${context.lessonContent.replace(/<[^>]*>?/gm, '')}"
      ${quizContext}

      Your personality:
      - Highly technical but uses metaphors to explain complex concepts.
      - Encouraging and rigorous.
      - You ALWAYS use Google Search to verify facts or provide up-to-date industry examples.
      - Format your responses using clean Markdown.
      - If the student provides an image, perform deep visual analysis to explain the contents.
    `;

    // Map history to parts format
    const contents = history.map(msg => ({
      role: msg.role === 'user' ? 'user' : 'model',
      parts: [
        { text: msg.text },
        ...(msg.image ? [{ inlineData: { mimeType: 'image/jpeg', data: msg.image.split(',')[1] } }] : [])
      ]
    }));

    // Add current message
    const currentParts: any[] = [{ text: userMessage }];
    if (imageData) {
      currentParts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: imageData.split(',')[1]
        }
      });
    }

    contents.push({ role: 'user', parts: currentParts });

    const response = await ai.models.generateContent({
      model,
      contents: contents as any,
      config: {
        systemInstruction,
        temperature: 0.8,
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || "I was unable to synthesize a response. Please try again.";

    // Extract grounding URLs for the UI
    const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title,
        uri: chunk.web.uri
      })) || [];

    return { text, urls };
  } catch (error) {
    console.error("Gemini Tutor Error:", error);
    return {
      text: "Connection to the Neural Core was interrupted. Check your link and try again.",
      urls: []
    };
  }
};

