import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Explore from './components/Explore';
import CourseView from './components/CourseView';
import AdminPanel from './components/AdminPanel';
import Profile from './components/Profile';
import Auth from './components/Auth';
import CourseDetails from './components/CourseDetails';
import { AppRoute, Course, User, QuizAttempt } from './types';
import { MOCK_COURSES } from './constants';
import { getAllCoursesFromDB, saveCourseToDB, deleteCourseFromDB } from './services/storage';

const App: React.FC = () => {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [activeCourseId, setActiveCourseId] = useState<string | null>(null);
  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [courses, setCourses] = useState<Course[]>([]);
  const [user, setUser] = useState<User | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [editingCourseId, setEditingCourseId] = useState<string | null>(null);

  // Persistence: Courses
  useEffect(() => {
    const loadCourses = async () => {
      try {
        const savedCourses = await getAllCoursesFromDB();
        if (savedCourses.length > 0) {
          setCourses(savedCourses);
        } else {
          for (const c of MOCK_COURSES) {
            await saveCourseToDB(c);
          }
          setCourses(MOCK_COURSES);
        }
      } catch (err) {
        console.error("Storage Error:", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadCourses();
  }, []);

  // Persistence: User
  useEffect(() => {
    const savedUser = localStorage.getItem('eduworld_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem('eduworld_user', JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (window.confirm("Are you sure you want to terminate the session?")) {
      setUser(null);
      localStorage.removeItem('eduworld_user');
      setRoute(AppRoute.DASHBOARD);
      setIsMobileMenuOpen(false);
    }
  };

  const handleCourseClick = (id: string) => {
    setActiveCourseId(id);
    const isEnrolled = user?.enrolledCourses.includes(id);
    setRoute(isEnrolled ? AppRoute.COURSE_VIEW : AppRoute.COURSE_DETAILS);
    setIsMobileMenuOpen(false);
  };

  const handleEnroll = (courseId: string) => {
    if (!user) return;
    const updatedUser: User = {
      ...user,
      enrolledCourses: [...new Set([...user.enrolledCourses, courseId])]
    };
    setUser(updatedUser);
    localStorage.setItem('eduworld_user', JSON.stringify(updatedUser));
    setSelectedCourseId(courseId);
    setActiveCourseId(courseId);
    setRoute(AppRoute.DASHBOARD);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleAddCourse = async (newCourse: Course) => {
    await saveCourseToDB(newCourse);
    setCourses(await getAllCoursesFromDB());
    setRoute(AppRoute.ADMIN);
  };

  const navigate = (r: AppRoute) => {
    setRoute(r);
    if (r !== AppRoute.ADMIN) setEditingCourseId(null);
    setIsMobileMenuOpen(false);
  };

  if (!user) return <Auth onLogin={handleLogin} />;

  if (isLoading) {
    return (
      <div className="h-screen bg-[#020617] flex flex-col items-center justify-center">
        <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="mt-6 text-[10px] font-black text-slate-500 uppercase tracking-widest animate-pulse">Neural Link Syncing...</p>
      </div>
    );
  }

  const activeCourse = courses.find(c => c.id === activeCourseId);
  const enrolledCourses = courses.filter(c => user.enrolledCourses.includes(c.id));

  return (
    <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden relative">
      {/* Mobile Drawer Backdrop */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/70 backdrop-blur-md z-[90] md:hidden animate-in fade-in"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Primary Sidebar (Desktop/Drawer) */}
      {route !== AppRoute.COURSE_VIEW && (
        <aside className={`
          fixed md:relative z-[100] h-full transition-transform duration-500 cubic-bezier(0.4, 0, 0.2, 1)
          ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
        `}>
          <Sidebar 
            currentRoute={route} 
            user={user} 
            setRoute={navigate} 
            onLogout={handleLogout} 
          />
        </aside>
      )}

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0 relative">
        {/* Mobile Navbar */}
        {route !== AppRoute.COURSE_VIEW && (
          <header className="md:hidden flex items-center justify-between px-6 py-4 bg-slate-950/90 backdrop-blur-2xl border-b border-slate-800 z-[80] sticky top-0 shadow-lg">
            <div className="flex items-center space-x-3" onClick={() => navigate(AppRoute.DASHBOARD)}>
              <div className="w-9 h-9 bg-indigo-600 rounded-xl flex items-center justify-center shadow-indigo-600/20 shadow-lg">
                <i className="fas fa-graduation-cap text-white text-sm"></i>
              </div>
              <span className="text-xl font-black text-white tracking-tighter">EduWorld</span>
            </div>
            <button 
              onClick={() => setIsMobileMenuOpen(true)}
              className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400"
            >
              <i className="fas fa-bars-staggered"></i>
            </button>
          </header>
        )}

        <main className={`
          flex-1 overflow-y-auto scroll-smooth
          ${route !== AppRoute.COURSE_VIEW ? 'p-6 lg:p-12 pb-32 lg:pb-12' : ''}
        `}>
          {route === AppRoute.DASHBOARD && (
            <Dashboard 
              onCourseClick={handleCourseClick} 
              setRoute={setRoute} 
              courses={enrolledCourses} 
              selectedCourseId={selectedCourseId} 
              onSelectCourse={setSelectedCourseId} 
            />
          )}
          {route === AppRoute.COURSES && <Explore onCourseClick={handleCourseClick} courses={courses} />}
          {route === AppRoute.PROFILE && <Profile user={user} courses={enrolledCourses} onCourseClick={handleCourseClick} onUpdateUser={setUser} />}
          {route === AppRoute.ADMIN && user.role === 'admin' && (
            <AdminPanel 
              courses={courses} 
              initialEditCourseId={editingCourseId} 
              onAddCourse={handleAddCourse} 
              onUpdateCourse={async (c) => { await saveCourseToDB(c); setCourses(await getAllCoursesFromDB()); }} 
              onDeleteCourse={async (id) => { await deleteCourseFromDB(id); setCourses(await getAllCoursesFromDB()); }} 
              onPreview={() => {}} 
            />
          )}
          {route === AppRoute.COURSE_DETAILS && activeCourse && (
            <CourseDetails 
              course={activeCourse} 
              isAdmin={user.role === 'admin'} 
              isEnrolled={user.enrolledCourses.includes(activeCourse.id)} 
              onEnroll={handleEnroll} 
              onAdminEdit={() => { setEditingCourseId(activeCourse.id); setRoute(AppRoute.ADMIN); }} 
              onBack={() => setRoute(AppRoute.COURSES)} 
            />
          )}
          {route === AppRoute.COURSE_VIEW && activeCourse && (
            <CourseView 
              course={activeCourse} 
              user={user} 
              onBack={() => setRoute(AppRoute.DASHBOARD)} 
              onQuizComplete={(lid, att) => {
                const updatedUser = { ...user, quizScores: { ...user.quizScores, [lid]: att } };
                setUser(updatedUser);
                localStorage.setItem('eduworld_user', JSON.stringify(updatedUser));
              }} 
            />
          )}
        </main>

        {/* Floating Mobile Navigation Bar */}
        {route !== AppRoute.COURSE_VIEW && (
          <nav className="md:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm bg-slate-900/80 backdrop-blur-3xl border border-slate-800 rounded-[32px] px-6 py-4 flex justify-between items-center z-[50] shadow-2xl shadow-black/80">
            {[
              { id: AppRoute.DASHBOARD, icon: 'fa-house', label: 'Home' },
              { id: AppRoute.COURSES, icon: 'fa-compass', label: 'Explore' },
              { id: AppRoute.PROFILE, icon: 'fa-user', label: 'Vault' },
            ].map(item => (
              <button
                key={item.id}
                onClick={() => navigate(item.id as AppRoute)}
                className={`flex flex-col items-center justify-center flex-1 transition-all ${
                  route === item.id ? 'text-indigo-400 scale-110' : 'text-slate-500'
                }`}
              >
                <i className={`fas ${item.icon} text-lg mb-1`}></i>
                <span className="text-[9px] font-black uppercase tracking-tighter">{item.label}</span>
                {route === item.id && (
                  <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full mt-1 animate-in zoom-in"></div>
                )}
              </button>
            ))}
          </nav>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Course, Lesson, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(course.lessons?.[0]?.id);
  const [activeTab, setActiveTab] = useState<'info' | 'resources' | 'quiz'>('info');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  const [quizState, setQuizState] = useState({
    currentIdx: 0,
    score: 0,
    complete: false
  });

  const activeLessonIndex = course.lessons.findIndex(l => l.id === activeLessonId);
  const activeLesson = course.lessons[activeLessonIndex] || course.lessons[0];

  useEffect(() => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
    if (videoRef.current) videoRef.current.load();
  }, [activeLessonId]);

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
    }
  };

  return (
    <div className="flex h-screen bg-[#020617] overflow-hidden">
      {/* Content Side */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto scroll-smooth pb-20 lg:pb-0">
