            <button onClick={onBack} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all">
              <i className="fas fa-arrow-left"></i>
            </button>
            <div className="hidden sm:block">
              <h2 className="text-sm font-black text-white truncate max-w-[200px]">{course.title}</h2>
              <p className="text-[10px] text-indigo-400 font-black uppercase tracking-widest">{activeLesson.title}</p>
            </div>
          </div>
          <button 
            onClick={() => setIsAiOpen(!isAiOpen)} 
            className={`px-5 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all flex items-center space-x-2 ${isAiOpen ? 'bg-white text-slate-950' : 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20'}`}
