import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, QuizAttempt, Course } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getTutorResponse = async (
  userMessage: string, 
  history: ChatMessage[],
  context: { 
    courseTitle: string; 
    lessonTitle: string; 
    lessonContent: string; 
    progress: number;
    quizHistory?: Record<string, QuizAttempt>;
  },
  imageData?: string 
) => {
  try {
    const model = 'gemini-3-pro-preview';

    let quizContext = "";
    if (context.quizHistory && Object.keys(context.quizHistory).length > 0) {
      quizContext = "\nStudent's Quiz History:\n" + 
        Object.entries(context.quizHistory).map(([lessonId, attempt]) => 
          `- Lesson: ${attempt.score}/${attempt.total}`
        ).join('\n');
    }

    const systemInstruction = `
      You are "Aris", the AI Tutor for Edu World. Assist the student with "${context.lessonTitle}" in the course "${context.courseTitle}".
      Lesson content: "${context.lessonContent.replace(/<[^>]*>?/gm, '')}"
      ${quizContext}

      Instructions:
      - Use Markdown for formatting.
      - Be technical, clear, and encouraging.
      - Use the googleSearch tool for facts and examples.
    `;

    const contents = history.map(msg => ({
      role: msg.role === 'user' ? 'user' : 'model',
      parts: [
        { text: msg.text },
        ...(msg.image ? [{ inlineData: { mimeType: 'image/jpeg', data: msg.image.split(',')[1] } }] : [])
      ]
    }));

    const currentParts: any[] = [{ text: userMessage }];
    if (imageData) {
      currentParts.push({
        inlineData: {
          mimeType: 'image/jpeg',
          data: imageData.split(',')[1]
        }
      });
    }

    contents.push({ role: 'user', parts: currentParts });

    const response = await ai.models.generateContent({
      model,
      contents: contents as any,
      config: {
        systemInstruction,
        temperature: 0.7,
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || "I'm sorry, I couldn't generate a response.";
    const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title,
        uri: chunk.web.uri
      })) || [];

    return { text, urls };
  } catch (error) {
    console.error("Gemini Error:", error);
    return { text: "Error connecting to AI service.", urls: [] };
  }
};

