import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Explore from './components/Explore';
import CourseView from './components/CourseView';
import AdminPanel from './components/AdminPanel';
import Profile from './components/Profile';
import Auth from './components/Auth';
import CourseDetails from './components/CourseDetails';
import { AppRoute, Course, User } from './types';
import { MOCK_COURSES } from './constants';
import { getAllCoursesFromDB, saveCourseToDB, deleteCourseFromDB } from './services/storage';

const App: React.FC = () => {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [activeCourseId, setActiveCourseId] = useState<string | null>(null);
  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [courses, setCourses] = useState<Course[]>([]);
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [editingCourseId, setEditingCourseId] = useState<string | null>(null);

  useEffect(() => {
    const init = async () => {
      try {
        const savedCourses = await getAllCoursesFromDB();
        if (savedCourses.length > 0) {
          setCourses(savedCourses);
        } else {
          for (const c of MOCK_COURSES) await saveCourseToDB(c);
          setCourses(MOCK_COURSES);
        }
        const savedUser = localStorage.getItem('eduworld_user');
        if (savedUser) setUser(JSON.parse(savedUser));
      } finally {
        setIsLoading(false);
      }
    };
    init();
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('eduworld_user', JSON.stringify(u));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('eduworld_user');
    setRoute(AppRoute.DASHBOARD);
  };

  const navigate = (r: AppRoute) => {
    setRoute(r);
    if (r !== AppRoute.ADMIN) setEditingCourseId(null);
  };

  const handleCourseClick = (id: string) => {
    setActiveCourseId(id);
    setRoute(user?.enrolledCourses.includes(id) ? AppRoute.COURSE_VIEW : AppRoute.COURSE_DETAILS);
  };

  const handleEnroll = (courseId: string) => {
    if (!user) return;
    const updated = { ...user, enrolledCourses: [...new Set([...user.enrolledCourses, courseId])] };
    setUser(updated);
    localStorage.setItem('eduworld_user', JSON.stringify(updated));
    setSelectedCourseId(courseId);
    setActiveCourseId(courseId);
    setRoute(AppRoute.DASHBOARD);
  };

  if (!user) return <Auth onLogin={handleLogin} />;
  if (isLoading) return <div className="h-screen bg-[#020617] flex items-center justify-center text-slate-500 font-bold uppercase tracking-widest animate-pulse">Initializing...</div>;

  const activeCourse = courses.find(c => c.id === activeCourseId);
  const enrolledCourses = courses.filter(c => user.enrolledCourses.includes(c.id));

  return (
    <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden">
      {route !== AppRoute.COURSE_VIEW && (
        <Sidebar currentRoute={route} user={user} setRoute={navigate} onLogout={handleLogout} />
      )}
      <main className="flex-1 overflow-y-auto">
        <div className={route !== AppRoute.COURSE_VIEW ? "p-6 lg:p-10" : ""}>
          {route === AppRoute.DASHBOARD && <Dashboard onCourseClick={handleCourseClick} setRoute={setRoute} courses={enrolledCourses} selectedCourseId={selectedCourseId} onSelectCourse={setSelectedCourseId} />}
          {route === AppRoute.COURSES && <Explore onCourseClick={handleCourseClick} courses={courses} />}
          {route === AppRoute.PROFILE && <Profile user={user} courses={enrolledCourses} onCourseClick={handleCourseClick} onUpdateUser={setUser} />}
          {route === AppRoute.ADMIN && user.role === 'admin' && (
            <AdminPanel 
              courses={courses} 
              initialEditCourseId={editingCourseId} 
              onAddCourse={async (c) => { await saveCourseToDB(c); setCourses(await getAllCoursesFromDB()); }} 
              onUpdateCourse={async (c) => { await saveCourseToDB(c); setCourses(await getAllCoursesFromDB()); }} 
              onDeleteCourse={async (id) => { await deleteCourseFromDB(id); setCourses(await getAllCoursesFromDB()); }} 
              onPreview={() => {}} 
            />
          )}
          {route === AppRoute.COURSE_DETAILS && activeCourse && (
            <CourseDetails course={activeCourse} isAdmin={user.role === 'admin'} isEnrolled={user.enrolledCourses.includes(activeCourse.id)} onEnroll={handleEnroll} onAdminEdit={() => { setEditingCourseId(activeCourse.id); setRoute(AppRoute.ADMIN); }} onBack={() => setRoute(AppRoute.COURSES)} />
          )}
          {route === AppRoute.COURSE_VIEW && activeCourse && (
            <CourseView course={activeCourse} user={user} onBack={() => setRoute(AppRoute.DASHBOARD)} onQuizComplete={(lid, att) => {
              const updated = { ...user, quizScores: { ...user.quizScores, [lid]: att } };
              setUser(updated);
              localStorage.setItem('eduworld_user', JSON.stringify(updated));
            }} />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'info' | 'quiz'>('info');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  const activeLessonIndex = course.lessons.findIndex(l => l.id === activeLessonId);
  const activeLesson = course.lessons[activeLessonIndex] || course.lessons[0];

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
    if (videoRef.current) videoRef.current.load();
  }, [activeLessonId]);

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
    }
  };

  return (
    <div className="flex h-screen bg-[#020617]">
      <div className="flex-1 flex flex-col h-full overflow-y-auto">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/50 backdrop-blur-md sticky top-0 z-10">
          <div className="flex items-center space-x-4">
            <button onClick={onBack} className="text-slate-500 hover:text-white"><i className="fas fa-arrow-left"></i></button>
            <h2 className="text-sm font-bold truncate max-w-[200px]">{activeLesson.title}</h2>
          </div>
          <button onClick={() => setIsAiOpen(!isAiOpen)} className="px-4 py-2 bg-indigo-600 text-white text-xs font-bold rounded-lg uppercase tracking-widest">
            {isAiOpen ? 'Close AI' : 'AI Tutor'}
          </button>
        </nav>

        <div className="p-6 lg:p-10 max-w-5xl mx-auto w-full space-y-8">
          <div className="bg-black rounded-3xl overflow-hidden aspect-video border border-slate-800 shadow-2xl">
            <video ref={videoRef} src={activeLesson.videoUrl} controls className="w-full h-full" />
          </div>

          <div className="flex border-b border-slate-800 space-x-8">
            <button onClick={() => setActiveTab('info')} className={`pb-4 text-xs font-bold uppercase tracking-widest border-b-2 transition-all ${activeTab === 'info' ? 'text-indigo-400 border-indigo-400' : 'text-slate-600 border-transparent'}`}>Overview</button>
            {activeLesson.quiz && <button onClick={() => setActiveTab('quiz')} className={`pb-4 text-xs font-bold uppercase tracking-widest border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-400' : 'text-slate-600 border-transparent'}`}>Quiz</button>}
          </div>

          <div className="min-h-[300px]">
            {activeTab === 'info' && <div className="prose prose-invert max-w-none" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />}
            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-6 max-w-xl">
                {quizState.complete ? (
                  <div className="p-10 bg-slate-900 border border-slate-800 rounded-3xl text-center">
                    <h3 className="text-2xl font-black text-white">Score: {quizState.score}/{activeLesson.quiz.length}</h3>
                    <button onClick={() => setActiveTab('info')} className="mt-6 px-6 py-3 bg-indigo-600 text-white rounded-xl text-xs font-bold uppercase">Back to Lesson</button>
                  </div>
                ) : (
                  <div className="space-y-4">
                    <p className="text-xs text-slate-500 font-bold uppercase">Question {quizState.currentIdx + 1}</p>
                    <h4 className="text-xl font-bold">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-3 pt-4">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button key={i} onClick={() => handleQuizAnswer(i)} className="w-full p-4 bg-slate-900 border border-slate-800 rounded-2xl text-left hover:border-indigo-500 transition-all">{opt}</button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="mt-auto p-6 border-t border-slate-800 flex justify-between">
          <button disabled={activeLessonIndex === 0} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex - 1].id)} className="px-6 py-2 bg-slate-900 rounded-lg text-xs font-bold uppercase disabled:opacity-20">Prev</button>
          <button disabled={activeLessonIndex === course.lessons.length - 1} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex + 1].id)} className="px-6 py-2 bg-indigo-600 rounded-lg text-xs font-bold uppercase disabled:opacity-20">Next</button>
        </div>
      </div>

      {isAiOpen && (
        <aside className="w-[400px] border-l border-slate-800 bg-slate-950 flex flex-col">
          <AIAssistant course={course} lesson={activeLesson} user={user} />
        </aside>
      )}
    </div>
  );
};

