    setRoute(AppRoute.DASHBOARD);
  };

  if (!user) return <Auth onLogin={handleLogin} />;
  if (isLoading) return <div className="h-screen bg-[#020617] flex items-center justify-center text-indigo-400 font-black uppercase tracking-widest animate-pulse text-xs">Initializing Neural Link...</div>;

  const activeCourse = courses.find(c => c.id === activeCourseId);
  const enrolledCourses = courses.filter(c => user.enrolledCourses.includes(c.id));

  return (
    <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden">
      {route !== AppRoute.COURSE_VIEW && (
        <Sidebar currentRoute={route} user={user} setRoute={navigate} onLogout={handleLogout} />
      )}
      <main className="flex-1 overflow-y-auto relative">
        <div className={route !== AppRoute.COURSE_VIEW ? "p-6 lg:p-12 max-w-[1600px] mx-auto" : ""}>
          {route === AppRoute.DASHBOARD && (
            <Dashboard 
              onCourseClick={handleCourseClick} 
              setRoute={setRoute} 
              courses={enrolledCourses} 
              selectedCourseId={selectedCourseId} 
              onSelectCourse={setSelectedCourseId} 
            />
          )}
          {route === AppRoute.COURSES && <Explore onCourseClick={handleCourseClick} courses={courses} />}
          {route === AppRoute.PROFILE && <Profile user={user} courses={enrolledCourses} onCourseClick={handleCourseClick} onUpdateUser={(u) => { setUser(u); localStorage.setItem('eduworld_user', JSON.stringify(u)); }} />}
          {route === AppRoute.ADMIN && user.role === 'admin' && (
            <AdminPanel 
              courses={courses} 
              initialEditCourseId={editingCourseId} 
              onAddCourse={async (c) => { await saveCourseToDB(c); setCourses(await getAllCoursesFromDB()); }} 
              onUpdateCourse={async (c) => { await saveCourseToDB(c); setCourses(await getAllCoursesFromDB()); }} 
              onDeleteCourse={async (id) => { await deleteCourseFromDB(id); setCourses(await getAllCoursesFromDB()); }} 
              onPreview={() => {}} 
            />
          )}
          {route === AppRoute.COURSE_DETAILS && activeCourse && (
            <CourseDetails 
              course={activeCourse} 
              isAdmin={user.role === 'admin'} 
              isEnrolled={user.enrolledCourses.includes(activeCourse.id)} 
              onEnroll={handleEnroll} 
              onAdminEdit={() => { setEditingCourseId(activeCourse.id); setRoute(AppRoute.ADMIN); }} 
              onBack={() => setRoute(AppRoute.COURSES)} 
            />
          )}
          {route === AppRoute.COURSE_VIEW && activeCourse && (
            <CourseView 
              course={activeCourse} 
              user={user} 
              onBack={() => setRoute(AppRoute.DASHBOARD)} 
              onQuizComplete={(lid, att) => {
                const updated = { ...user, quizScores: { ...user.quizScores, [lid]: att } };
                setUser(updated);
                localStorage.setItem('eduworld_user', JSON.stringify(updated));
              }} 
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  const activeLessonIndex = course.lessons.findIndex(l => l.id === activeLessonId);
  const activeLesson = course.lessons[activeLessonIndex] || course.lessons[0];

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
    if (videoRef.current) {
      videoRef.current.load();
    }
  }, [activeLessonId]);

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
    }
  };

  return (
    <div className="flex h-screen bg-[#020617] overflow-hidden">
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center space-x-5">
            <button onClick={onBack} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all shadow-sm">
              <i className="fas fa-arrow-left"></i>
            </button>
            <div className="hidden sm:block">
              <h2 className="text-xs font-black text-slate-500 uppercase tracking-widest leading-none mb-1">{course.title}</h2>
              <p className="text-sm font-bold text-white truncate max-w-[300px]">{activeLesson.title}</p>
            </div>
          </div>
          <button 
            onClick={() => setIsAiOpen(!isAiOpen)} 
            className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center space-x-2 ${isAiOpen ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/20' : 'bg-slate-900 text-slate-400 border border-slate-800'}`}
          >
            <i className={`fas ${isAiOpen ? 'fa-times' : 'fa-robot'}`}></i>
            <span className="hidden xs:inline">{isAiOpen ? 'Dismiss Aris' : 'Aris Tutor'}</span>
          </button>
        </nav>

        <div className="p-6 lg:p-10 max-w-6xl mx-auto w-full space-y-10">
          <div className="bg-black rounded-[32px] overflow-hidden aspect-video border border-slate-800 shadow-2xl relative">
            <video 
              ref={videoRef} 
              src={activeLesson.videoUrl || 'https://storage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4'} 
              controls 
              className="w-full h-full" 
            />
          </div>

          <div className="flex border-b border-slate-800 space-x-10">
            {['overview', 'quiz'].map(tab => {
              if (tab === 'quiz' && !activeLesson.quiz) return null;
              return (
                <button 
                  key={tab}
                  onClick={() => setActiveTab(tab as any)} 
                  className={`pb-4 text-xs font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === tab ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}
                >
                  {tab}
                </button>
              );
            })}
          </div>

          <div className="min-h-[400px]">
            {activeTab === 'overview' && (
              <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
                <h3 className="text-2xl font-black text-white mb-6 tracking-tight">{activeLesson.title}</h3>
                <div 
                  className="prose prose-invert max-w-none text-slate-400 leading-relaxed text-lg" 
                  dangerouslySetInnerHTML={{ __html: activeLesson.content }} 
                />
              </div>
            )}

            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="animate-in fade-in zoom-in-95 duration-500 space-y-8 max-w-2xl mx-auto">
                {quizState.complete ? (
                  <div className="p-12 bg-slate-900 border border-slate-800 rounded-[40px] text-center shadow-2xl">
                    <div className="w-20 h-20 bg-emerald-500/10 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6 text-3xl border border-emerald-500/20">
                      <i className="fas fa-check"></i>
                    </div>
                    <h3 className="text-3xl font-black text-white tracking-tight">Assessment Finished</h3>
                    <p className="text-slate-400 mt-2 font-bold text-lg">Your score: <span className="text-indigo-400">{quizState.score}</span> / {activeLesson.quiz.length}</p>
                    <button 
                      onClick={() => setActiveTab('overview')} 
                      className="mt-10 px-10 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] shadow-xl"
                    >
                      Return to Syllabus
                    </button>
                  </div>
                ) : (
                  <div className="space-y-6">
                    <div className="flex justify-between items-end">
                      <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Question {quizState.currentIdx + 1} of {activeLesson.quiz.length}</p>
                      <div className="flex space-x-1">
                        {activeLesson.quiz.map((_, i) => (
                          <div key={i} className={`w-6 h-1 rounded-full ${i <= quizState.currentIdx ? 'bg-indigo-500' : 'bg-slate-800'}`}></div>
                        ))}
                      </div>
                    </div>
                    <h4 className="text-2xl font-black text-white leading-tight">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-4 pt-6">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button 
                          key={i} 
                          onClick={() => handleQuizAnswer(i)} 
                          className="w-full p-6 bg-slate-900 border border-slate-800 rounded-[24px] text-left hover:border-indigo-500/50 hover:bg-slate-950 transition-all font-bold text-slate-300 group flex items-center space-x-4 shadow-sm"
                        >
                          <span className="w-8 h-8 rounded-lg bg-slate-950 flex items-center justify-center text-xs font-black text-slate-600 group-hover:text-indigo-400 transition-colors border border-slate-800">{String.fromCharCode(65 + i)}</span>
                          <span className="flex-1">{opt}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="mt-auto p-6 lg:p-10 border-t border-slate-800/50 bg-slate-950/30 flex justify-between items-center backdrop-blur-sm">
          <button 
            disabled={activeLessonIndex === 0} 
            onClick={() => setActiveLessonId(course.lessons[activeLessonIndex - 1].id)} 
            className="flex items-center space-x-3 px-8 py-3 bg-slate-900 text-slate-500 border border-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest disabled:opacity-20 hover:text-white transition-all"
          >
            <i className="fas fa-chevron-left"></i>
            <span>Back</span>
          </button>

          <div className="hidden sm:flex space-x-2">
            {course.lessons.map((l, i) => (
              <button 
                key={l.id} 
                onClick={() => setActiveLessonId(l.id)} 
                className={`w-3 h-3 rounded-full transition-all ${activeLessonId === l.id ? 'bg-indigo-500 w-8' : 'bg-slate-800 hover:bg-slate-700'}`}
              />
            ))}
          </div>

          <button 
            disabled={activeLessonIndex === course.lessons.length - 1} 
            onClick={() => setActiveLessonId(course.lessons[activeLessonIndex + 1].id)} 
            className="flex items-center space-x-3 px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest disabled:opacity-20 shadow-lg shadow-indigo-600/20"
          >
            <span>Next Module</span>
            <i className="fas fa-chevron-right"></i>
          </button>
        </div>
      </div>

      <aside className={`fixed lg:relative z-40 top-0 right-0 h-full w-[450px] bg-slate-950 border-l border-slate-800 flex flex-col transition-transform duration-500 ease-in-out ${isAiOpen ? 'translate-x-0' : 'translate-x-full lg:hidden'}`}>
        <AIAssistant course={course} lesson={activeLesson} user={user} />
      </aside>
    </div>
  );
};

