import React, { useState } from 'react';
import { Course } from '../types';

interface CourseDetailsProps {
  course: Course;
  isAdmin: boolean;
  isEnrolled: boolean;
  onEnroll: (courseId: string) => void;
  onAdminEdit: () => void;
  onBack: () => void;
}

const CourseDetails: React.FC<CourseDetailsProps> = ({ course, isAdmin, isEnrolled, onEnroll, onAdminEdit, onBack }) => {
  const [showCheckout, setShowCheckout] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [paymentSuccess, setPaymentSuccess] = useState(false);

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);
    setTimeout(() => {
      setIsProcessing(false);
      setPaymentSuccess(true);
      setTimeout(() => onEnroll(course.id), 1500);
    }, 2000);
  };

  const roadmapItems = course.roadmap && course.roadmap.length > 0 ? course.roadmap : [
    { icon: 'fa-tv', text: `${course.lessons.length} HD Modules` },
    { icon: 'fa-sparkles', text: 'AI Tutoring' },
    { icon: 'fa-file-pdf', text: 'Study Materials' },
    { icon: 'fa-infinity', text: 'Lifetime Access' },
    { icon: 'fa-certificate', text: 'Certification' },
  ];

  return (
    <div className="pb-24 animate-in fade-in duration-700">
      {/* Stripe Modal (Responsive) */}
      {showCheckout && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-md rounded-[32px] overflow-hidden border border-slate-800">
            <div className="p-6 border-b border-slate-800 flex items-center justify-between">
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Secure Payment</span>
              <button onClick={() => setShowCheckout(false)} className="text-slate-500"><i className="fas fa-times"></i></button>
            </div>
            <div className="p-6">
              {paymentSuccess ? (
                <div className="text-center py-8">
                  <div className="w-16 h-16 bg-emerald-500/10 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-4 text-2xl border border-emerald-500/20">
                    <i className="fas fa-check"></i>
                  </div>
                  <h3 className="text-xl font-black text-white">Payment Success!</h3>
                </div>
              ) : (
                <form onSubmit={handlePayment} className="space-y-6">
                  <div className="p-6 bg-indigo-600 rounded-2xl text-white">
                    <p className="text-[10px] font-black uppercase opacity-70">Total Due</p>
                    <p className="text-3xl font-black">${(course.price || 0).toFixed(2)}</p>
                  </div>
                  <div className="space-y-4">
                    <input required type="text" placeholder="Card Number" className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-sm" />
                    <div className="grid grid-cols-2 gap-4">
                      <input required type="text" placeholder="MM/YY" className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-sm" />
                      <input required type="text" placeholder="CVC" className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-sm" />
                    </div>
                  </div>
                  <button disabled={isProcessing} className="w-full py-4 bg-white text-slate-950 rounded-xl font-black uppercase text-xs">
                    {isProcessing ? 'Processing...' : 'Pay Now'}
                  </button>
                </form>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Hero Header */}
      <div className="flex items-center justify-between mb-8">
        <button onClick={onBack} className="flex items-center space-x-3 text-slate-400 hover:text-white transition-colors">
          <i className="fas fa-arrow-left"></i>
          <span className="text-[10px] font-black uppercase tracking-widest">Back</span>
        </button>
        {isAdmin && (
          <button onClick={onAdminEdit} className="p-2 text-indigo-400 border border-indigo-900/30 rounded-lg">
            <i className="fas fa-edit"></i>
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-16">
        <div className="lg:col-span-8 space-y-8">
          <div className="space-y-4">
            <span className="px-4 py-1.5 bg-indigo-500/10 text-indigo-400 text-[10px] font-black rounded-full uppercase border border-indigo-500/20">{course.category}</span>
            <h1 className="text-3xl md:text-6xl font-black text-white tracking-tight leading-tight">{course.title}</h1>
            <p className="text-lg text-slate-400 leading-relaxed">{course.description}</p>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 p-6 bg-slate-900 rounded-3xl border border-slate-800">
            <div className="space-y-1">
              <p className="text-[9px] font-black text-slate-600 uppercase">Instructor</p>
              <p className="text-xs font-bold text-slate-200 truncate">{course.instructor}</p>
            </div>
            <div className="space-y-1">
              <p className="text-[9px] font-black text-slate-600 uppercase">Students</p>
              <p className="text-xs font-bold text-slate-200">{course.studentsCount}+</p>
            </div>
            <div className="space-y-1">
              <p className="text-[9px] font-black text-slate-600 uppercase">Rating</p>
              <p className="text-xs font-bold text-slate-200">{course.rating}</p>
            </div>
            <div className="space-y-1">
              <p className="text-[9px] font-black text-slate-600 uppercase">Duration</p>
              <p className="text-xs font-bold text-slate-200">Self-Paced</p>
            </div>
          </div>

          <div className="space-y-6">
            <h3 className="text-2xl font-black text-white">Curriculum</h3>
            <div className="space-y-3">
              {course.lessons.map((lesson, idx) => (
                <div key={lesson.id} className="flex items-center p-5 bg-slate-900 rounded-2xl border border-slate-800">
                  <div className="w-10 h-10 rounded-lg bg-slate-950 flex items-center justify-center text-xs font-black text-slate-600 mr-4 border border-slate-800">{idx + 1}</div>
                  <div className="flex-1 min-w-0">
                    <p className="font-bold text-slate-200 text-sm truncate">{lesson.title}</p>
                    <p className="text-[10px] text-slate-600 font-bold uppercase">{lesson.duration}</p>
                  </div>
                  <i className="fas fa-lock text-slate-800 ml-4"></i>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Purchase Card (Desktop Sidebar, Mobile Bottom) */}
        <div className="lg:col-span-4">
          <div className="lg:sticky lg:top-8 bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
            <img src={course.thumbnail} className="w-full aspect-video object-cover" />
            <div className="p-8 space-y-6">
              <div className="flex items-baseline space-x-3">
                <span className="text-4xl font-black text-white">${course.price}</span>
                <span className="text-slate-600 line-through text-sm">${(course.price * 1.5).toFixed(2)}</span>
              </div>

              <ul className="space-y-3">
                {roadmapItems.map((item, i) => (
                  <li key={i} className="flex items-center text-xs font-bold text-slate-400">
                    <i className={`fas ${item.icon} w-5 mr-3 text-indigo-500`}></i>
                    {item.text}
                  </li>
                ))}
              </ul>

              <button 
                onClick={() => setShowCheckout(true)}
                disabled={isEnrolled}
                className={`w-full py-4 rounded-xl font-black uppercase text-xs tracking-widest ${isEnrolled ? 'bg-slate-950 text-slate-700' : 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/20'}`}
              >
                {isEnrolled ? 'Enrolled' : 'Start Program'}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CourseDetails;

import React, { useState, useEffect, useRef } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  const activeLessonIndex = course.lessons.findIndex(l => l.id === activeLessonId);
  const activeLesson = course.lessons[activeLessonIndex] || course.lessons[0];

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
    if (videoRef.current) videoRef.current.load();
  }, [activeLessonId]);

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
    }
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      {/* Main Content (Player & Info) */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center space-x-3">
            <button onClick={onBack} className="w-9 h-9 rounded-lg bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <h2 className="text-xs font-black text-slate-500 uppercase tracking-widest">{course.title}</h2>
              <p className="text-sm font-bold text-white truncate max-w-[200px]">{activeLesson.title}</p>
            </div>
            <div className="sm:hidden">
              <p className="text-xs font-bold text-white truncate max-w-[120px]">{activeLesson.title}</p>
            </div>
          </div>
          <button 
            onClick={() => setIsAiOpen(!isAiOpen)} 
            className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${isAiOpen ? 'bg-indigo-600 text-white' : 'bg-slate-900 text-slate-500 border border-slate-800'}`}
          >
            <i className="fas fa-robot mr-2"></i>AI
          </button>
        </nav>

        <div className="flex-1 p-4 md:p-10 max-w-5xl mx-auto w-full space-y-8">
          <div className="bg-black rounded-2xl md:rounded-3xl overflow-hidden aspect-video border border-slate-800 shadow-2xl">
            <video ref={videoRef} src={activeLesson.videoUrl || 'https://storage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4'} controls className="w-full h-full" />
          </div>

          <div className="flex border-b border-slate-800 space-x-6">
            <button onClick={() => setActiveTab('overview')} className={`pb-3 text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}>Overview</button>
            {activeLesson.quiz && <button onClick={() => setActiveTab('quiz')} className={`pb-3 text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}>Quiz</button>}
          </div>

          <div className="min-h-[300px] pb-20 md:pb-0">
            {activeTab === 'overview' && (
              <div className="prose prose-invert max-w-none text-slate-400" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />
            )}
            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-6 max-w-xl">
                {quizState.complete ? (
                  <div className="p-8 bg-slate-900 border border-slate-800 rounded-2xl text-center">
                    <h3 className="text-xl font-black text-white">Score: {quizState.score}/{activeLesson.quiz.length}</h3>
                    <button onClick={() => setActiveTab('overview')} className="mt-6 px-6 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase">Continue</button>
                  </div>
                ) : (
                  <div className="space-y-4">
                    <p className="text-[10px] text-slate-500 font-black uppercase">Question {quizState.currentIdx + 1}</p>
                    <h4 className="text-lg md:text-xl font-black text-white">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-3 pt-4">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button key={i} onClick={() => handleQuizAnswer(i)} className="w-full p-4 bg-slate-900 border border-slate-800 rounded-xl text-left hover:border-indigo-500 transition-all text-sm">{opt}</button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        {/* Footer Nav */}
        <div className="mt-auto p-4 md:p-6 border-t border-slate-800 bg-slate-950/50 flex justify-between items-center sticky bottom-0 z-30">
          <button disabled={activeLessonIndex === 0} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex - 1].id)} className="px-4 py-2 bg-slate-900 rounded-lg text-[10px] font-black uppercase disabled:opacity-20"><i className="fas fa-chevron-left mr-2"></i>Prev</button>
          <div className="flex space-x-1.5 overflow-x-auto px-2 max-w-[120px] no-scrollbar">
            {course.lessons.map(l => (
              <div key={l.id} className={`w-2 h-2 rounded-full flex-shrink-0 ${l.id === activeLessonId ? 'bg-indigo-500' : 'bg-slate-800'}`}></div>
            ))}
          </div>
          <button disabled={activeLessonIndex === course.lessons.length - 1} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex + 1].id)} className="px-4 py-2 bg-indigo-600 rounded-lg text-[10px] font-black uppercase disabled:opacity-20">Next<i className="fas fa-chevron-right ml-2"></i></button>
        </div>
      </div>

      {/* AI Assistant - responsive slide-up on mobile, sidebar on desktop */}
      <aside className={`
        fixed lg:relative bottom-0 right-0 w-full lg:w-[400px] h-[80vh] lg:h-full bg-slate-950 border-t lg:border-t-0 lg:border-l border-slate-800 z-[40] transition-transform duration-300 transform
        ${isAiOpen ? 'translate-y-0 lg:translate-x-0' : 'translate-y-full lg:translate-x-full lg:hidden'}
      `}>
        <div className="flex flex-col h-full relative">
          <button onClick={() => setIsAiOpen(false)} className="lg:hidden absolute top-4 right-4 z-50 text-slate-500 text-lg p-2"><i className="fas fa-times"></i></button>
          <AIAssistant course={course} lesson={activeLesson} user={user} />
        </div>
      </aside>
    </div>
  );
};

