                          <div className="flex items-center space-x-3">
                            <input 
                              type="text" 
                              value={subj.icon} 
                              onChange={e => {
                                const subjs = [...currentCourse!.subjects!];
                                subjs[sIdx].icon = e.target.value;
                                setCurrentCourse({...currentCourse!, subjects: subjs});
                              }}
                              className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500" 
                              placeholder="fa-icon-name"
                            />
                            <select 
                              value={subj.color} 
                              onChange={e => {
                                const subjs = [...currentCourse!.subjects!];
                                subjs[sIdx].color = e.target.value;
                                setCurrentCourse({...currentCourse!, subjects: subjs});
                              }}
                              className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500"
                            >
                              {COLOR_PRESETS.map((c, i) => <option key={i} value={c}>Theme {i+1}</option>)}
                            </select>
                          </div>
                        </div>
                        <button onClick={() => {
                          const subjs = currentCourse!.subjects!.filter(s => s.id !== subj.id);
                          setCurrentCourse({...currentCourse!, subjects: subjs});
                        }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>

                      <div className="pl-12 space-y-3">
                         <div className="flex justify-between items-center">
                            <h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4>
                            <button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Sub</button>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                           {(subj.subSubjects || []).map((ss, ssIdx) => (
                             <div key={ss.id} className="flex items-center space-x-2 bg-slate-900 rounded-lg px-3 py-2 border border-slate-800">
                               <input 
                                 type="text" 
                                 value={ss.name} 
                                 onChange={e => {
                                   const subjs = [...currentCourse!.subjects!];
                                   subjs[sIdx].subSubjects[ssIdx].name = e.target.value;
                                   setCurrentCourse({...currentCourse!, subjects: subjs});
                                 }}
                                 className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-300"
                               />
                               <button onClick={() => {
                                 const subjs = [...currentCourse!.subjects!];
                                 subjs[sIdx].subSubjects = subjs[sIdx].subSubjects.filter(item => item.id !== ss.id);
                                 setCurrentCourse({...currentCourse!, subjects: subjs});
                               }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                             </div>
                           ))}
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      {isAiModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-lg rounded-[40px] border border-slate-800 p-10 space-y-8 shadow-2xl animate-in zoom-in-95">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-black text-white tracking-tight">AI Architect</h2>
              <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Describe your vision for the course</p>
            </div>
            <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="e.g. Master React and TypeScript with modern architecture..." className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-200 min-h-[120px] focus:border-indigo-500/50 transition-all outline-none" />
            <div className="flex space-x-4">
              <button onClick={() => setIsAiModalOpen(false)} className="flex-1 py-5 bg-slate-950 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest border border-slate-800">Cancel</button>
              <button onClick={handleAiGenerate} disabled={!aiPrompt.trim() || isGenerating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl disabled:opacity-50 flex items-center justify-center space-x-3">
                {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-sparkles"></i>}
                <span>{isGenerating ? 'Synthesizing...' : 'Build Syllabus'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="flex-1 md:flex-none px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ title: '', lessons: [], subjects: [] }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-6">
                    <img src={course.thumbnail} className="w-16 h-10 rounded-xl object-cover opacity-80 group-hover:opacity-100 transition-opacity border border-slate-800 shadow-inner" alt="" />
                    <div>
                      <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                      <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-500 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  // New state for pre-filling lessons
  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed. Check your API link.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;
    if (currentCourse.id) {
      onUpdateCourse(currentCourse as Course);
    } else {
      onAddCourse(currentCourse as Course);
    }
    setIsEditing(false);
    setCurrentCourse(null);
  };

  const addLesson = () => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Unit', 
      content: '', 
      duration: '15:00',
      subjectId: contextSubjectId || undefined,
      subSubjectId: contextSubSubjectId || undefined
    };
    setCurrentCourse({
      ...currentCourse!, 
      lessons: [...(currentCourse!.lessons || []), newLesson] 
    });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Group',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const updatedSubjects = currentCourse!.subjects!.map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group' }]
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  if (isEditing && currentCourse) {
    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">
        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Discard Changes</span>
          </button>
          <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab as any)} 
                className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}
              >
                {tab}
              </button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({...currentCourse!, title: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                    <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({...currentCourse!, category: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Price ($)</label>
                    <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({...currentCourse!, price: parseFloat(e.target.value)})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Overview</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({...currentCourse!, description: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <div>
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Lesson Units</h3>
                    {contextSubjectId && (
                      <p className="text-[8px] text-indigo-400 font-bold mt-1 uppercase tracking-widest">
                        Context: {currentCourse.subjects?.find(s => s.id === contextSubjectId)?.name} 
                        {contextSubSubjectId && ` / ${currentCourse.subjects?.find(s => s.id === contextSubjectId)?.subSubjects.find(ss => ss.id === contextSubSubjectId)?.name}`}
                      </p>
                    )}
                  </div>
                  <button type="button" onClick={addLesson} className="px-5 py-2 bg-slate-950 border border-slate-800 text-indigo-400 rounded-xl text-[9px] font-black uppercase tracking-widest hover:border-indigo-500/50 transition-all">+ Unit</button>
                </div>
                {(currentCourse.lessons || []).map((lesson, idx) => (
                  <div key={lesson.id} className="bg-slate-950 border border-slate-800 rounded-2xl p-6 space-y-4">
                    <div className="flex flex-wrap items-center gap-4">
                       <span className="text-[10px] font-black text-slate-700">{idx + 1}</span>
                       <input type="text" value={lesson.title} onChange={e => {
                         const lessons = [...currentCourse!.lessons!];
                         lessons[idx].title = e.target.value;
                         setCurrentCourse({...currentCourse!, lessons});
                       }} className="flex-1 min-w-[200px] bg-transparent border-none focus:ring-0 text-sm font-bold text-slate-200" />

                       <div className="flex gap-2">
                         <select 
                           value={lesson.subjectId || ''} 
                           onChange={e => {
                              const lessons = [...currentCourse!.lessons!];
                              lessons[idx].subjectId = e.target.value;
                              lessons[idx].subSubjectId = undefined; // Reset sub-subject if main subject changes
                              setCurrentCourse({...currentCourse!, lessons});
                           }}
                           className="bg-slate-900 border border-slate-800 rounded-lg text-[9px] font-black uppercase tracking-widest text-slate-400 px-3 py-1.5"
                         >
                           <option value="">No Group</option>
                           {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                         </select>

                         {lesson.subjectId && (
                           <select 
                             value={lesson.subSubjectId || ''} 
                             onChange={e => {
                                const lessons = [...currentCourse!.lessons!];
                                lessons[idx].subSubjectId = e.target.value;
                                setCurrentCourse({...currentCourse!, lessons});
                             }}
                             className="bg-slate-900 border border-slate-800 rounded-lg text-[9px] font-black uppercase tracking-widest text-slate-400 px-3 py-1.5"
                           >
                             <option value="">No Sub-Group</option>
                             {currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.subSubjects.map(ss => (
                               <option key={ss.id} value={ss.id}>{ss.name}</option>
                             ))}
                           </select>
                         )}
                       </div>

                       <button type="button" onClick={() => {
                         const lessons = currentCourse!.lessons!.filter(l => l.id !== lesson.id);
                         setCurrentCourse({...currentCourse!, lessons});
                       }} className="text-slate-800 hover:text-rose-500 ml-auto"><i className="fas fa-trash-alt"></i></button>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {activeTab === 'structure' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Subject Architecture</h3>
                  <button type="button" onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">+ Subject Group</button>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {(currentCourse.subjects || []).map((subj, sIdx) => (
                    <div 
                      key={subj.id} 
                      className={`bg-slate-950 border rounded-[32px] p-8 space-y-6 transition-all ${contextSubjectId === subj.id ? 'border-indigo-500 shadow-[0_0_30px_rgba(79,70,229,0.1)]' : 'border-slate-800'}`}
                    >
                      <div className="flex flex-wrap items-center gap-4">
                        <button 
                          onClick={() => {
                            setContextSubjectId(subj.id);
                            setContextSubSubjectId(null);
                          }}
                          className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl transition-transform hover:scale-105 ${subj.color}`}
                        >
                          <i className={`fas ${subj.icon}`}></i>
                        </button>
                        <div className="flex-1 min-w-[200px] space-y-4">
                          <input 
                            type="text" 
                            value={subj.name} 
                            onChange={e => {
                              const subjs = [...currentCourse!.subjects!];
                              subjs[sIdx].name = e.target.value;
                              setCurrentCourse({...currentCourse!, subjects: subjs});
                            }}
                            className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" 
                            placeholder="Subject Name"
                          />
                          <div className="flex items-center space-x-3">
                            <input 
                              type="text" 
                              value={subj.icon} 
                              onChange={e => {
                                const subjs = [...currentCourse!.subjects!];
                                subjs[sIdx].icon = e.target.value;
                                setCurrentCourse({...currentCourse!, subjects: subjs});
                              }}
                              className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500" 
                              placeholder="fa-icon-name"
                            />
                            <select 
                              value={subj.color} 
                              onChange={e => {
                                const subjs = [...currentCourse!.subjects!];
                                subjs[sIdx].color = e.target.value;
                                setCurrentCourse({...currentCourse!, subjects: subjs});
                              }}
                              className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500"
                            >
                              {COLOR_PRESETS.map((c, i) => <option key={i} value={c}>Theme {i+1}</option>)}
                            </select>
                            <button 
                              onClick={() => {
                                setContextSubjectId(subj.id);
                                setContextSubSubjectId(null);
                                setActiveTab('curriculum');
                              }}
                              className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest flex items-center"
                            >
                              <i className="fas fa-plus mr-1"></i> Add Unit Here
                            </button>
                          </div>
                        </div>
                        <button onClick={() => {
                          if (contextSubjectId === subj.id) setContextSubjectId(null);
                          const subjs = currentCourse!.subjects!.filter(s => s.id !== subj.id);
                          setCurrentCourse({...currentCourse!, subjects: subjs});
                        }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>

                      <div className="pl-12 space-y-3">
                         <div className="flex justify-between items-center">
                            <h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4>
                            <button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Sub</button>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                           {(subj.subSubjects || []).map((ss, ssIdx) => (
                             <div 
                               key={ss.id} 
                               className={`flex items-center space-x-2 rounded-lg px-3 py-2 border transition-all ${contextSubSubjectId === ss.id ? 'bg-indigo-600/10 border-indigo-500/40' : 'bg-slate-900 border-slate-800'}`}
                             >
                               <input 
                                 type="text" 
                                 value={ss.name} 
                                 onFocus={() => {
                                   setContextSubjectId(subj.id);
                                   setContextSubSubjectId(ss.id);
                                 }}
                                 onChange={e => {
                                   const subjs = [...currentCourse!.subjects!];
                                   subjs[sIdx].subSubjects[ssIdx].name = e.target.value;
                                   setCurrentCourse({...currentCourse!, subjects: subjs});
                                 }}
                                 className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-300"
                               />
                               <button 
                                 onClick={() => {
                                   setContextSubjectId(subj.id);
                                   setContextSubSubjectId(ss.id);
                                   setActiveTab('curriculum');
                                 }}
                                 className="text-[9px] text-slate-600 hover:text-indigo-400"
                                 title="Add unit to this sub-group"
                               >
                                 <i className="fas fa-plus"></i>
                               </button>
                               <button onClick={() => {
                                 if (contextSubSubjectId === ss.id) setContextSubSubjectId(null);
                                 const subjs = [...currentCourse!.subjects!];
                                 subjs[sIdx].subSubjects = subjs[sIdx].subSubjects.filter(item => item.id !== ss.id);
                                 setCurrentCourse({...currentCourse!, subjects: subjs});
                               }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                             </div>
                           ))}
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      {isAiModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-lg rounded-[40px] border border-slate-800 p-10 space-y-8 shadow-2xl animate-in zoom-in-95">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-black text-white tracking-tight">AI Architect</h2>
              <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Describe your vision for the course</p>
            </div>
            <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="e.g. Master React and TypeScript with modern architecture..." className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-200 min-h-[120px] focus:border-indigo-500/50 transition-all outline-none" />
            <div className="flex space-x-4">
              <button onClick={() => setIsAiModalOpen(false)} className="flex-1 py-5 bg-slate-950 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest border border-slate-800">Cancel</button>
              <button onClick={handleAiGenerate} disabled={!aiPrompt.trim() || isGenerating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl disabled:opacity-50 flex items-center justify-center space-x-3">
                {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-sparkles"></i>}
                <span>{isGenerating ? 'Synthesizing...' : 'Build Syllabus'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="flex-1 md:flex-none px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ title: '', lessons: [], subjects: [] }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-6">
                    <img src={course.thumbnail} className="w-16 h-10 rounded-xl object-cover opacity-80 group-hover:opacity-100 transition-opacity border border-slate-800 shadow-inner" alt="" />
                    <div>
                      <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                      <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-500 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  // Track which lesson is expanded for editing
  const [expandedLessonId, setExpandedLessonId] = useState<string | null>(null);

  // Context state for pre-filling lessons
  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed. Check your API link.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;
    if (currentCourse.id) {
      onUpdateCourse(currentCourse as Course);
    } else {
      onAddCourse(currentCourse as Course);
    }
    setIsEditing(false);
    setCurrentCourse(null);
  };

  const addLesson = () => {
    const newId = Math.random().toString(36).substr(2, 9);
    const newLesson: Lesson = { 
      id: newId, 
      title: 'New Unit', 
      content: '<p>Start typing lesson content here...</p>', 
      duration: '15:00',
      subjectId: contextSubjectId || undefined,
      subSubjectId: contextSubSubjectId || undefined,
      hasAiFeature: true
    };
    setCurrentCourse({
      ...currentCourse!, 
      lessons: [...(currentCourse!.lessons || []), newLesson] 
    });
    setExpandedLessonId(newId);
  };

  const updateLessonField = (idx: number, field: keyof Lesson, value: any) => {
    const lessons = [...(currentCourse!.lessons || [])];
    lessons[idx] = { ...lessons[idx], [field]: value };
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Group',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const updatedSubjects = currentCourse!.subjects!.map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group' }]
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  if (isEditing && currentCourse) {
    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">
        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Discard Changes</span>
          </button>
          <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab as any)} 
                className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}
              >
                {tab}
              </button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({...currentCourse!, title: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                    <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({...currentCourse!, category: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Price ($)</label>
                    <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({...currentCourse!, price: parseFloat(e.target.value)})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Overview</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({...currentCourse!, description: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <div>
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Lesson Units</h3>
                    {contextSubjectId && (
                      <p className="text-[8px] text-indigo-400 font-bold mt-1 uppercase tracking-widest">
                        Context: {currentCourse.subjects?.find(s => s.id === contextSubjectId)?.name} 
                        {contextSubSubjectId && ` / ${currentCourse.subjects?.find(s => s.id === contextSubjectId)?.subSubjects.find(ss => ss.id === contextSubSubjectId)?.name}`}
                      </p>
                    )}
                  </div>
                  <button type="button" onClick={addLesson} className="px-5 py-2 bg-slate-950 border border-slate-800 text-indigo-400 rounded-xl text-[9px] font-black uppercase tracking-widest hover:border-indigo-500/50 transition-all">+ Unit</button>
                </div>

                <div className="space-y-4">
                  {(currentCourse.lessons || []).map((lesson, idx) => {
                    const isExpanded = expandedLessonId === lesson.id;
                    return (
                      <div key={lesson.id} className={`bg-slate-950 border rounded-2xl overflow-hidden transition-all duration-300 ${isExpanded ? 'border-indigo-500/50 shadow-lg' : 'border-slate-800'}`}>
                        {/* Header Row */}
                        <div 
                          className="flex items-center px-6 py-4 cursor-pointer hover:bg-slate-900/40 transition-colors"
                          onClick={() => setExpandedLessonId(isExpanded ? null : lesson.id)}
                        >
                          <span className="text-[10px] font-black text-slate-700 w-8">{idx + 1}</span>
                          <span className="flex-1 font-bold text-slate-200 text-sm">{lesson.title || 'Untitled Lesson'}</span>
                          <div className="flex items-center space-x-4">
                            <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration || '00:00'}</span>
                            {lesson.subjectId && (
                              <span className="text-[8px] font-black text-indigo-400/60 uppercase tracking-widest bg-indigo-500/5 px-2 py-1 rounded border border-indigo-500/10">
                                {currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.name}
                              </span>
                            )}
                            <i className={`fas fa-chevron-${isExpanded ? 'up' : 'down'} text-[10px] text-slate-700`}></i>
                          </div>
                        </div>

                        {/* Expandable Editor Panel */}
                        {isExpanded && (
                          <div className="px-8 pb-8 pt-4 space-y-6 border-t border-slate-900 bg-slate-900/20 animate-in slide-in-from-top-4 duration-300">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Lesson Title</label>
                                <input 
                                  type="text" 
                                  value={lesson.title} 
                                  onChange={e => updateLessonField(idx, 'title', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white font-bold" 
                                />
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Duration (e.g. 15:00)</label>
                                <input 
                                  type="text" 
                                  value={lesson.duration} 
                                  onChange={e => updateLessonField(idx, 'duration', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white" 
                                />
                              </div>
                            </div>

                            <div className="space-y-2">
                              <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Video Source URL</label>
                              <input 
                                type="text" 
                                value={lesson.videoUrl || ''} 
                                onChange={e => updateLessonField(idx, 'videoUrl', e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-slate-400 font-mono"
                                placeholder="https://storage.googleapis.com/..."
                              />
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Subject Group</label>
                                <select 
                                  value={lesson.subjectId || ''} 
                                  onChange={e => {
                                    updateLessonField(idx, 'subjectId', e.target.value);
                                    updateLessonField(idx, 'subSubjectId', undefined);
                                  }}
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest text-slate-400"
                                >
                                  <option value="">Unassigned</option>
                                  {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                                </select>
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Sub-Unit</label>
                                <select 
                                  value={lesson.subSubjectId || ''} 
                                  disabled={!lesson.subjectId}
                                  onChange={e => updateLessonField(idx, 'subSubjectId', e.target.value)}
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest text-slate-400 disabled:opacity-20"
                                >
                                  <option value="">No Sub-Group</option>
                                  {currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.subSubjects.map(ss => (
                                    <option key={ss.id} value={ss.id}>{ss.name}</option>
                                  ))}
                                </select>
                              </div>
                            </div>

                            <div className="space-y-2">
                              <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Content (HTML Support)</label>
                              <textarea 
                                rows={6} 
                                value={lesson.content} 
                                onChange={e => updateLessonField(idx, 'content', e.target.value)} 
                                className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-4 py-4 text-xs text-slate-300 leading-relaxed font-mono"
                                placeholder="<h1>Lesson Header</h1><p>Body text...</p>"
                              />
                            </div>

                            <div className="flex items-center justify-between pt-4">
                              <div className="flex items-center space-x-6">
                                <label className="flex items-center space-x-3 cursor-pointer group">
                                  <div 
                                    onClick={() => updateLessonField(idx, 'hasAiFeature', !lesson.hasAiFeature)}
                                    className={`w-10 h-5 rounded-full relative transition-all ${lesson.hasAiFeature ? 'bg-indigo-600' : 'bg-slate-800'}`}
                                  >
                                    <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all ${lesson.hasAiFeature ? 'left-6' : 'left-1'}`}></div>
                                  </div>
                                  <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest group-hover:text-indigo-400 transition-colors">AI Neural Features</span>
                                </label>
                              </div>

                              <button 
                                type="button" 
                                onClick={() => {
                                  if (confirm('Delete this lesson module?')) {
                                    const lessons = currentCourse!.lessons!.filter(l => l.id !== lesson.id);
                                    setCurrentCourse({...currentCourse!, lessons});
                                  }
                                }} 
                                className="flex items-center space-x-2 text-rose-500/60 hover:text-rose-500 text-[9px] font-black uppercase tracking-widest transition-colors"
                              >
                                <i className="fas fa-trash-alt"></i>
                                <span>Purge Module</span>
                              </button>
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {activeTab === 'structure' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Subject Architecture</h3>
                  <button type="button" onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">+ Subject Group</button>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {(currentCourse.subjects || []).map((subj, sIdx) => (
                    <div 
                      key={subj.id} 
                      className={`bg-slate-950 border rounded-[32px] p-8 space-y-6 transition-all ${contextSubjectId === subj.id ? 'border-indigo-500 shadow-[0_0_30px_rgba(79,70,229,0.1)]' : 'border-slate-800'}`}
                    >
                      <div className="flex flex-wrap items-center gap-4">
                        <button 
                          onClick={() => {
                            setContextSubjectId(subj.id);
                            setContextSubSubjectId(null);
                          }}
                          className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl transition-transform hover:scale-105 ${subj.color}`}
                        >
                          <i className={`fas ${subj.icon}`}></i>
                        </button>
                        <div className="flex-1 min-w-[200px] space-y-4">
                          <input 
                            type="text" 
                            value={subj.name} 
                            onChange={e => {
                              const subjs = [...currentCourse!.subjects!];
                              subjs[sIdx].name = e.target.value;
                              setCurrentCourse({...currentCourse!, subjects: subjs});
                            }}
                            className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" 
                            placeholder="Subject Name"
                          />
                          <div className="flex items-center space-x-3">
                            <input 
                              type="text" 
                              value={subj.icon} 
                              onChange={e => {
                                const subjs = [...currentCourse!.subjects!];
                                subjs[sIdx].icon = e.target.value;
                                setCurrentCourse({...currentCourse!, subjects: subjs});
                              }}
                              className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500" 
                              placeholder="fa-icon-name"
                            />
                            <select 
                              value={subj.color} 
                              onChange={e => {
                                const subjs = [...currentCourse!.subjects!];
                                subjs[sIdx].color = e.target.value;
                                setCurrentCourse({...currentCourse!, subjects: subjs});
                              }}
                              className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500"
                            >
                              {COLOR_PRESETS.map((c, i) => <option key={i} value={c}>Theme {i+1}</option>)}
                            </select>
                            <button 
                              onClick={() => {
                                setContextSubjectId(subj.id);
                                setContextSubSubjectId(null);
                                setActiveTab('curriculum');
                                addLesson();
                              }}
                              className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest flex items-center"
                            >
                              <i className="fas fa-plus mr-1"></i> Add Unit Here
                            </button>
                          </div>
                        </div>
                        <button onClick={() => {
                          if (contextSubjectId === subj.id) setContextSubjectId(null);
                          const subjs = currentCourse!.subjects!.filter(s => s.id !== subj.id);
                          setCurrentCourse({...currentCourse!, subjects: subjs});
                        }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>

                      <div className="pl-12 space-y-3">
                         <div className="flex justify-between items-center">
                            <h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4>
                            <button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Sub</button>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                           {(subj.subSubjects || []).map((ss, ssIdx) => (
                             <div 
                               key={ss.id} 
                               className={`flex items-center space-x-2 rounded-lg px-3 py-2 border transition-all ${contextSubSubjectId === ss.id ? 'bg-indigo-600/10 border-indigo-500/40' : 'bg-slate-900 border-slate-800'}`}
                             >
                               <input 
                                 type="text" 
                                 value={ss.name} 
                                 onFocus={() => {
                                   setContextSubjectId(subj.id);
                                   setContextSubSubjectId(ss.id);
                                 }}
                                 onChange={e => {
                                   const subjs = [...currentCourse!.subjects!];
                                   subjs[sIdx].subSubjects[ssIdx].name = e.target.value;
                                   setCurrentCourse({...currentCourse!, subjects: subjs});
                                 }}
                                 className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-300"
                               />
                               <button 
                                 onClick={() => {
                                   setContextSubjectId(subj.id);
                                   setContextSubSubjectId(ss.id);
                                   setActiveTab('curriculum');
                                   addLesson();
                                 }}
                                 className="text-[9px] text-slate-600 hover:text-indigo-400"
                                 title="Add unit to this sub-group"
                               >
                                 <i className="fas fa-plus"></i>
                               </button>
                               <button onClick={() => {
                                 if (contextSubSubjectId === ss.id) setContextSubSubjectId(null);
                                 const subjs = [...currentCourse!.subjects!];
                                 subjs[sIdx].subSubjects = subjs[sIdx].subSubjects.filter(item => item.id !== ss.id);
                                 setCurrentCourse({...currentCourse!, subjects: subjs});
                               }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                             </div>
                           ))}
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      {isAiModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-lg rounded-[40px] border border-slate-800 p-10 space-y-8 shadow-2xl animate-in zoom-in-95">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-black text-white tracking-tight">AI Architect</h2>
              <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Describe your vision for the course</p>
            </div>
            <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="e.g. Master React and TypeScript with modern architecture..." className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-200 min-h-[120px] focus:border-indigo-500/50 transition-all outline-none" />
            <div className="flex space-x-4">
              <button onClick={() => setIsAiModalOpen(false)} className="flex-1 py-5 bg-slate-950 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest border border-slate-800">Cancel</button>
              <button onClick={handleAiGenerate} disabled={!aiPrompt.trim() || isGenerating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl disabled:opacity-50 flex items-center justify-center space-x-3">
                {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-sparkles"></i>}
                <span>{isGenerating ? 'Synthesizing...' : 'Build Syllabus'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="flex-1 md:flex-none px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ title: '', lessons: [], subjects: [] }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-6">
                    <img src={course.thumbnail} className="w-16 h-10 rounded-xl object-cover opacity-80 group-hover:opacity-100 transition-opacity border border-slate-800 shadow-inner" alt="" />
                    <div>
                      <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                      <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Resource, QuizQuestion } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-500 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const RESOURCE_TYPES = ['link', 'pdf', 'video', 'zip'];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const [expandedLessonId, setExpandedLessonId] = useState<string | null>(null);

  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed. Check your API link.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;
    if (currentCourse.id) {
      onUpdateCourse(currentCourse as Course);
    } else {
      onAddCourse(currentCourse as Course);
    }
    setIsEditing(false);
    setCurrentCourse(null);
  };

  const addLesson = () => {
    const newId = Math.random().toString(36).substr(2, 9);
    const newLesson: Lesson = { 
      id: newId, 
      title: 'New Unit', 
      content: '<p>Start typing lesson content here...</p>', 
      duration: '15:00',
      subjectId: contextSubjectId || undefined,
      subSubjectId: contextSubSubjectId || undefined,
      hasAiFeature: true,
      resources: [],
      quiz: []
    };
    setCurrentCourse({
      ...currentCourse!, 
      lessons: [...(currentCourse!.lessons || []), newLesson] 
    });
    setExpandedLessonId(newId);
  };

  const updateLessonField = (idx: number, field: keyof Lesson, value: any) => {
    const lessons = [...(currentCourse!.lessons || [])];
    lessons[idx] = { ...lessons[idx], [field]: value };
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addResource = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newResource: Resource = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Resource',
      url: '',
      type: 'link'
    };
    lessons[lessonIdx].resources = [...(lessons[lessonIdx].resources || []), newResource];
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addQuizQuestion = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newQuestion: QuizQuestion = {
      id: Math.random().toString(36).substr(2, 9),
      question: 'New Question?',
      options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
      correctAnswer: 0
    };
    lessons[lessonIdx].quiz = [...(lessons[lessonIdx].quiz || []), newQuestion];
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Group',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const updatedSubjects = currentCourse!.subjects!.map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group' }]
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  if (isEditing && currentCourse) {
    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">
        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Discard Changes</span>
          </button>
          <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab as any)} 
                className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}
              >
                {tab}
              </button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({...currentCourse!, title: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                    <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({...currentCourse!, category: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Price ($)</label>
                    <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({...currentCourse!, price: parseFloat(e.target.value)})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Overview</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({...currentCourse!, description: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <div>
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Lesson Units</h3>
                    {contextSubjectId && (
                      <p className="text-[8px] text-indigo-400 font-bold mt-1 uppercase tracking-widest">
                        Context: {currentCourse.subjects?.find(s => s.id === contextSubjectId)?.name} 
                        {contextSubSubjectId && ` / ${currentCourse.subjects?.find(s => s.id === contextSubjectId)?.subSubjects.find(ss => ss.id === contextSubSubjectId)?.name}`}
                      </p>
                    )}
                  </div>
                  <button type="button" onClick={addLesson} className="px-5 py-2 bg-slate-950 border border-slate-800 text-indigo-400 rounded-xl text-[9px] font-black uppercase tracking-widest hover:border-indigo-500/50 transition-all">+ Unit</button>
                </div>

                <div className="space-y-4">
                  {(currentCourse.lessons || []).map((lesson, lessonIdx) => {
                    const isExpanded = expandedLessonId === lesson.id;
                    return (
                      <div key={lesson.id} className={`bg-slate-950 border rounded-2xl overflow-hidden transition-all duration-300 ${isExpanded ? 'border-indigo-500/50 shadow-lg' : 'border-slate-800'}`}>
                        {/* Header Row */}
                        <div 
                          className="flex items-center px-6 py-4 cursor-pointer hover:bg-slate-900/40 transition-colors"
                          onClick={() => setExpandedLessonId(isExpanded ? null : lesson.id)}
                        >
                          <span className="text-[10px] font-black text-slate-700 w-8">{lessonIdx + 1}</span>
                          <span className="flex-1 font-bold text-slate-200 text-sm">{lesson.title || 'Untitled Lesson'}</span>
                          <div className="flex items-center space-x-4">
                            <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration || '00:00'}</span>
                            {lesson.subjectId && (
                              <span className="text-[8px] font-black text-indigo-400/60 uppercase tracking-widest bg-indigo-500/5 px-2 py-1 rounded border border-indigo-500/10">
                                {currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.name}
                              </span>
                            )}
                            <i className={`fas fa-chevron-${isExpanded ? 'up' : 'down'} text-[10px] text-slate-700`}></i>
                          </div>
                        </div>

                        {/* Expandable Editor Panel */}
                        {isExpanded && (
                          <div className="px-8 pb-8 pt-4 space-y-8 border-t border-slate-900 bg-slate-900/20 animate-in slide-in-from-top-4 duration-300">
                            {/* Basic Lesson Settings */}
                            <div className="space-y-6">
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Lesson Title</label>
                                  <input 
                                    type="text" 
                                    value={lesson.title} 
                                    onChange={e => updateLessonField(lessonIdx, 'title', e.target.value)} 
                                    className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white font-bold" 
                                  />
                                </div>
                                <div className="space-y-2">
                                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Duration (e.g. 15:00)</label>
                                  <input 
                                    type="text" 
                                    value={lesson.duration} 
                                    onChange={e => updateLessonField(lessonIdx, 'duration', e.target.value)} 
                                    className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white" 
                                  />
                                </div>
                              </div>

                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Video Source URL</label>
                                <input 
                                  type="text" 
                                  value={lesson.videoUrl || ''} 
                                  onChange={e => updateLessonField(lessonIdx, 'videoUrl', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-slate-400 font-mono"
                                  placeholder="https://storage.googleapis.com/..."
                                />
                              </div>

                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Content (HTML Support)</label>
                                <textarea 
                                  rows={6} 
                                  value={lesson.content} 
                                  onChange={e => updateLessonField(lessonIdx, 'content', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-4 py-4 text-xs text-slate-300 leading-relaxed font-mono"
                                  placeholder="<h1>Lesson Header</h1><p>Body text...</p>"
                                />
                              </div>

                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Instructor Notes (Internal)</label>
                                <textarea 
                                  rows={4} 
                                  value={lesson.instructorNotes || ''} 
                                  onChange={e => updateLessonField(lessonIdx, 'instructorNotes', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-4 py-4 text-xs text-indigo-400/80 leading-relaxed font-medium italic"
                                  placeholder="Notes for instructors only..."
                                />
                              </div>
                            </div>

                            {/* Resource Hub Section */}
                            <div className="space-y-4 pt-4 border-t border-slate-800/50">
                              <div className="flex justify-between items-center">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Resource Hub</h4>
                                <button 
                                  type="button" 
                                  onClick={() => addResource(lessonIdx)}
                                  className="text-[9px] font-black text-indigo-400 hover:text-white uppercase tracking-widest"
                                >
                                  + Add Resource
                                </button>
                              </div>
                              <div className="grid grid-cols-1 gap-3">
                                {(lesson.resources || []).map((res, resIdx) => (
                                  <div key={res.id} className="bg-slate-950/50 border border-slate-800 rounded-xl p-4 space-y-3">
                                    <div className="flex gap-4">
                                      <div className="flex-1 space-y-2">
                                        <input 
                                          type="text" 
                                          value={res.title} 
                                          onChange={e => {
                                            const resources = [...(lesson.resources || [])];
                                            resources[resIdx].title = e.target.value;
                                            updateLessonField(lessonIdx, 'resources', resources);
                                          }}
                                          placeholder="Title"
                                          className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-1.5 text-xs text-white"
                                        />
                                        <input 
                                          type="text" 
                                          value={res.url} 
                                          onChange={e => {
                                            const resources = [...(lesson.resources || [])];
                                            resources[resIdx].url = e.target.value;
                                            updateLessonField(lessonIdx, 'resources', resources);
                                          }}
                                          placeholder="URL"
                                          className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-1.5 text-[10px] text-slate-400 font-mono"
                                        />
                                      </div>
                                      <div className="w-24 space-y-2">
                                        <select 
                                          value={res.type} 
                                          onChange={e => {
                                            const resources = [...(lesson.resources || [])];
                                            resources[resIdx].type = e.target.value as any;
                                            updateLessonField(lessonIdx, 'resources', resources);
                                          }}
                                          className="w-full bg-slate-900 border border-slate-800 rounded-lg px-2 py-1.5 text-[9px] font-black uppercase tracking-widest text-slate-500"
                                        >
                                          {RESOURCE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                                        </select>
                                        <button 
                                          onClick={() => {
                                            const resources = (lesson.resources || []).filter(r => r.id !== res.id);
                                            updateLessonField(lessonIdx, 'resources', resources);
                                          }}
                                          className="w-full text-rose-500/60 hover:text-rose-500 text-[9px] font-black uppercase"
                                        >
                                          Delete
                                        </button>
                                      </div>
                                    </div>
                                    <input 
                                      type="text" 
                                      value={res.description || ''} 
                                      onChange={e => {
                                        const resources = [...(lesson.resources || [])];
                                        resources[resIdx].description = e.target.value;
                                        updateLessonField(lessonIdx, 'resources', resources);
                                      }}
                                      placeholder="Brief description (optional)"
                                      className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-1.5 text-[10px] text-slate-500"
                                    />
                                  </div>
                                ))}
                              </div>
                            </div>

                            {/* Quiz Builder Section */}
                            <div className="space-y-4 pt-4 border-t border-slate-800/50">
                              <div className="flex justify-between items-center">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quiz Builder</h4>
                                <button 
                                  type="button" 
                                  onClick={() => addQuizQuestion(lessonIdx)}
                                  className="text-[9px] font-black text-indigo-400 hover:text-white uppercase tracking-widest"
                                >
                                  + Add Question
                                </button>
                              </div>
                              <div className="space-y-6">
                                {(lesson.quiz || []).map((q, qIdx) => (
                                  <div key={q.id} className="bg-slate-950 border border-slate-800 rounded-2xl p-6 space-y-4">
                                    <div className="flex justify-between gap-4">
                                      <textarea 
                                        value={q.question} 
                                        onChange={e => {
                                          const quiz = [...(lesson.quiz || [])];
                                          quiz[qIdx].question = e.target.value;
                                          updateLessonField(lessonIdx, 'quiz', quiz);
                                        }}
                                        rows={2}
                                        placeholder="Enter question text..."
                                        className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-sm text-white font-bold"
                                      />
                                      <button 
                                        onClick={() => {
                                          const quiz = (lesson.quiz || []).filter(item => item.id !== q.id);
                                          updateLessonField(lessonIdx, 'quiz', quiz);
                                        }}
                                        className="text-slate-800 hover:text-rose-500 h-10 w-10 flex items-center justify-center border border-slate-800 rounded-xl"
                                      >
                                        <i className="fas fa-trash"></i>
                                      </button>
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                      {q.options.map((opt, optIdx) => (
                                        <div key={optIdx} className="flex items-center space-x-3 bg-slate-900/50 p-2 rounded-xl border border-slate-800">
                                          <input 
                                            type="radio" 
                                            name={`correct-${q.id}`} 
                                            checked={q.correctAnswer === optIdx} 
                                            onChange={() => {
                                              const quiz = [...(lesson.quiz || [])];
                                              quiz[qIdx].correctAnswer = optIdx;
                                              updateLessonField(lessonIdx, 'quiz', quiz);
                                            }}
                                            className="accent-indigo-500"
                                          />
                                          <input 
                                            type="text" 
                                            value={opt} 
                                            onChange={e => {
                                              const quiz = [...(lesson.quiz || [])];
                                              quiz[qIdx].options[optIdx] = e.target.value;
                                              updateLessonField(lessonIdx, 'quiz', quiz);
                                            }}
                                            className="flex-1 bg-transparent border-none text-xs text-slate-300 focus:ring-0"
                                            placeholder={`Option ${optIdx + 1}`}
                                          />
                                        </div>
                                      ))}
                                    </div>
                                  </div>
                                ))}
                              </div>
                            </div>

                            <div className="flex items-center justify-between pt-4 border-t border-slate-800">
                              <div className="flex items-center space-x-6">
                                <label className="flex items-center space-x-3 cursor-pointer group">
                                  <div 
                                    onClick={() => updateLessonField(lessonIdx, 'hasAiFeature', !lesson.hasAiFeature)}
                                    className={`w-10 h-5 rounded-full relative transition-all ${lesson.hasAiFeature ? 'bg-indigo-600' : 'bg-slate-800'}`}
                                  >
                                    <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all ${lesson.hasAiFeature ? 'left-6' : 'left-1'}`}></div>
                                  </div>
                                  <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest group-hover:text-indigo-400 transition-colors">AI Neural Features</span>
                                </label>
                              </div>

                              <button 
                                type="button" 
                                onClick={() => {
                                  if (confirm('Delete this lesson module?')) {
                                    const lessons = currentCourse!.lessons!.filter(l => l.id !== lesson.id);
                                    setCurrentCourse({...currentCourse!, lessons});
                                  }
                                }} 
                                className="flex items-center space-x-2 text-rose-500/60 hover:text-rose-500 text-[9px] font-black uppercase tracking-widest transition-colors"
                              >
                                <i className="fas fa-trash-alt"></i>
                                <span>Purge Module</span>
                              </button>
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {activeTab === 'structure' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Subject Architecture</h3>
                  <button type="button" onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">+ Subject Group</button>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {(currentCourse.subjects || []).map((subj, sIdx) => (
                    <div 
                      key={subj.id} 
                      className={`bg-slate-950 border rounded-[32px] p-8 space-y-6 transition-all ${contextSubjectId === subj.id ? 'border-indigo-500 shadow-[0_0_30px_rgba(79,70,229,0.1)]' : 'border-slate-800'}`}
                    >
                      <div className="flex flex-wrap items-center gap-4">
                        <button 
                          onClick={() => {
                            setContextSubjectId(subj.id);
                            setContextSubSubjectId(null);
                          }}
                          className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl transition-transform hover:scale-105 ${subj.color}`}
                        >
                          <i className={`fas ${subj.icon}`}></i>
                        </button>
                        <div className="flex-1 min-w-[200px] space-y-4">
                          <input 
                            type="text" 
                            value={subj.name} 
                            onChange={e => {
                              const subjs = [...currentCourse!.subjects!];
                              subjs[sIdx].name = e.target.value;
                              setCurrentCourse({...currentCourse!, subjects: subjs});
                            }}
                            className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" 
                            placeholder="Subject Name"
                          />
                          <div className="flex items-center space-x-3">
                            <input 
                              type="text" 
                              value={subj.icon} 
                              onChange={e => {
                                const subjs = [...currentCourse!.subjects!];
                                subjs[sIdx].icon = e.target.value;
                                setCurrentCourse({...currentCourse!, subjects: subjs});
                              }}
                              className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500" 
                              placeholder="fa-icon-name"
                            />
                            <select 
                              value={subj.color} 
                              onChange={e => {
                                const subjs = [...currentCourse!.subjects!];
                                subjs[sIdx].color = e.target.value;
                                setCurrentCourse({...currentCourse!, subjects: subjs});
                              }}
                              className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500"
                            >
                              {COLOR_PRESETS.map((c, i) => <option key={i} value={c}>Theme {i+1}</option>)}
                            </select>
                            <button 
                              onClick={() => {
                                setContextSubjectId(subj.id);
                                setContextSubSubjectId(null);
                                setActiveTab('curriculum');
                                addLesson();
                              }}
                              className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest flex items-center"
                            >
                              <i className="fas fa-plus mr-1"></i> Add Unit Here
                            </button>
                          </div>
                        </div>
                        <button onClick={() => {
                          if (contextSubjectId === subj.id) setContextSubjectId(null);
                          const subjs = currentCourse!.subjects!.filter(s => s.id !== subj.id);
                          setCurrentCourse({...currentCourse!, subjects: subjs});
                        }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>

                      <div className="pl-12 space-y-3">
                         <div className="flex justify-between items-center">
                            <h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4>
                            <button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Sub</button>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                           {(subj.subSubjects || []).map((ss, ssIdx) => (
                             <div 
                               key={ss.id} 
                               className={`flex items-center space-x-2 rounded-lg px-3 py-2 border transition-all ${contextSubSubjectId === ss.id ? 'bg-indigo-600/10 border-indigo-500/40' : 'bg-slate-900 border-slate-800'}`}
                             >
                               <input 
                                 type="text" 
                                 value={ss.name} 
                                 onFocus={() => {
                                   setContextSubjectId(subj.id);
                                   setContextSubSubjectId(ss.id);
                                 }}
                                 onChange={e => {
                                   const subjs = [...currentCourse!.subjects!];
                                   subjs[sIdx].subSubjects[ssIdx].name = e.target.value;
                                   setCurrentCourse({...currentCourse!, subjects: subjs});
                                 }}
                                 className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-300"
                               />
                               <button 
                                 onClick={() => {
                                   setContextSubjectId(subj.id);
                                   setContextSubSubjectId(ss.id);
                                   setActiveTab('curriculum');
                                   addLesson();
                                 }}
                                 className="text-[9px] text-slate-600 hover:text-indigo-400"
                                 title="Add unit to this sub-group"
                               >
                                 <i className="fas fa-plus"></i>
                               </button>
                               <button onClick={() => {
                                 if (contextSubSubjectId === ss.id) setContextSubSubjectId(null);
                                 const subjs = [...currentCourse!.subjects!];
                                 subjs[sIdx].subSubjects = subjs[sIdx].subSubjects.filter(item => item.id !== ss.id);
                                 setCurrentCourse({...currentCourse!, subjects: subjs});
                               }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                             </div>
                           ))}
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      {isAiModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-lg rounded-[40px] border border-slate-800 p-10 space-y-8 shadow-2xl animate-in zoom-in-95">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-black text-white tracking-tight">AI Architect</h2>
              <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Describe your vision for the course</p>
            </div>
            <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="e.g. Master React and TypeScript with modern architecture..." className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-200 min-h-[120px] focus:border-indigo-500/50 transition-all outline-none" />
            <div className="flex space-x-4">
              <button onClick={() => setIsAiModalOpen(false)} className="flex-1 py-5 bg-slate-950 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest border border-slate-800">Cancel</button>
              <button onClick={handleAiGenerate} disabled={!aiPrompt.trim() || isGenerating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl disabled:opacity-50 flex items-center justify-center space-x-3">
                {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-sparkles"></i>}
                <span>{isGenerating ? 'Synthesizing...' : 'Build Syllabus'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="flex-1 md:flex-none px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ title: '', lessons: [], subjects: [] }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-6">
                    <img src={course.thumbnail} className="w-16 h-10 rounded-xl object-cover opacity-80 group-hover:opacity-100 transition-opacity border border-slate-800 shadow-inner" alt="" />
                    <div>
                      <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                      <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Lesson } from '../types';

interface DashboardProps {
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse 
}) => {
  const [selectedSubject, setSelectedSubject] = useState<SubjectGroup | null>(null);
  const [selectedSubSubject, setSelectedSubSubject] = useState<SubSubject | null>(null);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-16 h-16 md:w-24 md:h-24 bg-slate-900 text-indigo-400 rounded-[30px] md:rounded-[40px] flex items-center justify-center mb-8 border border-slate-800">
          <i className="fas fa-rocket text-2xl md:text-3xl"></i>
        </div>
        <h2 className="text-2xl md:text-3xl font-black text-slate-100 mb-4">No active programs</h2>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Explore Catalog</button>
      </div>
    );
  }

  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubject(subj);
    setSelectedSubSubject(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubject(ss);
  };

  const handleBack = () => {
    if (selectedSubSubject) {
      setSelectedSubSubject(null);
    } else if (selectedSubject) {
      setSelectedSubject(null);
    }
  };

  const filteredLessons = activeCourse.lessons.filter(l => 
    l.subjectId === selectedSubject?.id && 
    l.subSubjectId === selectedSubSubject?.id
  );

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-5xl mx-auto">
      {/* Dynamic Header */}
      <div className="bg-slate-900/50 rounded-[32px] border border-slate-800/50 p-8 md:p-12 text-center shadow-2xl backdrop-blur-sm relative overflow-hidden">
        {selectedSubject && (
          <button 
            onClick={handleBack}
            className="absolute left-6 top-1/2 -translate-y-1/2 w-10 h-10 bg-slate-950 border border-slate-800 rounded-full flex items-center justify-center text-slate-400 hover:text-white hover:border-indigo-500/50 transition-all z-10"
          >
            <i className="fas fa-arrow-left text-sm"></i>
          </button>
        )}

        <div className="relative z-10">
          <p className="text-xs md:text-sm font-bold text-slate-400 uppercase tracking-widest mb-2 opacity-80">
            {selectedSubSubject 
              ? `${selectedSubject?.name} • ${selectedSubSubject.name}`
              : selectedSubject 
                ? `Selected Subject: ${selectedSubject.name}` 
                : 'Course & Content'}
          </p>
          <h1 className="text-2xl md:text-4xl lg:text-5xl font-black text-indigo-400 tracking-tight leading-tight drop-shadow-sm">
            {selectedSubSubject 
              ? 'Available Modules' 
              : selectedSubject 
                ? selectedSubject.name 
                : activeCourse.title}
          </h1>
        </div>

        {/* Aesthetic background glow */}
        <div className="absolute -top-20 -right-20 w-64 h-64 bg-indigo-600/10 rounded-full blur-[100px]"></div>
        <div className="absolute -bottom-20 -left-20 w-64 h-64 bg-emerald-600/5 rounded-full blur-[100px]"></div>
      </div>

      {/* Dynamic Grid */}
      <div className="bg-slate-900/30 rounded-[40px] border border-slate-800/40 p-4 md:p-8 lg:p-10 shadow-xl backdrop-blur-sm min-h-[400px]">
        {!selectedSubject ? (
          /* Level 1: Subjects */
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
            {(activeCourse.subjects || []).map((subj) => (
              <button 
                key={subj.id} 
                onClick={() => handleSubjectClick(subj)}
                className="flex items-center justify-between p-4 md:p-5 bg-slate-950 border border-slate-800/50 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-sm hover:shadow-indigo-500/5"
              >
                <div className="flex items-center space-x-4">
                  <div className={`w-12 h-12 md:w-14 md:h-14 rounded-xl flex items-center justify-center text-xl md:text-2xl shadow-inner border border-white/5 ${subj.color}`}>
                    <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                  </div>
                  <div className="text-left">
                    <span className="text-lg font-bold text-slate-100 group-hover:text-white transition-colors block">
                      {subj.name}
                    </span>
                    <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">
                      {subj.subSubjects.length} Sub-units
                    </span>
                  </div>
                </div>
                <div className="w-8 h-8 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500/50 group-hover:bg-indigo-600/10 transition-all">
                  <i className="fas fa-chevron-right text-[10px] text-emerald-500 group-hover:text-indigo-400 group-hover:translate-x-0.5 transition-transform"></i>
                </div>
              </button>
            ))}
          </div>
        ) : !selectedSubSubject ? (
          /* Level 2: Sub-Subjects */
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-4 duration-300">
            {selectedSubject.subSubjects.map((ss) => (
              <button 
                key={ss.id} 
                onClick={() => handleSubSubjectClick(ss)}
                className="flex items-center justify-between p-4 md:p-5 bg-slate-950 border border-slate-800/50 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-sm"
              >
                <div className="flex items-center space-x-4">
                  <div className={`w-10 h-10 rounded-lg flex items-center justify-center text-sm shadow-inner border border-white/5 bg-slate-900 text-indigo-400`}>
                    <i className="fas fa-layer-group"></i>
                  </div>
                  <span className="text-base font-bold text-slate-100 group-hover:text-indigo-400 transition-colors">
                    {ss.name}
                  </span>
                </div>
                <div className="w-8 h-8 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:bg-indigo-600/20 transition-all">
                  <i className="fas fa-chevron-right text-[10px] text-indigo-500"></i>
                </div>
              </button>
            ))}
          </div>
        ) : (
          /* Level 3: Lessons */
          <div className="space-y-4 animate-in slide-in-from-right-4 duration-300">
            {filteredLessons.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {filteredLessons.map((lesson, idx) => (
                  <button 
                    key={lesson.id} 
                    onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                    className="flex items-center p-5 bg-slate-950 border border-slate-800/50 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden"
                  >
                    <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-[10px] font-black text-slate-500 border border-slate-800 mr-4 group-hover:text-indigo-400 transition-colors">
                      {idx + 1}
                    </div>
                    <div className="flex-1 text-left">
                      <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors text-sm">{lesson.title}</h4>
                      <div className="flex items-center space-x-3 mt-1">
                        <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                        {lesson.hasAiFeature && <i className="fas fa-sparkles text-[9px] text-indigo-500"></i>}
                      </div>
                    </div>
                    <div className="w-9 h-9 bg-indigo-600/10 rounded-full flex items-center justify-center text-indigo-400 border border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white transition-all">
                      <i className="fas fa-play text-[10px]"></i>
                    </div>
                  </button>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-64 text-center opacity-40">
                <i className="fas fa-folder-open text-4xl mb-4 text-slate-700"></i>
                <h3 className="text-xl font-black text-white">No lessons in this sub-group</h3>
                <p className="text-xs font-bold text-slate-500 mt-2">The curriculum for this section is currently being updated.</p>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Progress Footer */}
      <div className="flex flex-col md:flex-row items-center justify-between gap-4 px-8 py-6 bg-slate-900/20 rounded-3xl border border-slate-800/30">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-600/10 rounded-full flex items-center justify-center text-indigo-400 border border-indigo-600/20">
            <i className="fas fa-chart-line text-sm"></i>
          </div>
          <div>
