export default Dashboard;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Explore from './components/Explore';
import CourseView from './components/CourseView';
import AdminPanel from './components/AdminPanel';
import Profile from './components/Profile';
import Auth from './components/Auth';
import CourseDetails from './components/CourseDetails';
import { AppRoute, Course, User } from './types';
import { MOCK_COURSES } from './constants';
import { getAllCoursesFromDB, saveCourseToDB, deleteCourseFromDB } from './services/storage';

const App: React.FC = () => {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [activeCourseId, setActiveCourseId] = useState<string | null>(null);
  const [initialLessonId, setInitialLessonId] = useState<string | undefined>(undefined);
  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [courses, setCourses] = useState<Course[]>([]);
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [editingCourseId, setEditingCourseId] = useState<string | null>(null);

  useEffect(() => {
    const init = async () => {
      try {
        const savedCourses = await getAllCoursesFromDB();
        if (savedCourses.length > 0) {
          setCourses(savedCourses);
        } else {
          for (const c of MOCK_COURSES) await saveCourseToDB(c);
          setCourses(MOCK_COURSES);
        }
        const savedUser = localStorage.getItem('eduworld_user');
        if (savedUser) setUser(JSON.parse(savedUser));
      } catch (e) {
        console.error("Init Error", e);
      } finally {
        setIsLoading(false);
      }
    };
    init();
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('eduworld_user', JSON.stringify(u));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('eduworld_user');
    setRoute(AppRoute.DASHBOARD);
  };

  const navigate = (r: AppRoute) => {
    setRoute(r);
    if (r !== AppRoute.ADMIN) setEditingCourseId(null);
    window.scrollTo(0, 0);
  };

  const handleCourseClick = (id: string, lessonId?: string) => {
    setActiveCourseId(id);
    setInitialLessonId(lessonId);
    const isEnrolled = user?.enrolledCourses.includes(id);
    setRoute(isEnrolled ? AppRoute.COURSE_VIEW : AppRoute.COURSE_DETAILS);
  };

  const handleEnroll = (courseId: string) => {
    if (!user) return;
    const updated = { ...user, enrolledCourses: [...new Set([...user.enrolledCourses, courseId])] };
    setUser(updated);
    localStorage.setItem('eduworld_user', JSON.stringify(updated));
    setSelectedCourseId(courseId);
    setActiveCourseId(courseId);
    setRoute(AppRoute.DASHBOARD);
  };

  if (!user) return <Auth onLogin={handleLogin} />;
  if (isLoading) return <div className="h-screen bg-[#020617] flex items-center justify-center text-indigo-400 font-black uppercase tracking-widest animate-pulse text-xs">Syncing Neural Core...</div>;

  const activeCourse = courses.find(c => c.id === activeCourseId);
  const enrolledCourses = courses.filter(c => user.enrolledCourses.includes(c.id));

  const navItems = [
    { id: AppRoute.DASHBOARD, icon: 'fa-house', label: 'Home' },
    { id: AppRoute.COURSES, icon: 'fa-compass', label: 'Explore' },
    ...(user.role === 'admin' ? [{ id: AppRoute.ADMIN, icon: 'fa-shield-halved', label: 'Admin' }] : []),
    { id: AppRoute.PROFILE, icon: 'fa-user', label: 'Profile' }
  ];

  return (
    <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden relative">
      {/* Sidebar for Desktop only */}
      <div className={`hidden md:block h-full border-r border-slate-800 ${route === AppRoute.COURSE_VIEW ? 'hidden' : ''}`}>
        <Sidebar currentRoute={route} user={user} setRoute={navigate} onLogout={handleLogout} />
      </div>

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Mobile Top Header */}
        {route !== AppRoute.COURSE_VIEW && (
          <header className="md:hidden flex items-center justify-start px-6 py-5 bg-slate-950/80 backdrop-blur-xl border-b border-slate-800 z-50">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-600/20">
                <i className="fas fa-graduation-cap text-white text-[10px]"></i>
              </div>
              <span className="font-black text-white tracking-tighter text-lg uppercase">Edu World</span>
            </div>
          </header>
        )}

        <main className="flex-1 overflow-y-auto relative scroll-smooth bg-[#020617]">
          <div className={route !== AppRoute.COURSE_VIEW ? "p-4 md:p-12 pb-32 md:pb-12 max-w-[1600px] mx-auto" : "h-full"}>
            {route === AppRoute.DASHBOARD && (
              <Dashboard 
                onCourseClick={handleCourseClick} 
                setRoute={setRoute} 
                courses={enrolledCourses} 
                selectedCourseId={selectedCourseId} 
                onSelectCourse={setSelectedCourseId} 
              />
            )}
            {route === AppRoute.COURSES && <Explore onCourseClick={handleCourseClick} courses={courses} />}
            {route === AppRoute.PROFILE && <Profile user={user} courses={enrolledCourses} onCourseClick={handleCourseClick} onUpdateUser={(u) => { setUser(u); localStorage.setItem('eduworld_user', JSON.stringify(u)); }} onLogout={handleLogout} />}
            {route === AppRoute.ADMIN && user.role === 'admin' && (
              <AdminPanel 
                courses={courses} 
                initialEditCourseId={editingCourseId} 
                onAddCourse={async (c) => { await saveCourseToDB(c); setCourses(await getAllCoursesFromDB()); }} 
                onUpdateCourse={async (c) => { await saveCourseToDB(c); setCourses(await getAllCoursesFromDB()); }} 
                onDeleteCourse={async (id) => { await deleteCourseFromDB(id); setCourses(await getAllCoursesFromDB()); }} 
                onPreview={() => {}} 
              />
            )}
            {route === AppRoute.COURSE_DETAILS && activeCourse && (
              <CourseDetails 
                course={activeCourse} 
                isAdmin={user.role === 'admin'} 
                isEnrolled={user.enrolledCourses.includes(activeCourse.id)} 
                onEnroll={handleEnroll} 
                onAdminEdit={() => { setEditingCourseId(activeCourse.id); setRoute(AppRoute.ADMIN); }} 
                onBack={() => setRoute(AppRoute.COURSES)} 
              />
            )}
            {route === AppRoute.COURSE_VIEW && activeCourse && (
              <CourseView 
                course={activeCourse} 
                user={user} 
                onBack={() => setRoute(AppRoute.DASHBOARD)} 
                initialLessonId={initialLessonId}
                onQuizComplete={(lid, att) => {
                  const updated = { ...user, quizScores: { ...user.quizScores, [lid]: att } };
                  setUser(updated);
                  localStorage.setItem('eduworld_user', JSON.stringify(updated));
                }} 
              />
            )}
          </div>
        </main>

        {/* Mobile Bottom Navigation Bar */}
        {route !== AppRoute.COURSE_VIEW && (
          <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-slate-900/90 backdrop-blur-2xl border-t border-slate-800 flex justify-around items-center px-4 py-4 z-50 safe-area-bottom shadow-[0_-8px_40px_rgba(0,0,0,0.6)]">
            {navItems.map(item => (
              <button 
                key={item.id}
                onClick={() => navigate(item.id)}
                className={`flex flex-col items-center justify-center space-y-1.5 py-1 transition-all ${route === item.id ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}
              >
                <div className={`text-xl ${route === item.id ? 'scale-110' : 'scale-100'} transition-transform duration-300`}>
                  <i className={`fas ${item.icon}`}></i>
                </div>
                <span className="text-[8px] font-black uppercase tracking-widest">{item.label}</span>
              </button>
            ))}
          </nav>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  const activeLessonIndex = course.lessons.findIndex(l => l.id === activeLessonId);
  const activeLesson = course.lessons[activeLessonIndex] || course.lessons[0];

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  // Update lesson if initialLessonId changes (e.g. user clicks another lesson in dashboard)
  useEffect(() => {
    if (initialLessonId) {
      setActiveLessonId(initialLessonId);
    }
  }, [initialLessonId]);

  useEffect(() => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
    if (videoRef.current) videoRef.current.load();
  }, [activeLessonId]);

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
    }
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      {/* Main Content (Player & Info) */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center space-x-3">
            <button onClick={onBack} className="w-9 h-9 rounded-lg bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <h2 className="text-xs font-black text-slate-500 uppercase tracking-widest">{course.title}</h2>
              <p className="text-sm font-bold text-white truncate max-w-[200px]">{activeLesson.title}</p>
            </div>
            <div className="sm:hidden">
              <p className="text-xs font-bold text-white truncate max-w-[120px]">{activeLesson.title}</p>
            </div>
          </div>
          <button 
            onClick={() => setIsAiOpen(!isAiOpen)} 
            className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${isAiOpen ? 'bg-indigo-600 text-white' : 'bg-slate-900 text-slate-500 border border-slate-800'}`}
          >
            <i className="fas fa-robot mr-2"></i>AI
          </button>
        </nav>

        <div className="flex-1 p-4 md:p-10 max-w-5xl mx-auto w-full space-y-8">
          <div className="bg-black rounded-2xl md:rounded-3xl overflow-hidden aspect-video border border-slate-800 shadow-2xl">
            <video ref={videoRef} src={activeLesson.videoUrl || 'https://storage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4'} controls className="w-full h-full" />
          </div>

          <div className="flex border-b border-slate-800 space-x-6">
            <button onClick={() => setActiveTab('overview')} className={`pb-3 text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}>Overview</button>
            {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={() => setActiveTab('quiz')} className={`pb-3 text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}>Quiz</button>}
          </div>

          <div className="min-h-[300px] pb-20 md:pb-0">
            {activeTab === 'overview' && (
              <div className="prose prose-invert max-w-none text-slate-400 animate-in fade-in duration-300" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />
            )}
            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-6 max-w-xl animate-in fade-in duration-300">
                {quizState.complete ? (
                  <div className="p-8 bg-slate-900 border border-slate-800 rounded-2xl text-center">
                    <h3 className="text-xl font-black text-white">Score: {quizState.score}/{activeLesson.quiz.length}</h3>
                    <button onClick={() => setActiveTab('overview')} className="mt-6 px-6 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest">Continue Learning</button>
                  </div>
                ) : (
                  <div className="space-y-4">
                    <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Question {quizState.currentIdx + 1} of {activeLesson.quiz.length}</p>
                    <h4 className="text-lg md:text-xl font-black text-white">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-3 pt-4">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button key={i} onClick={() => handleQuizAnswer(i)} className="w-full p-4 bg-slate-900 border border-slate-800 rounded-xl text-left hover:border-indigo-500 hover:bg-slate-800/50 transition-all text-sm">{opt}</button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        {/* Footer Nav */}
        <div className="mt-auto p-4 md:p-6 border-t border-slate-800 bg-slate-950/50 flex justify-between items-center sticky bottom-0 z-30">
          <button disabled={activeLessonIndex === 0} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex - 1].id)} className="px-4 py-2 bg-slate-900 rounded-lg text-[10px] font-black uppercase tracking-widest disabled:opacity-20 hover:text-white transition-colors"><i className="fas fa-chevron-left mr-2"></i>Prev</button>
          <div className="flex space-x-1.5 overflow-x-auto px-2 max-w-[120px] no-scrollbar">
            {course.lessons.map(l => (
              <div key={l.id} className={`w-2 h-2 rounded-full flex-shrink-0 transition-all duration-500 ${l.id === activeLessonId ? 'bg-indigo-500 w-4' : 'bg-slate-800'}`}></div>
            ))}
          </div>
          <button disabled={activeLessonIndex === course.lessons.length - 1} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex + 1].id)} className="px-4 py-2 bg-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-widest disabled:opacity-20 hover:bg-indigo-700 transition-all">Next<i className="fas fa-chevron-right ml-2"></i></button>
        </div>
      </div>

      {/* AI Assistant */}
      <aside className={`
        fixed lg:relative bottom-0 right-0 w-full lg:w-[400px] h-[80vh] lg:h-full bg-slate-950 border-t lg:border-t-0 lg:border-l border-slate-800 z-[40] transition-transform duration-300 transform
        ${isAiOpen ? 'translate-y-0 lg:translate-x-0' : 'translate-y-full lg:translate-x-full lg:hidden'}
      `}>
        <div className="flex flex-col h-full relative">
          <button onClick={() => setIsAiOpen(false)} className="lg:hidden absolute top-4 right-4 z-50 text-slate-500 text-lg p-2"><i className="fas fa-times"></i></button>
          <AIAssistant course={course} lesson={activeLesson} user={user} />
        </div>
      </aside>
    </div>
  );
};

export default CourseView;

import React, { useState, useEffect, useMemo } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Resource, QuizQuestion } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-500 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const RESOURCE_TYPES = ['link', 'pdf', 'video', 'zip'];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const [expandedLessonId, setExpandedLessonId] = useState<string | null>(null);

  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);

  // Icon Picker State
  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);
  const [iconSearchTerm, setIconSearchTerm] = useState('');

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const filteredIcons = useMemo(() => {
    return ICON_OPTIONS.filter(icon => icon.toLowerCase().includes(iconSearchTerm.toLowerCase()));
  }, [iconSearchTerm]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed. Check your API link.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;
    if (currentCourse.id) {
      onUpdateCourse(currentCourse as Course);
    } else {
      onAddCourse(currentCourse as Course);
    }
    setIsEditing(false);
    setCurrentCourse(null);
  };

  const addLesson = () => {
    const newId = Math.random().toString(36).substr(2, 9);
    const newLesson: Lesson = { 
      id: newId, 
      title: 'New Unit', 
      content: '<p>Start typing lesson content here...</p>', 
      duration: '15:00',
      subjectId: contextSubjectId || undefined,
      subSubjectId: contextSubSubjectId || undefined,
      hasAiFeature: true,
      resources: [],
      quiz: []
    };
    setCurrentCourse({
      ...currentCourse!, 
      lessons: [...(currentCourse!.lessons || []), newLesson] 
    });
    setExpandedLessonId(newId);
  };

  const updateLessonField = (idx: number, field: keyof Lesson, value: any) => {
    const lessons = [...(currentCourse!.lessons || [])];
    lessons[idx] = { ...lessons[idx], [field]: value };
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addResource = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newResource: Resource = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Resource',
      url: '',
      type: 'link'
    };
    lessons[lessonIdx].resources = [...(lessons[lessonIdx].resources || []), newResource];
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addQuizQuestion = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newQuestion: QuizQuestion = {
      id: Math.random().toString(36).substr(2, 9),
      question: 'New Question?',
      options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
      correctAnswer: 0
    };
    lessons[lessonIdx].quiz = [...(lessons[lessonIdx].quiz || []), newQuestion];
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Group',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const updatedSubjects = currentCourse!.subjects!.map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group' }]
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  if (isEditing && currentCourse) {
    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">
        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Discard Changes</span>
          </button>
          <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button 
