            <div className="flex space-x-4">
              <button onClick={() => setIsAiModalOpen(false)} className="flex-1 py-5 bg-slate-950 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest border border-slate-800">Cancel</button>
              <button onClick={handleAiGenerate} disabled={!aiPrompt.trim() || isGenerating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl disabled:opacity-50 flex items-center justify-center space-x-3">
                {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-sparkles"></i>}
                <span>{isGenerating ? 'Synthesizing...' : 'Build Syllabus'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="flex-1 md:flex-none px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ title: '', lessons: [], subjects: [] }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-6">
                    <img src={course.thumbnail} className="w-16 h-10 rounded-xl object-cover opacity-80 group-hover:opacity-100 transition-opacity border border-slate-800 shadow-inner" alt="" />
                    <div>
                      <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                      <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Resource, QuizQuestion } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-500 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const RESOURCE_TYPES = ['link', 'pdf', 'video', 'zip'];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const [expandedLessonId, setExpandedLessonId] = useState<string | null>(null);

  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);

  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);
  const [iconSearchTerm, setIconSearchTerm] = useState('');

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const filteredIcons = useMemo(() => {
    return ICON_OPTIONS.filter(icon => icon.toLowerCase().includes(iconSearchTerm.toLowerCase()));
  }, [iconSearchTerm]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed. Check your API link.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;
    if (currentCourse.id) {
      onUpdateCourse(currentCourse as Course);
    } else {
      onAddCourse(currentCourse as Course);
    }
    setIsEditing(false);
    setCurrentCourse(null);
  };

  const addLesson = (subjId?: string, subSubjId?: string) => {
    const newId = Math.random().toString(36).substr(2, 9);
    const sId = subjId || contextSubjectId || undefined;
    const ssId = subSubjId || contextSubSubjectId || undefined;

    const newLesson: Lesson = { 
      id: newId, 
      title: 'New Module', 
      content: '<h1>Module Content</h1><p>Start typing here...</p>', 
      duration: '15:00',
      subjectId: sId,
      subSubjectId: ssId,
      hasAiFeature: true,
      resources: [],
      quiz: []
    };

    setCurrentCourse(prev => {
      if (!prev) return prev;
      return {
        ...prev, 
        lessons: [...(prev.lessons || []), newLesson] 
      };
    });
    setExpandedLessonId(newId);
  };

  const updateLessonField = (idx: number, field: keyof Lesson, value: any) => {
    const lessons = [...(currentCourse!.lessons || [])];
    lessons[idx] = { ...lessons[idx], [field]: value };
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addResource = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newResource: Resource = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Resource',
      url: '',
      type: 'link'
    };
    lessons[lessonIdx].resources = [...(lessons[lessonIdx].resources || []), newResource];
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addQuizQuestion = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newQuestion: QuizQuestion = {
      id: Math.random().toString(36).substr(2, 9),
      question: 'New Question?',
      options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
      correctAnswer: 0
    };
    lessons[lessonIdx].quiz = [...(lessons[lessonIdx].quiz || []), newQuestion];
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Group',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const updatedSubjects = currentCourse!.subjects!.map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group' }]
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  if (isEditing && currentCourse) {
    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">
        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Discard Changes</span>
          </button>
          <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab as any)} 
                className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}
              >
                {tab}
              </button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({...currentCourse!, title: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                    <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({...currentCourse!, category: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Price ($)</label>
                    <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({...currentCourse!, price: parseFloat(e.target.value)})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Overview</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({...currentCourse!, description: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <div>
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Lesson Units</h3>
                    {contextSubjectId && (
                      <p className="text-[8px] text-indigo-400 font-bold mt-1 uppercase tracking-widest">
                        Context: {currentCourse.subjects?.find(s => s.id === contextSubjectId)?.name} 
                        {contextSubSubjectId && ` / ${currentCourse.subjects?.find(s => s.id === contextSubjectId)?.subSubjects.find(ss => ss.id === contextSubSubjectId)?.name}`}
                      </p>
                    )}
                  </div>
                  <button type="button" onClick={() => addLesson()} className="px-5 py-2 bg-slate-950 border border-slate-800 text-indigo-400 rounded-xl text-[9px] font-black uppercase tracking-widest hover:border-indigo-500/50 transition-all">+ Unit</button>
                </div>

                <div className="space-y-4">
                  {(currentCourse.lessons || []).map((lesson, lessonIdx) => {
                    const isExpanded = expandedLessonId === lesson.id;
                    return (
                      <div key={lesson.id} className={`bg-slate-950 border rounded-2xl overflow-hidden transition-all duration-300 ${isExpanded ? 'border-indigo-500/50 shadow-lg' : 'border-slate-800'}`}>
                        <div 
                          className="flex items-center px-6 py-4 cursor-pointer hover:bg-slate-900/40 transition-colors"
                          onClick={() => setExpandedLessonId(isExpanded ? null : lesson.id)}
                        >
                          <span className="text-[10px] font-black text-slate-700 w-8">{lessonIdx + 1}</span>
                          <span className="flex-1 font-bold text-slate-200 text-sm">{lesson.title || 'Untitled Lesson'}</span>
                          <div className="flex items-center space-x-4">
                            <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.videoUrl ? 'Video' : 'Text Only'} • {lesson.duration || '00:00'}</span>
                            {lesson.subjectId && (
                              <span className="text-[8px] font-black text-indigo-400/60 uppercase tracking-widest bg-indigo-500/5 px-2 py-1 rounded border border-indigo-500/10">
                                {currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.name}
                              </span>
                            )}
                            <i className={`fas fa-chevron-${isExpanded ? 'up' : 'down'} text-[10px] text-slate-700`}></i>
                          </div>
                        </div>

                        {isExpanded && (
                          <div className="px-8 pb-8 pt-4 space-y-8 border-t border-slate-900 bg-slate-900/20 animate-in slide-in-from-top-4 duration-300">
                            <div className="space-y-6">
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Lesson Title</label>
                                  <input 
                                    type="text" 
                                    value={lesson.title} 
                                    onChange={e => updateLessonField(lessonIdx, 'title', e.target.value)} 
                                    className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white font-bold" 
                                  />
                                </div>
                                <div className="space-y-2">
                                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Duration (e.g. 15:00)</label>
                                  <input 
                                    type="text" 
                                    value={lesson.duration} 
                                    onChange={e => updateLessonField(lessonIdx, 'duration', e.target.value)} 
                                    className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white" 
                                  />
                                </div>
                              </div>

                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Video Source URL (Leave empty for Text Lesson)</label>
                                <input 
                                  type="text" 
                                  value={lesson.videoUrl || ''} 
                                  onChange={e => updateLessonField(lessonIdx, 'videoUrl', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-slate-400 font-mono"
                                  placeholder="https://..."
                                />
                              </div>

                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Lesson Body (HTML Content)</label>
                                <textarea 
                                  rows={8} 
                                  value={lesson.content} 
                                  onChange={e => updateLessonField(lessonIdx, 'content', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-4 py-4 text-xs text-slate-300 leading-relaxed font-mono"
                                  placeholder="<h1>Lesson Header</h1><p>Body text...</p>"
                                />
                              </div>

                              <div className="space-y-2 p-4 bg-indigo-500/5 rounded-2xl border border-indigo-500/10">
                                <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest">Internal Instructor Notes (Invisible to Students)</label>
                                <textarea 
                                  rows={4} 
                                  value={lesson.instructorNotes || ''} 
                                  onChange={e => updateLessonField(lessonIdx, 'instructorNotes', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-4 text-xs text-indigo-200/80 leading-relaxed font-medium italic"
                                  placeholder="Strategy notes for this lesson..."
                                />
                              </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4 border-t border-slate-800/50">
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Parent Subject</label>
                                <select 
                                  value={lesson.subjectId || ''} 
                                  onChange={e => {
                                    updateLessonField(lessonIdx, 'subjectId', e.target.value);
                                    updateLessonField(lessonIdx, 'subSubjectId', undefined);
                                  }}
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest text-slate-400"
                                >
                                  <option value="">Unassigned</option>
                                  {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                                </select>
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Sub-Unit Category</label>
                                <select 
                                  value={lesson.subSubjectId || ''} 
                                  disabled={!lesson.subjectId}
                                  onChange={e => updateLessonField(lessonIdx, 'subSubjectId', e.target.value)}
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest text-slate-400 disabled:opacity-20"
                                >
                                  <option value="">No Sub-Group</option>
                                  {currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.subSubjects.map(ss => (
                                    <option key={ss.id} value={ss.id}>{ss.name}</option>
                                  ))}
                                </select>
                              </div>
                            </div>

                            <div className="space-y-4 pt-4 border-t border-slate-800/50">
                              <div className="flex justify-between items-center">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Resource Hub</h4>
                                <button type="button" onClick={() => addResource(lessonIdx)} className="text-[9px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Resource</button>
                              </div>
                              <div className="grid grid-cols-1 gap-3">
                                {(lesson.resources || []).map((res, resIdx) => (
                                  <div key={res.id} className="bg-slate-950/50 border border-slate-800 rounded-xl p-4 space-y-3">
                                    <div className="flex gap-4">
                                      <div className="flex-1 space-y-2">
                                        <input type="text" value={res.title} onChange={e => { const r = [...(lesson.resources || [])]; r[resIdx].title = e.target.value; updateLessonField(lessonIdx, 'resources', r); }} placeholder="Title" className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-1.5 text-xs text-white" />
                                        <input type="text" value={res.url} onChange={e => { const r = [...(lesson.resources || [])]; r[resIdx].url = e.target.value; updateLessonField(lessonIdx, 'resources', r); }} placeholder="URL" className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-1.5 text-[10px] text-slate-400 font-mono" />
                                      </div>
                                      <div className="w-24 space-y-2">
                                        <select value={res.type} onChange={e => { const r = [...(lesson.resources || [])]; r[resIdx].type = e.target.value as any; updateLessonField(lessonIdx, 'resources', r); }} className="w-full bg-slate-900 border border-slate-800 rounded-lg px-2 py-1.5 text-[9px] font-black uppercase tracking-widest text-slate-500">
                                          {RESOURCE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                                        </select>
                                        <button onClick={() => { const r = (lesson.resources || []).filter(item => item.id !== res.id); updateLessonField(lessonIdx, 'resources', r); }} className="w-full text-rose-500/60 hover:text-rose-500 text-[9px] font-black uppercase">Delete</button>
                                      </div>
                                    </div>
                                  </div>
                                ))}
                              </div>
                            </div>

                            <div className="space-y-4 pt-4 border-t border-slate-800/50">
                              <div className="flex justify-between items-center">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quiz Builder</h4>
                                <button type="button" onClick={() => addQuizQuestion(lessonIdx)} className="text-[9px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Question</button>
                              </div>
                              <div className="space-y-6">
                                {(lesson.quiz || []).map((q, qIdx) => (
                                  <div key={q.id} className="bg-slate-950 border border-slate-800 rounded-2xl p-6 space-y-4">
                                    <div className="flex justify-between gap-4">
                                      <textarea value={q.question} onChange={e => { const quiz = [...(lesson.quiz || [])]; quiz[qIdx].question = e.target.value; updateLessonField(lessonIdx, 'quiz', quiz); }} rows={2} placeholder="Question..." className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-sm text-white font-bold" />
                                      <button onClick={() => { const quiz = (lesson.quiz || []).filter(item => item.id !== q.id); updateLessonField(lessonIdx, 'quiz', quiz); }} className="text-slate-800 hover:text-rose-500 h-10 w-10 flex items-center justify-center border border-slate-800 rounded-xl"><i className="fas fa-trash"></i></button>
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                      {q.options.map((opt, optIdx) => (
                                        <div key={optIdx} className="flex items-center space-x-3 bg-slate-900/50 p-2 rounded-xl border border-slate-800">
                                          <input type="radio" name={`correct-${q.id}`} checked={q.correctAnswer === optIdx} onChange={() => { const quiz = [...(lesson.quiz || [])]; quiz[qIdx].correctAnswer = optIdx; updateLessonField(lessonIdx, 'quiz', quiz); }} className="accent-indigo-500" />
                                          <input type="text" value={opt} onChange={e => { const quiz = [...(lesson.quiz || [])]; quiz[qIdx].options[optIdx] = e.target.value; updateLessonField(lessonIdx, 'quiz', quiz); }} className="flex-1 bg-transparent border-none text-xs text-slate-300 focus:ring-0" placeholder={`Option ${optIdx + 1}`} />
                                        </div>
                                      ))}
                                    </div>
                                  </div>
                                ))}
                              </div>
                            </div>

                            <div className="flex items-center justify-between pt-4 border-t border-slate-800">
                              <label className="flex items-center space-x-3 cursor-pointer group">
                                <div onClick={() => updateLessonField(lessonIdx, 'hasAiFeature', !lesson.hasAiFeature)} className={`w-10 h-5 rounded-full relative transition-all ${lesson.hasAiFeature ? 'bg-indigo-600' : 'bg-slate-800'}`}>
                                  <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all ${lesson.hasAiFeature ? 'left-6' : 'left-1'}`}></div>
                                </div>
                                <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest group-hover:text-indigo-400 transition-colors">AI Neural Features</span>
                              </label>

                              <button type="button" onClick={() => { if (confirm('Delete module?')) { const l = currentCourse!.lessons!.filter(item => item.id !== lesson.id); setCurrentCourse({...currentCourse!, lessons: l}); } }} className="flex items-center space-x-2 text-rose-500/60 hover:text-rose-500 text-[9px] font-black uppercase tracking-widest transition-colors">
                                <i className="fas fa-trash-alt"></i>
                                <span>Purge Module</span>
                              </button>
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {activeTab === 'structure' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Subject Architecture</h3>
                  <button type="button" onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">+ Subject Group</button>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {(currentCourse.subjects || []).map((subj, sIdx) => (
                    <div key={subj.id} className={`bg-slate-950 border rounded-[32px] p-8 space-y-6 transition-all ${contextSubjectId === subj.id ? 'border-indigo-500 shadow-[0_0_30px_rgba(79,70,229,0.1)]' : 'border-slate-800'}`}>
                      <div className="flex flex-wrap items-center gap-4 relative">
                        <div className="relative">
                          <button onClick={() => { setIconPickerOpenId(iconPickerOpenId === subj.id ? null : subj.id); setIconSearchTerm(''); }} className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl transition-transform hover:scale-105 shadow-inner border border-white/5 ${subj.color}`}>
                            <i className={`fas ${subj.icon}`}></i>
                          </button>
                          {iconPickerOpenId === subj.id && (
                            <div className="absolute top-14 left-0 z-50 w-72 bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl p-4 animate-in fade-in zoom-in-95">
                              <div className="flex items-center space-x-2 bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 mb-4">
                                <i className="fas fa-search text-[10px] text-slate-600"></i>
                                <input type="text" autoFocus placeholder="Search icon..." value={iconSearchTerm} onChange={(e) => setIconSearchTerm(e.target.value)} className="w-full bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-200 p-0" />
                              </div>
                              <div className="grid grid-cols-6 gap-2 max-h-48 overflow-y-auto no-scrollbar pr-1">
                                {filteredIcons.map((icon) => (
                                  <button key={icon} onClick={() => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].icon = icon; setCurrentCourse({...currentCourse!, subjects: subjs}); setIconPickerOpenId(null); }} className={`w-8 h-8 rounded-lg flex items-center justify-center text-sm transition-all border ${subj.icon === icon ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-950 text-slate-500 border-slate-800 hover:border-indigo-500/50 hover:text-indigo-400'}`}>
                                    <i className={`fas ${icon}`}></i>
                                  </button>
                                ))}
                              </div>
                            </div>
                          )}
                        </div>

                        <div className="flex-1 min-w-[200px] space-y-4">
                          <input type="text" value={subj.name} onFocus={() => { setContextSubjectId(subj.id); setContextSubSubjectId(null); }} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" placeholder="Subject Name" />
                          <div className="flex items-center space-x-3">
                            <select value={subj.color} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].color = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500">
                              {COLOR_PRESETS.map((c, i) => <option key={i} value={c}>Theme {i+1}</option>)}
                            </select>
                            <button onClick={() => { setContextSubjectId(subj.id); setContextSubSubjectId(null); setActiveTab('curriculum'); addLesson(subj.id); }} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest flex items-center">
                              <i className="fas fa-plus mr-1"></i> Add Unit Here
                            </button>
                          </div>
                        </div>
                        <button onClick={() => { if (contextSubjectId === subj.id) setContextSubjectId(null); const subjs = currentCourse!.subjects!.filter(s => s.id !== subj.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>

                      <div className="pl-12 space-y-3">
                         <div className="flex justify-between items-center">
                            <h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4>
                            <button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Sub</button>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                           {(subj.subSubjects || []).map((ss, ssIdx) => (
                             <div key={ss.id} className={`flex items-center space-x-2 rounded-lg px-3 py-2 border transition-all ${contextSubSubjectId === ss.id ? 'bg-indigo-600/10 border-indigo-500/40' : 'bg-slate-900 border-slate-800'}`}>
                               <input type="text" value={ss.name} onFocus={() => { setContextSubjectId(subj.id); setContextSubSubjectId(ss.id); }} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects[ssIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-300" />
                               <button onClick={() => { setContextSubjectId(subj.id); setContextSubSubjectId(ss.id); setActiveTab('curriculum'); addLesson(subj.id, ss.id); }} className="text-[9px] text-slate-600 hover:text-indigo-400" title="Add unit to this sub-group"><i className="fas fa-plus"></i></button>
                               <button onClick={() => { if (contextSubSubjectId === ss.id) setContextSubSubjectId(null); const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects = subjs[sIdx].subSubjects.filter(item => item.id !== ss.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                             </div>
                           ))}
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      {isAiModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-lg rounded-[40px] border border-slate-800 p-10 space-y-8 shadow-2xl animate-in zoom-in-95">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-black text-white tracking-tight">AI Architect</h2>
              <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Describe your vision for the course</p>
            </div>
            <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="e.g. Master React and TypeScript with modern architecture..." className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-200 min-h-[120px] focus:border-indigo-500/50 transition-all outline-none" />
            <div className="flex space-x-4">
              <button onClick={() => setIsAiModalOpen(false)} className="flex-1 py-5 bg-slate-950 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest border border-slate-800">Cancel</button>
              <button onClick={handleAiGenerate} disabled={!aiPrompt.trim() || isGenerating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl disabled:opacity-50 flex items-center justify-center space-x-3">
                {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-sparkles"></i>}
                <span>{isGenerating ? 'Synthesizing...' : 'Build Syllabus'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="flex-1 md:flex-none px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ title: '', lessons: [], subjects: [] }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-6">
                    <img src={course.thumbnail} className="w-16 h-10 rounded-xl object-cover opacity-80 group-hover:opacity-100 transition-opacity border border-slate-800 shadow-inner" alt="" />
                    <div>
                      <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                      <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useRef } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  const activeLessonIndex = course.lessons.findIndex(l => l.id === activeLessonId);
  const activeLesson = course.lessons[activeLessonIndex] || course.lessons[0];

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    if (initialLessonId) {
      setActiveLessonId(initialLessonId);
    }
  }, [initialLessonId]);

  useEffect(() => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
    if (videoRef.current) videoRef.current.load();
  }, [activeLessonId]);

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
    }
  };

  const isAdmin = user.role === 'admin';

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center space-x-3">
            <button onClick={onBack} className="w-9 h-9 rounded-lg bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <h2 className="text-xs font-black text-slate-500 uppercase tracking-widest">{course.title}</h2>
              <p className="text-sm font-bold text-white truncate max-w-[200px]">{activeLesson.title}</p>
            </div>
          </div>
          <button 
            onClick={() => setIsAiOpen(!isAiOpen)} 
            className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${isAiOpen ? 'bg-indigo-600 text-white' : 'bg-slate-900 text-slate-500 border border-slate-800'}`}
          >
            <i className="fas fa-robot mr-2"></i>AI
          </button>
        </nav>

        <div className="flex-1 p-4 md:p-10 max-w-5xl mx-auto w-full space-y-8">
          {activeLesson.videoUrl ? (
            <div className="bg-black rounded-2xl md:rounded-3xl overflow-hidden aspect-video border border-slate-800 shadow-2xl relative group">
              <video ref={videoRef} src={activeLesson.videoUrl} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-slate-900/50 rounded-2xl md:rounded-3xl border border-dashed border-slate-800 py-16 flex flex-col items-center justify-center text-center">
              <div className="w-16 h-16 bg-indigo-600/10 text-indigo-400 rounded-2xl flex items-center justify-center text-2xl mb-4 border border-indigo-600/20 shadow-inner">
                <i className="fas fa-book-open"></i>
              </div>
              <h3 className="text-xl font-black text-white">Reading Material</h3>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mt-1">This module is focused on text content</p>
            </div>
          )}

          <div className="flex border-b border-slate-800 space-x-6 overflow-x-auto no-scrollbar">
            <button onClick={() => setActiveTab('overview')} className={`pb-3 whitespace-nowrap text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}>Overview</button>
            {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={() => setActiveTab('quiz')} className={`pb-3 whitespace-nowrap text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}>Quiz</button>}
            {isAdmin && activeLesson.instructorNotes && <button onClick={() => setActiveTab('notes')} className={`pb-3 whitespace-nowrap text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'notes' ? 'text-emerald-400 border-emerald-500' : 'text-slate-600 border-transparent'}`}>Instructor Notes</button>}
          </div>

          <div className="min-h-[300px] pb-20 md:pb-0">
            {activeTab === 'overview' && (
              <div className="animate-in fade-in duration-300">
                <div className="prose prose-invert max-w-none text-slate-300 leading-relaxed" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                {activeLesson.resources && activeLesson.resources.length > 0 && (
                  <div className="mt-12 space-y-4 pt-8 border-t border-slate-800">
                    <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Supplemental Materials</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                      {activeLesson.resources.map(res => (
                        <a key={res.id} href={res.url} target="_blank" rel="noopener noreferrer" className="flex items-center p-4 bg-slate-900 border border-slate-800 rounded-xl hover:border-indigo-500/50 transition-all group">
                          <div className="w-8 h-8 rounded-lg bg-slate-950 flex items-center justify-center text-xs text-indigo-400 mr-3 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                            <i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play' : res.type === 'zip' ? 'fa-file-zipper' : 'fa-link'}`}></i>
                          </div>
                          <span className="text-xs font-bold text-slate-200">{res.title}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-6 max-w-xl animate-in fade-in duration-300">
                {quizState.complete ? (
                  <div className="p-10 bg-slate-900 border border-slate-800 rounded-3xl text-center shadow-xl">
                    <div className="w-20 h-20 bg-emerald-500/10 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6 text-3xl border border-emerald-500/20">
                      <i className="fas fa-award"></i>
                    </div>
                    <h3 className="text-2xl font-black text-white mb-2">Completion Achieved</h3>
                    <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mb-6">Score: {quizState.score}/{activeLesson.quiz.length}</p>
                    <button onClick={() => setActiveTab('overview')} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-600/20">Resume Study</button>
                  </div>
                ) : (
                  <div className="space-y-6">
                    <div className="flex justify-between items-center">
                      <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Question {quizState.currentIdx + 1} of {activeLesson.quiz.length}</p>
                    </div>
                    <h4 className="text-xl md:text-2xl font-black text-white leading-tight">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-4 pt-4">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button key={i} onClick={() => handleQuizAnswer(i)} className="w-full p-5 bg-slate-900 border border-slate-800 rounded-2xl text-left hover:border-indigo-500 hover:bg-slate-800/50 transition-all font-bold text-sm text-slate-200">{opt}</button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'notes' && isAdmin && (
              <div className="animate-in slide-in-from-top-4 duration-300 p-8 bg-emerald-500/5 border border-emerald-500/20 rounded-3xl">
                <div className="flex items-center space-x-3 mb-6">
                  <div className="w-10 h-10 bg-emerald-500/10 text-emerald-400 rounded-xl flex items-center justify-center border border-emerald-500/20 shadow-inner">
                    <i className="fas fa-clipboard-check"></i>
                  </div>
                  <h3 className="text-lg font-black text-emerald-400 uppercase tracking-widest">Instructor Guidance</h3>
                </div>
                <div className="text-emerald-200/80 leading-relaxed text-sm italic whitespace-pre-wrap">
                  {activeLesson.instructorNotes}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer Navigation */}
        <div className="mt-auto p-4 md:p-6 border-t border-slate-800 bg-slate-950/50 flex justify-between items-center sticky bottom-0 z-30 shadow-[0_-10px_30px_rgba(0,0,0,0.5)]">
          <button disabled={activeLessonIndex === 0} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex - 1].id)} className="px-5 py-2.5 bg-slate-900 border border-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest disabled:opacity-20 hover:text-white transition-all"><i className="fas fa-chevron-left mr-2"></i>Prev</button>
          <div className="flex space-x-2 overflow-x-auto px-2 max-w-[150px] no-scrollbar">
            {course.lessons.map(l => (
              <div key={l.id} className={`w-2 h-2 rounded-full flex-shrink-0 transition-all duration-500 ${l.id === activeLessonId ? 'bg-indigo-500 w-6 shadow-[0_0_10px_rgba(99,102,241,0.5)]' : 'bg-slate-800'}`}></div>
            ))}
          </div>
          <button disabled={activeLessonIndex === course.lessons.length - 1} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex + 1].id)} className="px-5 py-2.5 bg-indigo-600 border border-indigo-500/20 rounded-xl text-[10px] font-black uppercase tracking-widest disabled:opacity-20 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-600/20 text-white">Next<i className="fas fa-chevron-right ml-2"></i></button>
        </div>
      </div>

      {/* AI Panel */}
      <aside className={`fixed lg:relative bottom-0 right-0 w-full lg:w-[400px] h-[80vh] lg:h-full bg-slate-950 border-t lg:border-t-0 lg:border-l border-slate-800 z-[40] transition-transform duration-300 transform ${isAiOpen ? 'translate-y-0 lg:translate-x-0' : 'translate-y-full lg:translate-x-full lg:hidden'}`}>
        <div className="flex flex-col h-full relative">
          <button onClick={() => setIsAiOpen(false)} className="lg:hidden absolute top-4 right-4 z-50 text-slate-500 text-lg p-2"><i className="fas fa-times"></i></button>
          <AIAssistant course={course} lesson={activeLesson} user={user} />
        </div>
      </aside>
    </div>
  );
};

export default CourseView;

import React, { useState, useEffect, useMemo } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Resource, QuizQuestion } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-500 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const RESOURCE_TYPES = ['link', 'pdf', 'video', 'zip'];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const [expandedLessonId, setExpandedLessonId] = useState<string | null>(null);

  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);

  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);
  const [iconSearchTerm, setIconSearchTerm] = useState('');

  // Auto-save & Restore logic
  const [hasDraft, setHasDraft] = useState(false);
  const [draftData, setDraftData] = useState<Partial<Course> | null>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  // Draft Detection Effect
  useEffect(() => {
    if (isEditing && currentCourse) {
      const draftKey = `eduworld_draft_${currentCourse.id || 'new'}`;
      const saved = localStorage.getItem(draftKey);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          // Check if it's truly different from current server/base state
          if (JSON.stringify(parsed) !== JSON.stringify(currentCourse)) {
            setDraftData(parsed);
            setHasDraft(true);
          }
        } catch (e) {
          console.error("Failed to parse draft", e);
        }
      }
    } else {
      setHasDraft(false);
      setDraftData(null);
    }
  }, [isEditing, currentCourse?.id]);

  // Auto-Save Effect
  useEffect(() => {
    if (isEditing && currentCourse) {
      const draftKey = `eduworld_draft_${currentCourse.id || 'new'}`;
      localStorage.setItem(draftKey, JSON.stringify(currentCourse));
    }
  }, [currentCourse, isEditing]);

  const filteredIcons = useMemo(() => {
    return ICON_OPTIONS.filter(icon => icon.toLowerCase().includes(iconSearchTerm.toLowerCase()));
  }, [iconSearchTerm]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed. Check your API link.");
    } finally {
      setIsGenerating(false);
    }
  };

  const clearDraft = () => {
    const draftKey = `eduworld_draft_${currentCourse?.id || 'new'}`;
    localStorage.removeItem(draftKey);
    setHasDraft(false);
    setDraftData(null);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;
    if (currentCourse.id) {
      onUpdateCourse(currentCourse as Course);
    } else {
      onAddCourse(currentCourse as Course);
    }
    clearDraft();
    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleDiscard = () => {
    if (confirm("Discard all changes? Unsaved progress will be lost.")) {
      clearDraft();
      setIsEditing(false);
      setCurrentCourse(null);
    }
  };

  const addLesson = (subjId?: string, subSubjId?: string) => {
    const newId = Math.random().toString(36).substr(2, 9);
    const sId = subjId || contextSubjectId || undefined;
    const ssId = subSubjId || contextSubSubjectId || undefined;

    const newLesson: Lesson = { 
      id: newId, 
      title: 'New Module', 
      content: '<h1>Module Content</h1><p>Start typing here...</p>', 
      duration: '15:00',
      subjectId: sId,
      subSubjectId: ssId,
      hasAiFeature: true,
      resources: [],
      quiz: []
    };

    setCurrentCourse(prev => {
      if (!prev) return prev;
      return {
        ...prev, 
        lessons: [...(prev.lessons || []), newLesson] 
      };
    });
    setExpandedLessonId(newId);
  };

  const updateLessonField = (idx: number, field: keyof Lesson, value: any) => {
    const lessons = [...(currentCourse!.lessons || [])];
    lessons[idx] = { ...lessons[idx], [field]: value };
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addResource = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newResource: Resource = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Resource',
      url: '',
      type: 'link'
    };
    lessons[lessonIdx].resources = [...(lessons[lessonIdx].resources || []), newResource];
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addQuizQuestion = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newQuestion: QuizQuestion = {
      id: Math.random().toString(36).substr(2, 9),
      question: 'New Question?',
      options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
      correctAnswer: 0
    };
    lessons[lessonIdx].quiz = [...(lessons[lessonIdx].quiz || []), newQuestion];
    setCurrentCourse({ ...currentCourse!, lessons });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Group',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const updatedSubjects = currentCourse!.subjects!.map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group' }]
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  if (isEditing && currentCourse) {
    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">
        <div className="flex items-center justify-between">
          <button onClick={handleDiscard} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Discard Changes</span>
          </button>
          <div className="flex items-center space-x-4">
            <span className="text-[8px] font-black text-slate-600 uppercase tracking-widest animate-pulse">Auto-saving...</span>
            <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
          </div>
        </div>

        {hasDraft && (
          <div className="bg-indigo-600/10 border border-indigo-500/30 rounded-2xl p-5 flex items-center justify-between animate-in slide-in-from-top-2">
            <div className="flex items-center space-x-4">
              <div className="w-10 h-10 bg-indigo-600/20 rounded-xl flex items-center justify-center text-indigo-400">
                <i className="fas fa-history"></i>
              </div>
              <div>
                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Syllabus Recovery</p>
                <p className="text-xs text-slate-300 font-medium">Unsaved progress from your last session was detected for this course.</p>
              </div>
            </div>
            <div className="flex space-x-3">
              <button 
                onClick={() => {
                  const draftKey = `eduworld_draft_${currentCourse?.id || 'new'}`;
                  localStorage.removeItem(draftKey);
                  setHasDraft(false);
                }} 
                className="px-4 py-2 text-[9px] font-black text-slate-500 uppercase tracking-widest hover:text-rose-500 transition-colors"
              >
                Clear Draft
              </button>
              <button 
                onClick={() => {
                  if (draftData) setCurrentCourse(draftData);
                  setHasDraft(false);
                }} 
                className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg shadow-indigo-600/20"
              >
                Restore Changes
              </button>
            </div>
          </div>
        )}

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab as any)} 
                className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}
              >
                {tab}
              </button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({...currentCourse!, title: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                    <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({...currentCourse!, category: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Price ($)</label>
                    <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({...currentCourse!, price: parseFloat(e.target.value)})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Overview</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({...currentCourse!, description: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <div>
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Lesson Units</h3>
                    {contextSubjectId && (
                      <p className="text-[8px] text-indigo-400 font-bold mt-1 uppercase tracking-widest">
                        Context: {currentCourse.subjects?.find(s => s.id === contextSubjectId)?.name} 
                        {contextSubSubjectId && ` / ${currentCourse.subjects?.find(s => s.id === contextSubjectId)?.subSubjects.find(ss => ss.id === contextSubSubjectId)?.name}`}
                      </p>
                    )}
                  </div>
                  <button type="button" onClick={() => addLesson()} className="px-5 py-2 bg-slate-950 border border-slate-800 text-indigo-400 rounded-xl text-[9px] font-black uppercase tracking-widest hover:border-indigo-500/50 transition-all">+ Unit</button>
                </div>

                <div className="space-y-4">
                  {(currentCourse.lessons || []).map((lesson, lessonIdx) => {
                    const isExpanded = expandedLessonId === lesson.id;
                    const isVideo = !!lesson.videoUrl;

                    return (
                      <div key={lesson.id} className={`bg-slate-950 border rounded-2xl overflow-hidden transition-all duration-300 ${isExpanded ? 'border-indigo-500/50 shadow-lg' : 'border-slate-800'}`}>
                        <div 
                          className="flex items-center px-6 py-4 cursor-pointer hover:bg-slate-900/40 transition-colors"
                          onClick={() => setExpandedLessonId(isExpanded ? null : lesson.id)}
                        >
                          <span className="text-[10px] font-black text-slate-700 w-8">{lessonIdx + 1}</span>
                          <span className="flex-1 font-bold text-slate-200 text-sm">{lesson.title || 'Untitled Lesson'}</span>
                          <div className="flex items-center space-x-6">
                            <div className="flex items-center space-x-2 text-[9px] font-black text-slate-600 uppercase tracking-widest">
                              <i className={`fas ${isVideo ? 'fa-play-circle text-indigo-400' : 'fa-file-lines text-emerald-400'} text-[10px]`}></i>
                              <span>{isVideo ? 'Video' : 'Reading'}</span>
                              <span className="opacity-30">•</span>
                              <span>{lesson.duration || '00:00'}</span>
                            </div>
                            {lesson.subjectId && (
                              <span className="text-[8px] font-black text-indigo-400/60 uppercase tracking-widest bg-indigo-500/5 px-2 py-1 rounded border border-indigo-500/10">
                                {currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.name}
                              </span>
                            )}
                            <i className={`fas fa-chevron-${isExpanded ? 'up' : 'down'} text-[10px] text-slate-700`}></i>
                          </div>
                        </div>

                        {isExpanded && (
                          <div className="px-8 pb-8 pt-4 space-y-8 border-t border-slate-900 bg-slate-900/20 animate-in slide-in-from-top-4 duration-300">
                            <div className="space-y-6">
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Lesson Title</label>
                                  <input 
                                    type="text" 
                                    value={lesson.title} 
                                    onChange={e => updateLessonField(lessonIdx, 'title', e.target.value)} 
                                    className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white font-bold" 
                                  />
                                </div>
                                <div className="space-y-2">
                                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Duration (e.g. 15:00)</label>
                                  <input 
                                    type="text" 
                                    value={lesson.duration} 
                                    onChange={e => updateLessonField(lessonIdx, 'duration', e.target.value)} 
                                    className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-white" 
                                  />
                                </div>
                              </div>

                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Video Source URL (Leave empty for Text Lesson)</label>
                                <input 
                                  type="text" 
                                  value={lesson.videoUrl || ''} 
                                  onChange={e => updateLessonField(lessonIdx, 'videoUrl', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-sm text-slate-400 font-mono"
                                  placeholder="https://..."
                                />
                              </div>

                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Lesson Body (HTML Content)</label>
                                <textarea 
                                  rows={8} 
                                  value={lesson.content} 
                                  onChange={e => updateLessonField(lessonIdx, 'content', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-4 py-4 text-xs text-slate-300 leading-relaxed font-mono"
                                  placeholder="<h1>Lesson Header</h1><p>Body text...</p>"
                                />
                              </div>

                              <div className="space-y-2 p-4 bg-indigo-500/5 rounded-2xl border border-indigo-500/10">
                                <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest">Internal Instructor Notes (Invisible to Students)</label>
                                <textarea 
                                  rows={4} 
                                  value={lesson.instructorNotes || ''} 
                                  onChange={e => updateLessonField(lessonIdx, 'instructorNotes', e.target.value)} 
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-4 text-xs text-indigo-200/80 leading-relaxed font-medium italic"
                                  placeholder="Strategy notes for this lesson..."
                                />
                              </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4 border-t border-slate-800/50">
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Parent Subject</label>
                                <select 
                                  value={lesson.subjectId || ''} 
                                  onChange={e => {
                                    updateLessonField(lessonIdx, 'subjectId', e.target.value);
                                    updateLessonField(lessonIdx, 'subSubjectId', undefined);
                                  }}
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest text-slate-400"
                                >
                                  <option value="">Unassigned</option>
                                  {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                                </select>
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Sub-Unit Category</label>
                                <select 
                                  value={lesson.subSubjectId || ''} 
                                  disabled={!lesson.subjectId}
                                  onChange={e => updateLessonField(lessonIdx, 'subSubjectId', e.target.value)}
                                  className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest text-slate-400 disabled:opacity-20"
                                >
                                  <option value="">No Sub-Group</option>
                                  {currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.subSubjects.map(ss => (
                                    <option key={ss.id} value={ss.id}>{ss.name}</option>
                                  ))}
                                </select>
                              </div>
                            </div>

                            <div className="space-y-4 pt-4 border-t border-slate-800/50">
                              <div className="flex justify-between items-center">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Resource Hub</h4>
                                <button type="button" onClick={() => addResource(lessonIdx)} className="text-[9px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Resource</button>
                              </div>
                              <div className="grid grid-cols-1 gap-3">
                                {(lesson.resources || []).map((res, resIdx) => (
                                  <div key={res.id} className="bg-slate-950/50 border border-slate-800 rounded-xl p-4 space-y-3">
                                    <div className="flex gap-4">
                                      <div className="flex-1 space-y-2">
                                        <input type="text" value={res.title} onChange={e => { const r = [...(lesson.resources || [])]; r[resIdx].title = e.target.value; updateLessonField(lessonIdx, 'resources', r); }} placeholder="Title" className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-1.5 text-xs text-white" />
                                        <input type="text" value={res.url} onChange={e => { const r = [...(lesson.resources || [])]; r[resIdx].url = e.target.value; updateLessonField(lessonIdx, 'resources', r); }} placeholder="URL" className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-1.5 text-[10px] text-slate-400 font-mono" />
                                      </div>
                                      <div className="w-24 space-y-2">
