            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="flex-1 md:flex-none px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ title: '', lessons: [], subjects: [] }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-6">
                    <img src={course.thumbnail} className="w-16 h-10 rounded-xl object-cover opacity-80 group-hover:opacity-100 transition-opacity border border-slate-800 shadow-inner" alt="" />
                    <div>
                      <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                      <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

