    { icon: 'fa-sparkles', text: 'AI Tutoring' },
    { icon: 'fa-file-pdf', text: 'Study Materials' },
    { icon: 'fa-infinity', text: 'Lifetime Access' },
    { icon: 'fa-certificate', text: 'Certification' },
  ];

  const getLessonsForSubSubject = (subjectId: string, subSubjectId: string) => {
    return course.lessons.filter(l => l.subjectId === subjectId && l.subSubjectId === subSubjectId);
