                            <div className="space-y-4 pt-4 border-t border-slate-800/50">
                              <div className="flex justify-between items-center">
                                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Resource Hub</h4>
                                <button type="button" onClick={() => addResource(lessonIdx)} className="text-[9px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Resource</button>
                              </div>
                              <div className="grid grid-cols-1 gap-3">
                                {(lesson.resources || []).map((res, resIdx) => (
                                  <div key={res.id} className="bg-slate-950/50 border border-slate-800 rounded-xl p-4 space-y-3">
                                    <div className="flex gap-4">
