                                        <input type="text" value={res.title} onChange={e => { const r = [...(lesson.resources || [])]; r[resIdx].title = e.target.value; updateLesson(lessonIdx, { resources: r }); }} placeholder="Title" className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-1.5 text-xs text-white" />
