                                      <textarea value={q.question} onChange={e => { const quiz = [...(lesson.quiz || [])]; quiz[qIdx].question = e.target.value; updateLesson(lessonIdx, { quiz }); }} rows={2} placeholder="Question..." className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-sm text-white font-bold" />
                                      <button onClick={() => { const quiz = (lesson.quiz || []).filter(item => item.id !== q.id); updateLesson(lessonIdx, { quiz }); }} className="text-slate-800 hover:text-rose-500 h-10 w-10 flex items-center justify-center border border-slate-800 rounded-xl"><i className="fas fa-trash"></i></button>
