                        </div>
                      </div>
                      <i className={`fas fa-chevron-${showQuiz ? 'up' : 'down'} text-slate-600`}></i>
                    </button>
                    {showQuiz && (
                      <div className="p-8 pt-0 space-y-6 border-t border-slate-800/50 animate-in slide-in-from-top-2">
                        {(currentLesson.quiz || []).map((q, qIdx) => (
                          <div key={q.id} className="bg-slate-950 border border-slate-800 rounded-[24px] p-6 space-y-6">
                            <div className="flex justify-between items-start gap-4">
                              <textarea rows={2} value={q.question} onChange={e => { const qz = [...currentLesson.quiz!]; qz[qIdx].question = e.target.value; updateLesson(editingLessonIdx!, { quiz: qz }); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-sm text-white font-bold" placeholder="Inquiry phrasing..." />
                              <button onClick={() => { const qz = currentLesson.quiz!.filter(item => item.id !== q.id); updateLesson(editingLessonIdx!, { quiz: qz }); }} className="w-10 h-10 bg-slate-900 rounded-xl text-slate-700 hover:text-rose-500 flex items-center justify-center border border-slate-800"><i className="fas fa-trash"></i></button>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              {q.options.map((opt, optIdx) => (
                                <div key={optIdx} className="flex items-center space-x-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800 transition-all group focus-within:border-indigo-500/30">
                                  <input type="radio" name={`correct-${q.id}`} checked={q.correctAnswer === optIdx} onChange={() => { const qz = [...currentLesson.quiz!]; qz[qIdx].correctAnswer = optIdx; updateLesson(editingLessonIdx!, { quiz: qz }); }} className="accent-indigo-500 w-4 h-4" />
                                  <input type="text" value={opt} onChange={e => { const qz = [...currentLesson.quiz!]; qz[qIdx].options[optIdx] = e.target.value; updateLesson(editingLessonIdx!, { quiz: qz }); }} className="flex-1 bg-transparent border-none text-xs text-slate-200 focus:ring-0 font-medium" />
                                </div>
                              ))}
                            </div>
                          </div>
                        ))}
                        <button onClick={() => addQuizQuestion(editingLessonIdx!)} className="w-full py-4 border-2 border-dashed border-slate-800 rounded-2xl text-[10px] font-black text-slate-600 uppercase tracking-widest hover:border-emerald-500/50 hover:text-emerald-400 transition-all">+ Forge New Inquiry</button>
                      </div>
                    )}
                  </div>
                </div>

                {/* Sidebar Meta Info */}
                <div className="lg:col-span-4 space-y-8">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-8">
                    <div className="space-y-4">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Metadata Anchor</h3>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Parent Subject</label>
                          <select 
                            value={currentLesson.subjectId || ''} 
                            onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value || undefined, subSubjectId: undefined })}
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400"
                          >
                            <option value="">Unassigned</option>
                            {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                          </select>
                       </div>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Sub-Unit Category</label>
                          <select 
                            value={currentLesson.subSubjectId || ''} 
                            disabled={!currentLesson.subjectId}
                            onChange={e => updateLesson(editingLessonIdx!, { subSubjectId: e.target.value || undefined })}
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 disabled:opacity-20"
                          >
                            <option value="">No Specific Group</option>
                            {currentCourse.subjects?.find(s => s.id === currentLesson.subjectId)?.subSubjects.map(ss => (
                              <option key={ss.id} value={ss.id}>{ss.name}</option>
                            ))}
                          </select>
                       </div>
                    </div>

                    <div className="pt-8 border-t border-slate-800 space-y-4">
                      <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Advanced Protocols</h3>
                      <label className="flex items-center justify-between p-4 bg-slate-950 rounded-2xl border border-slate-800 cursor-pointer group">
                        <span className="text-[9px] font-black text-slate-400 group-hover:text-indigo-400 uppercase tracking-widest transition-colors">AI Neural Features</span>
                        <div onClick={() => updateLesson(editingLessonIdx!, { hasAiFeature: !currentLesson.hasAiFeature })} className={`w-10 h-5 rounded-full relative transition-all ${currentLesson.hasAiFeature ? 'bg-indigo-600 shadow-[0_0_10px_rgba(79,70,229,0.5)]' : 'bg-slate-800'}`}>
                          <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all ${currentLesson.hasAiFeature ? 'left-6' : 'left-1'}`}></div>
                        </div>
                      </label>
                    </div>

                    <div className="pt-8 border-t border-slate-800 space-y-4">
                      <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Internal Instructor Ledger</h3>
                      <textarea 
                        rows={6} 
                        value={currentLesson.instructorNotes || ''} 
                        onChange={e => updateLesson(editingLessonIdx!, { instructorNotes: e.target.value })} 
                        className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 text-xs text-indigo-200/60 leading-relaxed italic"
                        placeholder="Pedagogical strategies and notes for this unit..."
                      />
                    </div>

                    <button onClick={() => { if (confirm('Purge this entire module?')) { const l = currentCourse.lessons!.filter((_, i) => i !== editingLessonIdx); setCurrentCourse({...currentCourse, lessons: l}); setEditingLessonIdx(null); } }} className="w-full py-4 bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all">Delete Module</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between">
          <button onClick={handleDiscard} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Discard Changes</span>
          </button>
          <div className="flex items-center space-x-4">
            <span className="text-[8px] font-black text-slate-600 uppercase tracking-widest animate-pulse">Auto-saving...</span>
            <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
          </div>
        </div>

        {hasDraft && !isEditingLesson && (
          <div className="bg-indigo-600/10 border border-indigo-500/30 rounded-2xl p-5 flex items-center justify-between animate-in slide-in-from-top-2">
            <div className="flex items-center space-x-4">
              <div className="w-10 h-10 bg-indigo-600/20 rounded-xl flex items-center justify-center text-indigo-400">
                <i className="fas fa-history"></i>
              </div>
              <div>
                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Syllabus Recovery</p>
                <p className="text-xs text-slate-300 font-medium">Unsaved progress from your last session was detected for this course.</p>
              </div>
            </div>
            <div className="flex space-x-3">
              <button 
                onClick={() => {
                  const draftKey = `eduworld_draft_${currentCourse?.id || 'new'}`;
                  localStorage.removeItem(draftKey);
                  setHasDraft(false);
                }} 
                className="px-4 py-2 text-[9px] font-black text-slate-500 uppercase tracking-widest hover:text-rose-500 transition-colors"
              >
                Clear Draft
              </button>
              <button 
                onClick={() => {
                  if (draftData) setCurrentCourse(draftData);
                  setHasDraft(false);
                }} 
                className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg shadow-indigo-600/20"
              >
                Restore Changes
              </button>
            </div>
          </div>
        )}

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab as any)} 
                className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}
              >
                {tab}
              </button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({...currentCourse!, title: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Syllabus Category</label>
                    <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({...currentCourse!, category: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Tuition ($)</label>
                    <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({...currentCourse!, price: parseFloat(e.target.value)})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Academic Overview</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({...currentCourse!, description: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in">
                <div className="flex justify-between items-center mb-6">
                  <div>
                    <h3 className="text-xl font-black text-white tracking-tight">Academic Unit Registry</h3>
                    <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-1">Total: {currentCourse.lessons?.length || 0} Modules recorded</p>
                  </div>
                  <button type="button" onClick={() => addLesson()} className="px-6 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20">+ Add New Module</button>
                </div>

                <div className="space-y-3">
                  {(currentCourse.lessons || []).map((lesson, lessonIdx) => {
                    const isVideo = !!lesson.videoUrl;
                    const subjectName = currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.name;

                    return (
                      <div 
                        key={lesson.id} 
                        className="group bg-slate-950/50 border border-slate-800 rounded-2xl p-5 flex items-center justify-between hover:border-indigo-500/30 hover:bg-slate-900 transition-all shadow-sm"
                      >
                        <div className="flex items-center space-x-6 overflow-hidden">
                          <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-lg border transition-all ${isVideo ? 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20' : 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'}`}>
                             <i className={`fas ${isVideo ? 'fa-play-circle' : 'fa-file-text'}`}></i>
                          </div>
                          <div className="truncate">
                             <h4 className="font-bold text-slate-100 truncate group-hover:text-white transition-colors">{lesson.title}</h4>
                             <div className="flex items-center space-x-4 mt-1">
                                <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration || '00:00'}</span>
                                {subjectName && (
                                   <span className="text-[9px] font-black text-indigo-400/60 uppercase tracking-widest bg-indigo-500/5 px-2 py-0.5 rounded border border-indigo-500/10 truncate max-w-[150px]">
                                      {subjectName}
                                   </span>
                                )}
                             </div>
                          </div>
                        </div>
                        <div className="flex items-center space-x-3 ml-4">
                           <button 
                             onClick={() => setEditingLessonIdx(lessonIdx)}
                             className="px-4 py-2 bg-slate-900 border border-slate-800 text-[9px] font-black text-slate-500 uppercase tracking-widest rounded-lg hover:text-white hover:border-indigo-500/50 transition-all"
                           >
                             Edit Module
                           </button>
                           <button 
                             onClick={() => { if (confirm('Purge this unit?')) { const l = currentCourse.lessons!.filter((_, i) => i !== lessonIdx); setCurrentCourse({...currentCourse, lessons: l}); } }}
                             className="w-10 h-10 bg-slate-950 rounded-lg text-slate-800 hover:text-rose-500 flex items-center justify-center border border-slate-800"
                           >
                             <i className="fas fa-trash-alt text-sm"></i>
                           </button>
                        </div>
                      </div>
                    );
                  })}
                  {(!currentCourse.lessons || currentCourse.lessons.length === 0) && (
                    <div className="py-20 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-[32px] text-center opacity-40">
                       <i className="fas fa-cubes text-4xl mb-4 text-slate-700"></i>
                       <h4 className="text-xl font-black text-white">Registry Empty</h4>
                       <p className="text-xs font-bold text-slate-500 mt-2">Initialize your first teaching unit above</p>
                    </div>
                  )}
                </div>
              </div>
            )}

            {activeTab === 'structure' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Subject Architecture</h3>
                  <button type="button" onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">+ Subject Group</button>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {(currentCourse.subjects || []).map((subj, sIdx) => (
                    <div key={subj.id} className={`bg-slate-950 border rounded-[32px] p-8 space-y-6 transition-all ${contextSubjectId === subj.id ? 'border-indigo-500 shadow-[0_0_30px_rgba(79,70,229,0.1)]' : 'border-slate-800'}`}>
                      <div className="flex flex-wrap items-center gap-4 relative">
                        <div className="relative">
                          <button onClick={() => { setIconPickerOpenId(iconPickerOpenId === subj.id ? null : subj.id); setIconSearchTerm(''); }} className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl transition-transform hover:scale-105 shadow-inner border border-white/5 ${subj.color}`}>
                            <i className={`fas ${subj.icon}`}></i>
                          </button>
                          {iconPickerOpenId === subj.id && (
                            <div className="absolute top-14 left-0 z-50 w-72 bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl p-4 animate-in fade-in zoom-in-95">
                              <div className="flex items-center space-x-2 bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 mb-4">
                                <i className="fas fa-search text-[10px] text-slate-600"></i>
                                <input type="text" autoFocus placeholder="Search icon..." value={iconSearchTerm} onChange={(e) => setIconSearchTerm(e.target.value)} className="w-full bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-200 p-0" />
                              </div>
                              <div className="grid grid-cols-6 gap-2 max-h-48 overflow-y-auto no-scrollbar pr-1">
                                {filteredIcons.map((icon) => (
                                  <button key={icon} onClick={() => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].icon = icon; setCurrentCourse({...currentCourse!, subjects: subjs}); setIconPickerOpenId(null); }} className={`w-8 h-8 rounded-lg flex items-center justify-center text-sm transition-all border ${subj.icon === icon ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-950 text-slate-500 border-slate-800 hover:border-indigo-500/50 hover:text-indigo-400'}`}>
                                    <i className={`fas ${icon}`}></i>
                                  </button>
                                ))}
                              </div>
                            </div>
                          )}
                        </div>

                        <div className="flex-1 min-w-[200px] space-y-4">
                          <input type="text" value={subj.name} onFocus={() => { setContextSubjectId(subj.id); setContextSubSubjectId(null); }} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" placeholder="Subject Name" />
                          <div className="flex items-center space-x-3">
                            <select value={subj.color} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].color = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500">
                              {COLOR_PRESETS.map((c, i) => <option key={i} value={c}>Theme {i+1}</option>)}
                            </select>
                            <button onClick={() => { setContextSubjectId(subj.id); setContextSubSubjectId(null); setActiveTab('curriculum'); addLesson(subj.id); }} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest flex items-center">
                              <i className="fas fa-plus mr-1"></i> Add Unit Here
                            </button>
                          </div>
                        </div>
                        <button onClick={() => { if (contextSubjectId === subj.id) setContextSubjectId(null); const subjs = currentCourse!.subjects!.filter(s => s.id !== subj.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>

                      <div className="pl-12 space-y-3">
                         <div className="flex justify-between items-center">
                            <h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4>
                            <button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Sub</button>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                           {(subj.subSubjects || []).map((ss, ssIdx) => (
                             <div key={ss.id} className={`flex items-center space-x-2 rounded-lg px-3 py-2 border transition-all ${contextSubSubjectId === ss.id ? 'bg-indigo-600/10 border-indigo-500/40' : 'bg-slate-900 border-slate-800'}`}>
                               <input type="text" value={ss.name} onFocus={() => { setContextSubjectId(subj.id); setContextSubSubjectId(ss.id); }} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects[ssIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-300" />
                               <button onClick={() => { setContextSubjectId(subj.id); setContextSubSubjectId(ss.id); setActiveTab('curriculum'); addLesson(subj.id, ss.id); }} className="text-[9px] text-slate-600 hover:text-indigo-400" title="Add unit to this sub-group"><i className="fas fa-plus"></i></button>
                               <button onClick={() => { if (contextSubSubjectId === ss.id) setContextSubSubjectId(null); const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects = subjs[sIdx].subSubjects.filter(item => item.id !== ss.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                             </div>
                           ))}
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      {isAiModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-lg rounded-[40px] border border-slate-800 p-10 space-y-8 shadow-2xl animate-in zoom-in-95">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-black text-white tracking-tight">AI Architect</h2>
              <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Describe your vision for the course</p>
            </div>
            <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="e.g. Master React and TypeScript with modern architecture..." className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-200 min-h-[120px] focus:border-indigo-500/50 transition-all outline-none" />
            <div className="flex space-x-4">
              <button onClick={() => setIsAiModalOpen(false)} className="flex-1 py-5 bg-slate-950 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest border border-slate-800">Cancel</button>
              <button onClick={handleAiGenerate} disabled={!aiPrompt.trim() || isGenerating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl disabled:opacity-50 flex items-center justify-center space-x-3">
                {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-sparkles"></i>}
                <span>{isGenerating ? 'Synthesizing...' : 'Build Syllabus'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="flex-1 md:flex-none px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ title: '', lessons: [], subjects: [] }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-6">
                    <img src={course.thumbnail} className="w-16 h-10 rounded-xl object-cover opacity-80 group-hover:opacity-100 transition-opacity border border-slate-800 shadow-inner" alt="" />
                    <div>
                      <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                      <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Resource, QuizQuestion } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-500 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const RESOURCE_TYPES = ['link', 'pdf', 'video', 'zip'];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  // Lesson Editing Detail View
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [showResources, setShowResources] = useState(false);
  const [showQuiz, setShowQuiz] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  const videoInputRef = useRef<HTMLInputElement>(null);
  const resourceFileRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);

  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);
  const [iconSearchTerm, setIconSearchTerm] = useState('');

  // Auto-save & Restore logic
  const [hasDraft, setHasDraft] = useState(false);
  const [draftData, setDraftData] = useState<Partial<Course> | null>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  useEffect(() => {
    if (isEditing && currentCourse) {
      const draftKey = `eduworld_draft_${currentCourse.id || 'new'}`;
      const saved = localStorage.getItem(draftKey);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          if (JSON.stringify(parsed) !== JSON.stringify(currentCourse)) {
            setDraftData(parsed);
            setHasDraft(true);
          }
        } catch (e) {
          console.error("Failed to parse draft", e);
        }
      }
    } else {
      setHasDraft(false);
      setDraftData(null);
    }
  }, [isEditing, currentCourse?.id]);

  useEffect(() => {
    if (isEditing && currentCourse) {
      const draftKey = `eduworld_draft_${currentCourse.id || 'new'}`;
      localStorage.setItem(draftKey, JSON.stringify(currentCourse));
    }
  }, [currentCourse, isEditing]);

  const filteredIcons = useMemo(() => {
    return ICON_OPTIONS.filter(icon => icon.toLowerCase().includes(iconSearchTerm.toLowerCase()));
  }, [iconSearchTerm]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed. Check your API link.");
    } finally {
      setIsGenerating(false);
    }
  };

  const clearDraft = () => {
    const draftKey = `eduworld_draft_${currentCourse?.id || 'new'}`;
    localStorage.removeItem(draftKey);
    setHasDraft(false);
    setDraftData(null);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;
    if (currentCourse.id) {
      onUpdateCourse(currentCourse as Course);
    } else {
      onAddCourse(currentCourse as Course);
    }
    clearDraft();
    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleDiscard = () => {
    if (confirm("Discard all changes? Unsaved progress will be lost.")) {
      clearDraft();
      setIsEditing(false);
      setCurrentCourse(null);
    }
  };

  const addLesson = (subjId?: string, subSubjId?: string) => {
    const newId = Math.random().toString(36).substr(2, 9);
    const sId = subjId || contextSubjectId || undefined;
    const ssId = subSubjId || contextSubSubjectId || undefined;

    const newLesson: Lesson = { 
      id: newId, 
      title: 'New Module', 
      content: '<h1>Module Content</h1><p>Start typing here...</p>', 
      duration: '15:00',
      subjectId: sId,
      subSubjectId: ssId,
      hasAiFeature: true,
      resources: [],
      quiz: []
    };

    setCurrentCourse(prev => {
      if (!prev) return prev;
      const updatedLessons = [...(prev.lessons || []), newLesson];
      setEditingLessonIdx(updatedLessons.length - 1);
      return {
        ...prev, 
        lessons: updatedLessons
      };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev || !prev.lessons) return prev;
      const newLessons = [...prev.lessons];
      newLessons[idx] = { ...newLessons[idx], ...updates };
      return { ...prev, lessons: newLessons };
    });
  };

  const handleVideoFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 50 * 1024 * 1024) { // 50MB limit for browser-based storage
      alert("Video file too large for local hosting. Please use a URL or a smaller file (Max 50MB).");
      return;
    }

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      updateLesson(editingLessonIdx!, { videoUrl: base64 });
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResourceFileUpload = async (lessonIdx: number, resourceIdx: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      const lessons = [...(currentCourse!.lessons || [])];
      const resources = [...(lessons[lessonIdx].resources || [])];

      let type: Resource['type'] = 'link';
      if (file.type.includes('pdf')) type = 'pdf';
      else if (file.type.includes('video')) type = 'video';
      else if (file.name.endsWith('.zip')) type = 'zip';

      resources[resourceIdx] = {
        ...resources[resourceIdx],
        url: base64,
        title: file.name,
        type: type
      };

      updateLesson(lessonIdx, { resources });
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const addResource = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newResource: Resource = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Resource',
      url: '',
      type: 'link'
    };
    lessons[lessonIdx].resources = [...(lessons[lessonIdx].resources || []), newResource];
    setCurrentCourse({ ...currentCourse!, lessons });
    setShowResources(true);
  };

  const addQuizQuestion = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newQuestion: QuizQuestion = {
      id: Math.random().toString(36).substr(2, 9),
      question: 'New Question?',
      options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
      correctAnswer: 0
    };
    lessons[lessonIdx].quiz = [...(lessons[lessonIdx].quiz || []), newQuestion];
    setCurrentCourse({ ...currentCourse!, lessons });
    setShowQuiz(true);
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Group',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const updatedSubjects = currentCourse!.subjects!.map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group' }]
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">

        {/* Full Page Lesson Editor Overlay */}
        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto animate-in slide-in-from-right-8 duration-500 flex flex-col">
            <div className="flex-1 max-w-5xl mx-auto w-full px-6 py-12 space-y-12">
              <div className="flex items-center justify-between border-b border-slate-800 pb-8">
                <div className="flex items-center space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all">
                    <i className="fas fa-arrow-left"></i>
                  </button>
                  <div>
                    <h2 className="text-3xl font-black text-white tracking-tight">Module Architect</h2>
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mt-1">Refining: {currentLesson.title}</p>
                  </div>
                </div>
                <div className="flex items-center space-x-4">
                  <div className="text-right hidden sm:block">
                     <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Type</p>
                     <p className="text-xs font-bold text-indigo-400">{currentLesson.videoUrl ? 'HD Video Module' : 'Text Reading Module'}</p>
                  </div>
                  <button onClick={() => setEditingLessonIdx(null)} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Apply & Exit</button>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
                {/* Main Content Areas */}
                <div className="lg:col-span-8 space-y-10">
                  {/* Field Group: Identity */}
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <div className="flex items-center space-x-3 mb-2">
                       <i className="fas fa-id-card text-indigo-500 text-sm"></i>
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">General Identity</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="md:col-span-2 space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Unit Title</label>
                        <input type="text" value={currentLesson.title} onChange={e => updateLesson(editingLessonIdx!, { title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Length</label>
                        <input type="text" value={currentLesson.duration} onChange={e => updateLesson(editingLessonIdx!, { duration: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" placeholder="e.g. 15:00" />
                      </div>
                    </div>
                    <div className="space-y-4 pt-4">
                      <div className="flex items-center justify-between">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Streaming Source (MP4 URL or Upload)</label>
                        <button 
                          type="button" 
                          onClick={() => videoInputRef.current?.click()}
                          className="text-[9px] font-black text-indigo-400 hover:text-white uppercase tracking-widest bg-indigo-500/10 px-3 py-1 rounded-lg border border-indigo-500/20"
                        >
                          <i className={`fas ${isUploading ? 'fa-spinner fa-spin' : 'fa-upload'} mr-2`}></i>
                          {isUploading ? 'Encoding...' : 'Upload Video'}
                        </button>
                        <input 
                          type="file" 
                          ref={videoInputRef} 
                          onChange={handleVideoFileUpload} 
                          accept="video/mp4,video/x-m4v,video/*" 
                          className="hidden" 
                        />
                      </div>
                      <input 
                        type="text" 
                        value={currentLesson.videoUrl || ''} 
                        onChange={e => updateLesson(editingLessonIdx!, { videoUrl: e.target.value })} 
                        className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 font-mono text-xs truncate" 
                        placeholder="https://... or data:video/..." 
                      />
                      {currentLesson.videoUrl?.startsWith('data:') && (
                        <p className="text-[8px] font-black text-emerald-500 uppercase tracking-widest ml-1">
                          <i className="fas fa-check-circle mr-1"></i> Locally Hosted Video Attached
                        </p>
                      )}
                    </div>
                  </div>

                  {/* Content Hub */}
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <div className="flex items-center space-x-3">
                       <i className="fas fa-file-lines text-emerald-500 text-sm"></i>
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Academic Body (HTML)</h3>
                    </div>
                    <textarea 
                      rows={12} 
                      value={currentLesson.content} 
                      onChange={e => updateLesson(editingLessonIdx!, { content: e.target.value })} 
                      className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-300 font-mono text-xs leading-relaxed focus:border-indigo-500/50 transition-all outline-none"
                      placeholder="<h1>Introduction</h1><p>Start your curriculum here...</p>"
                    />
                  </div>

                  {/* Resources Collapsible */}
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden">
                    <button onClick={() => setShowResources(!showResources)} className="w-full p-8 flex items-center justify-between hover:bg-slate-800/50 transition-colors">
                      <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-indigo-600/10 rounded-xl flex items-center justify-center text-indigo-400 border border-indigo-600/20 shadow-inner">
                          <i className="fas fa-paperclip"></i>
                        </div>
                        <div className="text-left">
                          <h3 className="text-[10px] font-black text-slate-200 uppercase tracking-[0.15em]">Supplemental Assets</h3>
                          <p className="text-[9px] text-slate-600 font-black uppercase mt-0.5">{currentLesson.resources?.length || 0} Files Attached</p>
                        </div>
                      </div>
                      <i className={`fas fa-chevron-${showResources ? 'up' : 'down'} text-slate-600`}></i>
                    </button>
                    {showResources && (
                      <div className="p-8 pt-0 space-y-4 border-t border-slate-800/50 animate-in slide-in-from-top-2">
                        {(currentLesson.resources || []).map((res, rIdx) => (
                          <div key={res.id} className="bg-slate-950 border border-slate-800 rounded-2xl p-5 grid grid-cols-1 md:grid-cols-4 gap-4">
                            <div className="md:col-span-2 space-y-1">
                              <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Asset Name</label>
                              <div className="flex items-center space-x-2">
                                <input type="text" value={res.title} onChange={e => { const rs = [...currentLesson.resources!]; rs[rIdx].title = e.target.value; updateLesson(editingLessonIdx!, { resources: rs }); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-lg px-3 py-2 text-xs text-white" />
                                <button 
                                  onClick={() => resourceFileRefs.current[res.id]?.click()}
                                  className="p-2 bg-slate-900 border border-slate-800 rounded-lg text-slate-500 hover:text-indigo-400"
                                >
                                  <i className="fas fa-upload"></i>
                                </button>
                                <input 
                                  type="file" 
                                  className="hidden" 
                                  ref={el => resourceFileRefs.current[res.id] = el}
                                  onChange={(e) => handleResourceFileUpload(editingLessonIdx!, rIdx, e)}
                                />
                              </div>
                            </div>
                            <div className="space-y-1">
                              <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Type</label>
                              <select value={res.type} onChange={e => { const rs = [...currentLesson.resources!]; rs[rIdx].type = e.target.value as any; updateLesson(editingLessonIdx!, { resources: rs }); }} className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-2 text-xs text-slate-400">
                                {RESOURCE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                              </select>
                            </div>
                            <div className="flex items-end space-x-2">
                              <button onClick={() => { const rs = currentLesson.resources!.filter(item => item.id !== res.id); updateLesson(editingLessonIdx!, { resources: rs }); }} className="flex-1 py-2 bg-rose-500/10 text-rose-500 rounded-lg text-[9px] font-black uppercase hover:bg-rose-500/20 transition-all">Remove</button>
                            </div>
                            <div className="md:col-span-4 space-y-1">
                              <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Resource Endpoint (URL or Uploaded Blob)</label>
                              <input type="text" value={res.url} onChange={e => { const rs = [...currentLesson.resources!]; rs[rIdx].url = e.target.value; updateLesson(editingLessonIdx!, { resources: rs }); }} className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-2 text-[10px] text-slate-400 font-mono truncate" />
                            </div>
                          </div>
                        ))}
                        <button onClick={() => addResource(editingLessonIdx!)} className="w-full py-4 border-2 border-dashed border-slate-800 rounded-2xl text-[10px] font-black text-slate-600 uppercase tracking-widest hover:border-indigo-500/50 hover:text-indigo-400 transition-all">+ Add New Entry</button>
                      </div>
                    )}
                  </div>

                  {/* Quiz Builder Collapsible */}
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden">
                    <button onClick={() => setShowQuiz(!showQuiz)} className="w-full p-8 flex items-center justify-between hover:bg-slate-800/50 transition-colors">
                      <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-emerald-500/10 rounded-xl flex items-center justify-center text-emerald-400 border border-emerald-500/20 shadow-inner">
                          <i className="fas fa-check-double"></i>
                        </div>
                        <div className="text-left">
                          <h3 className="text-[10px] font-black text-slate-200 uppercase tracking-[0.15em]">Assessment Forge</h3>
                          <p className="text-[9px] text-slate-600 font-black uppercase mt-0.5">{currentLesson.quiz?.length || 0} Questions Total</p>
                        </div>
                      </div>
                      <i className={`fas fa-chevron-${showQuiz ? 'up' : 'down'} text-slate-600`}></i>
                    </button>
                    {showQuiz && (
                      <div className="p-8 pt-0 space-y-6 border-t border-slate-800/50 animate-in slide-in-from-top-2">
                        {(currentLesson.quiz || []).map((q, qIdx) => (
                          <div key={q.id} className="bg-slate-950 border border-slate-800 rounded-[24px] p-6 space-y-6">
                            <div className="flex justify-between items-start gap-4">
                              <textarea rows={2} value={q.question} onChange={e => { const qz = [...currentLesson.quiz!]; qz[qIdx].question = e.target.value; updateLesson(editingLessonIdx!, { quiz: qz }); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-sm text-white font-bold" placeholder="Inquiry phrasing..." />
                              <button onClick={() => { const qz = currentLesson.quiz!.filter(item => item.id !== q.id); updateLesson(editingLessonIdx!, { quiz: qz }); }} className="w-10 h-10 bg-slate-900 rounded-xl text-slate-700 hover:text-rose-500 flex items-center justify-center border border-slate-800"><i className="fas fa-trash"></i></button>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              {q.options.map((opt, optIdx) => (
                                <div key={optIdx} className="flex items-center space-x-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800 transition-all group focus-within:border-indigo-500/30">
                                  <input type="radio" name={`correct-${q.id}`} checked={q.correctAnswer === optIdx} onChange={() => { const qz = [...currentLesson.quiz!]; qz[qIdx].correctAnswer = optIdx; updateLesson(editingLessonIdx!, { quiz: qz }); }} className="accent-indigo-500 w-4 h-4" />
                                  <input type="text" value={opt} onChange={e => { const qz = [...currentLesson.quiz!]; qz[qIdx].options[optIdx] = e.target.value; updateLesson(editingLessonIdx!, { quiz: qz }); }} className="flex-1 bg-transparent border-none text-xs text-slate-200 focus:ring-0 font-medium" />
                                </div>
                              ))}
                            </div>
                          </div>
                        ))}
                        <button onClick={() => addQuizQuestion(editingLessonIdx!)} className="w-full py-4 border-2 border-dashed border-slate-800 rounded-2xl text-[10px] font-black text-slate-600 uppercase tracking-widest hover:border-emerald-500/50 hover:text-emerald-400 transition-all">+ Forge New Inquiry</button>
                      </div>
                    )}
                  </div>
                </div>

                {/* Sidebar Meta Info */}
                <div className="lg:col-span-4 space-y-8">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-8">
                    <div className="space-y-4">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Metadata Anchor</h3>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Parent Subject</label>
                          <select 
                            value={currentLesson.subjectId || ''} 
                            onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value || undefined, subSubjectId: undefined })}
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400"
                          >
                            <option value="">Unassigned</option>
                            {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                          </select>
                       </div>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Sub-Unit Category</label>
                          <select 
                            value={currentLesson.subSubjectId || ''} 
                            disabled={!currentLesson.subjectId}
                            onChange={e => updateLesson(editingLessonIdx!, { subSubjectId: e.target.value || undefined })}
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 disabled:opacity-20"
                          >
                            <option value="">No Specific Group</option>
                            {currentCourse.subjects?.find(s => s.id === currentLesson.subjectId)?.subSubjects.map(ss => (
                              <option key={ss.id} value={ss.id}>{ss.name}</option>
                            ))}
                          </select>
                       </div>
                    </div>

                    <div className="pt-8 border-t border-slate-800 space-y-4">
                      <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Advanced Protocols</h3>
                      <label className="flex items-center justify-between p-4 bg-slate-950 rounded-2xl border border-slate-800 cursor-pointer group">
                        <span className="text-[9px] font-black text-slate-400 group-hover:text-indigo-400 uppercase tracking-widest transition-colors">AI Neural Features</span>
                        <div onClick={() => updateLesson(editingLessonIdx!, { hasAiFeature: !currentLesson.hasAiFeature })} className={`w-10 h-5 rounded-full relative transition-all ${currentLesson.hasAiFeature ? 'bg-indigo-600 shadow-[0_0_10px_rgba(79,70,229,0.5)]' : 'bg-slate-800'}`}>
                          <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all ${currentLesson.hasAiFeature ? 'left-6' : 'left-1'}`}></div>
                        </div>
                      </label>
                    </div>

                    <div className="pt-8 border-t border-slate-800 space-y-4">
                      <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Internal Instructor Ledger</h3>
                      <textarea 
                        rows={6} 
                        value={currentLesson.instructorNotes || ''} 
                        onChange={e => updateLesson(editingLessonIdx!, { instructorNotes: e.target.value })} 
                        className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 text-xs text-indigo-200/60 leading-relaxed italic"
                        placeholder="Pedagogical strategies and notes for this unit..."
                      />
                    </div>

                    <button onClick={() => { if (confirm('Purge this entire module?')) { const l = currentCourse.lessons!.filter((_, i) => i !== editingLessonIdx); setCurrentCourse({...currentCourse, lessons: l}); setEditingLessonIdx(null); } }} className="w-full py-4 bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all">Delete Module</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between">
          <button onClick={handleDiscard} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Discard Changes</span>
          </button>
          <div className="flex items-center space-x-4">
            <span className="text-[8px] font-black text-slate-600 uppercase tracking-widest animate-pulse">Auto-saving...</span>
            <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
          </div>
        </div>

        {hasDraft && !isEditingLesson && (
          <div className="bg-indigo-600/10 border border-indigo-500/30 rounded-2xl p-5 flex items-center justify-between animate-in slide-in-from-top-2">
            <div className="flex items-center space-x-4">
              <div className="w-10 h-10 bg-indigo-600/20 rounded-xl flex items-center justify-center text-indigo-400">
                <i className="fas fa-history"></i>
              </div>
              <div>
                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Syllabus Recovery</p>
                <p className="text-xs text-slate-300 font-medium">Unsaved progress from your last session was detected for this course.</p>
              </div>
            </div>
            <div className="flex space-x-3">
              <button 
                onClick={() => {
                  const draftKey = `eduworld_draft_${currentCourse?.id || 'new'}`;
                  localStorage.removeItem(draftKey);
                  setHasDraft(false);
                }} 
                className="px-4 py-2 text-[9px] font-black text-slate-500 uppercase tracking-widest hover:text-rose-500 transition-colors"
              >
                Clear Draft
              </button>
              <button 
                onClick={() => {
                  if (draftData) setCurrentCourse(draftData);
                  setHasDraft(false);
                }} 
                className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg shadow-indigo-600/20"
              >
                Restore Changes
              </button>
            </div>
          </div>
        )}

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button 
                key={tab}
                onClick={() => setActiveTab(tab as any)} 
                className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}
              >
                {tab}
              </button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({...currentCourse!, title: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Syllabus Category</label>
                    <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({...currentCourse!, category: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Tuition ($)</label>
                    <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({...currentCourse!, price: parseFloat(e.target.value)})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Academic Overview</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({...currentCourse!, description: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>
              </div>
            )}

