                    <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-1">Total: {currentCourse.lessons?.length || 0} Modules recorded</p>
                  </div>
                  <button type="button" onClick={() => addLesson()} className="px-6 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20">+ Add New Module</button>
                </div>

                <div className="space-y-3">
                  {(currentCourse.lessons || []).map((lesson, lessonIdx) => {
                    const isVideo = !!lesson.videoUrl;
                    const subjectName = currentCourse.subjects?.find(s => s.id === lesson.subjectId)?.name;

                    return (
                      <div 
                        key={lesson.id} 
                        className="group bg-slate-950/50 border border-slate-800 rounded-2xl p-5 flex items-center justify-between hover:border-indigo-500/30 hover:bg-slate-900 transition-all shadow-sm"
                      >
                        <div className="flex items-center space-x-6 overflow-hidden">
                          <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-lg border transition-all ${isVideo ? 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20' : 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'}`}>
                             <i className={`fas ${isVideo ? 'fa-play-circle' : 'fa-file-text'}`}></i>
                          </div>
                          <div className="truncate">
                             <h4 className="font-bold text-slate-100 truncate group-hover:text-white transition-colors">{lesson.title}</h4>
                             <div className="flex items-center space-x-4 mt-1">
                                <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration || '00:00'}</span>
