                        placeholder="Pedagogical strategies and notes for this unit..."
                      />
                    </div>

                    <button onClick={() => { if (confirm('Purge this entire module?')) { const l = currentCourse.lessons!.filter((_, i) => i !== editingLessonIdx); setCurrentCourse({...currentCourse, lessons: l}); setEditingLessonIdx(null); } }} className="w-full py-4 bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all">Delete Module</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between">
          <button onClick={handleDiscard} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
