                  localStorage.removeItem(draftKey);
                  setHasDraft(false);
                }} 
                className="px-4 py-2 text-[9px] font-black text-slate-500 uppercase tracking-widest hover:text-rose-500 transition-colors"
              >
                Clear Draft
