                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Subject Architecture</h3>
                  <button type="button" onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">+ Subject Group</button>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {(currentCourse.subjects || []).map((subj, sIdx) => (
                    <div key={subj.id} className={`bg-slate-950 border rounded-[32px] p-8 space-y-6 transition-all ${contextSubjectId === subj.id ? 'border-indigo-500 shadow-[0_0_30px_rgba(79,70,229,0.1)]' : 'border-slate-800'}`}>
                      <div className="flex flex-wrap items-center gap-4 relative">
                        <div className="relative">
                          <button onClick={() => { setIconPickerOpenId(iconPickerOpenId === subj.id ? null : subj.id); setIconSearchTerm(''); }} className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl transition-transform hover:scale-105 shadow-inner border border-white/5 ${subj.color}`}>
                            <i className={`fas ${subj.icon}`}></i>
                          </button>
                          {iconPickerOpenId === subj.id && (
                            <div className="absolute top-14 left-0 z-50 w-72 bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl p-4 animate-in fade-in zoom-in-95">
                              <div className="flex items-center space-x-2 bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 mb-4">
                                <i className="fas fa-search text-[10px] text-slate-600"></i>
                                <input type="text" autoFocus placeholder="Search icon..." value={iconSearchTerm} onChange={(e) => setIconSearchTerm(e.target.value)} className="w-full bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-200 p-0" />
                              </div>
                              <div className="grid grid-cols-6 gap-2 max-h-48 overflow-y-auto no-scrollbar pr-1">
                                {filteredIcons.map((icon) => (
                                  <button key={icon} onClick={() => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].icon = icon; setCurrentCourse({...currentCourse!, subjects: subjs}); setIconPickerOpenId(null); }} className={`w-8 h-8 rounded-lg flex items-center justify-center text-sm transition-all border ${subj.icon === icon ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-950 text-slate-500 border-slate-800 hover:border-indigo-500/50 hover:text-indigo-400'}`}>
                                    <i className={`fas ${icon}`}></i>
                                  </button>
                                ))}
                              </div>
                            </div>
                          )}
                        </div>

                        <div className="flex-1 min-w-[200px] space-y-4">
                          <input type="text" value={subj.name} onFocus={() => { setContextSubjectId(subj.id); setContextSubSubjectId(null); }} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" placeholder="Subject Name" />
                          <div className="flex items-center space-x-3">
                            <select value={subj.color} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].color = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-[9px] font-black bg-slate-900 border border-slate-800 rounded px-2 py-1 text-slate-500">
                              {COLOR_PRESETS.map((c, i) => <option key={i} value={c}>Theme {i+1}</option>)}
                            </select>
                            <button onClick={() => { setContextSubjectId(subj.id); setContextSubSubjectId(null); setActiveTab('curriculum'); addLesson(subj.id); }} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest flex items-center">
                              <i className="fas fa-plus mr-1"></i> Add Unit Here
                            </button>
                          </div>
                        </div>
                        <button onClick={() => { if (contextSubjectId === subj.id) setContextSubjectId(null); const subjs = currentCourse!.subjects!.filter(s => s.id !== subj.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>

                      <div className="pl-12 space-y-3">
                         <div className="flex justify-between items-center">
                            <h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4>
                            <button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Sub</button>
                         </div>
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                           {(subj.subSubjects || []).map((ss, ssIdx) => (
                             <div key={ss.id} className={`flex items-center space-x-2 rounded-lg px-3 py-2 border transition-all ${contextSubSubjectId === ss.id ? 'bg-indigo-600/10 border-indigo-500/40' : 'bg-slate-900 border-slate-800'}`}>
                               <input type="text" value={ss.name} onFocus={() => { setContextSubjectId(subj.id); setContextSubSubjectId(ss.id); }} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects[ssIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-300" />
                               <button onClick={() => { setContextSubjectId(subj.id); setContextSubSubjectId(ss.id); setActiveTab('curriculum'); addLesson(subj.id, ss.id); }} className="text-[9px] text-slate-600 hover:text-indigo-400" title="Add unit to this sub-group"><i className="fas fa-plus"></i></button>
                               <button onClick={() => { if (contextSubSubjectId === ss.id) setContextSubSubjectId(null); const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects = subjs[sIdx].subSubjects.filter(item => item.id !== ss.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                             </div>
                           ))}
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      {isAiModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-lg rounded-[40px] border border-slate-800 p-10 space-y-8 shadow-2xl animate-in zoom-in-95">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-black text-white tracking-tight">AI Architect</h2>
              <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Describe your vision for the course</p>
            </div>
            <textarea value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} placeholder="e.g. Master React and TypeScript with modern architecture..." className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-200 min-h-[120px] focus:border-indigo-500/50 transition-all outline-none" />
            <div className="flex space-x-4">
              <button onClick={() => setIsAiModalOpen(false)} className="flex-1 py-5 bg-slate-950 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest border border-slate-800">Cancel</button>
              <button onClick={handleAiGenerate} disabled={!aiPrompt.trim() || isGenerating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl disabled:opacity-50 flex items-center justify-center space-x-3">
                {isGenerating ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-sparkles"></i>}
                <span>{isGenerating ? 'Synthesizing...' : 'Build Syllabus'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="flex-1 md:flex-none px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ id: Math.random().toString(36).substr(2, 9), title: '', lessons: [], subjects: [] }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div className="flex items-center space-x-6">
                    <img src={course.thumbnail} className="w-16 h-10 rounded-xl object-cover opacity-80 group-hover:opacity-100 transition-opacity border border-slate-800 shadow-inner" alt="" />
                    <div>
                      <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                      <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

