];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [showResources, setShowResources] = useState(false);
  const [showQuiz, setShowQuiz] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [targetedResourceIdx, setTargetedResourceIdx] = useState<number | null>(null);

  const videoInputRef = useRef<HTMLInputElement>(null);
  const resourceInputRef = useRef<HTMLInputElement>(null);

  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);

  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);
  const [iconSearchTerm, setIconSearchTerm] = useState('');

  const [hasDraft, setHasDraft] = useState(false);
  const [draftData, setDraftData] = useState<Partial<Course> | null>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  useEffect(() => {
    if (isEditing && currentCourse) {
      const draftKey = `eduworld_draft_${currentCourse.id || 'new'}`;
      const saved = localStorage.getItem(draftKey);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          if (JSON.stringify(parsed) !== JSON.stringify(currentCourse)) {
            setDraftData(parsed);
            setHasDraft(true);
          }
        } catch (e) {
          console.error("Failed to parse draft", e);
        }
      }
    } else {
      setHasDraft(false);
      setDraftData(null);
    }
  }, [isEditing, currentCourse?.id]);

  useEffect(() => {
    if (isEditing && currentCourse) {
      const draftKey = `eduworld_draft_${currentCourse.id || 'new'}`;
      localStorage.setItem(draftKey, JSON.stringify(currentCourse));
    }
  }, [currentCourse, isEditing]);

  const filteredIcons = useMemo(() => {
    return ICON_OPTIONS.filter(icon => icon.toLowerCase().includes(iconSearchTerm.toLowerCase()));
  }, [iconSearchTerm]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed. Check your API link.");
    } finally {
      setIsGenerating(false);
    }
  };

  const clearDraft = () => {
    const draftKey = `eduworld_draft_${currentCourse?.id || 'new'}`;
    localStorage.removeItem(draftKey);
    setHasDraft(false);
    setDraftData(null);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse || !currentCourse.id) return;

    // Create a robust course object with fallbacks to ensure it shows up in UI
    const finalCourse: Course = {
      id: currentCourse.id,
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || 'No description provided.',
      instructor: currentCourse.instructor || 'Staff Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || []
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) {
      onUpdateCourse(finalCourse);
    } else {
      onAddCourse(finalCourse);
    }

    clearDraft();
    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleDiscard = () => {
    if (confirm("Discard all changes? Unsaved progress will be lost.")) {
      clearDraft();
      setIsEditing(false);
      setCurrentCourse(null);
    }
  };

  const addLesson = (subjId?: string, subSubjId?: string) => {
    const newId = Math.random().toString(36).substr(2, 9);
    const sId = subjId || contextSubjectId || undefined;
    const ssId = subSubjId || contextSubSubjectId || undefined;

    const newLesson: Lesson = { 
      id: newId, 
      title: 'New Module', 
      content: '<h1>Module Content</h1><p>Start typing here...</p>', 
      duration: '15:00',
      subjectId: sId,
      subSubjectId: ssId,
      hasAiFeature: true,
      resources: [],
      quiz: []
    };

    setCurrentCourse(prev => {
      if (!prev) return prev;
      const updatedLessons = [...(prev.lessons || []), newLesson];
      setEditingLessonIdx(updatedLessons.length - 1);
      return {
        ...prev, 
        lessons: updatedLessons
      };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev || !prev.lessons) return prev;
      const newLessons = [...prev.lessons];
      newLessons[idx] = { ...newLessons[idx], ...updates };
      return { ...prev, lessons: newLessons };
    });
  };

  const handleVideoFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      updateLesson(editingLessonIdx!, { videoUrl: base64 });
      setIsUploading(false);
      if (videoInputRef.current) videoInputRef.current.value = '';
    };
    reader.onerror = () => {
      alert("Encryption error during video processing.");
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResourceFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || editingLessonIdx === null || targetedResourceIdx === null) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;

      setCurrentCourse(prev => {
        if (!prev || !prev.lessons) return prev;
        const newLessons = [...prev.lessons];
        const lesson = { ...newLessons[editingLessonIdx] };
        const resources = [...(lesson.resources || [])];

        let type: Resource['type'] = 'link';
        if (file.type.includes('pdf')) type = 'pdf';
        else if (file.type.includes('video')) type = 'video';
        else if (file.name.endsWith('.zip')) type = 'zip';

        resources[targetedResourceIdx] = {
          ...resources[targetedResourceIdx],
          url: base64,
          title: file.name,
          type: type
        };

        lesson.resources = resources;
        newLessons[editingLessonIdx] = lesson;
        return { ...prev, lessons: newLessons };
      });

      setIsUploading(false);
      setTargetedResourceIdx(null);
      if (resourceInputRef.current) resourceInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  const addResource = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newResource: Resource = {
      id: Math.random().toString(36).substr(2, 9),
      title: 'New Resource',
      url: '',
      type: 'link'
    };
    lessons[lessonIdx].resources = [...(lessons[lessonIdx].resources || []), newResource];
    setCurrentCourse({ ...currentCourse!, lessons });
    setShowResources(true);
  };

  const addQuizQuestion = (lessonIdx: number) => {
    const lessons = [...(currentCourse!.lessons || [])];
    const newQuestion: QuizQuestion = {
      id: Math.random().toString(36).substr(2, 9),
      question: 'New Question?',
      options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
      correctAnswer: 0
    };
    lessons[lessonIdx].quiz = [...(lessons[lessonIdx].quiz || []), newQuestion];
    setCurrentCourse({ ...currentCourse!, lessons });
    setShowQuiz(true);
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Group',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const updatedSubjects = (currentCourse!.subjects || []).map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: [...(s.subSubjects || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group' }]
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">

        {/* Full Page Lesson Editor Overlay */}
        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto animate-in slide-in-from-right-8 duration-500 flex flex-col">
            <div className="flex-1 max-w-5xl mx-auto w-full px-6 py-12 space-y-12">
              <div className="flex items-center justify-between border-b border-slate-800 pb-8">
                <div className="flex items-center space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all">
                    <i className="fas fa-arrow-left"></i>
                  </button>
                  <div>
                    <h2 className="text-3xl font-black text-white tracking-tight">Module Architect</h2>
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mt-1">Refining: {currentLesson.title}</p>
                  </div>
                </div>
                <div className="flex items-center space-x-4">
                  <div className="text-right hidden sm:block">
                     <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Type</p>
                     <p className="text-xs font-bold text-indigo-400">{currentLesson.videoUrl ? 'HD Video Module' : 'Text Reading Module'}</p>
                  </div>
                  <button onClick={() => setEditingLessonIdx(null)} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Apply & Exit</button>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
                <div className="lg:col-span-8 space-y-10">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <div className="flex items-center space-x-3 mb-2">
                       <i className="fas fa-id-card text-indigo-500 text-sm"></i>
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">General Identity</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="md:col-span-2 space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Unit Title</label>
                        <input type="text" value={currentLesson.title} onChange={e => updateLesson(editingLessonIdx!, { title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Length</label>
                        <input type="text" value={currentLesson.duration} onChange={e => updateLesson(editingLessonIdx!, { duration: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" placeholder="e.g. 15:00" />
                      </div>
                    </div>
                    <div className="space-y-4 pt-4">
                      <div className="flex items-center justify-between">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Streaming Source (MP4 URL or Upload)</label>
                        <button 
                          type="button" 
                          onClick={() => videoInputRef.current?.click()}
                          className="text-[9px] font-black text-indigo-400 hover:text-white uppercase tracking-widest bg-indigo-500/10 px-3 py-1 rounded-lg border border-indigo-500/20"
                        >
                          <i className={`fas ${isUploading ? 'fa-spinner fa-spin' : 'fa-upload'} mr-2`}></i>
                          {isUploading ? 'Processing...' : 'Upload Video'}
                        </button>
                        <input 
                          type="file" 
                          ref={videoInputRef} 
                          onChange={handleVideoFileUpload} 
                          accept="video/*" 
                          className="hidden" 
                        />
                      </div>
                      <input 
                        type="text" 
                        value={currentLesson.videoUrl || ''} 
                        onChange={e => updateLesson(editingLessonIdx!, { videoUrl: e.target.value })} 
                        className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 font-mono text-xs truncate" 
                        placeholder="https://... or data:video/..." 
                      />
                      {currentLesson.videoUrl?.startsWith('data:') && (
                        <p className="text-[8px] font-black text-emerald-500 uppercase tracking-widest ml-1">
                          <i className="fas fa-check-circle mr-1"></i> Locally Hosted Video Attached
                        </p>
                      )}
                    </div>
                  </div>

                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <div className="flex items-center space-x-3">
                       <i className="fas fa-file-lines text-emerald-500 text-sm"></i>
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Academic Body (HTML)</h3>
                    </div>
                    <textarea 
                      rows={12} 
                      value={currentLesson.content} 
                      onChange={e => updateLesson(editingLessonIdx!, { content: e.target.value })} 
                      className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-300 font-mono text-xs leading-relaxed focus:border-indigo-500/50 transition-all outline-none"
                      placeholder="<h1>Introduction</h1><p>Start your curriculum here...</p>"
                    />
                  </div>

                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden">
                    <button onClick={() => setShowResources(!showResources)} className="w-full p-8 flex items-center justify-between hover:bg-slate-800/50 transition-colors">
                      <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-indigo-600/10 rounded-xl flex items-center justify-center text-indigo-400 border border-indigo-600/20 shadow-inner">
                          <i className="fas fa-paperclip"></i>
                        </div>
                        <div className="text-left">
                          <h3 className="text-[10px] font-black text-slate-200 uppercase tracking-[0.15em]">Supplemental Assets</h3>
                          <p className="text-[9px] text-slate-600 font-black uppercase mt-0.5">{currentLesson.resources?.length || 0} Files Attached</p>
                        </div>
                      </div>
                      <i className={`fas fa-chevron-${showResources ? 'up' : 'down'} text-slate-600`}></i>
                    </button>
                    {showResources && (
                      <div className="p-8 pt-0 space-y-4 border-t border-slate-800/50 animate-in slide-in-from-top-2">
                        <input type="file" ref={resourceInputRef} onChange={handleResourceFileUpload} className="hidden" />
                        {(currentLesson.resources || []).map((res, rIdx) => (
                          <div key={res.id} className="bg-slate-950 border border-slate-800 rounded-2xl p-5 grid grid-cols-1 md:grid-cols-4 gap-4">
                            <div className="md:col-span-2 space-y-1">
                              <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Asset Name</label>
                              <div className="flex items-center space-x-2">
                                <input type="text" value={res.title} onChange={e => { const rs = [...currentLesson.resources!]; rs[rIdx].title = e.target.value; updateLesson(editingLessonIdx!, { resources: rs }); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-lg px-3 py-2 text-xs text-white" />
                                <button onClick={() => { setTargetedResourceIdx(rIdx); resourceInputRef.current?.click(); }} className="p-2 bg-slate-900 border border-slate-800 rounded-lg text-slate-500 hover:text-indigo-400 transition-colors">
                                  <i className={`fas ${targetedResourceIdx === rIdx && isUploading ? 'fa-spinner fa-spin' : 'fa-upload'}`}></i>
                                </button>
                              </div>
                            </div>
                            <div className="space-y-1">
                              <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Type</label>
                              <select value={res.type} onChange={e => { const rs = [...currentLesson.resources!]; rs[rIdx].type = e.target.value as any; updateLesson(editingLessonIdx!, { resources: rs }); }} className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-2 text-xs text-slate-400">
                                {RESOURCE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                              </select>
                            </div>
                            <div className="flex items-end space-x-2">
                              <button onClick={() => { const rs = currentLesson.resources!.filter(item => item.id !== res.id); updateLesson(editingLessonIdx!, { resources: rs }); }} className="flex-1 py-2 bg-rose-500/10 text-rose-500 rounded-lg text-[9px] font-black uppercase hover:bg-rose-500/20 transition-all">Remove</button>
                            </div>
                            <div className="md:col-span-4 space-y-1">
                              <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Resource Endpoint (URL or Uploaded Blob)</label>
                              <input type="text" value={res.url} onChange={e => { const rs = [...currentLesson.resources!]; rs[rIdx].url = e.target.value; updateLesson(editingLessonIdx!, { resources: rs }); }} className="w-full bg-slate-900 border border-slate-800 rounded-lg px-3 py-2 text-[10px] text-slate-400 font-mono truncate" />
                            </div>
                          </div>
                        ))}
                        <button onClick={() => addResource(editingLessonIdx!)} className="w-full py-4 border-2 border-dashed border-slate-800 rounded-2xl text-[10px] font-black text-slate-600 uppercase tracking-widest hover:border-indigo-500/50 hover:text-indigo-400 transition-all">+ Add New Entry</button>
                      </div>
                    )}
                  </div>

                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden">
                    <button onClick={() => setShowQuiz(!showQuiz)} className="w-full p-8 flex items-center justify-between hover:bg-slate-800/50 transition-colors">
                      <div className="flex items-center space-x-4">
                        <div className="w-10 h-10 bg-emerald-500/10 rounded-xl flex items-center justify-center text-emerald-400 border border-emerald-500/20 shadow-inner">
                          <i className="fas fa-check-double"></i>
                        </div>
                        <div className="text-left">
                          <h3 className="text-[10px] font-black text-slate-200 uppercase tracking-[0.15em]">Assessment Forge</h3>
                          <p className="text-[9px] text-slate-600 font-black uppercase mt-0.5">{currentLesson.quiz?.length || 0} Questions Total</p>
                        </div>
                      </div>
                      <i className={`fas fa-chevron-${showQuiz ? 'up' : 'down'} text-slate-600`}></i>
                    </button>
                    {showQuiz && (
                      <div className="p-8 pt-0 space-y-6 border-t border-slate-800/50 animate-in slide-in-from-top-2">
                        {(currentLesson.quiz || []).map((q, qIdx) => (
                          <div key={q.id} className="bg-slate-950 border border-slate-800 rounded-[24px] p-6 space-y-6">
                            <div className="flex justify-between items-start gap-4">
                              <textarea rows={2} value={q.question} onChange={e => { const qz = [...currentLesson.quiz!]; qz[qIdx].question = e.target.value; updateLesson(editingLessonIdx!, { quiz: qz }); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-sm text-white font-bold" placeholder="Inquiry phrasing..." />
                              <button onClick={() => { const qz = currentLesson.quiz!.filter(item => item.id !== q.id); updateLesson(editingLessonIdx!, { quiz: qz }); }} className="w-10 h-10 bg-slate-900 rounded-xl text-slate-700 hover:text-rose-500 flex items-center justify-center border border-slate-800"><i className="fas fa-trash"></i></button>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              {q.options.map((opt, optIdx) => (
                                <div key={optIdx} className="flex items-center space-x-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800 transition-all group focus-within:border-indigo-500/30">
                                  <input type="radio" name={`correct-${q.id}`} checked={q.correctAnswer === optIdx} onChange={() => { const qz = [...currentLesson.quiz!]; qz[qIdx].correctAnswer = optIdx; updateLesson(editingLessonIdx!, { quiz: qz }); }} className="accent-indigo-500 w-4 h-4" />
                                  <input type="text" value={opt} onChange={e => { const qz = [...currentLesson.quiz!]; qz[qIdx].options[optIdx] = e.target.value; updateLesson(editingLessonIdx!, { quiz: qz }); }} className="flex-1 bg-transparent border-none text-xs text-slate-200 focus:ring-0 font-medium" />
                                </div>
                              ))}
                            </div>
                          </div>
                        ))}
                        <button onClick={() => addQuizQuestion(editingLessonIdx!)} className="w-full py-4 border-2 border-dashed border-slate-800 rounded-2xl text-[10px] font-black text-slate-600 uppercase tracking-widest hover:border-emerald-500/50 hover:text-emerald-400 transition-all">+ Forge New Inquiry</button>
                      </div>
                    )}
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-8">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-8">
                    <div className="space-y-4">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Metadata Anchor</h3>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Parent Subject</label>
                          <select 
                            value={currentLesson.subjectId || ''} 
                            onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value || undefined, subSubjectId: undefined })}
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400"
                          >
                            <option value="">Unassigned</option>
                            {(currentCourse.subjects || []).map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                          </select>
                       </div>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Sub-Unit Category</label>
                          <select 
                            value={currentLesson.subSubjectId || ''} 
                            disabled={!currentLesson.subjectId}
                            onChange={e => updateLesson(editingLessonIdx!, { subSubjectId: e.target.value || undefined })}
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 disabled:opacity-20"
                          >
                            <option value="">No Specific Group</option>
