  const [selectedSubject, setSelectedSubject] = useState<SubjectGroup | null>(null);
  const [selectedSubSubject, setSelectedSubSubject] = useState<SubSubject | null>(null);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-16 h-16 md:w-24 md:h-24 bg-slate-900 text-indigo-400 rounded-[30px] md:rounded-[40px] flex items-center justify-center mb-8 border border-slate-800">
