  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);
  const [contextUnitId, setContextUnitId] = useState<string | null>(null);

  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);
  const [iconSearchTerm, setIconSearchTerm] = useState('');

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const filteredIcons = useMemo(() => {
    return ICON_OPTIONS.filter(icon => icon.toLowerCase().includes(iconSearchTerm.toLowerCase()));
  }, [iconSearchTerm]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse || !currentCourse.id) return;

    const finalCourse: Course = {
      id: currentCourse.id,
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || 'No description.',
      instructor: currentCourse.instructor || 'Staff',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || []
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const addLesson = (subjId?: string, subSubjId?: string, unitId?: string) => {
    const newId = Math.random().toString(36).substr(2, 9);
    const sId = subjId || contextSubjectId || undefined;
    const ssId = subSubjId || contextSubSubjectId || undefined;
    const uId = unitId || contextUnitId || undefined;

    const newLesson: Lesson = { 
      id: newId, 
      title: 'New Lesson', 
      content: '<h1>Start here</h1>', 
      duration: '10:00',
      subjectId: sId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      resources: [],
      quiz: []
    };

    setCurrentCourse(prev => {
      if (!prev) return prev;
      const updatedLessons = [...(prev.lessons || []), newLesson];
      setEditingLessonIdx(updatedLessons.length - 1);
      return { ...prev, lessons: updatedLessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev || !prev.lessons) return prev;
      const newLessons = [...prev.lessons];
      newLessons[idx] = { ...newLessons[idx], ...updates };
      return { ...prev, lessons: newLessons };
    });
  };

  const handleVideoFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      updateLesson(editingLessonIdx!, { videoUrl: base64 });
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResourceFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || editingLessonIdx === null || targetedResourceIdx === null) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setCurrentCourse(prev => {
        if (!prev || !prev.lessons) return prev;
        const newLessons = [...prev.lessons];
        const res = [...(newLessons[editingLessonIdx].resources || [])];
        res[targetedResourceIdx] = { ...res[targetedResourceIdx], url: base64, title: file.name, type: file.type.includes('pdf') ? 'pdf' : 'link' };
        newLessons[editingLessonIdx].resources = res;
        return { ...prev, lessons: newLessons };
      });
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Subject',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const subjs = (currentCourse!.subjects || []).map(s => {
      if (s.id === subjectId) {
        return { ...s, subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group', units: [] }] };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: subjs});
  };

  const addUnit = (subjectId: string, subSubjId: string) => {
    const subjs = (currentCourse!.subjects || []).map(s => {
      if (s.id === subjectId) {
        const subSubjs = s.subSubjects.map(ss => {
          if (ss.id === subSubjId) {
            return { ...ss, units: [...(ss.units || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Unit' }] };
          }
          return ss;
        });
        return { ...s, subSubjects: subSubjs };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: subjs});
  };

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">
        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto animate-in slide-in-from-right-8 duration-500 flex flex-col">
            <div className="flex-1 max-w-5xl mx-auto w-full px-6 py-12 space-y-12">
              <div className="flex items-center justify-between border-b border-slate-800 pb-8">
                <div className="flex items-center space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all">
                    <i className="fas fa-arrow-left"></i>
                  </button>
                  <h2 className="text-3xl font-black text-white tracking-tight">Lesson Architect</h2>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl">Apply & Exit</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
                <div className="lg:col-span-8 space-y-10">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="md:col-span-2 space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Lesson Title</label>
                        <input type="text" value={currentLesson.title} onChange={e => updateLesson(editingLessonIdx!, { title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Duration</label>
                        <input type="text" value={currentLesson.duration} onChange={e => updateLesson(editingLessonIdx!, { duration: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                      </div>
                    </div>
                    <div className="space-y-4 pt-4">
                      <div className="flex items-center justify-between">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Video Stream</label>
                        <button type="button" onClick={() => videoInputRef.current?.click()} className="text-[9px] font-black text-indigo-400 uppercase bg-indigo-500/10 px-3 py-1 rounded-lg border border-indigo-500/20">
                          {isUploading ? '...' : <i className="fas fa-upload mr-2"></i>} Upload
                        </button>
                        <input type="file" ref={videoInputRef} onChange={handleVideoFileUpload} accept="video/*" className="hidden" />
                      </div>
                      <input type="text" value={currentLesson.videoUrl || ''} onChange={e => updateLesson(editingLessonIdx!, { videoUrl: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 font-mono text-xs truncate" />
                    </div>
                  </div>

                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Academic Content (HTML)</h3>
                    <textarea rows={12} value={currentLesson.content} onChange={e => updateLesson(editingLessonIdx!, { content: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-300 font-mono text-xs leading-relaxed outline-none" />
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-8">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-8">
                    <div className="space-y-4">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Hierarchy Anchor</h3>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Subject</label>
                          <select value={currentLesson.subjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value || undefined, subSubjectId: undefined, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400">
                            <option value="">Unassigned</option>
                            {(currentCourse.subjects || []).map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                          </select>
                       </div>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Sub-group</label>
                          <select value={currentLesson.subSubjectId || ''} disabled={!currentLesson.subjectId} onChange={e => updateLesson(editingLessonIdx!, { subSubjectId: e.target.value || undefined, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20">
                            <option value="">No Sub-group</option>
                            {(currentCourse.subjects || []).find(s => s.id === currentLesson.subjectId)?.subSubjects.map(ss => <option key={ss.id} value={ss.id}>{ss.name}</option>)}
                          </select>
                       </div>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Unit</label>
                          <select value={currentLesson.unitId || ''} disabled={!currentLesson.subSubjectId} onChange={e => updateLesson(editingLessonIdx!, { unitId: e.target.value || undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20">
                            <option value="">No Unit</option>
                            {(currentCourse.subjects || []).flatMap(s => s.subSubjects).find(ss => ss.id === currentLesson.subSubjectId)?.units?.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                          </select>
                       </div>
                    </div>
                    <button onClick={() => { if (confirm('Purge this lesson?')) { const l = currentCourse.lessons!.filter((_, i) => i !== editingLessonIdx); setCurrentCourse({...currentCourse, lessons: l}); setEditingLessonIdx(null); } }} className="w-full py-4 bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all">Delete Lesson</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Back</span>
          </button>
          <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl">Commit Course</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}>{tab}</button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-8">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({...currentCourse!, title: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                    <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({...currentCourse!, category: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Price ($)</label>
                    <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({...currentCourse!, price: parseFloat(e.target.value)})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-200 font-bold" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Description</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({...currentCourse!, description: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-xl font-black text-white">Lessons</h3>
                  <button type="button" onClick={() => addLesson()} className="px-6 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase shadow-xl">+ New Lesson</button>
                </div>
                <div className="space-y-3">
                  {(currentCourse.lessons || []).map((lesson, lessonIdx) => {
                    const subj = (currentCourse.subjects || []).find(s => s.id === lesson.subjectId);
                    const ss = subj?.subSubjects.find(s => s.id === lesson.subSubjectId);
                    const unit = ss?.units.find(u => u.id === lesson.unitId);
                    return (
                      <div key={lesson.id} className="group bg-slate-950/50 border border-slate-800 rounded-2xl p-5 flex items-center justify-between hover:bg-slate-900 transition-all">
                        <div className="flex items-center space-x-6">
                          <div className={`w-12 h-12 rounded-xl flex items-center justify-center border ${lesson.videoUrl ? 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20' : 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'}`}><i className={`fas ${lesson.videoUrl ? 'fa-play' : 'fa-file'}`}></i></div>
                          <div className="truncate">
                             <h4 className="font-bold text-slate-100">{lesson.title}</h4>
                             <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-1">
                                {subj?.name || 'Unassigned'} / {ss?.name || '---'} / {unit?.name || '---'}
                             </p>
                          </div>
                        </div>
                        <div className="flex items-center space-x-3 ml-4">
                           <button onClick={() => setEditingLessonIdx(lessonIdx)} className="px-4 py-2 bg-slate-900 border border-slate-800 text-[9px] font-black text-slate-500 uppercase rounded-lg hover:text-white transition-all">Edit</button>
                           <button onClick={() => { if (confirm('Purge?')) { const l = currentCourse.lessons!.filter((_, i) => i !== lessonIdx); setCurrentCourse({...currentCourse, lessons: l}); } }} className="w-10 h-10 bg-slate-950 rounded-lg text-slate-800 hover:text-rose-500 flex items-center justify-center border border-slate-800"><i className="fas fa-trash-alt text-sm"></i></button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {activeTab === 'structure' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Hierarchy Architect</h3>
                  <button type="button" onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">+ Subject</button>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {(currentCourse.subjects || []).map((subj, sIdx) => (
                    <div key={subj.id} className="bg-slate-950 border border-slate-800 rounded-[32px] p-8 space-y-6">
                      <div className="flex items-center gap-4">
                        <button onClick={() => setIconPickerOpenId(iconPickerOpenId === subj.id ? null : subj.id)} className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl ${subj.color}`}><i className={`fas ${subj.icon}`}></i></button>
                        <input type="text" value={subj.name} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" />
                        <button onClick={() => { const subjs = currentCourse!.subjects!.filter(s => s.id !== subj.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>

                      <div className="pl-12 space-y-6">
                        <div className="flex justify-between items-center"><h4 className="text-[8px] font-black text-slate-600 uppercase tracking-widest">Sub-groups</h4><button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">+ Add Sub-group</button></div>
                        {(subj.subSubjects || []).map((ss, ssIdx) => (
                          <div key={ss.id} className="space-y-4 p-5 bg-slate-900/50 border border-slate-800 rounded-2xl">
                             <div className="flex items-center gap-4">
                               <input type="text" value={ss.name} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects[ssIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="flex-1 bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 text-slate-300 font-bold text-xs" />
                               <button onClick={() => addUnit(subj.id, ss.id)} className="text-[8px] font-black text-emerald-400 uppercase tracking-widest">+ Unit</button>
                               <button onClick={() => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects = subjs[sIdx].subSubjects.filter(item => item.id !== ss.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times"></i></button>
                             </div>

                             <div className="pl-6 space-y-3">
                                {(ss.units || []).map((unit, uIdx) => (
                                  <div key={unit.id} className="flex items-center gap-3 bg-slate-950 border border-slate-800/50 rounded-lg px-3 py-2">
                                     <input type="text" value={unit.name} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects[ssIdx].units[uIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-400" />
                                     <button onClick={() => { setContextSubjectId(subj.id); setContextSubSubjectId(ss.id); setContextUnitId(unit.id); setActiveTab('curriculum'); addLesson(subj.id, ss.id, unit.id); }} className="text-[9px] text-indigo-400 hover:text-white" title="Add lesson here"><i className="fas fa-plus"></i></button>
                                     <button onClick={() => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects[ssIdx].units = ss.units.filter(u => u.id !== unit.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                                  </div>
                                ))}
                             </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div><h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Registry</h1><p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">System Control Center</p></div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => setIsAiModalOpen(true)} className="px-8 py-4 bg-slate-900 text-indigo-400 border border-slate-800 rounded-2xl font-black text-[10px] uppercase shadow-lg"><i className="fas fa-magic mr-3"></i> AI Architect</button>
          <button onClick={() => { setCurrentCourse({ id: Math.random().toString(36).substr(2, 9), title: 'New Program', lessons: [], subjects: [], category: 'Academic', price: 0 }); setIsEditing(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-xl"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950 border-b border-slate-800">
            <tr><th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Course Profile</th><th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th></tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
