import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, QuizAttempt, Course } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getTutorResponse = async (
  userMessage: string, 
  history: ChatMessage[],
  context: { 
    courseTitle: string; 
    lessonTitle: string; 
    lessonContent: string; 
    progress: number;
    quizHistory?: Record<string, QuizAttempt>;
  },
  imageData?: string 
) => {
  try {
    const model = 'gemini-3-pro-preview';
    const systemInstruction = `
      You are "Aris", an AI Tutor. Course: "${context.courseTitle}", Lesson: "${context.lessonTitle}".
      Help students deeply understand concepts. Be clear, professional, and use Markdown.
    `;
    const contents = history.map(msg => ({
      role: msg.role === 'user' ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));
    const currentParts: any[] = [{ text: userMessage }];
    if (imageData) currentParts.push({ inlineData: { mimeType: 'image/jpeg', data: imageData.split(',')[1] } });
    contents.push({ role: 'user', parts: currentParts } as any);

    const response = await ai.models.generateContent({
      model,
      contents: contents as any,
      config: { systemInstruction, temperature: 0.7, tools: [{ googleSearch: {} }] }
    });
    return { text: response.text || "...", urls: [] };
  } catch (error) {
    return { text: "Error connecting to AI core.", urls: [] };
  }
};

export const generateCourseOutline = async (topic: string): Promise<Partial<Course>> => {
  try {
    const model = 'gemini-3-pro-preview';
    const response = await ai.models.generateContent({
      model,
      contents: `Design a 4-level course structure for: ${topic}. Structure: Subject -> Sub-group -> Unit -> Lesson. Return JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            category: { type: Type.STRING },
            subjects: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  name: { type: Type.STRING },
                  icon: { type: Type.STRING },
                  color: { type: Type.STRING },
                  subSubjects: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        id: { type: Type.STRING },
                        name: { type: Type.STRING },
                        units: {
                          type: Type.ARRAY,
                          items: {
                            type: Type.OBJECT,
                            properties: {
                              id: { type: Type.STRING },
                              name: { type: Type.STRING }
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            },
            lessons: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  unitId: { type: Type.STRING },
                  title: { type: Type.STRING },
                  content: { type: Type.STRING },
                  duration: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const data = JSON.parse(response.text);
    // Link lessons to their parents based on IDs
    data.lessons = data.lessons.map((l: any) => {
      // Find unit to get subgroup and subject
      for (const s of data.subjects) {
        for (const ss of s.subSubjects) {
          for (const u of ss.units) {
            if (u.id === l.unitId) {
              return { ...l, subjectId: s.id, subSubjectId: ss.id };
            }
          }
        }
      }
      return l;
    });

    return {
      ...data,
      id: Math.random().toString(36).substr(2, 9),
      thumbnail: 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&q=80&w=800',
      instructor: 'AI Expert',
      price: 49.99
    };
  } catch (error) {
    throw error;
  }
};

