}

export interface QuizQuestion {
  id: string;
  question: string;
  options: string[];
  correctAnswer: number; // Index of the correct option
}

export interface Lesson {
  id: string;
  title: string;
  content: string;
  videoUrl?: string;
  duration: string;
  completed?: boolean;
  resources?: Resource[];
  instructorNotes?: string;
  quiz?: QuizQuestion[];
  subjectId?: string; // Links lesson to a subject group
  subSubjectId?: string; // Links lesson to a specific sub-subject
  unitId?: string; // Links lesson to a specific unit
  hasAiFeature?: boolean; // Flag to enable AI features for this lesson
}

export interface Unit {
  id: string;
  name: string;
}

export interface SubSubject {
  id: string;
  name: string;
  units: Unit[]; // Now contains units
}

export interface SubjectGroup {
  id: string;
  name: string;
  icon: string;
  color: string;
  subSubjects: SubSubject[]; 
}

export interface SupplementalItem {
  id: string;
  title: string;
  thumbnail: string;
  action: string; 
}

export interface RoadmapItem {
  id: string;
  icon: string;
  text: string;
}

export interface Course {
  id: string;
  title: string;
  description: string;
  instructor: string;
  instructorAvatar: string;
  thumbnail: string;
  lessons: Lesson[];
  category: string;
  rating: number;
  studentsCount: number;
  price: number; 
  progress?: number;
  subjects: SubjectGroup[];
  supplementalContent?: SupplementalItem[];
  roadmap?: RoadmapItem[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  image?: string; 
  groundingUrls?: { title: string, uri: string }[];
}

export enum AppRoute {
  DASHBOARD = 'dashboard',
  COURSES = 'courses',
  COURSE_DETAILS = 'course-details',
  COURSE_VIEW = 'course-view',
  PROFILE = 'profile',
  ADMIN = 'admin'
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, Resource, QuizQuestion } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-500 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-500 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const RESOURCE_TYPES = ['link', 'pdf', 'video', 'zip'];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [isAiModalOpen, setIsAiModalOpen] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [showResources, setShowResources] = useState(false);
  const [showQuiz, setShowQuiz] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [targetedResourceIdx, setTargetedResourceIdx] = useState<number | null>(null);

  const videoInputRef = useRef<HTMLInputElement>(null);
  const resourceInputRef = useRef<HTMLInputElement>(null);

  const [contextSubjectId, setContextSubjectId] = useState<string | null>(null);
  const [contextSubSubjectId, setContextSubSubjectId] = useState<string | null>(null);
  const [contextUnitId, setContextUnitId] = useState<string | null>(null);

  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);
  const [iconSearchTerm, setIconSearchTerm] = useState('');

  const [hasDraft, setHasDraft] = useState(false);
  const [draftData, setDraftData] = useState<Partial<Course> | null>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  useEffect(() => {
    if (isEditing && currentCourse) {
      const draftKey = `eduworld_draft_${currentCourse.id || 'new'}`;
      const saved = localStorage.getItem(draftKey);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          if (JSON.stringify(parsed) !== JSON.stringify(currentCourse)) {
            setDraftData(parsed);
            setHasDraft(true);
          }
        } catch (e) {
          console.error("Failed to parse draft", e);
        }
      }
    } else {
      setHasDraft(false);
      setDraftData(null);
    }
  }, [isEditing, currentCourse?.id]);

  useEffect(() => {
    if (isEditing && currentCourse) {
      const draftKey = `eduworld_draft_${currentCourse.id || 'new'}`;
      localStorage.setItem(draftKey, JSON.stringify(currentCourse));
    }
  }, [currentCourse, isEditing]);

  const filteredIcons = useMemo(() => {
    return ICON_OPTIONS.filter(icon => icon.toLowerCase().includes(iconSearchTerm.toLowerCase()));
  }, [iconSearchTerm]);

  const handleAiGenerate = async () => {
    if (!aiPrompt.trim() || isGenerating) return;
    setIsGenerating(true);
    try {
      const outline = await generateCourseOutline(aiPrompt);
      setCurrentCourse(outline);
      setIsEditing(true);
      setIsAiModalOpen(false);
      setAiPrompt('');
    } catch (err) {
      alert("Course generation failed. Check your API link.");
    } finally {
      setIsGenerating(false);
    }
  };

  const clearDraft = () => {
    const draftKey = `eduworld_draft_${currentCourse?.id || 'new'}`;
    localStorage.removeItem(draftKey);
    setHasDraft(false);
    setDraftData(null);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse || !currentCourse.id) return;

    const finalCourse: Course = {
      id: currentCourse.id,
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || 'No description provided.',
      instructor: currentCourse.instructor || 'Staff Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || []
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) {
      onUpdateCourse(finalCourse);
    } else {
      onAddCourse(finalCourse);
    }

    clearDraft();
    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleDiscard = () => {
    if (confirm("Discard all changes? Unsaved progress will be lost.")) {
      clearDraft();
      setIsEditing(false);
      setCurrentCourse(null);
    }
  };

  const addLesson = (subjId?: string, subSubjId?: string, unitId?: string) => {
    const newId = Math.random().toString(36).substr(2, 9);
    const sId = subjId || contextSubjectId || undefined;
    const ssId = subSubjId || contextSubSubjectId || undefined;
    const uId = unitId || contextUnitId || undefined;

    const newLesson: Lesson = { 
      id: newId, 
      title: 'New Lesson Module', 
      content: '<h1>Start lesson content here</h1>', 
      duration: '15:00',
      subjectId: sId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      resources: [],
      quiz: []
    };

    setCurrentCourse(prev => {
      if (!prev) return prev;
      const updatedLessons = [...(prev.lessons || []), newLesson];
      setEditingLessonIdx(updatedLessons.length - 1);
      return {
        ...prev, 
        lessons: updatedLessons
      };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev || !prev.lessons) return prev;
      const newLessons = [...prev.lessons];
      newLessons[idx] = { ...newLessons[idx], ...updates };
      return { ...prev, lessons: newLessons };
    });
  };

  const handleVideoFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      updateLesson(editingLessonIdx!, { videoUrl: base64 });
      setIsUploading(false);
      if (videoInputRef.current) videoInputRef.current.value = '';
    };
    reader.onerror = () => {
      alert("Error during video processing.");
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleResourceFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || editingLessonIdx === null || targetedResourceIdx === null) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;

      setCurrentCourse(prev => {
        if (!prev || !prev.lessons) return prev;
        const newLessons = [...prev.lessons];
        const lesson = { ...newLessons[editingLessonIdx] };
        const resources = [...(lesson.resources || [])];

        let type: Resource['type'] = 'link';
        if (file.type.includes('pdf')) type = 'pdf';
        else if (file.type.includes('video')) type = 'video';
        else if (file.name.endsWith('.zip')) type = 'zip';

        resources[targetedResourceIdx] = {
          ...resources[targetedResourceIdx],
          url: base64,
          title: file.name,
          type: type
        };

        lesson.resources = resources;
        newLessons[editingLessonIdx] = lesson;
        return { ...prev, lessons: newLessons };
      });

      setIsUploading(false);
      setTargetedResourceIdx(null);
      if (resourceInputRef.current) resourceInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = {
      id: Math.random().toString(36).substr(2, 9),
      name: 'New Subject',
      icon: 'fa-book',
      color: COLOR_PRESETS[0],
      subSubjects: []
    };
    setCurrentCourse({...currentCourse!, subjects: [...(currentCourse!.subjects || []), newSubj]});
  };

  const addSubSubject = (subjectId: string) => {
    const updatedSubjects = (currentCourse!.subjects || []).map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: [...(s.subSubjects || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group', units: [] }]
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  const addUnit = (subjectId: string, subSubjectId: string) => {
    const updatedSubjects = (currentCourse!.subjects || []).map(s => {
      if (s.id === subjectId) {
        return {
          ...s,
          subSubjects: s.subSubjects.map(ss => {
            if (ss.id === subSubjectId) {
              return {
                ...ss,
                units: [...(ss.units || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Unit' }]
              };
            }
            return ss;
          })
        };
      }
      return s;
    });
    setCurrentCourse({...currentCourse!, subjects: updatedSubjects});
  };

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">

        {/* Full Page Lesson Editor Overlay */}
        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto animate-in slide-in-from-right-8 duration-500 flex flex-col">
            <div className="flex-1 max-w-5xl mx-auto w-full px-6 py-12 space-y-12">
              <div className="flex items-center justify-between border-b border-slate-800 pb-8">
                <div className="flex items-center space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all">
                    <i className="fas fa-arrow-left"></i>
                  </button>
                  <div>
                    <h2 className="text-3xl font-black text-white tracking-tight">Lesson Architect</h2>
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mt-1">Refining: {currentLesson.title}</p>
                  </div>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl">Apply & Exit</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
                <div className="lg:col-span-8 space-y-10">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="md:col-span-2 space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Lesson Title</label>
                        <input type="text" value={currentLesson.title} onChange={e => updateLesson(editingLessonIdx!, { title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Length</label>
                        <input type="text" value={currentLesson.duration} onChange={e => updateLesson(editingLessonIdx!, { duration: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                      </div>
                    </div>
                  </div>

                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Academic Body (HTML)</h3>
                    <textarea 
                      rows={12} 
                      value={currentLesson.content} 
                      onChange={e => updateLesson(editingLessonIdx!, { content: e.target.value })} 
                      className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-300 font-mono text-xs leading-relaxed focus:border-indigo-500/50 transition-all outline-none"
                    />
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-8">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-8">
                    <div className="space-y-4">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Hierarchy Anchor</h3>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Subject</label>
                          <select 
                            value={currentLesson.subjectId || ''} 
                            onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value || undefined, subSubjectId: undefined, unitId: undefined })}
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400"
                          >
                            <option value="">Unassigned</option>
                            {(currentCourse.subjects || []).map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                          </select>
                       </div>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Sub-group</label>
                          <select 
                            value={currentLesson.subSubjectId || ''} 
                            disabled={!currentLesson.subjectId}
                            onChange={e => updateLesson(editingLessonIdx!, { subSubjectId: e.target.value || undefined, unitId: undefined })}
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 disabled:opacity-20"
                          >
                            <option value="">No Specific Sub-group</option>
                            {(currentCourse.subjects || []).find(s => s.id === currentLesson.subjectId)?.subSubjects.map(ss => (
                              <option key={ss.id} value={ss.id}>{ss.name}</option>
                            ))}
                          </select>
                       </div>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-700 uppercase tracking-widest ml-1">Unit</label>
                          <select 
                            value={currentLesson.unitId || ''} 
                            disabled={!currentLesson.subSubjectId}
                            onChange={e => updateLesson(editingLessonIdx!, { unitId: e.target.value || undefined })}
                            className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 disabled:opacity-20"
                          >
                            <option value="">No Specific Unit</option>
                            {(currentCourse.subjects || []).flatMap(s => s.subSubjects).find(ss => ss.id === currentLesson.subSubjectId)?.units?.map(u => (
                              <option key={u.id} value={u.id}>{u.name}</option>
                            ))}
                          </select>
                       </div>
                    </div>

                    <button onClick={() => { if (confirm('Purge this module?')) { const l = currentCourse.lessons!.filter((_, i) => i !== editingLessonIdx); setCurrentCourse({...currentCourse, lessons: l}); setEditingLessonIdx(null); } }} className="w-full py-4 bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all">Delete Module</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between">
          <button onClick={handleDiscard} className="text-slate-500 hover:text-white flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest">
            <i className="fas fa-arrow-left"></i> <span>Discard Changes</span>
          </button>
          <div className="flex items-center space-x-4">
            <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
          </div>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}>{tab}</button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({...currentCourse!, title: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Description</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({...currentCourse!, description: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in">
                <div className="flex justify-between items-center mb-6">
                  <div>
                    <h3 className="text-xl font-black text-white tracking-tight">Academic Unit Registry</h3>
                    <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-1">Total: {currentCourse.lessons?.length || 0} Modules recorded</p>
                  </div>
                  <button type="button" onClick={() => addLesson()} className="px-6 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20">+ Add New Module</button>
                </div>

                <div className="space-y-3">
                  {(currentCourse.lessons || []).map((lesson, lessonIdx) => {
                    const subj = (currentCourse.subjects || []).find(s => s.id === lesson.subjectId);
                    const ss = subj?.subSubjects.find(s => s.id === lesson.subSubjectId);
                    const unit = ss?.units.find(u => u.id === lesson.unitId);

                    return (
                      <div key={lesson.id} className="group bg-slate-950/50 border border-slate-800 rounded-2xl p-5 flex items-center justify-between hover:border-indigo-500/30 hover:bg-slate-900 transition-all shadow-sm">
                        <div className="flex items-center space-x-6 overflow-hidden">
                          <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-lg border transition-all ${lesson.videoUrl ? 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20' : 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'}`}>
                             <i className={`fas ${lesson.videoUrl ? 'fa-play-circle' : 'fa-file-text'}`}></i>
                          </div>
                          <div className="truncate">
                             <h4 className="font-bold text-slate-100 truncate group-hover:text-white transition-colors">{lesson.title}</h4>
                             <div className="flex items-center space-x-2 mt-1">
                                <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration || '00:00'}</span>
                                <span className="text-[9px] font-black text-indigo-400/60 uppercase tracking-widest bg-indigo-500/5 px-2 py-0.5 rounded border border-indigo-500/10 truncate">
                                  {subj?.name || 'Unset'} / {ss?.name || 'Unset'} / {unit?.name || 'Unset'}
                                </span>
                             </div>
                          </div>
                        </div>
                        <div className="flex items-center space-x-3 ml-4">
                           <button onClick={() => setEditingLessonIdx(lessonIdx)} className="px-4 py-2 bg-slate-900 border border-slate-800 text-[9px] font-black text-slate-500 uppercase tracking-widest rounded-lg hover:text-white hover:border-indigo-500/50 transition-all">Edit</button>
                           <button onClick={() => { if (confirm('Purge this unit?')) { const l = currentCourse.lessons!.filter((_, i) => i !== lessonIdx); setCurrentCourse({...currentCourse, lessons: l}); } }} className="w-10 h-10 bg-slate-950 rounded-lg text-slate-800 hover:text-rose-500 flex items-center justify-center border border-slate-800"><i className="fas fa-trash-alt text-sm"></i></button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {activeTab === 'structure' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Subject Architecture</h3>
                  <button type="button" onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">+ Subject Group</button>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {(currentCourse.subjects || []).map((subj, sIdx) => (
                    <div key={subj.id} className={`bg-slate-950 border border-slate-800 rounded-[32px] p-8 space-y-6 transition-all`}>
                      <div className="flex flex-wrap items-center gap-4 relative">
                        <button onClick={() => setIconPickerOpenId(iconPickerOpenId === subj.id ? null : subj.id)} className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl shadow-inner border border-white/5 ${subj.color}`}><i className={`fas ${subj.icon}`}></i></button>
                        <input type="text" value={subj.name} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" placeholder="Subject Name" />
                        <button onClick={() => { const subjs = currentCourse!.subjects!.filter(s => s.id !== subj.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>

                      <div className="pl-12 space-y-6">
                         <div className="flex justify-between items-center">
                            <h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4>
                            <button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 hover:text-white uppercase tracking-widest">+ Add Sub-group</button>
                         </div>
                         <div className="space-y-6">
                           {(subj.subSubjects || []).map((ss, ssIdx) => (
                             <div key={ss.id} className="bg-slate-900/50 border border-slate-800 rounded-[24px] p-6 space-y-4">
                               <div className="flex items-center gap-4">
                                  <input type="text" value={ss.name} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects[ssIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="flex-1 bg-slate-950 border border-slate-800 rounded-xl px-4 py-2 text-slate-300 font-bold text-sm" />
                                  <button onClick={() => addUnit(subj.id, ss.id)} className="text-[8px] font-black text-emerald-400 uppercase tracking-widest">+ Add Unit</button>
                                  <button onClick={() => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects = subjs[sIdx].subSubjects.filter(item => item.id !== ss.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times"></i></button>
                               </div>

                               <div className="pl-8 space-y-3">
                                  <div className="flex justify-between items-center mb-1">
                                    <h5 className="text-[7px] font-black text-slate-600 uppercase tracking-widest">Units & Lessons</h5>
                                  </div>
                                  {(ss.units || []).map((unit, uIdx) => (
                                    <div key={unit.id} className="flex flex-col gap-2 p-3 bg-slate-950 border border-slate-800/50 rounded-xl">
                                       <div className="flex items-center gap-3">
                                          <div className="w-6 h-6 rounded bg-slate-900 flex items-center justify-center text-[10px] text-emerald-500"><i className="fas fa-cube"></i></div>
                                          <input type="text" value={unit.name} onChange={e => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects[ssIdx].units[uIdx].name = e.target.value; setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-400" placeholder="Unit Name" />
                                          <button onClick={() => { setContextSubjectId(subj.id); setContextSubSubjectId(ss.id); setContextUnitId(unit.id); setActiveTab('curriculum'); addLesson(subj.id, ss.id, unit.id); }} className="text-[10px] text-indigo-400 hover:text-white" title="Add lesson to this unit"><i className="fas fa-plus"></i></button>
                                          <button onClick={() => { const subjs = [...currentCourse!.subjects!]; subjs[sIdx].subSubjects[ssIdx].units = ss.units.filter(u => u.id !== unit.id); setCurrentCourse({...currentCourse!, subjects: subjs}); }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                                       </div>
                                       {/* Optional: Show count of lessons in this unit */}
                                       <span className="text-[7px] font-black text-slate-700 uppercase pl-9">
                                          {(currentCourse.lessons || []).filter(l => l.unitId === unit.id).length} Lessons Registered
                                       </span>
                                    </div>
                                  ))}
                               </div>
                             </div>
                           ))}
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Program Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Command center for all system content</p>
        </div>
        <div className="flex space-x-3 w-full md:w-auto">
          <button onClick={() => { setCurrentCourse({ id: Math.random().toString(36).substr(2, 9), title: 'New Program', lessons: [], subjects: [], category: 'Academic', price: 0 }); setIsEditing(true); }} className="flex-1 md:flex-none px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20"><i className="fas fa-plus mr-3"></i> New Entry</button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Content Profile</th>
              <th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                  <div>
                    <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                    <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • {course.lessons.length} Modules</p>
                  </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-40 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800 shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit, Lesson } from '../types';

interface DashboardProps {
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse 
}) => {
  const [selectedSubject, setSelectedSubject] = useState<SubjectGroup | null>(null);
  const [selectedSubSubject, setSelectedSubSubject] = useState<SubSubject | null>(null);
  const [selectedUnit, setSelectedUnit] = useState<Unit | null>(null);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-16 h-16 md:w-24 md:h-24 bg-slate-900 text-indigo-400 rounded-[30px] md:rounded-[40px] flex items-center justify-center mb-8 border border-slate-800">
          <i className="fas fa-rocket text-2xl md:text-3xl"></i>
        </div>
        <h2 className="text-2xl md:text-3xl font-black text-slate-100 mb-4">No active programs</h2>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Explore Catalog</button>
      </div>
    );
  }

  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubject(subj);
    setSelectedSubSubject(null);
    setSelectedUnit(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubject(ss);
    setSelectedUnit(null);
  };

  const handleUnitClick = (unit: Unit) => {
    setSelectedUnit(unit);
  };

  const handleBack = () => {
    if (selectedUnit) {
      setSelectedUnit(null);
    } else if (selectedSubSubject) {
      setSelectedSubSubject(null);
    } else if (selectedSubject) {
      setSelectedSubject(null);
    }
  };

  const filteredLessons = activeCourse.lessons.filter(l => 
    l.subjectId === selectedSubject?.id && 
    l.subSubjectId === selectedSubSubject?.id &&
    l.unitId === selectedUnit?.id
  );

  const uncategorizedLessons = activeCourse.lessons.filter(l => !l.subjectId);

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-5xl mx-auto">
      <div className="bg-slate-900/50 rounded-[32px] border border-slate-800/50 p-8 md:p-12 text-center shadow-2xl backdrop-blur-sm relative overflow-hidden">
        {(selectedSubject || selectedSubSubject || selectedUnit) && (
          <button 
            onClick={handleBack}
            className="absolute left-6 top-1/2 -translate-y-1/2 w-10 h-10 bg-slate-950 border border-slate-800 rounded-full flex items-center justify-center text-slate-400 hover:text-white hover:border-indigo-500/50 transition-all z-10"
          >
            <i className="fas fa-arrow-left text-sm"></i>
          </button>
        )}

        <div className="relative z-10">
          <p className="text-xs md:text-sm font-bold text-slate-400 uppercase tracking-widest mb-2 opacity-80">
            {selectedUnit 
              ? `${selectedSubSubject?.name} • ${selectedUnit.name}`
              : selectedSubSubject 
                ? `${selectedSubject?.name} • ${selectedSubSubject.name}`
                : selectedSubject 
                  ? `Selected Subject: ${selectedSubject.name}` 
                  : 'Course & Content'}
          </p>
          <h1 className="text-2xl md:text-4xl lg:text-5xl font-black text-indigo-400 tracking-tight leading-tight drop-shadow-sm">
            {selectedUnit 
              ? 'Learning Modules' 
              : selectedSubSubject 
                ? 'Select a Unit'
                : selectedSubject 
                  ? selectedSubject.name 
                  : activeCourse.title}
          </h1>
        </div>
        <div className="absolute -top-20 -right-20 w-64 h-64 bg-indigo-600/10 rounded-full blur-[100px]"></div>
      </div>

      <div className="bg-slate-900/30 rounded-[40px] border border-slate-800/40 p-4 md:p-8 lg:p-10 shadow-xl backdrop-blur-sm min-h-[400px]">
        {!selectedSubject ? (
          <div className="space-y-12">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
              {(activeCourse.subjects || []).map((subj) => (
                <button 
                  key={subj.id} 
                  onClick={() => handleSubjectClick(subj)}
                  className="flex items-center justify-between p-4 md:p-5 bg-slate-950 border border-slate-800/50 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-sm"
                >
                  <div className="flex items-center space-x-4">
                    <div className={`w-12 h-12 md:w-14 md:h-14 rounded-xl flex items-center justify-center text-xl md:text-2xl shadow-inner border border-white/5 ${subj.color}`}>
                      <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                    </div>
                    <div className="text-left">
                      <span className="text-lg font-bold text-slate-100 group-hover:text-white transition-colors block">{subj.name}</span>
                      <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{subj.subSubjects.length} Sub-units</span>
                    </div>
                  </div>
                  <div className="w-8 h-8 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center transition-all">
                    <i className="fas fa-chevron-right text-[10px] text-emerald-500"></i>
                  </div>
                </button>
              ))}
            </div>

            {uncategorizedLessons.length > 0 && (
              <div className="space-y-6 pt-10 border-t border-slate-800/50">
                <div className="flex items-center space-x-4">
                  <div className="w-10 h-10 bg-slate-950 border border-slate-800 rounded-xl flex items-center justify-center text-slate-600">
                    <i className="fas fa-folder-open"></i>
                  </div>
                  <h3 className="text-sm font-black text-slate-500 uppercase tracking-[0.2em]">General Modules</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {uncategorizedLessons.map((lesson) => (
                    <button 
                      key={lesson.id} 
                      onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                      className="flex items-center p-5 bg-slate-950/50 border border-slate-800/50 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group"
                    >
                      <div className="flex-1 text-left">
                        <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors text-sm">{lesson.title}</h4>
                        <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : !selectedSubSubject ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-4 duration-300">
            {selectedSubject.subSubjects.map((ss) => (
              <button 
                key={ss.id} 
                onClick={() => handleSubSubjectClick(ss)}
                className="flex items-center justify-between p-4 md:p-5 bg-slate-950 border border-slate-800/50 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group shadow-sm"
              >
                <div className="flex items-center space-x-4">
                  <div className={`w-10 h-10 rounded-lg flex items-center justify-center text-sm bg-slate-900 text-indigo-400`}><i className="fas fa-layer-group"></i></div>
                  <span className="text-base font-bold text-slate-100 group-hover:text-indigo-400 transition-colors">{ss.name}</span>
                </div>
                <div className="w-8 h-8 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center"><i className="fas fa-chevron-right text-[10px] text-indigo-500"></i></div>
              </button>
            ))}
          </div>
        ) : !selectedUnit ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-4 duration-300">
            {selectedSubSubject.units?.map((unit) => (
              <button 
                key={unit.id} 
                onClick={() => handleUnitClick(unit)}
                className="flex items-center justify-between p-4 md:p-5 bg-slate-950 border border-slate-800/50 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group shadow-sm"
              >
                <div className="flex items-center space-x-4">
                  <div className={`w-10 h-10 rounded-lg flex items-center justify-center text-sm bg-slate-900 text-emerald-400`}><i className="fas fa-cube"></i></div>
                  <span className="text-base font-bold text-slate-100 group-hover:text-emerald-400 transition-colors">{unit.name}</span>
                </div>
                <div className="w-8 h-8 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center"><i className="fas fa-chevron-right text-[10px] text-emerald-500"></i></div>
              </button>
            ))}
            {(!selectedSubSubject.units || selectedSubSubject.units.length === 0) && (
              <div className="col-span-full py-20 flex flex-col items-center justify-center text-center opacity-40">
                <i className="fas fa-ghost text-4xl mb-4 text-slate-700"></i>
                <h3 className="text-xl font-black text-white">No units created here</h3>
                <p className="text-xs font-bold text-slate-500 mt-2">Add units to this sub-group in the Admin Panel.</p>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-4 animate-in slide-in-from-right-4 duration-300">
            {filteredLessons.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {filteredLessons.map((lesson, idx) => (
                  <button 
                    key={lesson.id} 
                    onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                    className="flex items-center p-5 bg-slate-950 border border-slate-800/50 rounded-2xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group"
                  >
                    <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-[10px] font-black text-slate-500 border border-slate-800 mr-4 group-hover:text-indigo-400 transition-colors">{idx + 1}</div>
                    <div className="flex-1 text-left">
                      <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors text-sm">{lesson.title}</h4>
                      <div className="flex items-center space-x-3 mt-1">
                        <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                        {lesson.hasAiFeature && <i className="fas fa-sparkles text-[9px] text-indigo-500"></i>}
                      </div>
                    </div>
                    <div className="w-9 h-9 bg-indigo-600/10 rounded-full flex items-center justify-center text-indigo-400 border border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white transition-all">
                      <i className="fas fa-play text-[10px]"></i>
                    </div>
                  </button>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-64 text-center opacity-40">
                <i className="fas fa-folder-open text-4xl mb-4 text-slate-700"></i>
                <h3 className="text-xl font-black text-white">No lessons in this unit</h3>
                <p className="text-xs font-bold text-slate-500 mt-2">Add lessons to this unit in the Admin Panel.</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Course, Lesson } from '../types';

interface CourseDetailsProps {
  course: Course;
  isAdmin: boolean;
  isEnrolled: boolean;
  onEnroll: (courseId: string) => void;
  onAdminEdit: () => void;
  onBack: () => void;
}

const CourseDetails: React.FC<CourseDetailsProps> = ({ course, isAdmin, isEnrolled, onEnroll, onAdminEdit, onBack }) => {
  const [showCheckout, setShowCheckout] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [paymentSuccess, setPaymentSuccess] = useState(false);

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);
    setTimeout(() => {
      setIsProcessing(false);
      setPaymentSuccess(true);
      setTimeout(() => onEnroll(course.id), 1500);
    }, 2000);
  };

  const roadmapItems = course.roadmap && course.roadmap.length > 0 ? course.roadmap : [
    { icon: 'fa-tv', text: `${course.lessons.length} HD Modules` },
    { icon: 'fa-sparkles', text: 'AI Tutoring' },
    { icon: 'fa-file-pdf', text: 'Study Materials' },
    { icon: 'fa-infinity', text: 'Lifetime Access' },
    { icon: 'fa-certificate', text: 'Certification' },
  ];

  return (
    <div className="pb-24 animate-in fade-in duration-700 max-w-7xl mx-auto">
      {/* Stripe Modal */}
      {showCheckout && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-md rounded-[32px] overflow-hidden border border-slate-800 shadow-2xl">
            <div className="p-6 border-b border-slate-800 flex items-center justify-between">
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Secure Payment</span>
              <button onClick={() => setShowCheckout(false)} className="text-slate-500 hover:text-white transition-colors"><i className="fas fa-times"></i></button>
            </div>
            <div className="p-6 text-center">
              {paymentSuccess ? (
                <div className="py-8">
                  <div className="w-16 h-16 bg-emerald-500/10 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-4 text-2xl border border-emerald-500/20"><i className="fas fa-check"></i></div>
                  <h3 className="text-xl font-black text-white">Payment Success!</h3>
                </div>
              ) : (
                <form onSubmit={handlePayment} className="space-y-6">
                  <div className="p-6 bg-indigo-600 rounded-2xl text-white shadow-lg"><p className="text-3xl font-black">${(course.price || 0).toFixed(2)}</p></div>
                  <button disabled={isProcessing} className="w-full py-4 bg-white text-slate-950 rounded-xl font-black uppercase text-xs shadow-xl disabled:opacity-50">
                    {isProcessing ? 'Processing...' : 'Pay Now'}
                  </button>
                </form>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <button onClick={onBack} className="flex items-center space-x-3 text-slate-400 hover:text-white transition-all group">
          <div className="w-8 h-8 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500 transition-all"><i className="fas fa-arrow-left text-xs"></i></div>
          <span className="text-[10px] font-black uppercase tracking-widest">Explore</span>
        </button>
        {isAdmin && <button onClick={onAdminEdit} className="px-4 py-2 text-indigo-400 border border-indigo-900/30 rounded-lg hover:bg-indigo-600/10 transition-all text-[9px] font-black uppercase">Edit Course</button>}
      </div>

