                      <select disabled={!currentLesson.subjectId} value={currentLesson.subSubjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subSubjectId: e.target.value, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20">
                        <option value="">Unassigned Sub-group</option>
                        {currentCourse.subjects?.find(s => s.id === currentLesson.subjectId)?.subSubjects.map(ss => <option key={ss.id} value={ss.id}>{ss.name}</option>)}
                      </select>
                      <select disabled={!currentLesson.subSubjectId} value={currentLesson.unitId || ''} onChange={e => updateLesson(editingLessonIdx!, { unitId: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20">
                        <option value="">Unassigned Unit</option>
                        {currentCourse.subjects?.flatMap(s => s.subSubjects).find(ss => ss.id === currentLesson.subSubjectId)?.units?.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                      </select>
                    </div>
                  </div>
                  <button onClick={() => { if (confirm('Delete lesson?')) { const l = currentCourse.lessons!.filter((_, i) => i !== editingLessonIdx); setCurrentCourse({ ...currentCourse, lessons: l }); setEditingLessonIdx(null); } }} className="w-full py-4 bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all">Delete Module</button>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white text-[10px] font-black uppercase tracking-widest"><i className="fas fa-arrow-left mr-2"></i> Cancel</button>
          <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl">Commit Program</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}>{tab}</button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-10 animate-in fade-in">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Program Title</label>
                      <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({ ...currentCourse!, title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Category</label>
                      <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({ ...currentCourse!, category: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Price ($)</label>
                      <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({ ...currentCourse!, price: parseFloat(e.target.value) })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                    </div>
                  </div>
                  <div className="space-y-6">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Program Thumbnail</label>
                    <div className="aspect-video bg-slate-950 rounded-3xl border border-slate-800 overflow-hidden relative group">
                      {currentCourse.thumbnail ? (
                        <img src={currentCourse.thumbnail} className="w-full h-full object-cover" alt="preview" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-slate-700 font-black uppercase text-[10px]">No Image Selected</div>
                      )}
                      <div className="absolute inset-0 bg-slate-950/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                        <button onClick={() => thumbnailInputRef.current?.click()} className="px-6 py-2 bg-white text-slate-950 rounded-xl font-black text-[9px] uppercase">Replace</button>
                      </div>
                    </div>
                    <input type="file" ref={thumbnailInputRef} className="hidden" accept="image/*" onChange={handleThumbnailUpload} />
                    <input type="text" value={currentCourse.thumbnail || ''} onChange={e => setCurrentCourse({ ...currentCourse!, thumbnail: e.target.value })} placeholder="Thumbnail URL..." className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2 text-[10px] text-slate-500 font-mono" />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Description</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({ ...currentCourse!, description: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed" />
                </div>

                <div className="space-y-6 border-t border-slate-800 pt-10">
                  <div className="flex items-center justify-between">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Program Roadmap Milestones</h3>
                    <button onClick={addRoadmapItem} className="text-[9px] font-black text-indigo-400 uppercase">+ Add Milestone</button>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {currentCourse.roadmap?.map((item, idx) => (
                      <div key={item.id} className="bg-slate-950 border border-slate-800 rounded-2xl p-4 flex items-center space-x-4">
                        <select value={item.icon} onChange={e => updateRoadmapItem(idx, { icon: e.target.value })} className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-slate-400">
                          {ICON_OPTIONS.map(icon => <option key={icon} value={icon}>{icon}</option>)}
                        </select>
                        <input type="text" value={item.text} onChange={e => updateRoadmapItem(idx, { text: e.target.value })} className="flex-1 bg-transparent border-none text-xs font-bold text-white outline-none" />
                        <button onClick={() => setCurrentCourse({ ...currentCourse, roadmap: currentCourse.roadmap?.filter((_, i) => i !== idx) })} className="text-slate-700 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-xl font-black text-white">Registry</h3>
                  <button onClick={() => addLesson()} className="px-6 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl">+ New Module</button>
                </div>
                <div className="space-y-3">
                  {currentCourse.lessons?.map((lesson, idx) => (
                    <div key={lesson.id} className="group bg-slate-950 border border-slate-800 rounded-2xl p-5 flex items-center justify-between hover:bg-slate-900 transition-all">
                      <div className="flex items-center space-x-6">
                        <div className="w-12 h-12 rounded-xl bg-indigo-500/10 text-indigo-400 flex items-center justify-center text-lg border border-indigo-500/20"><i className="fas fa-file-lines"></i></div>
                        <div>
                          <h4 className="font-bold text-slate-100">{lesson.title}</h4>
                          <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                        </div>
                      </div>
                      <div className="flex items-center space-x-3">
                        <button onClick={() => setEditingLessonIdx(idx)} className="px-4 py-2 bg-slate-900 border border-slate-800 text-[9px] font-black text-slate-500 uppercase rounded-lg hover:text-white">Edit</button>
                        <button onClick={() => setCurrentCourse({ ...currentCourse, lessons: currentCourse.lessons?.filter((_, i) => i !== idx) })} className="text-slate-800 hover:text-rose-500 p-2"><i className="fas fa-trash"></i></button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'structure' && (
              <div className="space-y-8 animate-in fade-in">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Architectural Mapping</h3>
                  <button onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase">+ Subject Group</button>
                </div>
                <div className="space-y-6">
                  {currentCourse.subjects?.map((subj, sIdx) => (
                    <div key={subj.id} className="bg-slate-950 border border-slate-800 rounded-[32px] p-8 space-y-6">
                      <div className="flex items-center gap-4">
                        <button onClick={() => setIconPickerOpenId(iconPickerOpenId === subj.id ? null : subj.id)} className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl shadow-inner border border-white/5 ${subj.color}`}><i className={`fas ${subj.icon}`}></i></button>
                        <input type="text" value={subj.name} onChange={e => { const subjs = [...currentCourse.subjects!]; subjs[sIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: subjs }); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" />
                        <button onClick={() => setCurrentCourse({ ...currentCourse, subjects: currentCourse.subjects?.filter(s => s.id !== subj.id) })} className="text-slate-800 hover:text-rose-500"><i className="fas fa-trash"></i></button>
                      </div>
                      {iconPickerOpenId === subj.id && (
                        <div className="p-4 bg-slate-900 rounded-2xl grid grid-cols-8 gap-2">
                          {ICON_OPTIONS.slice(0, 32).map(icon => <button key={icon} onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].icon = icon; setCurrentCourse({ ...currentCourse, subjects: s }); setIconPickerOpenId(null); }} className="p-2 hover:bg-slate-800 rounded-lg text-slate-500"><i className={`fas ${icon}`}></i></button>)}
                        </div>
                      )}
                      <div className="pl-12 space-y-6">
                        <div className="flex justify-between items-center"><h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4><button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">+ Add Sub-group</button></div>
                        <div className="space-y-6">
                          {subj.subSubjects?.map((ss, ssIdx) => (
                            <div key={ss.id} className="bg-slate-900/50 border border-slate-800 rounded-[24px] p-6 space-y-4">
                              <div className="flex items-center gap-4">
                                <input type="text" value={ss.name} onChange={e => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: s }); }} className="flex-1 bg-slate-950 border border-slate-800 rounded-xl px-4 py-2 text-slate-300 font-bold text-sm" />
                                <button onClick={() => addUnit(subj.id, ss.id)} className="text-[8px] font-black text-emerald-400 uppercase tracking-widest">+ Unit</button>
                                <button onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects = s[sIdx].subSubjects.filter(i => i.id !== ss.id); setCurrentCourse({ ...currentCourse, subjects: s }); }} className="text-slate-700 hover:text-rose-500"><i className="fas fa-times"></i></button>
                              </div>
                              <div className="pl-8 space-y-3">
                                {ss.units?.map((unit, uIdx) => (
                                  <div key={unit.id} className="flex items-center gap-3 bg-slate-950 border border-slate-800/50 rounded-xl px-3 py-2">
                                    <div className="w-6 h-6 rounded bg-slate-900 flex items-center justify-center text-[10px] text-emerald-500"><i className="fas fa-cube"></i></div>
                                    <input type="text" value={unit.name} onChange={e => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].units[uIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: s }); }} className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-400" />
                                    <button onClick={() => addLesson(subj.id, ss.id, unit.id)} className="text-[10px] text-indigo-400 hover:text-white"><i className="fas fa-plus"></i></button>
                                    <button onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].units = ss.units.filter(u => u.id !== unit.id); setCurrentCourse({ ...currentCourse, subjects: s }); }} className="text-slate-800 hover:text-rose-500"><i className="fas fa-times text-[10px]"></i></button>
                                  </div>
                                ))}
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div><h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Registry</h1><p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Central Content Hub</p></div>
        <button onClick={() => { setCurrentCourse({ id: Math.random().toString(36).substr(2, 9), title: 'New Program', lessons: [], subjects: [], category: 'Academic', price: 0, roadmap: [] }); setIsEditing(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-xl"><i className="fas fa-plus mr-3"></i> New Entry</button>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr><th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Profile</th><th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Action</th></tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8"><h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors">{course.title}</h4><p className="text-[9px] text-slate-600 font-black uppercase mt-1">{course.category} • ${course.price}</p></td>
                <td className="px-10 py-8 text-right"><div className="flex items-center justify-end space-x-3"><button onClick={() => { setCurrentCourse({ ...course }); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-indigo-400 flex items-center justify-center border border-slate-800"><i className="fas fa-edit text-sm"></i></button><button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-600 hover:text-rose-500 flex items-center justify-center border border-slate-800"><i className="fas fa-trash text-sm"></i></button></div></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, Resource, QuizQuestion, RoadmapItem } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe', 'fa-award', 'fa-certificate'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse || !currentCourse.id) return;

    const finalCourse: Course = {
      id: currentCourse.id,
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || []
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      setCurrentCourse(prev => ({ ...prev, thumbnail: event.target?.result as string }));
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      if (editingLessonIdx !== null) {
        updateLesson(editingLessonIdx, { videoUrl: event.target?.result as string });
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      quiz: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addQuizQuestion = () => {
    if (editingLessonIdx === null) return;
    const currentQuiz = currentCourse?.lessons?.[editingLessonIdx].quiz || [];
    const newQuestion: QuizQuestion = {
      id: Math.random().toString(36).substr(2, 9),
      question: 'New Question?',
      options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
      correctAnswer: 0
    };
    updateLesson(editingLessonIdx, { quiz: [...currentQuiz, newQuestion] });
  };

  const updateQuizQuestion = (qIdx: number, updates: Partial<QuizQuestion>) => {
    if (editingLessonIdx === null) return;
    const currentQuiz = [...(currentCourse?.lessons?.[editingLessonIdx].quiz || [])];
    currentQuiz[qIdx] = { ...currentQuiz[qIdx], ...updates };
    updateLesson(editingLessonIdx, { quiz: currentQuiz });
  };

  const removeQuizQuestion = (qIdx: number) => {
    if (editingLessonIdx === null) return;
    const currentQuiz = (currentCourse?.lessons?.[editingLessonIdx].quiz || []).filter((_, i) => i !== qIdx);
    updateLesson(editingLessonIdx, { quiz: currentQuiz });
  };

  const addRoadmapItem = () => {
    const newItem: RoadmapItem = { id: Math.random().toString(36).substr(2, 9), icon: 'fa-star', text: 'New Milestone' };
    setCurrentCourse(prev => ({ ...prev, roadmap: [...(prev?.roadmap || []), newItem] }));
  };

  const updateRoadmapItem = (idx: number, updates: Partial<RoadmapItem>) => {
    setCurrentCourse(prev => {
      if (!prev?.roadmap) return prev;
      const roadmap = [...prev.roadmap];
      roadmap[idx] = { ...roadmap[idx], ...updates };
      return { ...prev, roadmap };
    });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = { id: Math.random().toString(36).substr(2, 9), name: 'New Subject', icon: 'fa-book', color: COLOR_PRESETS[0], subSubjects: [] };
    setCurrentCourse(prev => ({ ...prev, subjects: [...(prev?.subjects || []), newSubj] }));
  };

  const addSubSubject = (subjectId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjectId ? { ...s, subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group', units: [] }] } : s)
    }));
  };

  const addUnit = (subjId: string, ssId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjId ? { 
        ...s, 
        subSubjects: s.subSubjects.map(ss => ss.id === ssId ? { ...ss, units: [...(ss.units || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Unit' }] } : ss) 
      } : s)
    }));
  };

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">

        {isEditingLesson && currentLesson && (
