            <div className="max-w-5xl mx-auto w-full space-y-8">
              <div className="flex items-center justify-between border-b border-slate-800 pb-8">
                <div className="flex items-center space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all"><i className="fas fa-arrow-left"></i></button>
                  <h2 className="text-3xl font-black text-white">Module Studio</h2>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl">Apply Changes</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                <div className="lg:col-span-8 space-y-8">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="md:col-span-2 space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Title</label>
                        <input type="text" value={currentLesson.title} onChange={e => updateLesson(editingLessonIdx!, { title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Length</label>
                        <input type="text" value={currentLesson.duration} onChange={e => updateLesson(editingLessonIdx!, { duration: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                      </div>
                    </div>

                    <div className="space-y-4 pt-4 border-t border-slate-800">
                      <div className="flex items-center justify-between">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Video Source</label>
                        <button onClick={() => videoInputRef.current?.click()} className="px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">
                          {isUploading ? 'Uploading...' : <><i className="fas fa-upload mr-2"></i>Upload Video</>}
                        </button>
                        <input type="file" ref={videoInputRef} onChange={handleVideoUpload} className="hidden" accept="video/*" />
                      </div>
                      <input type="text" value={currentLesson.videoUrl || ''} onChange={e => updateLesson(editingLessonIdx!, { videoUrl: e.target.value })} placeholder="Paste video URL or upload file..." className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 font-mono text-xs" />
                    </div>
                  </div>

                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 ml-1">Lesson Content (HTML)</h3>
                    <textarea rows={12} value={currentLesson.content} onChange={e => updateLesson(editingLessonIdx!, { content: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-300 font-mono text-xs leading-relaxed outline-none focus:border-indigo-500/50 transition-all" />
                  </div>

                  {/* Quiz Builder */}
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <div className="flex items-center justify-between">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Knowledge Check (Quiz)</h3>
                       <button onClick={addQuizQuestion} className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg">+ New Question</button>
                    </div>

                    <div className="space-y-6">
                      {(currentLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="p-6 bg-slate-950 border border-slate-800 rounded-2xl space-y-4 relative group">
                          <button onClick={() => removeQuizQuestion(qIdx)} className="absolute top-4 right-4 text-slate-800 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100"><i className="fas fa-trash-alt"></i></button>

                          <div className="space-y-2">
                             <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Question {qIdx + 1}</label>
                             <input type="text" value={q.question} onChange={e => updateQuizQuestion(qIdx, { question: e.target.value })} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-slate-100 font-bold text-sm" />
                          </div>

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {q.options.map((opt, oIdx) => (
                              <div key={oIdx} className="flex items-center space-x-3 bg-slate-900/50 p-2 rounded-xl border border-slate-800">
                                <input 
                                  type="radio" 
                                  name={`correct-${q.id}`} 
                                  checked={q.correctAnswer === oIdx} 
                                  onChange={() => updateQuizQuestion(qIdx, { correctAnswer: oIdx })}
                                  className="w-4 h-4 text-indigo-600 bg-slate-900 border-slate-800 focus:ring-indigo-500"
                                />
                                <input 
                                  type="text" 
                                  value={opt} 
                                  onChange={e => {
                                    const opts = [...q.options];
                                    opts[oIdx] = e.target.value;
                                    updateQuizQuestion(qIdx, { options: opts });
                                  }}
                                  className="flex-1 bg-transparent border-none focus:ring-0 text-xs text-slate-400 font-medium"
                                />
                              </div>
                            ))}
                          </div>
                        </div>
                      ))}
                      {(!currentLesson.quiz || currentLesson.quiz.length === 0) && (
                        <div className="py-10 text-center border-2 border-dashed border-slate-800 rounded-2xl opacity-40">
                          <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">No questions added yet</p>
                        </div>
                      )}
                    </div>
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-8">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Anchoring</h3>
                    <div className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Subject</label>
                        <select value={currentLesson.subjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value, subSubjectId: undefined, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 outline-none">
                          <option value="">Unassigned</option>
                          {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Sub-group</label>
                        <select disabled={!currentLesson.subjectId} value={currentLesson.subSubjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subSubjectId: e.target.value, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20 outline-none">
                          <option value="">No sub-group</option>
                          {currentCourse.subjects?.find(s => s.id === currentLesson.subjectId)?.subSubjects.map(ss => <option key={ss.id} value={ss.id}>{ss.name}</option>)}
                        </select>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Unit</label>
                        <select disabled={!currentLesson.subSubjectId} value={currentLesson.unitId || ''} onChange={e => updateLesson(editingLessonIdx!, { unitId: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20 outline-none">
                          <option value="">No unit</option>
                          {currentCourse.subjects?.flatMap(s => s.subSubjects).find(ss => ss.id === currentLesson.subSubjectId)?.units?.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                      </div>
                    </div>
                  </div>
                  <button onClick={() => { if (confirm('Delete lesson?')) { const l = currentCourse.lessons!.filter((_, i) => i !== editingLessonIdx); setCurrentCourse({ ...currentCourse, lessons: l }); setEditingLessonIdx(null); } }} className="w-full py-4 bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all shadow-lg">Delete Module</button>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white text-[10px] font-black uppercase tracking-widest transition-colors"><i className="fas fa-arrow-left mr-2"></i> Return to Registry</button>
          <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">Commit Program</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}>{tab}</button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-10 animate-in fade-in duration-300">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                      <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({ ...currentCourse!, title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                      <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({ ...currentCourse!, category: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Price ($)</label>
                      <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({ ...currentCourse!, price: parseFloat(e.target.value) })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold" />
                    </div>
                  </div>
                  <div className="space-y-6">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Thumbnail</label>
                    <div className="aspect-video bg-slate-950 rounded-3xl border border-slate-800 overflow-hidden relative group">
                      {currentCourse.thumbnail ? (
                        <img src={currentCourse.thumbnail} className="w-full h-full object-cover" alt="preview" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-slate-700 font-black uppercase text-[10px]">No Image Selected</div>
                      )}
                      <div className="absolute inset-0 bg-slate-950/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                        <button onClick={() => thumbnailInputRef.current?.click()} className="px-6 py-2 bg-white text-slate-950 rounded-xl font-black text-[9px] uppercase">Replace Cover</button>
                      </div>
                    </div>
                    <input type="file" ref={thumbnailInputRef} className="hidden" accept="image/*" onChange={handleThumbnailUpload} />
                    <input type="text" value={currentCourse.thumbnail || ''} onChange={e => setCurrentCourse({ ...currentCourse!, thumbnail: e.target.value })} placeholder="Thumbnail URL..." className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2 text-[10px] text-slate-500 font-mono focus:border-indigo-500 outline-none" />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Description</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({ ...currentCourse!, description: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed outline-none focus:border-indigo-500/50" />
                </div>

                <div className="space-y-6 border-t border-slate-800 pt-10">
                  <div className="flex items-center justify-between">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Success Roadmap</h3>
                    <button onClick={addRoadmapItem} className="text-[9px] font-black text-indigo-400 uppercase tracking-widest hover:text-white transition-colors">+ Add Milestone</button>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {currentCourse.roadmap?.map((item, idx) => (
                      <div key={item.id} className="bg-slate-950 border border-slate-800 rounded-2xl p-4 flex items-center space-x-4 group">
                        <select value={item.icon} onChange={e => updateRoadmapItem(idx, { icon: e.target.value })} className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-slate-400 outline-none">
                          {ICON_OPTIONS.map(icon => <option key={icon} value={icon}>{icon}</option>)}
                        </select>
                        <input type="text" value={item.text} onChange={e => updateRoadmapItem(idx, { text: e.target.value })} className="flex-1 bg-transparent border-none text-xs font-bold text-white outline-none" />
                        <button onClick={() => setCurrentCourse({ ...currentCourse, roadmap: currentCourse.roadmap?.filter((_, i) => i !== idx) })} className="text-slate-800 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100"><i className="fas fa-trash"></i></button>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in duration-300">
                <div className="flex justify-between items-center mb-6">
                   <div>
                    <h3 className="text-xl font-black text-white tracking-tight">Academic Registry</h3>
                    <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-1">{currentCourse.lessons?.length || 0} Learning Modules Registered</p>
                   </div>
                  <button onClick={() => addLesson()} className="px-6 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20">+ Add New Module</button>
                </div>
                <div className="space-y-3">
                  {currentCourse.lessons?.map((lesson, idx) => {
                     const subj = currentCourse.subjects?.find(s => s.id === lesson.subjectId);
                     const ss = subj?.subSubjects.find(s => s.id === lesson.subSubjectId);
                     const unit = ss?.units.find(u => u.id === lesson.unitId);
                     return (
                      <div key={lesson.id} className="group bg-slate-950 border border-slate-800 rounded-2xl p-5 flex items-center justify-between hover:border-indigo-500/30 hover:bg-slate-900 transition-all">
                        <div className="flex items-center space-x-6 overflow-hidden">
                          <div className="w-12 h-12 rounded-xl bg-indigo-500/10 text-indigo-400 flex items-center justify-center text-lg border border-indigo-500/20 group-hover:scale-105 transition-transform"><i className={`fas ${lesson.videoUrl ? 'fa-play-circle' : 'fa-file-lines'}`}></i></div>
                          <div className="truncate">
                            <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors truncate">{lesson.title}</h4>
                            <div className="flex items-center space-x-3 mt-1">
                               <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration || '00:00'}</span>
                               <span className="text-[8px] font-black text-indigo-400/50 uppercase tracking-widest bg-indigo-500/5 px-2 py-0.5 rounded truncate">
                                  {subj?.name || 'Unset'} / {ss?.name || 'Unset'} / {unit?.name || 'Unset'}
                               </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center space-x-3 ml-4">
                          <button onClick={() => setEditingLessonIdx(idx)} className="px-4 py-2 bg-slate-900 border border-slate-800 text-[9px] font-black text-slate-500 uppercase tracking-widest rounded-lg hover:text-white hover:border-indigo-500 transition-all shadow-sm">Edit</button>
                          <button onClick={() => setCurrentCourse({ ...currentCourse, lessons: currentCourse.lessons?.filter((_, i) => i !== idx) })} className="text-slate-800 hover:text-rose-500 p-2 transition-colors"><i className="fas fa-trash"></i></button>
                        </div>
                      </div>
                     );
                  })}
                </div>
              </div>
            )}

            {activeTab === 'structure' && (
              <div className="space-y-8 animate-in fade-in duration-300">
