                  <button onClick={addSubject} className="px-5 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 rounded-xl text-[9px] font-black uppercase tracking-widest">+ Subject Group</button>
                </div>
                <div className="space-y-6">
                  {currentCourse.subjects?.map((subj, sIdx) => (
                    <div key={subj.id} className="bg-slate-950 border border-slate-800 rounded-[32px] p-8 space-y-6">
                      <div className="flex items-center gap-4">
                        <button onClick={() => setIconPickerOpenId(iconPickerOpenId === subj.id ? null : subj.id)} className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl shadow-inner border border-white/5 ${subj.color}`}><i className={`fas ${subj.icon}`}></i></button>
                        <input type="text" value={subj.name} onChange={e => { const subjs = [...currentCourse.subjects!]; subjs[sIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: subjs }); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold" />
                        <button onClick={() => setCurrentCourse({ ...currentCourse, subjects: currentCourse.subjects?.filter(s => s.id !== subj.id) })} className="text-slate-800 hover:text-rose-500 transition-colors"><i className="fas fa-trash"></i></button>
                      </div>
                      {iconPickerOpenId === subj.id && (
                        <div className="p-4 bg-slate-900 rounded-2xl grid grid-cols-8 gap-2 animate-in slide-in-from-top-2">
                          {ICON_OPTIONS.slice(0, 32).map(icon => <button key={icon} onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].icon = icon; setCurrentCourse({ ...currentCourse, subjects: s }); setIconPickerOpenId(null); }} className="p-2 hover:bg-slate-800 rounded-lg text-slate-500 transition-colors"><i className={`fas ${icon}`}></i></button>)}
                        </div>
                      )}
                      <div className="pl-12 space-y-6">
                        <div className="flex justify-between items-center"><h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4><button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 uppercase tracking-widest hover:text-white transition-colors">+ Add Sub-group</button></div>
                        <div className="space-y-6">
                          {subj.subSubjects?.map((ss, ssIdx) => (
                            <div key={ss.id} className="bg-slate-900/50 border border-slate-800 rounded-[24px] p-6 space-y-4">
                              <div className="flex items-center gap-4">
                                <input type="text" value={ss.name} onChange={e => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: s }); }} className="flex-1 bg-slate-950 border border-slate-800 rounded-xl px-4 py-2 text-slate-300 font-bold text-sm" />
                                <button onClick={() => addUnit(subj.id, ss.id)} className="text-[8px] font-black text-emerald-400 uppercase tracking-widest hover:text-white transition-colors">+ Unit</button>
                                <button onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects = s[sIdx].subSubjects.filter(i => i.id !== ss.id); setCurrentCourse({ ...currentCourse, subjects: s }); }} className="text-slate-700 hover:text-rose-500 p-1"><i className="fas fa-times"></i></button>
                              </div>
                              <div className="pl-8 space-y-3">
                                {ss.units?.map((unit, uIdx) => (
                                  <div key={unit.id} className="flex items-center gap-3 bg-slate-950 border border-slate-800/50 rounded-xl px-3 py-2 group">
                                    <div className="w-6 h-6 rounded bg-slate-900 flex items-center justify-center text-[10px] text-emerald-500 border border-slate-800"><i className="fas fa-cube"></i></div>
                                    <input type="text" value={unit.name} onChange={e => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].units[uIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: s }); }} className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-400" />
                                    <button onClick={() => addLesson(subj.id, ss.id, unit.id)} className="text-[10px] text-indigo-400 hover:text-white opacity-0 group-hover:opacity-100 transition-opacity"><i className="fas fa-plus"></i></button>
                                    <button onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].units = ss.units.filter(u => u.id !== unit.id); setCurrentCourse({ ...currentCourse, subjects: s }); }} className="text-slate-800 hover:text-rose-500 transition-colors"><i className="fas fa-times text-[10px]"></i></button>
                                  </div>
                                ))}
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
