import React, { useState, useEffect, useRef } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  const activeLessonIndex = course.lessons.findIndex(l => l.id === activeLessonId);
  const activeLesson = course.lessons[activeLessonIndex] || course.lessons[0];

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    if (initialLessonId) {
      setActiveLessonId(initialLessonId);
    }
  }, [initialLessonId]);

  // Reset quiz state when active lesson changes
  useEffect(() => {
    resetQuiz();
    if (videoRef.current) videoRef.current.load();
  }, [activeLessonId]);

  const resetQuiz = () => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
  };

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
    }
  };

  const isAdmin = user.role === 'admin';

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30">
          <div className="flex items-center space-x-3">
            <button onClick={onBack} className="w-9 h-9 rounded-lg bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <h2 className="text-xs font-black text-slate-500 uppercase tracking-widest">{course.title}</h2>
              <p className="text-sm font-bold text-white truncate max-w-[200px]">{activeLesson.title}</p>
            </div>
          </div>
          <button 
            onClick={() => setIsAiOpen(!isAiOpen)} 
            className={`px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${isAiOpen ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-900 text-slate-500 border border-slate-800'}`}
          >
            <i className="fas fa-robot mr-2"></i>AI Assistant
          </button>
        </nav>

        <div className="flex-1 p-4 md:p-10 max-w-5xl mx-auto w-full space-y-8">
          {activeLesson.videoUrl ? (
            <div className="bg-black rounded-2xl md:rounded-3xl overflow-hidden aspect-video border border-slate-800 shadow-2xl relative group">
              <video key={activeLesson.id} ref={videoRef} src={activeLesson.videoUrl} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-slate-900/50 rounded-2xl md:rounded-3xl border border-dashed border-slate-800 py-16 flex flex-col items-center justify-center text-center">
              <div className="w-16 h-16 bg-indigo-600/10 text-indigo-400 rounded-2xl flex items-center justify-center text-2xl mb-4 border border-indigo-600/20 shadow-inner">
                <i className="fas fa-book-open"></i>
              </div>
              <h3 className="text-xl font-black text-white">Reading Material</h3>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mt-1">This module is focused on text content</p>
            </div>
          )}

          <div className="flex border-b border-slate-800 space-x-6 overflow-x-auto no-scrollbar">
            <button onClick={() => setActiveTab('overview')} className={`pb-3 whitespace-nowrap text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}>Overview</button>
            {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={() => setActiveTab('quiz')} className={`pb-3 whitespace-nowrap text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent'}`}>Knowledge Check</button>}
            {isAdmin && <button onClick={() => setActiveTab('notes')} className={`pb-3 whitespace-nowrap text-xs font-black uppercase border-b-2 transition-all ${activeTab === 'notes' ? 'text-emerald-400 border-emerald-500' : 'text-slate-600 border-transparent'}`}>Instructor Notes</button>}
          </div>

          <div className="min-h-[300px] pb-20 md:pb-0">
            {activeTab === 'overview' && (
              <div className="animate-in fade-in duration-300">
                <div className="prose prose-invert max-w-none text-slate-300 leading-relaxed" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                {activeLesson.resources && activeLesson.resources.length > 0 && (
                  <div className="mt-12 space-y-4 pt-8 border-t border-slate-800">
                    <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Supplemental Materials</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                      {activeLesson.resources.map(res => (
                        <a key={res.id} href={res.url} target="_blank" rel="noopener noreferrer" className="flex items-center p-4 bg-slate-900 border border-slate-800 rounded-xl hover:border-indigo-500/50 transition-all group">
                          <div className="w-8 h-8 rounded-lg bg-slate-950 flex items-center justify-center text-xs text-indigo-400 mr-3 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                            <i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play' : res.type === 'zip' ? 'fa-file-zipper' : 'fa-link'}`}></i>
                          </div>
                          <span className="text-xs font-bold text-slate-200">{res.title}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-6 max-w-xl animate-in fade-in slide-in-from-right-4 duration-300">
                {quizState.complete ? (
                  <div className="p-10 bg-slate-900 border border-slate-800 rounded-3xl text-center shadow-xl">
                    <div className="w-20 h-20 bg-emerald-500/10 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6 text-3xl border border-emerald-500/20 shadow-inner">
                      <i className="fas fa-award"></i>
                    </div>
                    <h3 className="text-2xl font-black text-white mb-2">Assessment Finished</h3>
                    <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mb-10">Neural Accuracy: {Math.round((quizState.score/activeLesson.quiz.length)*100)}% ({quizState.score}/{activeLesson.quiz.length})</p>

                    <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                      <button onClick={resetQuiz} className="w-full sm:w-auto px-8 py-3 bg-slate-800 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-700 transition-all">Retake Assessment</button>
                      <button onClick={() => setActiveTab('overview')} className="w-full sm:w-auto px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-600/20">Resume Study</button>
                    </div>
                  </div>
                ) : (
                  <div key={quizState.currentIdx} className="space-y-6 animate-in slide-in-from-right-8 duration-300">
                    <div className="flex justify-between items-center">
                      <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Question {quizState.currentIdx + 1} of {activeLesson.quiz.length}</p>
                      <div className="w-32 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-indigo-500 transition-all duration-500" 
                          style={{ width: `${((quizState.currentIdx + 1) / activeLesson.quiz.length) * 100}%` }}
                        ></div>
                      </div>
                    </div>
                    <h4 className="text-xl md:text-2xl font-black text-white leading-tight">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-4 pt-4">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button 
                          key={i} 
                          onClick={() => handleQuizAnswer(i)} 
                          className="w-full p-5 bg-slate-900 border border-slate-800 rounded-2xl text-left hover:border-indigo-500 hover:bg-slate-800/50 transition-all font-bold text-sm text-slate-200 group flex items-center"
                        >
                          <span className="w-6 h-6 rounded-lg bg-slate-950 border border-slate-800 flex items-center justify-center mr-4 text-[10px] group-hover:bg-indigo-600 group-hover:text-white transition-all">{String.fromCharCode(65 + i)}</span>
                          {opt}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'notes' && isAdmin && (
              <div className="animate-in slide-in-from-top-4 duration-300 p-8 bg-emerald-500/5 border border-emerald-500/20 rounded-3xl">
                <div className="flex items-center space-x-3 mb-6">
                  <div className="w-10 h-10 bg-emerald-500/10 text-emerald-400 rounded-xl flex items-center justify-center border border-emerald-500/20 shadow-inner">
                    <i className="fas fa-clipboard-check"></i>
                  </div>
                  <h3 className="text-lg font-black text-emerald-400 uppercase tracking-widest">Instructor Guidance</h3>
                </div>
                <div className="text-emerald-200/80 leading-relaxed text-sm italic whitespace-pre-wrap">
                  {activeLesson.instructorNotes || 'No specific guidance recorded for this module. Admins can update this in the Registry Control Panel.'}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer Navigation */}
        <div className="mt-auto p-4 md:p-6 border-t border-slate-800 bg-slate-950/50 flex justify-between items-center sticky bottom-0 z-30 shadow-[0_-10px_30px_rgba(0,0,0,0.5)]">
          <button disabled={activeLessonIndex === 0} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex - 1].id)} className="px-5 py-2.5 bg-slate-900 border border-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest disabled:opacity-20 hover:text-white transition-all"><i className="fas fa-chevron-left mr-2"></i>Prev</button>
          <div className="flex space-x-2 overflow-x-auto px-2 max-w-[150px] no-scrollbar">
            {course.lessons.map(l => (
              <button 
                key={l.id} 
                onClick={() => setActiveLessonId(l.id)}
                className={`w-2 h-2 rounded-full flex-shrink-0 transition-all duration-500 ${l.id === activeLessonId ? 'bg-indigo-500 w-6 shadow-[0_0_10px_rgba(99,102,241,0.5)]' : 'bg-slate-800 hover:bg-slate-700'}`}
              ></button>
            ))}
          </div>
          <button disabled={activeLessonIndex === course.lessons.length - 1} onClick={() => setActiveLessonId(course.lessons[activeLessonIndex + 1].id)} className="px-5 py-2.5 bg-indigo-600 border border-indigo-500/20 rounded-xl text-[10px] font-black uppercase tracking-widest disabled:opacity-20 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-600/20 text-white">Next<i className="fas fa-chevron-right ml-2"></i></button>
        </div>
      </div>

      {/* AI Panel */}
      <aside className={`fixed lg:relative bottom-0 right-0 w-full lg:w-[400px] h-[80vh] lg:h-full bg-slate-950 border-t lg:border-t-0 lg:border-l border-slate-800 z-[40] transition-transform duration-300 transform ${isAiOpen ? 'translate-y-0 lg:translate-x-0 shadow-2xl' : 'translate-y-full lg:translate-x-full lg:hidden'}`}>
        <div className="flex flex-col h-full relative">
          <button onClick={() => setIsAiOpen(false)} className="lg:hidden absolute top-4 right-4 z-50 text-slate-500 text-lg p-2"><i className="fas fa-times"></i></button>
          <AIAssistant course={course} lesson={activeLesson} user={user} />
        </div>
      </aside>
    </div>
  );
};

export default CourseView;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, Resource, QuizQuestion, RoadmapItem } from '../types';
import { generateCourseOutline } from '../services/geminiService';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe', 'fa-award', 'fa-certificate'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse || !currentCourse.id) return;

    const finalCourse: Course = {
      id: currentCourse.id,
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || []
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      setCurrentCourse(prev => ({ ...prev, thumbnail: event.target?.result as string }));
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      if (editingLessonIdx !== null) {
        updateLesson(editingLessonIdx, { videoUrl: event.target?.result as string });
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      quiz: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addQuizQuestion = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      const newQuestion: QuizQuestion = {
        id: Math.random().toString(36).substr(2, 9),
        question: 'New Question?',
        options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
        correctAnswer: 0
      };

      lesson.quiz = [...currentQuiz, newQuestion];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateQuizQuestion = (qIdx: number, updates: Partial<QuizQuestion>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      currentQuiz[qIdx] = { ...currentQuiz[qIdx], ...updates };

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeQuizQuestion = (qIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = (lesson.quiz || []).filter((_, i) => i !== qIdx);

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const addRoadmapItem = () => {
    const newItem: RoadmapItem = { id: Math.random().toString(36).substr(2, 9), icon: 'fa-star', text: 'New Milestone' };
    setCurrentCourse(prev => ({ ...prev, roadmap: [...(prev?.roadmap || []), newItem] }));
  };

  const updateRoadmapItem = (idx: number, updates: Partial<RoadmapItem>) => {
    setCurrentCourse(prev => {
      if (!prev?.roadmap) return prev;
      const roadmap = [...prev.roadmap];
      roadmap[idx] = { ...roadmap[idx], ...updates };
      return { ...prev, roadmap };
    });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = { id: Math.random().toString(36).substr(2, 9), name: 'New Subject', icon: 'fa-book', color: COLOR_PRESETS[0], subSubjects: [] };
    setCurrentCourse(prev => ({ ...prev, subjects: [...(prev?.subjects || []), newSubj] }));
  };

  const addSubSubject = (subjectId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjectId ? { ...s, subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group', units: [] }] } : s)
    }));
  };

  const addUnit = (subjId: string, ssId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjId ? { 
        ...s, 
        subSubjects: s.subSubjects.map(ss => ss.id === ssId ? { ...ss, units: [...(ss.units || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Unit' }] } : ss) 
      } : s)
    }));
  };

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-20 animate-in fade-in duration-500">

        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto flex flex-col p-6 md:p-12 animate-in slide-in-from-right-8 duration-500">
            <div className="max-w-5xl mx-auto w-full space-y-8">
              <div className="flex items-center justify-between border-b border-slate-800 pb-8">
                <div className="flex items-center space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all"><i className="fas fa-arrow-left"></i></button>
                  <h2 className="text-3xl font-black text-white tracking-tight">Module Architect</h2>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Done & Close</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                <div className="lg:col-span-8 space-y-8">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="md:col-span-2 space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Module Title</label>
                        <input type="text" value={currentLesson.title} onChange={e => updateLesson(editingLessonIdx!, { title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none transition-all" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Length (EST)</label>
                        <input type="text" value={currentLesson.duration} onChange={e => updateLesson(editingLessonIdx!, { duration: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none transition-all" />
                      </div>
                    </div>

                    <div className="space-y-4 pt-4 border-t border-slate-800">
                      <div className="flex items-center justify-between">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Video Resource</label>
                        <button onClick={() => videoInputRef.current?.click()} className="px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">
                          {isUploading ? 'Synchronizing...' : <><i className="fas fa-upload mr-2"></i>Upload File</>}
                        </button>
                        <input type="file" ref={videoInputRef} onChange={handleVideoUpload} className="hidden" accept="video/*" />
                      </div>
                      <input type="text" value={currentLesson.videoUrl || ''} onChange={e => updateLesson(editingLessonIdx!, { videoUrl: e.target.value })} placeholder="Neural link or local source..." className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 font-mono text-xs focus:border-indigo-500 outline-none transition-all" />
                    </div>
                  </div>

                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 ml-1">Academic Content (HTML)</h3>
                    <textarea rows={12} value={currentLesson.content} onChange={e => updateLesson(editingLessonIdx!, { content: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-300 font-mono text-xs leading-relaxed outline-none focus:border-indigo-500/30 transition-all" />
                  </div>

                  {/* Quiz Builder */}
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6 shadow-sm">
                    <div className="flex items-center justify-between">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Assessment Engine</h3>
                       <button onClick={addQuizQuestion} className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all">+ New Question</button>
                    </div>

                    <div className="space-y-6">
                      {(currentLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="p-6 bg-slate-950 border border-slate-800 rounded-3xl space-y-4 relative group animate-in slide-in-from-bottom-2">
                          <button onClick={() => removeQuizQuestion(qIdx)} className="absolute top-4 right-4 text-slate-800 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100 p-2"><i className="fas fa-trash-alt"></i></button>

                          <div className="space-y-2">
                             <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Question {qIdx + 1}</label>
                             <input type="text" value={q.question} onChange={e => updateQuizQuestion(qIdx, { question: e.target.value })} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-slate-100 font-bold text-sm focus:border-indigo-500 outline-none" />
                          </div>

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {q.options.map((opt, oIdx) => (
                              <div key={oIdx} className={`flex items-center space-x-3 p-3 rounded-xl border transition-all ${q.correctAnswer === oIdx ? 'bg-indigo-600/10 border-indigo-500/50' : 'bg-slate-900/50 border-slate-800'}`}>
                                <input 
                                  type="radio" 
                                  name={`correct-${q.id}`} 
                                  checked={q.correctAnswer === oIdx} 
                                  onChange={() => updateQuizQuestion(qIdx, { correctAnswer: oIdx })}
                                  className="w-4 h-4 text-indigo-600 bg-slate-950 border-slate-800 focus:ring-indigo-500"
                                />
                                <input 
                                  type="text" 
                                  value={opt} 
                                  onChange={e => {
                                    const opts = [...q.options];
                                    opts[oIdx] = e.target.value;
                                    updateQuizQuestion(qIdx, { options: opts });
                                  }}
                                  className="flex-1 bg-transparent border-none focus:ring-0 text-xs text-slate-100 font-medium"
                                  placeholder={`Option ${oIdx + 1}`}
                                />
                              </div>
                            ))}
                          </div>
                        </div>
                      ))}
                      {(!currentLesson.quiz || currentLesson.quiz.length === 0) && (
                        <div className="py-14 text-center border-2 border-dashed border-slate-800 rounded-3xl opacity-30">
                          <i className="fas fa-clipboard-list text-3xl mb-4 text-slate-700"></i>
                          <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">No evaluation questions recorded</p>
                        </div>
                      )}
                    </div>
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-8">
                  <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Architectural Link</h3>
                    <div className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Parent Subject</label>
                        <select value={currentLesson.subjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value, subSubjectId: undefined, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 outline-none focus:border-indigo-500">
                          <option value="">Unassigned</option>
                          {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Target Sub-group</label>
                        <select disabled={!currentLesson.subjectId} value={currentLesson.subSubjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subSubjectId: e.target.value, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20 outline-none focus:border-indigo-500">
                          <option value="">None</option>
                          {currentCourse.subjects?.find(s => s.id === currentLesson.subjectId)?.subSubjects.map(ss => <option key={ss.id} value={ss.id}>{ss.name}</option>)}
                        </select>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Specific Unit</label>
                        <select disabled={!currentLesson.subSubjectId} value={currentLesson.unitId || ''} onChange={e => updateLesson(editingLessonIdx!, { unitId: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20 outline-none focus:border-indigo-500">
                          <option value="">None</option>
                          {currentCourse.subjects?.flatMap(s => s.subSubjects).find(ss => ss.id === currentLesson.subSubjectId)?.units?.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                      </div>
                    </div>
                  </div>
                  <button onClick={() => { if (confirm('Purge this module? All content and quizzes will be deleted.')) { const l = currentCourse.lessons!.filter((_, i) => i !== editingLessonIdx); setCurrentCourse({ ...currentCourse, lessons: l }); setEditingLessonIdx(null); } }} className="w-full py-4 bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all shadow-lg active:scale-95">Delete Module</button>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white text-[10px] font-black uppercase tracking-widest transition-colors"><i className="fas fa-arrow-left mr-2"></i> Return to Registry</button>
          <div className="flex space-x-4">
             <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Commit Changes</button>
          </div>
        </div>

        <div className="bg-slate-900 rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent'}`}>{tab}</button>
            ))}
          </div>

          <div className="p-8 lg:p-12">
            {activeTab === 'info' && (
              <div className="space-y-10 animate-in fade-in duration-300">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                      <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({ ...currentCourse!, title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
