                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Price Tier ($)</label>
                      <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({ ...currentCourse!, price: parseFloat(e.target.value) })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none" />
                    </div>
                  </div>
                  <div className="space-y-6">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Visual Profile</label>
