                      )}
                      <div className="absolute inset-0 bg-slate-950/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                        <button onClick={() => thumbnailInputRef.current?.click()} className="px-6 py-2 bg-white text-slate-950 rounded-xl font-black text-[9px] uppercase shadow-xl">Select Image</button>
