                     const unit = ss?.units.find(u => u.id === lesson.unitId);
                     return (
                      <div key={lesson.id} className="group bg-slate-950 border border-slate-800 rounded-2xl p-5 flex items-center justify-between hover:border-indigo-500/30 hover:bg-slate-900 transition-all shadow-sm">
