                          <div className="w-12 h-12 rounded-xl bg-indigo-500/10 text-indigo-400 flex items-center justify-center text-lg border border-indigo-500/20 group-hover:scale-105 transition-transform"><i className={`fas ${lesson.videoUrl ? 'fa-play-circle' : 'fa-file-lines'}`}></i></div>
