                </div>
                <div className="space-y-6">
                  {currentCourse.subjects?.map((subj, sIdx) => (
                    <div key={subj.id} className="bg-slate-950 border border-slate-800 rounded-[32px] p-8 space-y-6 animate-in fade-in">
                      <div className="flex items-center gap-4">
                        <button onClick={() => setIconPickerOpenId(iconPickerOpenId === subj.id ? null : subj.id)} className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl shadow-inner border border-white/5 ${subj.color} hover:scale-105 transition-transform`}><i className={`fas ${subj.icon}`}></i></button>
                        <input type="text" value={subj.name} onChange={e => { const subjs = [...currentCourse.subjects!]; subjs[sIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: subjs }); }} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white font-bold focus:border-indigo-500 outline-none" />
                        <button onClick={() => setCurrentCourse({ ...currentCourse, subjects: currentCourse.subjects?.filter(s => s.id !== subj.id) })} className="text-slate-800 hover:text-rose-500 transition-colors p-2"><i className="fas fa-trash"></i></button>
                      </div>
                      {iconPickerOpenId === subj.id && (
                        <div className="p-4 bg-slate-900 rounded-2xl grid grid-cols-8 gap-2 animate-in slide-in-from-top-2 border border-slate-800">
                          {ICON_OPTIONS.slice(0, 32).map(icon => <button key={icon} onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].icon = icon; setCurrentCourse({ ...currentCourse, subjects: s }); setIconPickerOpenId(null); }} className="p-2 hover:bg-slate-800 rounded-lg text-slate-500 transition-colors"><i className={`fas ${icon}`}></i></button>)}
                        </div>
                      )}
                      <div className="pl-12 space-y-6 border-l border-slate-800/50 ml-6">
                        <div className="flex justify-between items-center"><h4 className="text-[8px] font-black text-slate-600 uppercase tracking-[0.2em]">Sub-Groups</h4><button onClick={() => addSubSubject(subj.id)} className="text-[8px] font-black text-indigo-400 uppercase tracking-widest hover:text-white transition-colors">+ Add Sub-group</button></div>
                        <div className="space-y-6">
                          {subj.subSubjects?.map((ss, ssIdx) => (
                            <div key={ss.id} className="bg-slate-900/50 border border-slate-800 rounded-[24px] p-6 space-y-4">
                              <div className="flex items-center gap-4">
                                <input type="text" value={ss.name} onChange={e => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: s }); }} className="flex-1 bg-slate-950 border border-slate-800 rounded-xl px-4 py-2 text-slate-300 font-bold text-sm focus:border-indigo-500 outline-none" />
                                <button onClick={() => addUnit(subj.id, ss.id)} className="text-[8px] font-black text-emerald-400 uppercase tracking-widest hover:text-white transition-colors">+ Unit</button>
                                <button onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects = s[sIdx].subSubjects.filter(i => i.id !== ss.id); setCurrentCourse({ ...currentCourse, subjects: s }); }} className="text-slate-700 hover:text-rose-500 p-1"><i className="fas fa-times"></i></button>
                              </div>
                              <div className="pl-8 space-y-3">
                                {ss.units?.map((unit, uIdx) => (
                                  <div key={unit.id} className="flex items-center gap-3 bg-slate-950 border border-slate-800/50 rounded-xl px-3 py-2 group hover:border-indigo-500/30 transition-all">
                                    <div className="w-6 h-6 rounded bg-slate-900 flex items-center justify-center text-[10px] text-emerald-500 border border-slate-800"><i className="fas fa-cube"></i></div>
                                    <input type="text" value={unit.name} onChange={e => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].units[uIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: s }); }} className="flex-1 bg-transparent border-none focus:ring-0 text-[11px] font-bold text-slate-400 focus:text-slate-100" />
                                    <button onClick={() => addLesson(subj.id, ss.id, unit.id)} title="Add module to unit" className="text-[10px] text-indigo-400 hover:text-white opacity-0 group-hover:opacity-100 transition-opacity"><i className="fas fa-plus"></i></button>
                                    <button onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].units = ss.units.filter(u => u.id !== unit.id); setCurrentCourse({ ...currentCourse, subjects: s }); }} className="text-slate-800 hover:text-rose-500 transition-colors p-1"><i className="fas fa-times text-[10px]"></i></button>
                                  </div>
                                ))}
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div><h1 className="text-5xl font-black text-white tracking-tight leading-none mb-3">Academic Registry</h1><p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Global Program Management</p></div>
        <button onClick={() => { setCurrentCourse({ id: Math.random().toString(36).substr(2, 9), title: 'New Program', lessons: [], subjects: [], category: 'Academic', price: 0, roadmap: [] }); setIsEditing(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-xl shadow-indigo-600/20 tracking-widest hover:bg-indigo-700 transition-all active:scale-95"><i className="fas fa-plus mr-3"></i> Initialize New Program</button>
      </div>

      <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
        <table className="w-full text-left">
          <thead className="bg-slate-950/80 border-b border-slate-800">
            <tr><th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest">Program Identity</th><th className="px-10 py-8 text-[10px] font-black text-slate-600 uppercase tracking-widest text-right">Action Control</th></tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {courses.map(course => (
              <tr key={course.id} className="hover:bg-slate-950/30 transition-all group">
                <td className="px-10 py-8">
                   <div className="flex items-center space-x-6">
                      <img src={course.thumbnail} className="w-16 h-10 object-cover rounded-lg border border-slate-800 shadow-sm" alt="" />
                      <div>
                        <h4 className="font-black text-slate-200 text-lg group-hover:text-indigo-400 transition-colors leading-tight">{course.title}</h4>
                        <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest mt-1">{course.category} • ${(course.price || 0).toFixed(2)}</p>
                      </div>
                   </div>
                </td>
                <td className="px-10 py-8 text-right">
                  <div className="flex items-center justify-end space-x-3 opacity-60 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => { setCurrentCourse({ ...course }); setIsEditing(true); }} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-500 hover:text-indigo-400 flex items-center justify-center border border-slate-800 transition-all shadow-sm"><i className="fas fa-edit text-sm"></i></button>
                    <button onClick={() => onDeleteCourse(course.id)} className="w-10 h-10 bg-slate-950 rounded-xl text-slate-500 hover:text-rose-500 flex items-center justify-center border border-slate-800 transition-all shadow-sm"><i className="fas fa-trash text-sm"></i></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState } from 'react';
import { Course, Lesson } from '../types';

interface CourseDetailsProps {
  course: Course;
  isAdmin: boolean;
  isEnrolled: boolean;
  onEnroll: (courseId: string) => void;
  onAdminEdit: () => void;
  onBack: () => void;
}

const CourseDetails: React.FC<CourseDetailsProps> = ({ course, isAdmin, isEnrolled, onEnroll, onAdminEdit, onBack }) => {
  const [showCheckout, setShowCheckout] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [paymentSuccess, setPaymentSuccess] = useState(false);

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);
    setTimeout(() => {
      setIsProcessing(false);
      setPaymentSuccess(true);
      setTimeout(() => onEnroll(course.id), 1500);
    }, 2000);
  };

  const roadmapItems = course.roadmap && course.roadmap.length > 0 ? course.roadmap : [
    { icon: 'fa-tv', text: `${course.lessons.length} HD Modules` },
    { icon: 'fa-sparkles', text: 'AI Tutoring' },
    { icon: 'fa-file-pdf', text: 'Study Materials' },
    { icon: 'fa-infinity', text: 'Lifetime Access' },
    { icon: 'fa-certificate', text: 'Certification' },
  ];

  return (
    <div className="pb-24 animate-in fade-in duration-700 max-w-7xl mx-auto px-4 md:px-0">
      {/* Stripe Modal */}
      {showCheckout && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-md rounded-[32px] overflow-hidden border border-slate-800 shadow-2xl">
            <div className="p-6 border-b border-slate-800 flex items-center justify-between">
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Secure Payment Terminal</span>
              <button onClick={() => setShowCheckout(false)} className="text-slate-500 hover:text-white transition-colors"><i className="fas fa-times"></i></button>
            </div>
            <div className="p-6 text-center">
              {paymentSuccess ? (
                <div className="py-8">
                  <div className="w-16 h-16 bg-emerald-500/10 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-4 text-2xl border border-emerald-500/20 shadow-inner animate-in zoom-in"><i className="fas fa-check"></i></div>
                  <h3 className="text-xl font-black text-white">Identity Verified. Access Granted.</h3>
                </div>
              ) : (
                <form onSubmit={handlePayment} className="space-y-6">
                  <div className="p-6 bg-indigo-600 rounded-2xl text-white shadow-xl text-center">
                     <p className="text-[10px] font-black uppercase opacity-60 tracking-widest mb-1">Total Enrollment Fee</p>
                     <p className="text-4xl font-black">${(course.price || 0).toFixed(2)}</p>
                  </div>
                  <div className="space-y-4">
                     <div className="p-4 bg-slate-950 border border-slate-800 rounded-xl text-slate-500 text-xs font-bold text-left flex items-center justify-between">
                        <span>Card Number</span>
                        <div className="flex space-x-2 text-[10px]"><i className="fab fa-cc-visa"></i><i className="fab fa-cc-mastercard"></i></div>
                     </div>
                  </div>
                  <button disabled={isProcessing} className="w-full py-4 bg-white text-slate-950 rounded-xl font-black uppercase text-xs shadow-xl disabled:opacity-50 hover:bg-slate-100 transition-all">
                    {isProcessing ? 'Synchronizing...' : 'Authorize Enrollment'}
                  </button>
                </form>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <button onClick={onBack} className="flex items-center space-x-3 text-slate-400 hover:text-white transition-all group">
          <div className="w-8 h-8 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500 transition-all"><i className="fas fa-arrow-left text-xs"></i></div>
          <span className="text-[10px] font-black uppercase tracking-widest">Back to Catalog</span>
        </button>
        {isAdmin && <button onClick={onAdminEdit} className="px-4 py-2 text-indigo-400 border border-indigo-900/30 rounded-lg hover:bg-indigo-600/10 transition-all text-[9px] font-black uppercase tracking-widest">Edit Program Registry</button>}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-16">
        <div className="lg:col-span-8 space-y-12">
          <div className="space-y-6">
            <div className="flex items-center space-x-3 mb-2">
               <span className="px-3 py-1 bg-indigo-500/10 text-indigo-400 text-[9px] font-black uppercase tracking-widest rounded-full border border-indigo-500/20">{course.category}</span>
               <div className="flex items-center text-[10px] text-amber-500 font-black"><i className="fas fa-star mr-1"></i> {course.rating}</div>
            </div>
            <h1 className="text-4xl md:text-6xl font-black text-white tracking-tighter leading-none">{course.title}</h1>
            <p className="text-lg text-slate-400 leading-relaxed max-w-3xl">{course.description}</p>
          </div>

          <div className="space-y-10">
            <h3 className="text-2xl font-black text-white tracking-tight flex items-center">
               <i className="fas fa-map-location-dot mr-4 text-indigo-500"></i> Curriculum Map
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {course.subjects.map((subject) => (
                <div key={subject.id} className="p-6 bg-slate-900/50 border border-slate-800 rounded-[32px] group hover:border-indigo-500/50 transition-all">
                  <div className="flex items-center space-x-4">
                    <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-inner border group-hover:scale-105 transition-transform ${subject.color}`}>
                      <i className={`fas ${subject.icon}`}></i>
                    </div>
                    <div>
                       <h4 className="text-xl font-black text-slate-100 uppercase tracking-tight">{subject.name}</h4>
                       <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{subject.subSubjects.length} Core Modules</p>
                    </div>
                  </div>
                </div>
              ))}
              {course.subjects.length === 0 && (
                <p className="text-slate-500 font-bold italic py-8">No subjects defined for this program.</p>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-4">
          <div className="lg:sticky lg:top-8 bg-slate-900 rounded-[32px] md:rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl relative">
            <img src={course.thumbnail} className="w-full aspect-video object-cover" alt="" />
            <div className="absolute top-4 right-4 bg-slate-950/80 backdrop-blur-md px-3 py-1 rounded-full text-[10px] font-black text-indigo-400 border border-slate-800 uppercase tracking-widest">
               ${(course.price || 0).toFixed(2)}
            </div>

            <div className="p-8 md:p-10 space-y-10">
              <div className="space-y-4">
                 <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Program Benefits</h4>
                 <ul className="space-y-5">
                   {roadmapItems.map((item, i) => (
                     <li key={i} className="flex items-center text-[11px] font-bold text-slate-300">
                        <div className="w-8 h-8 rounded-xl bg-slate-950 border border-slate-800 flex items-center justify-center text-indigo-400 mr-4 shadow-sm">
                           <i className={`fas ${item.icon}`}></i>
