                    <span className="text-slate-600">Active Students</span>
                    <span className="text-slate-200">{course.studentsCount.toLocaleString()}</span>
                 </div>
                 <button onClick={() => setShowCheckout(true)} disabled={isEnrolled} className={`w-full py-5 rounded-2xl font-black uppercase text-[11px] tracking-[0.25em] transition-all shadow-xl ${isEnrolled ? 'bg-slate-950 text-slate-700 border border-slate-800 cursor-not-allowed' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-600/20 active:scale-[0.98]'}`}>
                    {isEnrolled ? 'Enrolled Successfully' : 'Enroll Now'}
                 </button>
                 <p className="text-[9px] text-slate-600 font-bold uppercase text-center tracking-widest opacity-60">Lifetime Access Guaranteed</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

