import React, { useState, useMemo } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit, Lesson } from '../types';

interface DashboardProps {
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse 
}) => {
  const [selectedSubject, setSelectedSubject] = useState<SubjectGroup | null>(null);
  const [selectedSubSubject, setSelectedSubSubject] = useState<SubSubject | null>(null);
  const [selectedUnit, setSelectedUnit] = useState<Unit | null>(null);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-16 h-16 md:w-24 md:h-24 bg-slate-900 text-indigo-400 rounded-[30px] md:rounded-[40px] flex items-center justify-center mb-8 border border-slate-800 shadow-inner">
          <i className="fas fa-rocket text-2xl md:text-3xl"></i>
        </div>
        <h2 className="text-2xl md:text-3xl font-black text-slate-100 mb-4">Initialize Your Journey</h2>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-600/20">Access Course Catalog</button>
      </div>
    );
  }

  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubject(subj);
    setSelectedSubSubject(null);
    setSelectedUnit(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubject(ss);
    setSelectedUnit(null);
  };

  const handleUnitClick = (unit: Unit) => {
    setSelectedUnit(unit);
  };

  const handleBack = () => {
    if (selectedUnit) {
      setSelectedUnit(null);
    } else if (selectedSubSubject) {
      setSelectedSubSubject(null);
    } else if (selectedSubject) {
      setSelectedSubject(null);
    }
  };

  const filteredLessons = useMemo(() => {
    if (!selectedUnit) return [];
    return activeCourse.lessons.filter(l => 
      l.subjectId === selectedSubject?.id && 
      l.subSubjectId === selectedSubSubject?.id &&
      l.unitId === selectedUnit?.id
    );
  }, [activeCourse.lessons, selectedSubject, selectedSubSubject, selectedUnit]);

  const uncategorizedLessons = activeCourse.lessons.filter(l => !l.subjectId);

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-5xl mx-auto px-4 md:px-0">
      <div className="bg-slate-900/50 rounded-[32px] md:rounded-[48px] border border-slate-800/50 p-8 md:p-14 text-center shadow-2xl backdrop-blur-sm relative overflow-hidden group">
        {(selectedSubject || selectedSubSubject || selectedUnit) && (
          <button 
            onClick={handleBack}
            className="absolute left-6 md:left-10 top-1/2 -translate-y-1/2 w-10 h-10 md:w-12 md:h-12 bg-slate-950 border border-slate-800 rounded-full flex items-center justify-center text-slate-400 hover:text-white hover:border-indigo-500/50 transition-all z-10 shadow-xl"
          >
            <i className="fas fa-arrow-left text-sm"></i>
          </button>
        )}

        <div className="relative z-10 space-y-2">
          <p className="text-[10px] md:text-xs font-black text-slate-500 uppercase tracking-[0.3em] opacity-80 animate-in slide-in-from-top-2">
            {selectedUnit 
              ? `${selectedSubject?.name} • ${selectedSubSubject?.name} • ${selectedUnit.name}`
              : selectedSubSubject 
                ? `${selectedSubject?.name} • ${selectedSubSubject.name}`
                : selectedSubject 
                  ? `Focusing on ${selectedSubject.name}` 
                  : 'Academic Curriculum'}
          </p>
          <h1 className="text-2xl md:text-5xl font-black text-white tracking-tighter leading-tight drop-shadow-md">
            {selectedUnit 
              ? 'Unit Modules' 
              : selectedSubSubject 
                ? 'Select a Unit'
                : selectedSubject 
                  ? selectedSubject.name 
                  : activeCourse.title}
          </h1>
        </div>
        <div className="absolute -top-20 -right-20 w-80 h-80 bg-indigo-600/10 rounded-full blur-[100px] group-hover:bg-indigo-600/20 transition-all duration-1000"></div>
      </div>

      <div className="bg-slate-900/30 rounded-[40px] border border-slate-800/40 p-6 md:p-12 shadow-xl backdrop-blur-sm min-h-[500px] relative">
        {!selectedSubject ? (
          <div className="space-y-14">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8">
              {(activeCourse.subjects || []).map((subj) => (
                <button 
                  key={subj.id} 
                  onClick={() => handleSubjectClick(subj)}
                  className="flex items-center justify-between p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-lg active:scale-95"
                >
                  <div className="flex items-center space-x-5">
                    <div className={`w-14 h-14 md:w-16 md:h-16 rounded-2xl flex items-center justify-center text-2xl shadow-inner border border-white/5 ${subj.color} group-hover:scale-105 transition-transform`}>
                      <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                    </div>
                    <div className="text-left">
                      <span className="text-xl font-black text-slate-100 group-hover:text-white transition-colors block">{subj.name}</span>
                      <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-1 block">Explorer Sub-units</span>
                    </div>
                  </div>
                  <div className="w-9 h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center transition-all group-hover:bg-indigo-600/10">
                    <i className="fas fa-chevron-right text-[10px] text-indigo-500"></i>
                  </div>
                </button>
              ))}
            </div>

            {uncategorizedLessons.length > 0 && (
              <div className="space-y-8 pt-12 border-t border-slate-800/50">
                <div className="flex items-center space-x-4">
                  <div className="w-12 h-12 bg-slate-950 border border-slate-800 rounded-2xl flex items-center justify-center text-slate-600 shadow-inner">
                    <i className="fas fa-folder-open text-xl"></i>
                  </div>
                  <div>
                    <h3 className="text-sm font-black text-slate-200 uppercase tracking-[0.2em]">General Resources</h3>
                    <p className="text-[10px] font-black text-slate-600 uppercase mt-1">Foundation Modules</p>
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  {uncategorizedLessons.map((lesson) => (
                    <button 
                      key={lesson.id} 
                      onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                      className="flex items-center p-6 bg-slate-950 border border-slate-800/50 rounded-[28px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md"
                    >
                      <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-slate-700 mr-5 group-hover:text-indigo-400 transition-colors"><i className="fas fa-file-lines"></i></div>
                      <div className="flex-1 text-left">
