                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : !selectedSubSubject ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-right-8 duration-500">
            {selectedSubject.subSubjects.map((ss) => (
              <button 
                key={ss.id} 
                onClick={() => handleSubSubjectClick(ss)}
                className="flex items-center justify-between p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group shadow-lg active:scale-95"
              >
                <div className="flex items-center space-x-5">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg bg-slate-900 text-indigo-400 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm`}><i className="fas fa-layer-group"></i></div>
                  <span className="text-lg font-black text-slate-100 group-hover:text-indigo-400 transition-colors leading-tight">{ss.name}</span>
                </div>
                <div className="w-9 h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500/50"><i className="fas fa-chevron-right text-[10px] text-indigo-500"></i></div>
              </button>
            ))}
          </div>
        ) : !selectedUnit ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-right-8 duration-500">
            {selectedSubSubject.units?.map((unit) => (
              <button 
                key={unit.id} 
                onClick={() => handleUnitClick(unit)}
                className="flex items-center justify-between p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-emerald-500/40 hover:bg-slate-900 transition-all group shadow-lg active:scale-95"
              >
                <div className="flex items-center space-x-5">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-lg bg-slate-900 text-emerald-400 border border-slate-800 group-hover:bg-emerald-600 group-hover:text-white transition-all shadow-sm`}><i className="fas fa-cube"></i></div>
                  <span className="text-lg font-black text-slate-100 group-hover:text-emerald-400 transition-colors leading-tight">{unit.name}</span>
                </div>
                <div className="w-9 h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-emerald-500/50"><i className="fas fa-chevron-right text-[10px] text-emerald-500"></i></div>
              </button>
            ))}
            {(!selectedSubSubject.units || selectedSubSubject.units.length === 0) && (
              <div className="col-span-full py-28 flex flex-col items-center justify-center text-center opacity-40">
                <i className="fas fa-mountain-sun text-5xl mb-6 text-slate-700"></i>
                <h3 className="text-2xl font-black text-white">Structure Pending</h3>
                <p className="text-xs font-bold text-slate-500 mt-2 uppercase tracking-widest">Awaiting admin initialization for this unit</p>
