        ) : (
          <div className="space-y-8 animate-in slide-in-from-right-8 duration-500">
            {filteredLessons.length > 0 ? (
              <div className="space-y-6">
                <div className="p-8 bg-indigo-600 rounded-[32px] text-white flex flex-col md:flex-row items-center justify-between gap-6 shadow-2xl shadow-indigo-600/30">
                  <div className="text-center md:text-left">
                    <h3 className="text-2xl font-black tracking-tight leading-none mb-2">Resume Sequential Learning</h3>
                    <p className="text-indigo-100 font-bold text-[10px] uppercase tracking-widest opacity-80">Continue from the next available module in {selectedUnit.name}</p>
                  </div>
                  <button 
                    onClick={() => onCourseClick(activeCourse.id, filteredLessons[0].id)}
