                    >
                      <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center text-xs font-black text-slate-500 border border-slate-800 mr-5 group-hover:text-indigo-400 group-hover:border-indigo-500/30 transition-all shadow-inner">{idx + 1}</div>
                      <div className="flex-1 text-left">
