                        </div>
                      </div>
                      <div className="w-10 h-10 bg-indigo-600/10 rounded-full flex items-center justify-center text-indigo-400 border border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm">
