            </div>
          ) : (
            <div className="bg-slate-900/40 rounded-[32px] md:rounded-[40px] border border-dashed border-slate-800/60 py-24 flex flex-col items-center justify-center text-center backdrop-blur-sm">
              <div className="w-20 h-20 bg-indigo-600/10 text-indigo-400 rounded-3xl flex items-center justify-center text-3xl mb-6 border border-indigo-600/20 shadow-inner">
                <i className="fas fa-book-open"></i>
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight">Theory & Content</h3>
