            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CourseDetails;

import React, { useState, useEffect, useRef } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, QuizQuestion, RoadmapItem } from '../types';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
  'bg-slate-500/10 text-slate-400 border-slate-500/20',
];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe', 'fa-award', 'fa-certificate'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || []
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      setCurrentCourse(prev => ({ ...prev, thumbnail: event.target?.result as string }));
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      if (editingLessonIdx !== null) {
        updateLesson(editingLessonIdx, { videoUrl: event.target?.result as string });
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      quiz: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addQuizQuestion = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      const newQuestion: QuizQuestion = {
        id: Math.random().toString(36).substr(2, 9),
        question: 'New Question?',
        options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
        correctAnswer: 0
      };

      lesson.quiz = [...currentQuiz, newQuestion];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateQuizQuestion = (qIdx: number, updates: Partial<QuizQuestion>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      currentQuiz[qIdx] = { ...currentQuiz[qIdx], ...updates };

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeQuizQuestion = (qIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = (lesson.quiz || []).filter((_, i) => i !== qIdx);

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = { id: Math.random().toString(36).substr(2, 9), name: 'New Subject', icon: 'fa-book', color: COLOR_PRESETS[3], subSubjects: [] };
    setCurrentCourse(prev => ({ ...prev, subjects: [...(prev?.subjects || []), newSubj] }));
  };

  const addSubSubject = (subjectId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjectId ? { ...s, subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group', units: [] }] } : s)
    }));
  };

  const addUnit = (subjId: string, ssId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjId ? { 
        ...s, 
        subSubjects: s.subSubjects.map(ss => ss.id === ssId ? { ...ss, units: [...(ss.units || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Unit' }] } : ss) 
      } : s)
    }));
  };

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-6 md:space-y-8 pb-24 animate-in fade-in duration-500">

        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto flex flex-col p-4 md:p-12 animate-in slide-in-from-right-8 duration-500">
            <div className="max-w-5xl mx-auto w-full space-y-6 md:space-y-8">
              <div className="flex flex-col md:flex-row md:items-center justify-between border-b border-slate-800 pb-6 md:pb-8 gap-4">
                <div className="flex items-center space-x-4 md:space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all shadow-xl"><i className="fas fa-arrow-left"></i></button>
                  <h2 className="text-xl md:text-3xl font-black text-white tracking-tight">Module Architect</h2>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="w-full md:w-auto px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Done & Close</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8">
                <div className="lg:col-span-8 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="md:col-span-2 space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Module Title</label>
                        <input type="text" value={currentLesson.title} onChange={e => updateLesson(editingLessonIdx!, { title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none transition-all text-sm" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Length (EST)</label>
                        <input type="text" value={currentLesson.duration} onChange={e => updateLesson(editingLessonIdx!, { duration: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none transition-all text-sm" />
                      </div>
                    </div>

                    <div className="space-y-4 pt-4 border-t border-slate-800">
                      <div className="flex items-center justify-between">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Video Resource</label>
                        <button onClick={() => videoInputRef.current?.click()} className="px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">
                          {isUploading ? 'Syncing...' : <><i className="fas fa-upload mr-2"></i>Upload</>}
                        </button>
                        <input type="file" ref={videoInputRef} onChange={handleVideoUpload} className="hidden" accept="video/*" />
                      </div>
                      <input type="text" value={currentLesson.videoUrl || ''} onChange={e => updateLesson(editingLessonIdx!, { videoUrl: e.target.value })} placeholder="Cloud URL or local source..." className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 font-mono text-xs focus:border-indigo-500 outline-none transition-all" />
                    </div>
                  </div>

                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 ml-1">Academic Content (HTML)</h3>
                    <textarea rows={10} value={currentLesson.content} onChange={e => updateLesson(editingLessonIdx!, { content: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-300 font-mono text-xs leading-relaxed outline-none focus:border-indigo-500/30 transition-all" />
                  </div>

                  {/* Quiz Builder */}
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6 shadow-sm">
                    <div className="flex items-center justify-between">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Assessment Engine</h3>
                       <button onClick={addQuizQuestion} className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all">+ Question</button>
                    </div>

                    <div className="space-y-6">
                      {(currentLesson.quiz || []).map((q, qIdx) => (
                        <div key={q.id} className="p-6 bg-slate-950 border border-slate-800 rounded-[24px] md:rounded-3xl space-y-4 relative group animate-in slide-in-from-bottom-2">
                          <button onClick={() => removeQuizQuestion(qIdx)} className="absolute top-4 right-4 text-slate-800 hover:text-rose-500 transition-colors p-2"><i className="fas fa-trash-alt"></i></button>

                          <div className="space-y-2">
                             <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Question {qIdx + 1}</label>
                             <input type="text" value={q.question} onChange={e => updateQuizQuestion(qIdx, { question: e.target.value })} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-slate-100 font-bold text-sm focus:border-indigo-500 outline-none" />
                          </div>

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {q.options.map((opt, oIdx) => (
                              <div key={oIdx} className={`flex items-center space-x-3 p-3 rounded-xl border transition-all ${q.correctAnswer === oIdx ? 'bg-indigo-600/10 border-indigo-500/50' : 'bg-slate-900/50 border-slate-800'}`}>
                                <input 
                                  type="radio" 
                                  name={`correct-${q.id}`} 
                                  checked={q.correctAnswer === oIdx} 
                                  onChange={() => updateQuizQuestion(qIdx, { correctAnswer: oIdx })}
                                  className="w-4 h-4 text-indigo-600 bg-slate-950 border-slate-800 focus:ring-indigo-500"
                                />
                                <input 
                                  type="text" 
                                  value={opt} 
                                  onChange={e => {
                                    const opts = [...q.options];
                                    opts[oIdx] = e.target.value;
                                    updateQuizQuestion(qIdx, { options: opts });
                                  }}
                                  className="flex-1 bg-transparent border-none focus:ring-0 text-xs text-slate-100 font-medium"
                                  placeholder={`Option ${oIdx + 1}`}
                                />
                              </div>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 text-center md:text-left">Architectural Link</h3>
                    <div className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Parent Subject</label>
                        <select value={currentLesson.subjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value, subSubjectId: undefined, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 outline-none focus:border-indigo-500">
                          <option value="">Unassigned</option>
                          {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Target Sub-group</label>
                        <select disabled={!currentLesson.subjectId} value={currentLesson.subSubjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subSubjectId: e.target.value, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20 outline-none focus:border-indigo-500">
                          <option value="">None</option>
                          {currentCourse.subjects?.find(s => s.id === currentLesson.subjectId)?.subSubjects.map(ss => <option key={ss.id} value={ss.id}>{ss.name}</option>)}
                        </select>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Specific Unit</label>
                        <select disabled={!currentLesson.subSubjectId} value={currentLesson.unitId || ''} onChange={e => updateLesson(editingLessonIdx!, { unitId: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 disabled:opacity-20 outline-none focus:border-indigo-500">
                          <option value="">None</option>
                          {currentCourse.subjects?.flatMap(s => s.subSubjects).find(ss => ss.id === currentLesson.subSubjectId)?.units?.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                      </div>
                    </div>
                  </div>
                  <button onClick={() => { if (confirm('Purge this module?')) { const l = currentCourse.lessons!.filter((_, i) => i !== editingLessonIdx); setCurrentCourse({ ...currentCourse, lessons: l }); setEditingLessonIdx(null); } }} className="w-full py-4 bg-rose-500/10 text-rose-500 border border-rose-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all shadow-lg active:scale-95">Delete Module</button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Action Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-4 md:px-0">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white text-[10px] font-black uppercase tracking-widest transition-colors self-start flex items-center"><i className="fas fa-arrow-left mr-2"></i> Registry Hub</button>
          <button onClick={handleSave} className="w-full md:w-auto px-10 py-4 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Commit Changes</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] md:rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50 overflow-x-auto no-scrollbar">
            {['info', 'curriculum', 'structure'].map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 min-w-[120px] py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>{tab === 'info' ? 'Profile' : tab === 'curriculum' ? 'Modules' : 'Framework'}</button>
            ))}
          </div>

          <div className="p-6 md:p-12">
            {activeTab === 'info' && (
              <div className="space-y-10 animate-in fade-in duration-300">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                      <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({ ...currentCourse!, title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none text-sm shadow-inner" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                      <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({ ...currentCourse!, category: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none text-sm shadow-inner" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Enrollment Fee ($)</label>
                      <input type="number" value={currentCourse.price || 0} onChange={e => setCurrentCourse({ ...currentCourse!, price: parseFloat(e.target.value) })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none text-sm shadow-inner" />
                    </div>
                  </div>
                  <div className="space-y-6">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Identity Visual</label>
                    <div className="aspect-video bg-slate-950 rounded-3xl border border-slate-800 overflow-hidden relative group shadow-inner">
                      {currentCourse.thumbnail ? (
                        <img src={currentCourse.thumbnail} className="w-full h-full object-cover" alt="preview" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-slate-700 font-black uppercase text-[10px]">Registry Thumbnail Pending</div>
                      )}
                      <div className="absolute inset-0 bg-slate-950/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                        <button onClick={() => thumbnailInputRef.current?.click()} className="px-6 py-2 bg-white text-slate-950 rounded-xl font-black text-[9px] uppercase shadow-xl transform scale-90 group-hover:scale-100 transition-transform">Replace Asset</button>
                      </div>
                    </div>
                    <input type="file" ref={thumbnailInputRef} className="hidden" accept="image/*" onChange={handleThumbnailUpload} />
                    <input type="text" value={currentCourse.thumbnail || ''} onChange={e => setCurrentCourse({ ...currentCourse!, thumbnail: e.target.value })} placeholder="Asset URL source..." className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] text-slate-500 font-mono focus:border-indigo-500 outline-none shadow-sm" />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Abstract</label>
                  <textarea rows={4} value={currentCourse.description || ''} onChange={e => setCurrentCourse({ ...currentCourse!, description: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 leading-relaxed outline-none focus:border-indigo-500/30 text-sm shadow-inner" />
                </div>
              </div>
            )}

            {activeTab === 'curriculum' && (
              <div className="space-y-6 animate-in fade-in duration-300">
                <div className="flex flex-col md:flex-row justify-between md:items-center mb-6 gap-4">
