                        )}
                      </div>
                    </div>
                  ))}
                  {(currentCourse.subjects || []).length === 0 && (
                    <div className="py-24 text-center border-2 border-dashed border-slate-800 rounded-[40px] opacity-20">
                       <i className="fas fa-cubes text-4xl mb-4 text-slate-700"></i>
                       <p className="text-[10px] font-black uppercase tracking-widest">Architectural framework pending</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 px-4 md:px-0">
        <div>
          <h1 className="text-3xl md:text-5xl font-black text-white tracking-tight leading-none mb-2">Academic Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Manage program listings and neural links</p>
        </div>
        <button onClick={() => { setCurrentCourse({ id: Math.random().toString(36).substr(2, 9), title: 'New Program', lessons: [], subjects: [], category: 'Academic', price: 0, roadmap: [] }); setIsEditing(true); }} className="w-full md:w-auto px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-xl shadow-indigo-600/20 tracking-widest active:scale-95 transition-all"><i className="fas fa-plus mr-3"></i> Initialize New Program</button>
      </div>

      <div className="grid grid-cols-1 gap-4 px-4 md:px-0">
        {courses.map(course => (
          <div key={course.id} className="bg-slate-900 rounded-[28px] md:rounded-[40px] border border-slate-800 p-6 flex flex-col lg:flex-row lg:items-center justify-between gap-6 group hover:border-indigo-500/40 hover:bg-slate-900/50 transition-all shadow-xl">
             <div className="flex items-center space-x-6">
                <div className="w-20 md:w-32 h-14 md:h-20 overflow-hidden rounded-2xl border border-slate-800 shadow-inner shrink-0">
                  <img src={course.thumbnail} className="w-full h-full object-cover group-hover:scale-105 transition-transform" alt="" />
                </div>
                <div className="min-w-0">
                  <h4 className="font-black text-slate-100 text-lg md:text-2xl group-hover:text-indigo-400 transition-colors leading-tight truncate">{course.title}</h4>
                  <div className="flex items-center space-x-3 mt-1.5">
                     <span className="px-2 py-0.5 bg-slate-950 text-slate-600 font-black uppercase tracking-widest text-[8px] rounded border border-slate-800">{course.category}</span>
                     <span className="w-1 h-1 bg-slate-800 rounded-full"></span>
                     <span className="text-[10px] text-indigo-400 font-black uppercase tracking-widest">${(course.price || 0).toFixed(2)}</span>
                     <span className="w-1 h-1 bg-slate-800 rounded-full"></span>
                     <span className="text-[9px] text-slate-500 font-black uppercase tracking-widest">{course.lessons?.length || 0} Modules</span>
                  </div>
                </div>
             </div>
             <div className="flex items-center justify-end space-x-3 lg:ml-6 border-t lg:border-t-0 border-slate-800 pt-5 lg:pt-0">
                <button onClick={() => { setCurrentCourse({ ...course }); setIsEditing(true); }} className="flex-1 lg:flex-none h-12 md:h-14 px-8 bg-slate-950 rounded-2xl text-slate-500 hover:text-white hover:bg-indigo-600 border border-slate-800 hover:border-indigo-500 transition-all shadow-sm text-[10px] font-black uppercase tracking-widest"><i className="fas fa-edit mr-3"></i> Open Architect</button>
                <button onClick={() => { if(confirm('Purge this record from the neural link?')) onDeleteCourse(course.id); }} className="h-12 md:h-14 w-12 md:w-14 bg-slate-950 rounded-2xl text-slate-500 hover:text-rose-500 flex items-center justify-center border border-slate-800 transition-all shadow-sm"><i className="fas fa-trash-alt text-sm"></i></button>
             </div>
          </div>
        ))}
        {courses.length === 0 && (
          <div className="py-28 text-center bg-slate-900/40 rounded-[48px] border-2 border-dashed border-slate-800 opacity-20 mx-4 md:mx-0">
            <i className="fas fa-cloud-upload-alt text-5xl mb-6 text-slate-700"></i>
            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Academic Registry Empty. Initialize your first program above.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useRef } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, QuizQuestion, RoadmapItem, Resource } from '../types';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
  'bg-slate-500/10 text-slate-400 border-slate-500/20',
];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe', 'fa-award', 'fa-certificate'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || []
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      setCurrentCourse(prev => ({ ...prev, thumbnail: event.target?.result as string }));
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      if (editingLessonIdx !== null) {
        updateLesson(editingLessonIdx, { videoUrl: event.target?.result as string });
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      quiz: [],
      resources: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addQuizQuestion = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      const newQuestion: QuizQuestion = {
        id: Math.random().toString(36).substr(2, 9),
        question: 'New Question?',
        options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
        correctAnswer: 0
      };

      lesson.quiz = [...currentQuiz, newQuestion];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateQuizQuestion = (qIdx: number, updates: Partial<QuizQuestion>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      currentQuiz[qIdx] = { ...currentQuiz[qIdx], ...updates };

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeQuizQuestion = (qIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = (lesson.quiz || []).filter((_, i) => i !== qIdx);

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const addResource = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];

      const newResource: Resource = {
        id: Math.random().toString(36).substr(2, 9),
        title: 'New Resource',
        url: '',
        type: 'link',
        description: ''
      };

      lesson.resources = [...currentResources, newResource];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateResource = (rIdx: number, updates: Partial<Resource>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];

      currentResources[rIdx] = { ...currentResources[rIdx], ...updates };

      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeResource = (rIdx: number) => {
    if (editingLessonIdx === null) return;
