export default AdminPanel;

import React, { useState, useMemo } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit, Lesson } from '../types';

interface DashboardProps {
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse 
}) => {
  const [selectedSubject, setSelectedSubject] = useState<SubjectGroup | null>(null);
  const [selectedSubSubject, setSelectedSubSubject] = useState<SubSubject | null>(null);
  const [selectedUnit, setSelectedUnit] = useState<Unit | null>(null);
  const [showCoursePicker, setShowCoursePicker] = useState(false);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  const timeRemaining = useMemo(() => {
    if (!activeCourse?.expiryDate) return null;
    const now = new Date();
    const expiry = new Date(activeCourse.expiryDate);
    const diff = expiry.getTime() - now.getTime();
    const days = Math.ceil(diff / (1000 * 60 * 60 * 24));

    if (days < 0) return "Access Expired";
    if (days === 0) return "Expires Today";
    if (days === 1) return "1 day remaining";
    return `${days} days remaining`;
  }, [activeCourse]);

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-16 h-16 md:w-24 md:h-24 bg-slate-900 text-indigo-400 rounded-[30px] md:rounded-[40px] flex items-center justify-center mb-8 border border-slate-800 shadow-inner">
          <i className="fas fa-rocket text-2xl md:text-3xl"></i>
        </div>
        <h2 className="text-xl md:text-3xl font-black text-slate-100 mb-4 px-4">Initialize Your Journey</h2>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-600/20">Access Course Catalog</button>
      </div>
    );
  }

  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubject(subj);
    setSelectedSubSubject(null);
    setSelectedUnit(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubject(ss);
    setSelectedUnit(null);
  };

  const handleUnitClick = (unit: Unit) => {
    setSelectedUnit(unit);
  };

  const handleBack = () => {
    if (selectedUnit) {
      setSelectedUnit(null);
    } else if (selectedSubSubject) {
      setSelectedSubSubject(null);
    } else if (selectedSubject) {
      setSelectedSubject(null);
    }
  };

  const filteredLessons = useMemo(() => {
    if (!selectedUnit) return [];
    return activeCourse.lessons.filter(l => 
      l.subjectId === selectedSubject?.id && 
      l.subSubjectId === selectedSubSubject?.id &&
      l.unitId === selectedUnit?.id
    );
  }, [activeCourse.lessons, selectedSubject, selectedSubSubject, selectedUnit]);

  const uncategorizedLessons = activeCourse.lessons.filter(l => !l.subjectId);

  const subHeader = (selectedSubject || selectedSubSubject || selectedUnit) 
    ? activeCourse.title 
    : 'Academic Curriculum';

  const mainTitle = useMemo(() => {
    if (selectedUnit) return `${selectedSubject?.name} • ${selectedSubSubject?.name} • ${selectedUnit.name}`;
    if (selectedSubSubject) return `${selectedSubject?.name} • ${selectedSubSubject.name}`;
    if (selectedSubject) return selectedSubject.name;
    return activeCourse.title;
  }, [selectedSubject, selectedSubSubject, selectedUnit, activeCourse.title]);

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-5xl mx-auto px-0">
      {/* Course Switcher (if user has multiple) */}
      {courses.length > 1 && !selectedSubject && (
        <div className="flex justify-end px-4 md:px-0">
          <div className="relative">
            <button 
              onClick={() => setShowCoursePicker(!showCoursePicker)}
              className="flex items-center space-x-3 px-4 py-2 bg-slate-900 border border-slate-800 rounded-xl hover:border-indigo-500 transition-all group"
            >
              <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest group-hover:text-indigo-400">Switch Program</span>
              <i className={`fas fa-chevron-down text-[8px] text-slate-600 group-hover:text-indigo-400 transition-transform ${showCoursePicker ? 'rotate-180' : ''}`}></i>
            </button>
            {showCoursePicker && (
              <div className="absolute top-full right-0 mt-2 w-72 bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl z-[100] p-2 animate-in zoom-in-95 duration-200">
                {courses.map(c => (
                  <button 
                    key={c.id}
                    onClick={() => {
                      onSelectCourse(c.id);
                      setShowCoursePicker(false);
                    }}
                    className={`w-full text-left p-4 rounded-xl transition-all flex items-center space-x-3 group ${activeCourse.id === c.id ? 'bg-indigo-600/10 border border-indigo-500/20' : 'hover:bg-slate-800 border border-transparent'}`}
                  >
                    <img src={c.thumbnail} className="w-10 h-10 rounded-lg object-cover" alt="" />
                    <div className="min-w-0">
                      <p className={`text-xs font-black truncate ${activeCourse.id === c.id ? 'text-white' : 'text-slate-400'}`}>{c.title}</p>
                      {c.expiryDate && (
                        <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-0.5">
                          Expires: {new Date(c.expiryDate).toLocaleDateString()}
                        </p>
                      )}
                    </div>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* Responsive Header */}
      <div className="bg-slate-900/50 rounded-[32px] md:rounded-[48px] border border-slate-800/50 p-6 md:p-14 text-center shadow-2xl backdrop-blur-sm relative overflow-hidden group">
        {(selectedSubject || selectedSubSubject || selectedUnit) && (
          <button 
            onClick={handleBack}
            className="absolute left-4 md:left-10 top-6 md:top-1/2 md:-translate-y-1/2 w-9 h-9 md:w-12 md:h-12 bg-slate-950 border border-slate-800 rounded-full flex items-center justify-center text-slate-400 hover:text-white hover:border-indigo-500/50 transition-all z-10 shadow-xl"
          >
            <i className="fas fa-arrow-left text-xs"></i>
          </button>
        )}

        <div className="relative z-10 space-y-3 px-8 md:px-0">
          <p className="text-[9px] md:text-xs font-black text-slate-500 uppercase tracking-[0.3em] opacity-80 animate-in slide-in-from-top-2">
            {subHeader}
          </p>
          <h1 className="text-xl md:text-4xl font-black text-white tracking-tighter leading-tight drop-shadow-md break-words">
            {mainTitle}
          </h1>

          {/* Expiry Countdown Indicator */}
          {!selectedSubject && activeCourse.expiryDate && (
            <div className="inline-flex items-center px-4 py-1.5 bg-indigo-600/10 rounded-full border border-indigo-500/20 animate-in fade-in duration-700 delay-200">
               <i className="fas fa-hourglass-half text-indigo-400 text-[10px] mr-2"></i>
               <span className="text-[9px] md:text-[10px] font-black text-indigo-400 uppercase tracking-[0.1em]">
                  {timeRemaining}
               </span>
            </div>
          )}
        </div>
        <div className="absolute -top-20 -right-20 w-80 h-80 bg-indigo-600/10 rounded-full blur-[100px] group-hover:bg-indigo-600/20 transition-all duration-1000"></div>
      </div>

      <div className="bg-slate-900/30 rounded-[32px] md:rounded-[40px] border border-slate-800/40 p-4 md:p-12 shadow-xl backdrop-blur-sm min-h-[400px] relative">
        {!selectedSubject ? (
          <div className="space-y-10 md:space-y-14">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8">
              {(activeCourse.subjects || []).map((subj) => (
                <button 
                  key={subj.id} 
                  onClick={() => handleSubjectClick(subj)}
                  className="flex items-center justify-between p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-lg active:scale-95 text-left"
                >
                  <div className="flex items-center space-x-4 md:space-x-5">
                    <div className={`w-12 h-12 md:w-16 md:h-16 rounded-2xl flex items-center justify-center text-xl md:text-2xl shadow-inner border border-white/5 ${subj.color} group-hover:scale-105 transition-transform`}>
                      <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                    </div>
                    <div>
                      <span className="text-lg md:text-xl font-black text-slate-100 group-hover:text-white transition-colors block leading-tight">{subj.name}</span>
                      <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1 block">Explorer Units</span>
                    </div>
                  </div>
                  <div className="w-8 h-8 md:w-9 md:h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center transition-all group-hover:bg-indigo-600/10 shrink-0">
                    <i className="fas fa-chevron-right text-[10px] text-indigo-500"></i>
                  </div>
                </button>
              ))}
            </div>

            {uncategorizedLessons.length > 0 && (
              <div className="space-y-8 pt-10 border-t border-slate-800/50">
                <div className="flex items-center space-x-4">
                  <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-950 border border-slate-800 rounded-2xl flex items-center justify-center text-slate-600 shadow-inner">
                    <i className="fas fa-folder-open text-lg md:text-xl"></i>
                  </div>
                  <div>
                    <h3 className="text-[10px] md:text-sm font-black text-slate-200 uppercase tracking-[0.2em]">General Resources</h3>
                    <p className="text-[9px] md:text-[10px] font-black text-slate-600 uppercase mt-1">Foundation Modules</p>
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-5">
                  {uncategorizedLessons.map((lesson) => (
                    <button 
                      key={lesson.id} 
                      onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                      className="flex items-center p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-[24px] md:rounded-[28px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md"
                    >
                      <div className={`w-9 h-9 md:w-10 md:h-10 rounded-xl flex items-center justify-center mr-4 md:mr-5 transition-colors ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500' : 'bg-slate-900 text-slate-700 group-hover:text-indigo-400'}`}>
                        <i className={`fas ${lesson.isExamMode ? 'fa-file-signature' : 'fa-file-lines'}`}></i>
                      </div>
                      <div className="flex-1 text-left">
                        <div className="flex items-center space-x-2">
                          <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors text-sm md:text-base">{lesson.title}</h4>
                          {lesson.isExamMode && <i className="fas fa-stopwatch text-rose-500 text-[10px] animate-pulse"></i>}
                        </div>
                        <span className="text-[9px] md:text-[10px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : !selectedSubSubject ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-8 duration-500">
            {selectedSubject.subSubjects.map((ss) => (
              <button 
                key={ss.id} 
                onClick={() => handleSubSubjectClick(ss)}
                className="flex items-center justify-between p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group shadow-lg active:scale-95 text-left"
              >
                <div className="flex items-center space-x-4 md:space-x-5">
                  <div className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl flex items-center justify-center text-base md:text-lg bg-slate-900 text-indigo-400 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm`}><i className="fas fa-layer-group"></i></div>
                  <span className="text-base md:text-lg font-black text-slate-100 group-hover:text-indigo-400 transition-colors leading-tight">{ss.name}</span>
                </div>
                <div className="w-8 h-8 md:w-9 md:h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500/50 shrink-0"><i className="fas fa-chevron-right text-[10px] text-indigo-500"></i></div>
              </button>
            ))}
          </div>
        ) : !selectedUnit ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-8 duration-500">
            {selectedSubSubject.units?.map((unit) => (
              <button 
                key={unit.id} 
                onClick={() => handleUnitClick(unit)}
                className="flex items-center justify-between p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-emerald-500/40 hover:bg-slate-900 transition-all group shadow-lg active:scale-95 text-left"
              >
                <div className="flex items-center space-x-4 md:space-x-5">
                  <div className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl flex items-center justify-center text-base md:text-lg bg-slate-900 text-emerald-400 border border-slate-800 group-hover:bg-emerald-600 group-hover:text-white transition-all shadow-sm`}><i className="fas fa-cube"></i></div>
                  <span className="text-base md:text-lg font-black text-slate-100 group-hover:text-emerald-400 transition-colors leading-tight">{unit.name}</span>
                </div>
                <div className="w-8 h-8 md:w-9 md:h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-emerald-500/50 shrink-0"><i className="fas fa-chevron-right text-[10px] text-emerald-500"></i></div>
              </button>
            ))}
            {(!selectedSubSubject.units || selectedSubSubject.units.length === 0) && (
              <div className="col-span-full py-20 md:py-28 flex flex-col items-center justify-center text-center opacity-40 px-6">
                <i className="fas fa-mountain-sun text-4xl md:text-5xl mb-6 text-slate-700"></i>
                <h3 className="text-xl md:text-2xl font-black text-white">Structure Pending</h3>
                <p className="text-[9px] md:text-xs font-bold text-slate-500 mt-2 uppercase tracking-widest">Awaiting admin initialization for this unit</p>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6 md:space-y-8 animate-in slide-in-from-right-8 duration-500">
            {filteredLessons.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-5">
                {filteredLessons.map((lesson, idx) => (
                  <button 
                    key={lesson.id} 
                    onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                    className="flex items-center p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-[28px] md:rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md text-left"
                  >
                    <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center text-[10px] md:text-xs font-black border mr-4 md:mr-5 transition-all shadow-inner ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/30' : 'bg-slate-900 text-slate-500 border-slate-800 group-hover:text-indigo-400 group-hover:border-indigo-500/30'}`}>
                      {lesson.isExamMode ? <i className="fas fa-file-signature text-[10px]"></i> : (idx + 1)}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center space-x-2">
                        <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors text-sm md:text-base leading-tight truncate">{lesson.title}</h4>
                        {lesson.isExamMode && <span className="text-[7px] font-black text-rose-500 uppercase tracking-widest bg-rose-500/10 px-1.5 py-0.5 rounded border border-rose-500/20">EXAM</span>}
                      </div>
                      <div className="flex items-center space-x-2 md:space-x-3 mt-1.5 overflow-hidden">
                        <span className="text-[9px] md:text-[10px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                        {lesson.hasAiFeature && !lesson.isExamMode && <div className="flex items-center space-x-1 px-1.5 py-0.5 bg-indigo-500/10 text-indigo-400 rounded-md border border-indigo-500/20 shrink-0"><i className="fas fa-sparkles text-[7px]"></i><span className="text-[7px] font-black uppercase tracking-widest">AI+</span></div>}
                      </div>
                    </div>
                    <div className={`w-8 h-8 md:w-10 md:h-10 rounded-full flex items-center justify-center border transition-all shadow-sm shrink-0 ${lesson.isExamMode ? 'bg-rose-600 text-white border-rose-500' : 'bg-indigo-600/10 text-indigo-400 border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white'}`}>
                      <i className="fas fa-chevron-right text-[10px]"></i>
                    </div>
                  </button>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-64 md:h-80 text-center opacity-40 px-6">
                <i className="fas fa-compass-drafting text-4xl md:text-5xl mb-6 text-slate-700"></i>
                <h3 className="text-xl md:text-2xl font-black text-white">Registry Empty</h3>
                <p className="text-[9px] md:text-xs font-bold text-slate-500 mt-2 uppercase tracking-widest">No modules have been mapped to this academic unit</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  // Find the current lesson in the full course list
  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Define Scoped Navigation: Filter lessons to only include those in the current unit/subject context
  const scopedLessons = useMemo(() => {
    return course.lessons.filter(l => 
      l.subjectId === activeLesson.subjectId && 
      l.subSubjectId === activeLesson.subSubjectId &&
      l.unitId === activeLesson.unitId
    );
  }, [course.lessons, activeLesson]);

  // Index within the unit-scoped lessons
  const scopedIndex = useMemo(() => 
    scopedLessons.findIndex(l => l.id === activeLessonId)
  , [scopedLessons, activeLessonId]);

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    if (initialLessonId) {
      setActiveLessonId(initialLessonId);
    }
  }, [initialLessonId]);

  // Reset quiz state when active lesson changes
  useEffect(() => {
    resetQuiz();
    if (videoRef.current) videoRef.current.load();
    // If exam mode starts, ensure AI panel is closed
    if (activeLesson.isExamMode) {
      setIsAiOpen(false);
    }
  }, [activeLessonId, activeLesson.isExamMode]);

  const resetQuiz = () => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
  };

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
    }
  };

  const isAdmin = user.role === 'admin';

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50 relative">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30 shadow-xl">
          <div className="flex items-center space-x-4">
            <button onClick={onBack} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white hover:border-indigo-500/50 transition-all shadow-inner"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <div className="flex items-center space-x-2">
                <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">{course.title}</h2>
                {activeLesson.isExamMode && <span className="bg-rose-600 px-2 py-0.5 rounded text-[8px] font-black text-white uppercase tracking-widest animate-pulse">Exam Mode Active</span>}
              </div>
              <p className="text-base font-black text-white truncate max-w-[250px] leading-tight">{activeLesson.title}</p>
            </div>
          </div>

          <button 
            disabled={activeLesson.isExamMode}
            onClick={() => !activeLesson.isExamMode && setIsAiOpen(!isAiOpen)} 
            className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeLesson.isExamMode ? 'bg-slate-950 text-slate-800 border border-slate-900 cursor-not-allowed' : isAiOpen ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'bg-slate-900 text-slate-500 border border-slate-800 hover:text-white'}`}
          >
            <i className={`fas ${activeLesson.isExamMode ? 'fa-lock' : 'fa-sparkles'} mr-2`}></i>
            {activeLesson.isExamMode ? 'AI Disabled' : 'AI Tutoring'}
          </button>
        </nav>

        <div className="flex-1 p-6 md:p-14 max-w-5xl mx-auto w-full space-y-10">
          {activeLesson.videoUrl ? (
            <div className="bg-black rounded-[32px] md:rounded-[40px] overflow-hidden aspect-video border border-slate-800 shadow-2xl relative group ring-1 ring-white/5">
              <video key={activeLesson.id} ref={videoRef} src={activeLesson.videoUrl} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-slate-900/40 rounded-[32px] md:rounded-[40px] border border-dashed border-slate-800/60 py-24 flex flex-col items-center justify-center text-center backdrop-blur-sm">
              <div className={`w-20 h-20 rounded-3xl flex items-center justify-center text-3xl mb-6 border shadow-inner ${activeLesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/20' : 'bg-indigo-600/10 text-indigo-400 border-indigo-600/20'}`}>
                <i className={`fas ${activeLesson.isExamMode ? 'fa-file-signature' : 'fa-book-open'}`}></i>
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight">{activeLesson.isExamMode ? 'Examination Module' : 'Theory & Content'}</h3>
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-2">
                {activeLesson.isExamMode ? 'Resources and external aids are restricted for this assessment' : 'This module focuses on academic reading materials'}
              </p>
            </div>
          )}

          <div className="flex border-b border-slate-800 space-x-10 overflow-x-auto no-scrollbar scroll-smooth">
            <button onClick={() => setActiveTab('overview')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Content Overview</button>
            {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={() => setActiveTab('quiz')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Knowledge Check</button>}
            {isAdmin && <button onClick={() => setActiveTab('notes')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'notes' ? 'text-emerald-400 border-emerald-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Instructor Desk</button>}
          </div>

          <div className="min-h-[400px] pb-32 md:pb-24">
            {activeTab === 'overview' && (
              <div className="animate-in fade-in duration-500 space-y-8">
                <div className="prose prose-invert prose-slate max-w-none text-slate-300 leading-relaxed text-lg" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                {activeLesson.resources && activeLesson.resources.length > 0 && !activeLesson.isExamMode && (
                  <div className="mt-16 space-y-6 pt-12 border-t border-slate-800">
                    <h4 className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em]">Module Supplemental Assets</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {activeLesson.resources.map(res => (
                        <a key={res.id} href={res.url} target="_blank" rel="noopener noreferrer" className="flex items-center p-5 bg-slate-900 border border-slate-800 rounded-2xl hover:border-indigo-500/50 hover:bg-slate-950 transition-all group shadow-sm">
                          <div className="w-10 h-10 rounded-xl bg-slate-950 flex items-center justify-center text-sm text-indigo-400 mr-4 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner">
                            <i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play' : res.type === 'zip' ? 'fa-file-zipper' : 'fa-link'}`}></i>
                          </div>
                          <div>
                            <span className="text-sm font-black text-slate-200 block leading-tight">{res.title}</span>
                            <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1 block">{res.type} Format</span>
                          </div>
                        </a>
                      ))}
                    </div>
                  </div>
                )}

                {activeLesson.isExamMode && activeLesson.resources && activeLesson.resources.length > 0 && (
                  <div className="mt-16 p-8 bg-rose-500/5 border border-rose-500/10 rounded-3xl text-center">
                    <i className="fas fa-lock text-rose-500/30 text-3xl mb-4"></i>
                    <p className="text-[10px] font-black text-rose-500/60 uppercase tracking-widest">Supplemental assets are restricted during active examination</p>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-8 max-w-2xl animate-in fade-in slide-in-from-right-8 duration-500">
                {quizState.complete ? (
                  <div className="p-12 md:p-16 bg-slate-950 border border-slate-800 rounded-[40px] text-center shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1 bg-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.5)]"></div>
                    <div className="w-24 h-24 bg-emerald-500/10 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-8 text-4xl border border-emerald-500/20 shadow-inner animate-in zoom-in">
                      <i className="fas fa-check-double"></i>
                    </div>
                    <h3 className="text-3xl font-black text-white tracking-tight mb-3">Mastery Verified</h3>
                    <p className="text-slate-500 text-xs font-black uppercase tracking-[0.2em] mb-12">Performance Metric: {Math.round((quizState.score/activeLesson.quiz.length)*100)}% Proficiency achieved</p>

                    <div className="flex flex-col sm:flex-row items-center justify-center gap-5">
                      <button onClick={resetQuiz} className="w-full sm:w-auto px-10 py-4 bg-slate-900 border border-slate-800 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-md active:scale-95">Retake Assessment</button>
                      <button onClick={() => setActiveTab('overview')} className="w-full sm:w-auto px-10 py-4 bg-indigo-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-2xl shadow-indigo-600/30 hover:bg-indigo-700 transition-all active:scale-95">Back to Content</button>
                    </div>
                  </div>
                ) : (
                  <div key={quizState.currentIdx} className="space-y-8 animate-in slide-in-from-right-12 duration-500">
                    <div className="flex justify-between items-center mb-4">
                      <p className="text-[11px] text-slate-500 font-black uppercase tracking-widest">Stage {quizState.currentIdx + 1} of {activeLesson.quiz.length}</p>
                      <div className="w-48 h-2 bg-slate-900 border border-slate-800 rounded-full overflow-hidden shadow-inner">
                        <div 
                          className="h-full bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.4)] transition-all duration-700" 
                          style={{ width: `${((quizState.currentIdx + 1) / activeLesson.quiz.length) * 100}%` }}
                        ></div>
                      </div>
                    </div>
                    <h4 className="text-2xl md:text-3xl font-black text-white tracking-tight leading-snug">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-4 pt-6">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button 
                          key={i} 
                          onClick={() => handleQuizAnswer(i)} 
                          className={`w-full p-6 bg-slate-900/50 border border-slate-800 rounded-3xl text-left hover:border-indigo-500 hover:bg-slate-900 transition-all font-black text-base text-slate-200 group flex items-center shadow-lg active:scale-[0.99] ${activeLesson.isExamMode ? 'hover:border-rose-500/50' : ''}`}
                        >
                          <div className={`w-8 h-8 rounded-xl bg-slate-950 border border-slate-800 flex items-center justify-center mr-5 text-[10px] font-black transition-all shadow-inner ${activeLesson.isExamMode ? 'group-hover:bg-rose-600 group-hover:text-white' : 'group-hover:bg-indigo-600 group-hover:text-white'}`}>{String.fromCharCode(65 + i)}</div>
                          <span className="flex-1 leading-tight">{opt}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'notes' && isAdmin && (
              <div className="animate-in slide-in-from-top-6 duration-500 p-10 bg-emerald-500/5 border border-emerald-500/20 rounded-[40px] shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl"></div>
                <div className="flex items-center space-x-4 mb-8">
                  <div className="w-12 h-12 bg-emerald-500/10 text-emerald-400 rounded-2xl flex items-center justify-center border border-emerald-500/20 shadow-inner text-xl">
                    <i className="fas fa-graduation-cap"></i>
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-emerald-400 uppercase tracking-widest">Instructor Desk</h3>
                    <p className="text-[10px] font-black text-emerald-600/60 uppercase tracking-widest mt-1">Teaching Guidelines & Context</p>
                  </div>
                </div>
                <div className="text-emerald-100/70 leading-relaxed text-base italic whitespace-pre-wrap font-medium">
                  {activeLesson.instructorNotes || 'Universal instructor guidance applies. Maintain consistent terminology and encourage AI-driven inquiry for deeper understanding.'}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer Navigation - NOW SCOPED TO UNIT */}
        <div className="mt-auto p-4 md:p-8 border-t border-slate-800 bg-slate-950/80 backdrop-blur-xl flex justify-between items-center sticky bottom-0 z-30 shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
          <button 
            disabled={scopedIndex <= 0} 
            onClick={() => setActiveLessonId(scopedLessons[scopedIndex - 1].id)} 
            className="flex items-center space-x-3 px-6 py-3.5 bg-slate-900 border border-slate-800 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-slate-500 disabled:opacity-20 hover:text-white hover:border-slate-700 transition-all shadow-xl active:scale-95"
          >
            <i className="fas fa-chevron-left"></i><span>Previous Module</span>
          </button>

          <div className="hidden md:flex space-x-3 overflow-x-auto px-4 max-w-[300px] no-scrollbar">
            {scopedLessons.map(l => (
              <button 
                key={l.id} 
                onClick={() => setActiveLessonId(l.id)}
                className={`w-2.5 h-2.5 rounded-full flex-shrink-0 transition-all duration-700 ${l.id === activeLessonId ? (activeLesson.isExamMode ? 'bg-rose-500 w-10 shadow-[0_0_15px_rgba(244,63,94,0.6)]' : 'bg-indigo-500 w-10 shadow-[0_0_15px_rgba(99,102,241,0.6)]') : 'bg-slate-800 hover:bg-slate-700'}`}
              ></button>
            ))}
          </div>

          <button 
            disabled={scopedIndex === scopedLessons.length - 1} 
            onClick={() => setActiveLessonId(scopedLessons[scopedIndex + 1].id)} 
            className={`flex items-center space-x-3 px-8 py-3.5 border rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white disabled:opacity-20 transition-all shadow-2xl active:scale-95 ${activeLesson.isExamMode ? 'bg-rose-600 border-rose-500 shadow-rose-600/30 hover:bg-rose-700' : 'bg-indigo-600 border-indigo-500/30 shadow-indigo-600/30 hover:bg-indigo-700'}`}
          >
            <span>Proceed Next</span><i className="fas fa-chevron-right"></i>
          </button>
        </div>
      </div>

      {/* AI Panel */}
      <aside className={`fixed lg:relative bottom-0 right-0 w-full lg:w-[450px] h-[85vh] lg:h-full bg-slate-950 border-t lg:border-t-0 lg:border-l border-slate-800 z-[40] transition-transform duration-500 ease-in-out transform ${isAiOpen && !activeLesson.isExamMode ? 'translate-y-0 lg:translate-x-0 shadow-2xl' : 'translate-y-full lg:translate-x-full lg:hidden'}`}>
        <div className="flex flex-col h-full relative ring-1 ring-white/5">
          <button onClick={() => setIsAiOpen(false)} className="lg:hidden absolute top-4 right-4 z-50 text-slate-500 text-xl p-3 bg-slate-900/50 rounded-full hover:text-white transition-all"><i className="fas fa-times"></i></button>
          {!activeLesson.isExamMode && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </aside>
    </div>
  );
};

export default CourseView;

import React, { useState, useMemo } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit, Lesson } from '../types';

interface DashboardProps {
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse 
}) => {
  const [selectedSubject, setSelectedSubject] = useState<SubjectGroup | null>(null);
  const [selectedSubSubject, setSelectedSubSubject] = useState<SubSubject | null>(null);
  const [selectedUnit, setSelectedUnit] = useState<Unit | null>(null);
  const [showCoursePicker, setShowCoursePicker] = useState(false);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  const timeRemaining = useMemo(() => {
    if (!activeCourse?.expiryDate) return null;
    const now = new Date();
    const expiry = new Date(activeCourse.expiryDate);
    const diff = expiry.getTime() - now.getTime();
    const days = Math.ceil(diff / (1000 * 60 * 60 * 24));

    if (days < 0) return "Access Expired";
    if (days === 0) return "Expires Today";
    if (days === 1) return "1 day remaining";
    return `${days} days remaining`;
  }, [activeCourse]);

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-16 h-16 md:w-24 md:h-24 bg-slate-900 text-indigo-400 rounded-[30px] md:rounded-[40px] flex items-center justify-center mb-8 border border-slate-800 shadow-inner">
          <i className="fas fa-rocket text-2xl md:text-3xl"></i>
        </div>
        <h2 className="text-xl md:text-3xl font-black text-slate-100 mb-4 px-4">Initialize Your Journey</h2>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-600/20">Access Course Catalog</button>
      </div>
    );
  }

  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubject(subj);
    setSelectedSubSubject(null);
    setSelectedUnit(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubject(ss);
    setSelectedUnit(null);
  };

  const handleUnitClick = (unit: Unit) => {
    setSelectedUnit(unit);
  };

  const handleBack = () => {
    if (selectedUnit) {
      setSelectedUnit(null);
    } else if (selectedSubSubject) {
      setSelectedSubSubject(null);
    } else if (selectedSubject) {
      setSelectedSubject(null);
    }
  };

  const filteredLessons = useMemo(() => {
    if (!selectedUnit) return [];
    return activeCourse.lessons.filter(l => 
      l.subjectId === selectedSubject?.id && 
      l.subSubjectId === selectedSubSubject?.id &&
      l.unitId === selectedUnit?.id
    );
  }, [activeCourse.lessons, selectedSubject, selectedSubSubject, selectedUnit]);

  const uncategorizedLessons = activeCourse.lessons.filter(l => !l.subjectId);

  const subHeader = (selectedSubject || selectedSubSubject || selectedUnit) 
    ? activeCourse.title 
    : 'Academic Curriculum';

  const mainTitle = useMemo(() => {
    if (selectedUnit) return `${selectedSubject?.name} • ${selectedSubSubject?.name} • ${selectedUnit.name}`;
    if (selectedSubSubject) return `${selectedSubject?.name} • ${selectedSubSubject.name}`;
    if (selectedSubject) return selectedSubject.name;
    return activeCourse.title;
  }, [selectedSubject, selectedSubSubject, selectedUnit, activeCourse.title]);

  // Helper to check if a specific unit contains any lessons marked as Exam Mode
  const unitHasExams = (unitId: string) => {
    return activeCourse.lessons.some(l => l.unitId === unitId && l.isExamMode);
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-5xl mx-auto px-0">
      {/* Course Switcher (if user has multiple) */}
      {courses.length > 1 && !selectedSubject && (
        <div className="flex justify-end px-4 md:px-0">
          <div className="relative">
            <button 
              onClick={() => setShowCoursePicker(!showCoursePicker)}
              className="flex items-center space-x-3 px-4 py-2 bg-slate-900 border border-slate-800 rounded-xl hover:border-indigo-500 transition-all group"
            >
              <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest group-hover:text-indigo-400">Switch Program</span>
              <i className={`fas fa-chevron-down text-[8px] text-slate-600 group-hover:text-indigo-400 transition-transform ${showCoursePicker ? 'rotate-180' : ''}`}></i>
            </button>
            {showCoursePicker && (
              <div className="absolute top-full right-0 mt-2 w-72 bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl z-[100] p-2 animate-in zoom-in-95 duration-200">
                {courses.map(c => (
                  <button 
                    key={c.id}
                    onClick={() => {
                      onSelectCourse(c.id);
                      setShowCoursePicker(false);
                    }}
                    className={`w-full text-left p-4 rounded-xl transition-all flex items-center space-x-3 group ${activeCourse.id === c.id ? 'bg-indigo-600/10 border border-indigo-500/20' : 'hover:bg-slate-800 border border-transparent'}`}
                  >
                    <img src={c.thumbnail} className="w-10 h-10 rounded-lg object-cover" alt="" />
                    <div className="min-w-0">
                      <p className={`text-xs font-black truncate ${activeCourse.id === c.id ? 'text-white' : 'text-slate-400'}`}>{c.title}</p>
                      {c.expiryDate && (
                        <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-0.5">
                          Expires: {new Date(c.expiryDate).toLocaleDateString()}
                        </p>
                      )}
                    </div>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* Responsive Header */}
      <div className="bg-slate-900/50 rounded-[32px] md:rounded-[48px] border border-slate-800/50 p-6 md:p-14 text-center shadow-2xl backdrop-blur-sm relative overflow-hidden group">
        {(selectedSubject || selectedSubSubject || selectedUnit) && (
          <button 
            onClick={handleBack}
            className="absolute left-4 md:left-10 top-6 md:top-1/2 md:-translate-y-1/2 w-9 h-9 md:w-12 md:h-12 bg-slate-950 border border-slate-800 rounded-full flex items-center justify-center text-slate-400 hover:text-white hover:border-indigo-500/50 transition-all z-10 shadow-xl"
          >
            <i className="fas fa-arrow-left text-xs"></i>
          </button>
        )}

        <div className="relative z-10 space-y-3 px-8 md:px-0">
          <p className="text-[9px] md:text-xs font-black text-slate-500 uppercase tracking-[0.3em] opacity-80 animate-in slide-in-from-top-2">
            {subHeader}
          </p>
          <h1 className="text-xl md:text-4xl font-black text-white tracking-tighter leading-tight drop-shadow-md break-words">
            {mainTitle}
          </h1>

          {/* Expiry Countdown Indicator */}
          {!selectedSubject && activeCourse.expiryDate && (
            <div className="inline-flex items-center px-4 py-1.5 bg-indigo-600/10 rounded-full border border-indigo-500/20 animate-in fade-in duration-700 delay-200">
               <i className="fas fa-hourglass-half text-indigo-400 text-[10px] mr-2"></i>
               <span className="text-[9px] md:text-[10px] font-black text-indigo-400 uppercase tracking-[0.1em]">
                  {timeRemaining}
               </span>
            </div>
          )}
        </div>
        <div className="absolute -top-20 -right-20 w-80 h-80 bg-indigo-600/10 rounded-full blur-[100px] group-hover:bg-indigo-600/20 transition-all duration-1000"></div>
      </div>

      <div className="bg-slate-900/30 rounded-[32px] md:rounded-[40px] border border-slate-800/40 p-4 md:p-12 shadow-xl backdrop-blur-sm min-h-[400px] relative">
        {!selectedSubject ? (
          <div className="space-y-10 md:space-y-14">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8">
              {(activeCourse.subjects || []).map((subj) => (
                <button 
                  key={subj.id} 
                  onClick={() => handleSubjectClick(subj)}
                  className="flex items-center justify-between p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-lg active:scale-95 text-left"
                >
                  <div className="flex items-center space-x-4 md:space-x-5">
                    <div className={`w-12 h-12 md:w-16 md:h-16 rounded-2xl flex items-center justify-center text-xl md:text-2xl shadow-inner border border-white/5 ${subj.color} group-hover:scale-105 transition-transform`}>
                      <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                    </div>
                    <div>
                      <span className="text-lg md:text-xl font-black text-slate-100 group-hover:text-white transition-colors block leading-tight">{subj.name}</span>
                      <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1 block">Explorer Units</span>
                    </div>
                  </div>
                  <div className="w-8 h-8 md:w-9 md:h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center transition-all group-hover:bg-indigo-600/10 shrink-0">
                    <i className="fas fa-chevron-right text-[10px] text-indigo-500"></i>
                  </div>
                </button>
              ))}
            </div>

            {uncategorizedLessons.length > 0 && (
              <div className="space-y-8 pt-10 border-t border-slate-800/50">
                <div className="flex items-center space-x-4">
                  <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-950 border border-slate-800 rounded-2xl flex items-center justify-center text-slate-600 shadow-inner">
                    <i className="fas fa-folder-open text-lg md:text-xl"></i>
                  </div>
                  <div>
                    <h3 className="text-[10px] md:text-sm font-black text-slate-200 uppercase tracking-[0.2em]">General Resources</h3>
                    <p className="text-[9px] md:text-[10px] font-black text-slate-600 uppercase mt-1">Foundation Modules</p>
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-5">
                  {uncategorizedLessons.map((lesson) => (
                    <button 
                      key={lesson.id} 
                      onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                      className="flex items-center p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-[24px] md:rounded-[28px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md"
                    >
                      <div className={`w-9 h-9 md:w-10 md:h-10 rounded-xl flex items-center justify-center mr-4 md:mr-5 transition-colors ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500' : 'bg-slate-900 text-slate-700 group-hover:text-indigo-400'}`}>
                        <i className={`fas ${lesson.isExamMode ? 'fa-file-signature' : 'fa-file-lines'}`}></i>
                      </div>
                      <div className="flex-1 text-left">
                        <div className="flex items-center space-x-2">
                          <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors text-sm md:text-base">{lesson.title}</h4>
                          {lesson.isExamMode && <i className="fas fa-stopwatch text-rose-500 text-[10px] animate-pulse"></i>}
                        </div>
                        <span className="text-[9px] md:text-[10px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : !selectedSubSubject ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-8 duration-500">
            {selectedSubject.subSubjects.map((ss) => (
              <button 
                key={ss.id} 
                onClick={() => handleSubSubjectClick(ss)}
                className="flex items-center justify-between p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group shadow-lg active:scale-95 text-left"
              >
                <div className="flex items-center space-x-4 md:space-x-5">
                  <div className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl flex items-center justify-center text-base md:text-lg bg-slate-900 text-indigo-400 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm`}><i className="fas fa-layer-group"></i></div>
                  <span className="text-base md:text-lg font-black text-slate-100 group-hover:text-indigo-400 transition-colors leading-tight">{ss.name}</span>
                </div>
                <div className="w-8 h-8 md:w-9 md:h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center group-hover:border-indigo-500/50 shrink-0"><i className="fas fa-chevron-right text-[10px] text-indigo-500"></i></div>
              </button>
            ))}
          </div>
        ) : !selectedUnit ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-8 duration-500">
            {selectedSubSubject.units?.map((unit) => {
              const hasExam = unitHasExams(unit.id);
              return (
                <button 
                  key={unit.id} 
                  onClick={() => handleUnitClick(unit)}
                  className={`flex items-center justify-between p-5 md:p-6 bg-slate-950 border rounded-3xl transition-all group shadow-lg active:scale-95 text-left ${hasExam ? 'border-rose-500/30 hover:border-rose-500/50' : 'border-slate-800/50 hover:border-emerald-500/40'} hover:bg-slate-900`}
                >
                  <div className="flex items-center space-x-4 md:space-x-5">
                    <div className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl flex items-center justify-center text-base md:text-lg bg-slate-900 border border-slate-800 group-hover:text-white transition-all shadow-sm ${hasExam ? 'text-rose-400 group-hover:bg-rose-600' : 'text-emerald-400 group-hover:bg-emerald-600'}`}>
                      <i className={`fas ${hasExam ? 'fa-file-signature' : 'fa-cube'}`}></i>
                    </div>
                    <div>
                      <span className="text-base md:text-lg font-black text-slate-100 group-hover:text-white transition-colors leading-tight">{unit.name}</span>
                      {hasExam && <p className="text-[7px] font-black text-rose-500 uppercase tracking-widest mt-1">Exam Active</p>}
                    </div>
                  </div>
                  <div className={`w-8 h-8 md:w-9 md:h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center shrink-0 ${hasExam ? 'group-hover:border-rose-500/50' : 'group-hover:border-emerald-500/50'}`}>
                    <i className={`fas fa-chevron-right text-[10px] ${hasExam ? 'text-rose-500' : 'text-emerald-500'}`}></i>
                  </div>
                </button>
              );
            })}
            {(!selectedSubSubject.units || selectedSubSubject.units.length === 0) && (
              <div className="col-span-full py-20 md:py-28 flex flex-col items-center justify-center text-center opacity-40 px-6">
                <i className="fas fa-mountain-sun text-4xl md:text-5xl mb-6 text-slate-700"></i>
                <h3 className="text-xl md:text-2xl font-black text-white">Structure Pending</h3>
                <p className="text-[9px] md:text-xs font-bold text-slate-500 mt-2 uppercase tracking-widest">Awaiting admin initialization for this unit</p>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6 md:space-y-8 animate-in slide-in-from-right-8 duration-500">
            {filteredLessons.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-5">
                {filteredLessons.map((lesson, idx) => (
                  <button 
                    key={lesson.id} 
                    onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                    className="flex items-center p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-[28px] md:rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md text-left"
                  >
                    <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center text-[10px] md:text-xs font-black border mr-4 md:mr-5 transition-all shadow-inner ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/30' : 'bg-slate-900 text-slate-500 border-slate-800 group-hover:text-indigo-400 group-hover:border-indigo-500/30'}`}>
                      {lesson.isExamMode ? <i className="fas fa-file-signature text-[10px]"></i> : (idx + 1)}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center space-x-2">
                        <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors text-sm md:text-base leading-tight truncate">{lesson.title}</h4>
                        {lesson.isExamMode && <span className="text-[7px] font-black text-rose-500 uppercase tracking-widest bg-rose-500/10 px-1.5 py-0.5 rounded border border-rose-500/20">EXAM</span>}
                      </div>
                      <div className="flex items-center space-x-2 md:space-x-3 mt-1.5 overflow-hidden">
                        <span className="text-[9px] md:text-[10px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                        {lesson.hasAiFeature && !lesson.isExamMode && <div className="flex items-center space-x-1 px-1.5 py-0.5 bg-indigo-500/10 text-indigo-400 rounded-md border border-indigo-500/20 shrink-0"><i className="fas fa-sparkles text-[7px]"></i><span className="text-[7px] font-black uppercase tracking-widest">AI+</span></div>}
                      </div>
                    </div>
                    <div className={`w-8 h-8 md:w-10 md:h-10 rounded-full flex items-center justify-center border transition-all shadow-sm shrink-0 ${lesson.isExamMode ? 'bg-rose-600 text-white border-rose-500' : 'bg-indigo-600/10 text-indigo-400 border-indigo-500/20 group-hover:bg-indigo-600 group-hover:text-white'}`}>
                      <i className="fas fa-chevron-right text-[10px]"></i>
                    </div>
                  </button>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center h-64 md:h-80 text-center opacity-40 px-6">
                <i className="fas fa-compass-drafting text-4xl md:text-5xl mb-6 text-slate-700"></i>
                <h3 className="text-xl md:text-2xl font-black text-white">Registry Empty</h3>
                <p className="text-[9px] md:text-xs font-bold text-slate-500 mt-2 uppercase tracking-widest">No modules have been mapped to this academic unit</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

export interface UserDocument {
  id: string;
  title: string;
  data: string; // Base64 PDF data
  uploadDate: Date;
}

export interface QuizAttempt {
  score: number;
  total: number;
  date: Date;
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  role: 'student' | 'instructor' | 'admin';
  enrolledCourses: string[];
  documents: UserDocument[];
  quizScores: Record<string, QuizAttempt>; // Key is lessonId
}

export interface Resource {
  id: string;
  title: string;
  url: string;
  type: 'link' | 'pdf' | 'video' | 'zip';
  description?: string;
  tags?: string[];
}

export interface QuizQuestion {
  id: string;
  question: string;
  options: string[];
  correctAnswer: number; // Index of the correct option
}

export interface Lesson {
  id: string;
  title: string;
  content: string;
  videoUrl?: string;
  duration: string;
  completed?: boolean;
  resources?: Resource[];
  instructorNotes?: string;
  quiz?: QuizQuestion[];
  subjectId?: string; // Links lesson to a subject group
  subSubjectId?: string; // Links lesson to a specific sub-subject
  unitId?: string; // Links lesson to a specific unit
  hasAiFeature?: boolean; // Flag to enable AI features for this lesson
  isExamMode?: boolean; // Flag to enable exam mode (disables AI and Resources)
  examDuration?: number; // Duration in minutes for Exam Mode
}

export interface Unit {
  id: string;
  name: string;
}

export interface SubSubject {
  id: string;
  name: string;
  units: Unit[]; // Now contains units
}

export interface SubjectGroup {
  id: string;
  name: string;
  icon: string;
  color: string;
  subSubjects: SubSubject[]; 
}

export interface SupplementalItem {
  id: string;
  title: string;
  thumbnail: string;
  action: string; 
}

export interface RoadmapItem {
  id: string;
  icon: string;
  text: string;
}

export interface Course {
  id: string;
  title: string;
  description: string;
  instructor: string;
  instructorAvatar: string;
  thumbnail: string;
  lessons: Lesson[];
  category: string;
  rating: number;
  studentsCount: number;
  price: number; 
  progress?: number;
  subjects: SubjectGroup[];
  supplementalContent?: SupplementalItem[];
  roadmap?: RoadmapItem[];
  expiryDate?: string; // ISO date string for course expiration
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  image?: string; 
  groundingUrls?: { title: string, uri: string }[];
}

export enum AppRoute {
  DASHBOARD = 'dashboard',
  COURSES = 'courses',
  COURSE_DETAILS = 'course-details',
  COURSE_VIEW = 'course-view',
  PROFILE = 'profile',
  ADMIN = 'admin'
}

import React, { useState, useEffect, useRef } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, QuizQuestion, RoadmapItem, Resource } from '../types';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
  'bg-slate-500/10 text-slate-400 border-slate-500/20',
];

const ICON_OPTIONS = [
  'fa-book', 'fa-book-open', 'fa-graduation-cap', 'fa-microscope', 'fa-flask', 'fa-atom', 
  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe', 'fa-award', 'fa-certificate'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || [],
      expiryDate: currentCourse.expiryDate
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      setCurrentCourse(prev => ({ ...prev, thumbnail: event.target?.result as string }));
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      if (editingLessonIdx !== null) {
        updateLesson(editingLessonIdx, { videoUrl: event.target?.result as string });
      }
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      isExamMode: false,
      examDuration: 30,
      quiz: [],
      resources: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addQuizQuestion = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      const newQuestion: QuizQuestion = {
        id: Math.random().toString(36).substr(2, 9),
        question: 'New Question?',
        options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
        correctAnswer: 0
      };

      lesson.quiz = [...currentQuiz, newQuestion];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateQuizQuestion = (qIdx: number, updates: Partial<QuizQuestion>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      currentQuiz[qIdx] = { ...currentQuiz[qIdx], ...updates };

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeQuizQuestion = (qIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = (lesson.quiz || []).filter((_, i) => i !== qIdx);

      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const addResource = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];

      const newResource: Resource = {
        id: Math.random().toString(36).substr(2, 9),
        title: 'New Resource',
        url: '',
        type: 'link',
        description: ''
      };

      lesson.resources = [...currentResources, newResource];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateResource = (rIdx: number, updates: Partial<Resource>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];

      currentResources[rIdx] = { ...currentResources[rIdx], ...updates };

      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeResource = (rIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = (lesson.resources || []).filter((_, i) => i !== rIdx);

      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = { id: Math.random().toString(36).substr(2, 9), name: 'New Subject', icon: 'fa-book', color: COLOR_PRESETS[3], subSubjects: [] };
    setCurrentCourse(prev => ({ ...prev, subjects: [...(prev?.subjects || []), newSubj] }));
  };

  const addSubSubject = (subjectId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjectId ? { ...s, subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group', units: [] }] } : s)
    }));
  };

  const addUnit = (subjId: string, ssId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjId ? { 
        ...s, 
        subSubjects: s.subSubjects.map(ss => ss.id === ssId ? { ...ss, units: [...(ss.units || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Unit' }] } : ss) 
      } : s)
    }));
  };

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-6 md:space-y-8 pb-24 animate-in fade-in duration-500">

        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto flex flex-col p-4 md:p-12 animate-in slide-in-from-right-8 duration-500">
            <div className="max-w-5xl mx-auto w-full space-y-6 md:space-y-8">
              <div className="flex flex-col md:flex-row md:items-center justify-between border-b border-slate-800 pb-6 md:pb-8 gap-4">
                <div className="flex items-center space-x-4 md:space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all shadow-xl"><i className="fas fa-arrow-left"></i></button>
                  <h2 className="text-xl md:text-3xl font-black text-white tracking-tight">Module Architect</h2>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="w-full md:w-auto px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Done & Close</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8">
                <div className="lg:col-span-8 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="md:col-span-2 space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Module Title</label>
                        <input type="text" value={currentLesson.title} onChange={e => updateLesson(editingLessonIdx!, { title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none transition-all text-sm" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Length (EST)</label>
                        <input type="text" value={currentLesson.duration} onChange={e => updateLesson(editingLessonIdx!, { duration: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none transition-all text-sm" />
                      </div>
                    </div>

                    <div className="space-y-4 pt-4 border-t border-slate-800">
                      <div className="flex items-center justify-between">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Video Resource</label>
                        <button onClick={() => videoInputRef.current?.click()} className="px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">
                          {isUploading ? 'Syncing...' : <><i className="fas fa-upload mr-2"></i>Upload</>}
                        </button>
                        <input type="file" ref={videoInputRef} onChange={handleVideoUpload} className="hidden" accept="video/*" />
                      </div>
                      <input type="text" value={currentLesson.videoUrl || ''} onChange={e => updateLesson(editingLessonIdx!, { videoUrl: e.target.value })} placeholder="Cloud URL or local source..." className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 font-mono text-xs focus:border-indigo-500 outline-none transition-all" />
                    </div>
                  </div>

                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 ml-1">Academic Content (HTML)</h3>
                    <textarea rows={10} value={currentLesson.content} onChange={e => updateLesson(editingLessonIdx!, { content: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-300 font-mono text-xs leading-relaxed outline-none focus:border-indigo-500/30 transition-all" />
                  </div>

                  {/* Resource Manager */}
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6 shadow-sm">
                    <div className="flex items-center justify-between">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Asset Library (Resources)</h3>
