                      </div>

                      <div className="md:pl-16 space-y-6 md:border-l border-slate-800/30">
                        {subj.subSubjects?.map((ss, ssIdx) => (
                          <div key={ss.id} className="bg-slate-900/50 border border-slate-800 rounded-[24px] p-5 space-y-5 shadow-sm">
                            <div className="flex items-center gap-4">
                              <div className="flex-1">
                                <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1 mb-1 block">Sub-Subject Group</label>
                                <input type="text" value={ss.name} onChange={e => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: s }); }} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-2.5 text-slate-200 font-bold text-sm focus:border-indigo-500 outline-none" />
                              </div>
                              <button onClick={() => addUnit(subj.id, ss.id)} className="px-3 py-1.5 bg-emerald-600/10 text-emerald-400 border border-emerald-500/20 rounded-lg text-[8px] font-black uppercase tracking-widest hover:bg-emerald-600 hover:text-white transition-all">+ Unit</button>
                              <button onClick={() => {
                                const s = [...currentCourse.subjects!];
                                s[sIdx].subSubjects = s[sIdx].subSubjects.filter(subS => subS.id !== ss.id);
                                setCurrentCourse({ ...currentCourse, subjects: s });
                              }} className="text-slate-800 hover:text-rose-500 p-2"><i className="fas fa-times text-xs"></i></button>
                            </div>

                            <div className="pl-6 md:pl-8 space-y-3">
                              {(ss.units || []).map((unit, uIdx) => (
                                <div key={unit.id} className="flex items-center gap-3 bg-slate-950 border border-slate-800/40 rounded-xl px-4 py-2 group hover:border-emerald-500/30 transition-all">
                                  <div className="w-1.5 h-1.5 rounded-full bg-emerald-500/30 group-hover:bg-emerald-500 transition-colors shrink-0"></div>
                                  <input type="text" value={unit.name} onChange={e => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].units[uIdx].name = e.target.value; setCurrentCourse({ ...currentCourse, subjects: s }); }} className="flex-1 bg-transparent border-none focus:ring-0 text-xs font-bold text-slate-400 focus:text-slate-100" />
                                  <button onClick={() => { const s = [...currentCourse.subjects!]; s[sIdx].subSubjects[ssIdx].units = ss.units.filter(u => u.id !== unit.id); setCurrentCourse({ ...currentCourse, subjects: s }); }} className="text-slate-800 hover:text-rose-500 p-1 transition-colors"><i className="fas fa-times text-[10px]"></i></button>
                                </div>
                              ))}
                              {(ss.units || []).length === 0 && (
                                <p className="text-[9px] font-black text-slate-700 uppercase tracking-widest pl-4">No mapped units</p>
                              )}
                            </div>
                          </div>
                        ))}
                        {(subj.subSubjects || []).length === 0 && (
                          <p className="text-[10px] font-black text-slate-700 uppercase tracking-widest">No structural sub-groups established</p>
                        )}
                      </div>
                    </div>
                  ))}
                  {(currentCourse.subjects || []).length === 0 && (
                    <div className="py-24 text-center border-2 border-dashed border-slate-800 rounded-[40px] opacity-20">
                       <i className="fas fa-cubes text-4xl mb-4 text-slate-700"></i>
                       <p className="text-[10px] font-black uppercase tracking-widest">Architectural framework pending</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 px-4 md:px-0">
        <div>
          <h1 className="text-3xl md:text-5xl font-black text-white tracking-tight leading-none mb-2">Academic Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Manage program listings and neural links</p>
        </div>
        <button onClick={() => { setCurrentCourse({ id: Math.random().toString(36).substr(2, 9), title: 'New Program', lessons: [], subjects: [], category: 'Academic', price: 0, roadmap: [] }); setIsEditing(true); }} className="w-full md:w-auto px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-xl shadow-indigo-600/20 tracking-widest active:scale-95 transition-all"><i className="fas fa-plus mr-3"></i> Initialize New Program</button>
      </div>

      <div className="grid grid-cols-1 gap-4 px-4 md:px-0">
        {courses.map(course => (
          <div key={course.id} className="bg-slate-900 rounded-[28px] md:rounded-[40px] border border-slate-800 p-6 flex flex-col lg:flex-row lg:items-center justify-between gap-6 group hover:border-indigo-500/40 hover:bg-slate-900/50 transition-all shadow-xl">
             <div className="flex items-center space-x-6">
                <div className="w-20 md:w-32 h-14 md:h-20 overflow-hidden rounded-2xl border border-slate-800 shadow-inner shrink-0">
                  <img src={course.thumbnail} className="w-full h-full object-cover group-hover:scale-105 transition-transform" alt="" />
                </div>
                <div className="min-w-0">
                  <h4 className="font-black text-slate-100 text-lg md:text-2xl group-hover:text-indigo-400 transition-colors leading-tight truncate">{course.title}</h4>
                  <div className="flex items-center space-x-3 mt-1.5">
                     <span className="px-2 py-0.5 bg-slate-950 text-slate-600 font-black uppercase tracking-widest text-[8px] rounded border border-slate-800">{course.category}</span>
                     <span className="w-1 h-1 bg-slate-800 rounded-full"></span>
                     <span className="text-[10px] text-indigo-400 font-black uppercase tracking-widest">${(course.price || 0).toFixed(2)}</span>
                     <span className="w-1 h-1 bg-slate-800 rounded-full"></span>
                     <span className="text-[9px] text-slate-500 font-black uppercase tracking-widest">{course.lessons?.length || 0} Modules</span>
                  </div>
                </div>
             </div>
             <div className="flex items-center justify-end space-x-3 lg:ml-6 border-t lg:border-t-0 border-slate-800 pt-5 lg:pt-0">
                <button onClick={() => { setCurrentCourse({ ...course }); setIsEditing(true); }} className="flex-1 lg:flex-none h-12 md:h-14 px-8 bg-slate-950 rounded-2xl text-slate-500 hover:text-white hover:bg-indigo-600 border border-slate-800 hover:border-indigo-500 transition-all shadow-sm text-[10px] font-black uppercase tracking-widest"><i className="fas fa-edit mr-3"></i> Open Architect</button>
                <button onClick={() => { if(confirm('Purge this record from the neural link?')) onDeleteCourse(course.id); }} className="h-12 md:h-14 w-12 md:w-14 bg-slate-950 rounded-2xl text-slate-500 hover:text-rose-500 flex items-center justify-center border border-slate-800 transition-all shadow-sm"><i className="fas fa-trash-alt text-sm"></i></button>
             </div>
          </div>
        ))}
        {courses.length === 0 && (
          <div className="py-28 text-center bg-slate-900/40 rounded-[48px] border-2 border-dashed border-slate-800 opacity-20 mx-4 md:mx-0">
            <i className="fas fa-cloud-upload-alt text-5xl mb-6 text-slate-700"></i>
            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Academic Registry Empty. Initialize your first program above.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  // Find the current lesson in the full course list
  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Exam Timer State
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    if (activeLesson.isExamMode && !quizState.complete) {
      setTimeLeft((activeLesson.examDuration || 30) * 60);
      setActiveTab('quiz'); // Force quiz view in exam mode

      if (timerRef.current) clearInterval(timerRef.current);

      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            if (timerRef.current) clearInterval(timerRef.current);
            handleSubmitExam();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [activeLessonId, activeLesson.isExamMode]);

  const formatTimeLeft = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Define Scoped Navigation: Filter lessons to only include those in the current unit/subject context
  const scopedLessons = useMemo(() => {
    return course.lessons.filter(l => 
      l.subjectId === activeLesson.subjectId && 
      l.subSubjectId === activeLesson.subSubjectId &&
      l.unitId === activeLesson.unitId
    );
  }, [course.lessons, activeLesson]);

  // Index within the unit-scoped lessons
  const scopedIndex = useMemo(() => 
    scopedLessons.findIndex(l => l.id === activeLessonId)
  , [scopedLessons, activeLessonId]);

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    if (initialLessonId) {
      setActiveLessonId(initialLessonId);
    }
  }, [initialLessonId]);

  // Reset quiz state when active lesson changes
  useEffect(() => {
    resetQuiz();
    if (videoRef.current) videoRef.current.load();
    // If exam mode starts, ensure AI panel is closed
    if (activeLesson.isExamMode) {
      setIsAiOpen(false);
    }
  }, [activeLessonId, activeLesson.isExamMode]);

  const resetQuiz = () => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
  };

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const handleSubmitExam = () => {
    setQuizState(prev => ({ ...prev, complete: true }));
    onQuizComplete(activeLesson.id, { score: quizState.score, total: activeLesson.quiz?.length || 0, date: new Date() });
    if (timerRef.current) clearInterval(timerRef.current);
  };

  const isAdmin = user.role === 'admin';

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50 relative">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30 shadow-xl">
          <div className="flex items-center space-x-4">
            <button onClick={onBack} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white hover:border-indigo-500/50 transition-all shadow-inner"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <div className="flex items-center space-x-2">
                <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">{course.title}</h2>
                {activeLesson.isExamMode && <span className="bg-rose-600 px-2 py-0.5 rounded text-[8px] font-black text-white uppercase tracking-widest animate-pulse">Timed Examination</span>}
              </div>
              <p className="text-base font-black text-white truncate max-w-[250px] leading-tight">{activeLesson.title}</p>
            </div>
          </div>

          {activeLesson.isExamMode && !quizState.complete ? (
            <div className="flex items-center space-x-4 bg-rose-500/10 border border-rose-500/30 px-6 py-2 rounded-xl">
              <i className="fas fa-stopwatch text-rose-500 text-sm"></i>
              <span className={`text-sm font-black tracking-widest ${timeLeft < 60 ? 'text-rose-500 animate-pulse' : 'text-white'}`}>
                {formatTimeLeft(timeLeft)}
              </span>
            </div>
          ) : (
            <button 
              disabled={activeLesson.isExamMode}
              onClick={() => !activeLesson.isExamMode && setIsAiOpen(!isAiOpen)} 
              className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeLesson.isExamMode ? 'bg-slate-950 text-slate-800 border border-slate-900 cursor-not-allowed' : isAiOpen ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'bg-slate-900 text-slate-500 border border-slate-800 hover:text-white'}`}
            >
              <i className={`fas ${activeLesson.isExamMode ? 'fa-lock' : 'fa-sparkles'} mr-2`}></i>
              {activeLesson.isExamMode ? 'AI Disabled' : 'AI Tutoring'}
            </button>
          )}
        </nav>

        <div className="flex-1 p-6 md:p-14 max-w-5xl mx-auto w-full space-y-10">
          {activeLesson.isExamMode ? (
            <div className="bg-slate-900/40 rounded-[32px] md:rounded-[40px] border border-dashed border-rose-500/30 py-16 flex flex-col items-center justify-center text-center backdrop-blur-sm animate-in fade-in duration-700">
              <div className="w-20 h-20 rounded-3xl flex items-center justify-center text-3xl mb-6 border shadow-inner bg-rose-500/10 text-rose-500 border-rose-500/20">
                <i className="fas fa-file-signature"></i>
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight uppercase">Formal Assessment</h3>
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-2">
                External aids, resources, and AI tools are restricted
              </p>
            </div>
          ) : activeLesson.videoUrl ? (
            <div className="bg-black rounded-[32px] md:rounded-[40px] overflow-hidden aspect-video border border-slate-800 shadow-2xl relative group ring-1 ring-white/5">
              <video key={activeLesson.id} ref={videoRef} src={activeLesson.videoUrl} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-slate-900/40 rounded-[32px] md:rounded-[40px] border border-dashed border-slate-800/60 py-24 flex flex-col items-center justify-center text-center backdrop-blur-sm">
              <div className="w-20 h-20 rounded-3xl flex items-center justify-center text-3xl mb-6 border shadow-inner bg-indigo-600/10 text-indigo-400 border-indigo-600/20">
                <i className="fas fa-book-open"></i>
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight">Theory & Content</h3>
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-2">
                This module focuses on academic reading materials
              </p>
            </div>
          )}

          {!activeLesson.isExamMode && (
            <div className="flex border-b border-slate-800 space-x-10 overflow-x-auto no-scrollbar scroll-smooth">
              <button onClick={() => setActiveTab('overview')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Content Overview</button>
              {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={() => setActiveTab('quiz')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Knowledge Check</button>}
              {isAdmin && <button onClick={() => setActiveTab('notes')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'notes' ? 'text-emerald-400 border-emerald-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Instructor Desk</button>}
            </div>
          )}

          <div className="min-h-[400px] pb-32 md:pb-24">
            {activeTab === 'overview' && !activeLesson.isExamMode && (
              <div className="animate-in fade-in duration-500 space-y-8">
                <div className="prose prose-invert prose-slate max-w-none text-slate-300 leading-relaxed text-lg" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                {activeLesson.resources && activeLesson.resources.length > 0 && (
                  <div className="mt-16 space-y-6 pt-12 border-t border-slate-800">
                    <h4 className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em]">Module Supplemental Assets</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {activeLesson.resources.map(res => (
                        <a key={res.id} href={res.url} target="_blank" rel="noopener noreferrer" className="flex items-center p-5 bg-slate-900 border border-slate-800 rounded-2xl hover:border-indigo-500/50 hover:bg-slate-950 transition-all group shadow-sm">
                          <div className="w-10 h-10 rounded-xl bg-slate-950 flex items-center justify-center text-sm text-indigo-400 mr-4 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner">
                            <i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play' : res.type === 'zip' ? 'fa-file-zipper' : 'fa-link'}`}></i>
                          </div>
                          <div>
                            <span className="text-sm font-black text-slate-200 block leading-tight">{res.title}</span>
                            <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1 block">{res.type} Format</span>
                          </div>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-8 max-w-2xl mx-auto animate-in fade-in slide-in-from-right-8 duration-500">
                {quizState.complete ? (
                  <div className="p-12 md:p-16 bg-slate-950 border border-slate-800 rounded-[40px] text-center shadow-2xl relative overflow-hidden">
                    <div className={`absolute top-0 left-0 w-full h-1 ${activeLesson.isExamMode ? 'bg-rose-500 shadow-[0_0_20px_rgba(244,63,94,0.5)]' : 'bg-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.5)]'}`}></div>
                    <div className={`w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8 text-4xl border shadow-inner animate-in zoom-in ${activeLesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/20' : 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20'}`}>
                      <i className={`fas ${activeLesson.isExamMode ? 'fa-award' : 'fa-check-double'}`}></i>
                    </div>
                    <h3 className="text-3xl font-black text-white tracking-tight mb-3">{activeLesson.isExamMode ? 'Examination Complete' : 'Mastery Verified'}</h3>
                    <p className="text-slate-500 text-xs font-black uppercase tracking-[0.2em] mb-12">Performance Metric: {Math.round((quizState.score/activeLesson.quiz.length)*100)}% Proficiency achieved</p>

                    <div className="flex flex-col sm:flex-row items-center justify-center gap-5">
                      {!activeLesson.isExamMode && <button onClick={resetQuiz} className="w-full sm:w-auto px-10 py-4 bg-slate-900 border border-slate-800 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-md active:scale-95">Retake Assessment</button>}
                      <button onClick={activeLesson.isExamMode ? onBack : () => setActiveTab('overview')} className="w-full sm:w-auto px-10 py-4 bg-indigo-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-2xl shadow-indigo-600/30 hover:bg-indigo-700 transition-all active:scale-95">
                        {activeLesson.isExamMode ? 'Return to Dashboard' : 'Back to Content'}
                      </button>
                    </div>
                  </div>
                ) : (
                  <div key={quizState.currentIdx} className="space-y-8 animate-in slide-in-from-right-12 duration-500">
                    <div className="flex justify-between items-center mb-4">
                      <p className="text-[11px] text-slate-500 font-black uppercase tracking-widest">Question {quizState.currentIdx + 1} of {activeLesson.quiz.length}</p>
                      <div className="w-48 h-2 bg-slate-900 border border-slate-800 rounded-full overflow-hidden shadow-inner">
                        <div 
                          className={`h-full transition-all duration-700 ${activeLesson.isExamMode ? 'bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.4)]' : 'bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.4)]'}`}
                          style={{ width: `${((quizState.currentIdx + 1) / activeLesson.quiz.length) * 100}%` }}
                        ></div>
                      </div>
                    </div>
                    <h4 className="text-2xl md:text-3xl font-black text-white tracking-tight leading-snug">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-4 pt-6">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button 
                          key={i} 
                          onClick={() => handleQuizAnswer(i)} 
                          className={`w-full p-6 bg-slate-900/50 border border-slate-800 rounded-3xl text-left transition-all font-black text-base text-slate-200 group flex items-center shadow-lg active:scale-[0.99] ${activeLesson.isExamMode ? 'hover:border-rose-500 hover:bg-rose-500/5' : 'hover:border-indigo-500 hover:bg-slate-900'}`}
                        >
                          <div className={`w-8 h-8 rounded-xl bg-slate-950 border border-slate-800 flex items-center justify-center mr-5 text-[10px] font-black transition-all shadow-inner ${activeLesson.isExamMode ? 'group-hover:bg-rose-600 group-hover:text-white' : 'group-hover:bg-indigo-600 group-hover:text-white'}`}>{String.fromCharCode(65 + i)}</div>
                          <span className="flex-1 leading-tight">{opt}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'notes' && isAdmin && !activeLesson.isExamMode && (
              <div className="animate-in slide-in-from-top-6 duration-500 p-10 bg-emerald-500/5 border border-emerald-500/20 rounded-[40px] shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl"></div>
                <div className="flex items-center space-x-4 mb-8">
                  <div className="w-12 h-12 bg-emerald-500/10 text-emerald-400 rounded-2xl flex items-center justify-center border border-emerald-500/20 shadow-inner text-xl">
                    <i className="fas fa-graduation-cap"></i>
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-emerald-400 uppercase tracking-widest">Instructor Desk</h3>
                    <p className="text-[10px] font-black text-emerald-600/60 uppercase tracking-widest mt-1">Teaching Guidelines & Context</p>
                  </div>
                </div>
                <div className="text-emerald-100/70 leading-relaxed text-base italic whitespace-pre-wrap font-medium">
                  {activeLesson.instructorNotes || 'Universal instructor guidance applies. Maintain consistent terminology and encourage AI-driven inquiry for deeper understanding.'}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer Navigation */}
        <div className="mt-auto p-4 md:p-8 border-t border-slate-800 bg-slate-950/80 backdrop-blur-xl flex justify-between items-center sticky bottom-0 z-30 shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
          {activeLesson.isExamMode && !quizState.complete ? (
            <button 
              onClick={handleSubmitExam}
              className="w-full flex items-center justify-center space-x-3 py-4 bg-rose-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-[0.3em] hover:bg-rose-700 transition-all shadow-xl shadow-rose-600/20 active:scale-95"
            >
              <span>Submit Examination</span>
              <i className="fas fa-paper-plane"></i>
            </button>
          ) : (
            <>
              <button 
                disabled={scopedIndex <= 0 || activeLesson.isExamMode} 
                onClick={() => setActiveLessonId(scopedLessons[scopedIndex - 1].id)} 
                className="flex items-center space-x-3 px-6 py-3.5 bg-slate-900 border border-slate-800 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-slate-500 disabled:opacity-20 hover:text-white hover:border-slate-700 transition-all shadow-xl active:scale-95"
              >
                <i className="fas fa-chevron-left"></i><span>Previous Module</span>
              </button>

              <div className="hidden md:flex space-x-3 overflow-x-auto px-4 max-w-[300px] no-scrollbar">
                {scopedLessons.map(l => (
                  <button 
                    key={l.id} 
                    onClick={() => setActiveLessonId(l.id)}
                    className={`w-2.5 h-2.5 rounded-full flex-shrink-0 transition-all duration-700 ${l.id === activeLessonId ? (activeLesson.isExamMode ? 'bg-rose-500 w-10 shadow-[0_0_15px_rgba(244,63,94,0.6)]' : 'bg-indigo-500 w-10 shadow-[0_0_15px_rgba(99,102,241,0.6)]') : 'bg-slate-800 hover:bg-slate-700'}`}
                  ></button>
                ))}
              </div>

              <button 
                disabled={scopedIndex === scopedLessons.length - 1 || activeLesson.isExamMode} 
                onClick={() => setActiveLessonId(scopedLessons[scopedIndex + 1].id)} 
                className={`flex items-center space-x-3 px-8 py-3.5 border rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white disabled:opacity-20 transition-all shadow-2xl active:scale-95 ${activeLesson.isExamMode ? 'bg-rose-600 border-rose-500 shadow-rose-600/30 hover:bg-rose-700' : 'bg-indigo-600 border-indigo-500/30 shadow-indigo-600/30 hover:bg-indigo-700'}`}
              >
                <span>Proceed Next</span><i className="fas fa-chevron-right"></i>
              </button>
            </>
          )}
        </div>
      </div>

      {/* AI Panel */}
      <aside className={`fixed lg:relative bottom-0 right-0 w-full lg:w-[450px] h-[85vh] lg:h-full bg-slate-950 border-t lg:border-t-0 lg:border-l border-slate-800 z-[40] transition-transform duration-500 ease-in-out transform ${isAiOpen && !activeLesson.isExamMode ? 'translate-y-0 lg:translate-x-0 shadow-2xl' : 'translate-y-full lg:translate-x-full lg:hidden'}`}>
        <div className="flex flex-col h-full relative ring-1 ring-white/5">
          <button onClick={() => setIsAiOpen(false)} className="lg:hidden absolute top-4 right-4 z-50 text-slate-500 text-xl p-3 bg-slate-900/50 rounded-full hover:text-white transition-all"><i className="fas fa-times"></i></button>
          {!activeLesson.isExamMode && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </aside>
    </div>
  );
};

export default CourseView;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  // Find the current lesson in the full course list
  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Exam Timer State
  const [timeLeft, setTimeLeft] = useState<number>(0);
  // Fix: Use ReturnType<typeof setInterval> instead of NodeJS.Timeout to resolve "Cannot find namespace 'NodeJS'" error in browser environments
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (activeLesson.isExamMode && !quizState.complete) {
      setTimeLeft((activeLesson.examDuration || 30) * 60);
      setActiveTab('quiz'); // Force quiz view in exam mode

      if (timerRef.current) clearInterval(timerRef.current);

      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            if (timerRef.current) clearInterval(timerRef.current);
            handleSubmitExam();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [activeLessonId, activeLesson.isExamMode]);

  const formatTimeLeft = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Define Scoped Navigation: Filter lessons to only include those in the current unit/subject context
  const scopedLessons = useMemo(() => {
    return course.lessons.filter(l => 
      l.subjectId === activeLesson.subjectId && 
      l.subSubjectId === activeLesson.subSubjectId &&
      l.unitId === activeLesson.unitId
    );
  }, [course.lessons, activeLesson]);

  // Index within the unit-scoped lessons
  const scopedIndex = useMemo(() => 
    scopedLessons.findIndex(l => l.id === activeLessonId)
  , [scopedLessons, activeLessonId]);

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    if (initialLessonId) {
      setActiveLessonId(initialLessonId);
    }
  }, [initialLessonId]);

  // Reset quiz state when active lesson changes
  useEffect(() => {
    resetQuiz();
    if (videoRef.current) videoRef.current.load();
    // If exam mode starts, ensure AI panel is closed
    if (activeLesson.isExamMode) {
      setIsAiOpen(false);
    }
  }, [activeLessonId, activeLesson.isExamMode]);

  const resetQuiz = () => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
  };

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const handleSubmitExam = () => {
    setQuizState(prev => ({ ...prev, complete: true }));
    onQuizComplete(activeLesson.id, { score: quizState.score, total: activeLesson.quiz?.length || 0, date: new Date() });
    if (timerRef.current) clearInterval(timerRef.current);
  };

  const isAdmin = user.role === 'admin';

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50 relative">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30 shadow-xl">
          <div className="flex items-center space-x-4">
            <button onClick={onBack} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white hover:border-indigo-500/50 transition-all shadow-inner"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <div className="flex items-center space-x-2">
                <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">{course.title}</h2>
                {activeLesson.isExamMode && <span className="bg-rose-600 px-2 py-0.5 rounded text-[8px] font-black text-white uppercase tracking-widest animate-pulse">Timed Examination</span>}
              </div>
              <p className="text-base font-black text-white truncate max-w-[250px] leading-tight">{activeLesson.title}</p>
            </div>
          </div>

          {activeLesson.isExamMode && !quizState.complete ? (
            <div className="flex items-center space-x-4 bg-rose-500/10 border border-rose-500/30 px-6 py-2 rounded-xl">
              <i className="fas fa-stopwatch text-rose-500 text-sm"></i>
              <span className={`text-sm font-black tracking-widest ${timeLeft < 60 ? 'text-rose-500 animate-pulse' : 'text-white'}`}>
                {formatTimeLeft(timeLeft)}
              </span>
            </div>
          ) : (
            <button 
              disabled={activeLesson.isExamMode}
              onClick={() => !activeLesson.isExamMode && setIsAiOpen(!isAiOpen)} 
              className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeLesson.isExamMode ? 'bg-slate-950 text-slate-800 border border-slate-900 cursor-not-allowed' : isAiOpen ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'bg-slate-900 text-slate-500 border border-slate-800 hover:text-white'}`}
            >
              <i className={`fas ${activeLesson.isExamMode ? 'fa-lock' : 'fa-sparkles'} mr-2`}></i>
              {activeLesson.isExamMode ? 'AI Disabled' : 'AI Tutoring'}
            </button>
          )}
        </nav>

        <div className="flex-1 p-6 md:p-14 max-w-5xl mx-auto w-full space-y-10">
          {activeLesson.isExamMode ? (
            <div className="bg-slate-900/40 rounded-[32px] md:rounded-[40px] border border-dashed border-rose-500/30 py-16 flex flex-col items-center justify-center text-center backdrop-blur-sm animate-in fade-in duration-700">
              <div className="w-20 h-20 rounded-3xl flex items-center justify-center text-3xl mb-6 border shadow-inner bg-rose-500/10 text-rose-500 border-rose-500/20">
                <i className="fas fa-file-signature"></i>
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight uppercase">Formal Assessment</h3>
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-2">
                External aids, resources, and AI tools are restricted
              </p>
            </div>
          ) : activeLesson.videoUrl ? (
            <div className="bg-black rounded-[32px] md:rounded-[40px] overflow-hidden aspect-video border border-slate-800 shadow-2xl relative group ring-1 ring-white/5">
              <video key={activeLesson.id} ref={videoRef} src={activeLesson.videoUrl} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-slate-900/40 rounded-[32px] md:rounded-[40px] border border-dashed border-slate-800/60 py-24 flex flex-col items-center justify-center text-center backdrop-blur-sm">
              <div className="w-20 h-20 rounded-3xl flex items-center justify-center text-3xl mb-6 border shadow-inner bg-indigo-600/10 text-indigo-400 border-indigo-600/20">
                <i className="fas fa-book-open"></i>
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight">Theory & Content</h3>
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-2">
                This module focuses on academic reading materials
              </p>
            </div>
          )}

          {!activeLesson.isExamMode && (
            <div className="flex border-b border-slate-800 space-x-10 overflow-x-auto no-scrollbar scroll-smooth">
              <button onClick={() => setActiveTab('overview')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Content Overview</button>
              {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={() => setActiveTab('quiz')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Knowledge Check</button>}
              {isAdmin && <button onClick={() => setActiveTab('notes')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'notes' ? 'text-emerald-400 border-emerald-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Instructor Desk</button>}
            </div>
          )}

          <div className="min-h-[400px] pb-32 md:pb-24">
            {activeTab === 'overview' && !activeLesson.isExamMode && (
              <div className="animate-in fade-in duration-500 space-y-8">
                <div className="prose prose-invert prose-slate max-w-none text-slate-300 leading-relaxed text-lg" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                {activeLesson.resources && activeLesson.resources.length > 0 && (
                  <div className="mt-16 space-y-6 pt-12 border-t border-slate-800">
                    <h4 className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em]">Module Supplemental Assets</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {activeLesson.resources.map(res => (
                        <a key={res.id} href={res.url} target="_blank" rel="noopener noreferrer" className="flex items-center p-5 bg-slate-900 border border-slate-800 rounded-2xl hover:border-indigo-500/50 hover:bg-slate-950 transition-all group shadow-sm">
                          <div className="w-10 h-10 rounded-xl bg-slate-950 flex items-center justify-center text-sm text-indigo-400 mr-4 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner">
                            <i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play' : res.type === 'zip' ? 'fa-file-zipper' : 'fa-link'}`}></i>
                          </div>
                          <div>
                            <span className="text-sm font-black text-slate-200 block leading-tight">{res.title}</span>
                            <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1 block">{res.type} Format</span>
                          </div>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-8 max-w-2xl mx-auto animate-in fade-in slide-in-from-right-8 duration-500">
                {quizState.complete ? (
                  <div className="p-12 md:p-16 bg-slate-950 border border-slate-800 rounded-[40px] text-center shadow-2xl relative overflow-hidden">
                    <div className={`absolute top-0 left-0 w-full h-1 ${activeLesson.isExamMode ? 'bg-rose-500 shadow-[0_0_20px_rgba(244,63,94,0.5)]' : 'bg-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.5)]'}`}></div>
                    <div className={`w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8 text-4xl border shadow-inner animate-in zoom-in ${activeLesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/20' : 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20'}`}>
                      <i className={`fas ${activeLesson.isExamMode ? 'fa-award' : 'fa-check-double'}`}></i>
                    </div>
                    <h3 className="text-3xl font-black text-white tracking-tight mb-3">{activeLesson.isExamMode ? 'Examination Complete' : 'Mastery Verified'}</h3>
                    <p className="text-slate-500 text-xs font-black uppercase tracking-[0.2em] mb-12">Performance Metric: {Math.round((quizState.score/activeLesson.quiz.length)*100)}% Proficiency achieved</p>

                    <div className="flex flex-col sm:flex-row items-center justify-center gap-5">
                      {!activeLesson.isExamMode && <button onClick={resetQuiz} className="w-full sm:w-auto px-10 py-4 bg-slate-900 border border-slate-800 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-md active:scale-95">Retake Assessment</button>}
                      <button onClick={activeLesson.isExamMode ? onBack : () => setActiveTab('overview')} className="w-full sm:w-auto px-10 py-4 bg-indigo-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-2xl shadow-indigo-600/30 hover:bg-indigo-700 transition-all active:scale-95">
                        {activeLesson.isExamMode ? 'Return to Dashboard' : 'Back to Content'}
                      </button>
                    </div>
                  </div>
                ) : (
                  <div key={quizState.currentIdx} className="space-y-8 animate-in slide-in-from-right-12 duration-500">
                    <div className="flex justify-between items-center mb-4">
                      <p className="text-[11px] text-slate-500 font-black uppercase tracking-widest">Question {quizState.currentIdx + 1} of {activeLesson.quiz.length}</p>
                      <div className="w-48 h-2 bg-slate-900 border border-slate-800 rounded-full overflow-hidden shadow-inner">
                        <div 
                          className={`h-full transition-all duration-700 ${activeLesson.isExamMode ? 'bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.4)]' : 'bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.4)]'}`}
                          style={{ width: `${((quizState.currentIdx + 1) / activeLesson.quiz.length) * 100}%` }}
                        ></div>
                      </div>
                    </div>
                    <h4 className="text-2xl md:text-3xl font-black text-white tracking-tight leading-snug">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-4 pt-6">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button 
                          key={i} 
                          onClick={() => handleQuizAnswer(i)} 
                          className={`w-full p-6 bg-slate-900/50 border border-slate-800 rounded-3xl text-left transition-all font-black text-base text-slate-200 group flex items-center shadow-lg active:scale-[0.99] ${activeLesson.isExamMode ? 'hover:border-rose-500 hover:bg-rose-500/5' : 'hover:border-indigo-500 hover:bg-slate-900'}`}
                        >
                          <div className={`w-8 h-8 rounded-xl bg-slate-950 border border-slate-800 flex items-center justify-center mr-5 text-[10px] font-black transition-all shadow-inner ${activeLesson.isExamMode ? 'group-hover:bg-rose-600 group-hover:text-white' : 'group-hover:bg-indigo-600 group-hover:text-white'}`}>{String.fromCharCode(65 + i)}</div>
                          <span className="flex-1 leading-tight">{opt}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'notes' && isAdmin && !activeLesson.isExamMode && (
              <div className="animate-in slide-in-from-top-6 duration-500 p-10 bg-emerald-500/5 border border-emerald-500/20 rounded-[40px] shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl"></div>
                <div className="flex items-center space-x-4 mb-8">
                  <div className="w-12 h-12 bg-emerald-500/10 text-emerald-400 rounded-2xl flex items-center justify-center border border-emerald-500/20 shadow-inner text-xl">
                    <i className="fas fa-graduation-cap"></i>
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-emerald-400 uppercase tracking-widest">Instructor Desk</h3>
                    <p className="text-[10px] font-black text-emerald-600/60 uppercase tracking-widest mt-1">Teaching Guidelines & Context</p>
                  </div>
                </div>
                <div className="text-emerald-100/70 leading-relaxed text-base italic whitespace-pre-wrap font-medium">
                  {activeLesson.instructorNotes || 'Universal instructor guidance applies. Maintain consistent terminology and encourage AI-driven inquiry for deeper understanding.'}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer Navigation */}
        <div className="mt-auto p-4 md:p-8 border-t border-slate-800 bg-slate-950/80 backdrop-blur-xl flex justify-between items-center sticky bottom-0 z-30 shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
          {activeLesson.isExamMode && !quizState.complete ? (
            <button 
              onClick={handleSubmitExam}
              className="w-full flex items-center justify-center space-x-3 py-4 bg-rose-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-[0.3em] hover:bg-rose-700 transition-all shadow-xl shadow-rose-600/20 active:scale-95"
            >
              <span>Submit Examination</span>
              <i className="fas fa-paper-plane"></i>
            </button>
          ) : (
            <>
              <button 
                disabled={scopedIndex <= 0 || activeLesson.isExamMode} 
                onClick={() => setActiveLessonId(scopedLessons[scopedIndex - 1].id)} 
                className="flex items-center space-x-3 px-6 py-3.5 bg-slate-900 border border-slate-800 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-slate-500 disabled:opacity-20 hover:text-white hover:border-slate-700 transition-all shadow-xl active:scale-95"
              >
                <i className="fas fa-chevron-left"></i><span>Previous Module</span>
              </button>

              <div className="hidden md:flex space-x-3 overflow-x-auto px-4 max-w-[300px] no-scrollbar">
                {scopedLessons.map(l => (
                  <button 
                    key={l.id} 
                    onClick={() => setActiveLessonId(l.id)}
                    className={`w-2.5 h-2.5 rounded-full flex-shrink-0 transition-all duration-700 ${l.id === activeLessonId ? (activeLesson.isExamMode ? 'bg-rose-500 w-10 shadow-[0_0_15px_rgba(244,63,94,0.6)]' : 'bg-indigo-500 w-10 shadow-[0_0_15px_rgba(99,102,241,0.6)]') : 'bg-slate-800 hover:bg-slate-700'}`}
                  ></button>
                ))}
              </div>

              <button 
                disabled={scopedIndex === scopedLessons.length - 1 || activeLesson.isExamMode} 
                onClick={() => setActiveLessonId(scopedLessons[scopedIndex + 1].id)} 
                className={`flex items-center space-x-3 px-8 py-3.5 border rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white disabled:opacity-20 transition-all shadow-2xl active:scale-95 ${activeLesson.isExamMode ? 'bg-rose-600 border-rose-500 shadow-rose-600/30 hover:bg-rose-700' : 'bg-indigo-600 border-indigo-500/30 shadow-indigo-600/30 hover:bg-indigo-700'}`}
              >
                <span>Proceed Next</span><i className="fas fa-chevron-right"></i>
              </button>
            </>
          )}
        </div>
      </div>

      {/* AI Panel */}
      <aside className={`fixed lg:relative bottom-0 right-0 w-full lg:w-[450px] h-[85vh] lg:h-full bg-slate-950 border-t lg:border-t-0 lg:border-l border-slate-800 z-[40] transition-transform duration-500 ease-in-out transform ${isAiOpen && !activeLesson.isExamMode ? 'translate-y-0 lg:translate-x-0 shadow-2xl' : 'translate-y-full lg:translate-x-full lg:hidden'}`}>
        <div className="flex flex-col h-full relative ring-1 ring-white/5">
          <button onClick={() => setIsAiOpen(false)} className="lg:hidden absolute top-4 right-4 z-50 text-slate-500 text-xl p-3 bg-slate-900/50 rounded-full hover:text-white transition-all"><i className="fas fa-times"></i></button>
          {!activeLesson.isExamMode && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </aside>
    </div>
  );
};

export default CourseView;

import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Explore from './components/Explore';
import CourseView from './components/CourseView';
import AdminPanel from './components/AdminPanel';
import Profile from './components/Profile';
import Auth from './components/Auth';
import CourseDetails from './components/CourseDetails';
import { AppRoute, Course, User } from './types';
import { MOCK_COURSES } from './constants';
import { getAllCoursesFromDB, saveCourseToDB, deleteCourseFromDB } from './services/storage';

const App: React.FC = () => {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [activeCourseId, setActiveCourseId] = useState<string | null>(null);
  const [initialLessonId, setInitialLessonId] = useState<string | undefined>(undefined);
  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [courses, setCourses] = useState<Course[]>([]);
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [editingCourseId, setEditingCourseId] = useState<string | null>(null);

  // Selection states for Dashboard (Lifted to preserve "tp unit" context)
  const [selectedSubjectId, setSelectedSubjectId] = useState<string | null>(null);
  const [selectedSubSubjectId, setSelectedSubSubjectId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | null>(null);

  const checkCourseExpirations = useCallback((currentUser: User, allCourses: Course[]) => {
    if (!currentUser.enrolledCourses.length) return currentUser;

    const now = new Date();
    const validEnrolledIds = currentUser.enrolledCourses.filter(id => {
      const course = allCourses.find(c => c.id === id);
      if (!course || !course.expiryDate) return true;
      return new Date(course.expiryDate) > now;
    });

    if (validEnrolledIds.length !== currentUser.enrolledCourses.length) {
      const updatedUser = { ...currentUser, enrolledCourses: validEnrolledIds };
      localStorage.setItem('eduworld_user', JSON.stringify(updatedUser));
      return updatedUser;
    }
    return currentUser;
  }, []);

  useEffect(() => {
    const init = async () => {
      try {
        const savedCourses = await getAllCoursesFromDB();
        let currentCourses = savedCourses;
        if (savedCourses.length === 0) {
          for (const c of MOCK_COURSES) await saveCourseToDB(c);
          currentCourses = MOCK_COURSES;
        }
        setCourses(currentCourses);

        const savedUserStr = localStorage.getItem('eduworld_user');
        if (savedUserStr) {
          const savedUser = JSON.parse(savedUserStr);
          const cleanedUser = checkCourseExpirations(savedUser, currentCourses);
          setUser(cleanedUser);
        }
      } catch (e) {
        console.error("Init Error", e);
      } finally {
        setIsLoading(false);
      }
    };
    init();
  }, [checkCourseExpirations]);

  const handleLogin = (u: User) => {
    const cleanedUser = checkCourseExpirations(u, courses);
    setUser(cleanedUser);
    localStorage.setItem('eduworld_user', JSON.stringify(cleanedUser));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('eduworld_user');
    setRoute(AppRoute.DASHBOARD);
  };

  const navigate = (r: AppRoute) => {
    setRoute(r);
    if (r !== AppRoute.ADMIN) setEditingCourseId(null);
    window.scrollTo(0, 0);
  };

  const handleCourseClick = (id: string, lessonId?: string) => {
    setActiveCourseId(id);
    setInitialLessonId(lessonId);
    const isEnrolled = user?.enrolledCourses.includes(id);
    setRoute(isEnrolled ? AppRoute.COURSE_VIEW : AppRoute.COURSE_DETAILS);
  };

  const handleEnroll = (courseId: string) => {
    if (!user) return;
    const updated = { ...user, enrolledCourses: [...new Set([...user.enrolledCourses, courseId])] };
    setUser(updated);
    localStorage.setItem('eduworld_user', JSON.stringify(updated));
    setSelectedCourseId(courseId);
    setActiveCourseId(courseId);
    setRoute(AppRoute.DASHBOARD);
  };

  if (!user) return <Auth onLogin={handleLogin} />;
  if (isLoading) return <div className="h-screen bg-[#020617] flex items-center justify-center text-indigo-400 font-black uppercase tracking-widest animate-pulse text-xs">Syncing Neural Core...</div>;

  const activeCourse = courses.find(c => c.id === activeCourseId);
  const enrolledCourses = courses.filter(c => user.enrolledCourses.includes(c.id));

  const navItems = [
    { id: AppRoute.DASHBOARD, icon: 'fa-house', label: 'Home' },
    { id: AppRoute.COURSES, icon: 'fa-compass', label: 'Explore' },
    ...(user.role === 'admin' ? [{ id: AppRoute.ADMIN, icon: 'fa-shield-halved', label: 'Admin' }] : []),
    { id: AppRoute.PROFILE, icon: 'fa-user', label: 'Profile' }
  ];

  return (
    <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden relative">
      <div className={`hidden md:block h-full border-r border-slate-800 ${route === AppRoute.COURSE_VIEW ? 'hidden' : ''}`}>
        <Sidebar currentRoute={route} user={user} setRoute={navigate} onLogout={handleLogout} />
      </div>

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {route !== AppRoute.COURSE_VIEW && (
          <header className="md:hidden flex items-center justify-start px-6 py-5 bg-slate-950/80 backdrop-blur-xl border-b border-slate-800 z-50">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-600/20">
                <i className="fas fa-graduation-cap text-white text-[10px]"></i>
              </div>
              <span className="font-black text-white tracking-tighter text-lg uppercase">Edu World</span>
            </div>
          </header>
        )}

        <main className="flex-1 overflow-y-auto relative scroll-smooth bg-[#020617]">
          <div className={route !== AppRoute.COURSE_VIEW ? "p-4 md:p-12 pb-32 md:pb-12 max-w-[1600px] mx-auto" : "h-full"}>
            {route === AppRoute.DASHBOARD && (
              <Dashboard 
                onCourseClick={handleCourseClick} 
                setRoute={setRoute} 
                courses={enrolledCourses} 
                selectedCourseId={selectedCourseId} 
                onSelectCourse={setSelectedCourseId}
                selectedSubjectId={selectedSubjectId}
                setSelectedSubjectId={setSelectedSubjectId}
                selectedSubSubjectId={selectedSubSubjectId}
                setSelectedSubSubjectId={setSelectedSubSubjectId}
                selectedUnitId={selectedUnitId}
                setSelectedUnitId={setSelectedUnitId}
              />
            )}
            {route === AppRoute.COURSES && <Explore onCourseClick={handleCourseClick} courses={courses} />}
            {route === AppRoute.PROFILE && <Profile user={user} courses={enrolledCourses} onCourseClick={handleCourseClick} onUpdateUser={(u) => { setUser(u); localStorage.setItem('eduworld_user', JSON.stringify(u)); }} onLogout={handleLogout} />}
            {route === AppRoute.ADMIN && user.role === 'admin' && (
              <AdminPanel 
                courses={courses} 
                initialEditCourseId={editingCourseId} 
                onAddCourse={async (c) => { await saveCourseToDB(c); setCourses(await getAllCoursesFromDB()); }} 
                onUpdateCourse={async (c) => { await saveCourseToDB(c); setCourses(await getAllCoursesFromDB()); }} 
                onDeleteCourse={async (id) => { await deleteCourseFromDB(id); setCourses(await getAllCoursesFromDB()); }} 
                onPreview={() => {}} 
              />
            )}
            {route === AppRoute.COURSE_DETAILS && activeCourse && (
              <CourseDetails 
                course={activeCourse} 
                isAdmin={user.role === 'admin'} 
                isEnrolled={user.enrolledCourses.includes(activeCourse.id)} 
                onEnroll={handleEnroll} 
                onAdminEdit={() => { setEditingCourseId(activeCourse.id); setRoute(AppRoute.ADMIN); }} 
                onBack={() => setRoute(AppRoute.COURSES)} 
              />
            )}
            {route === AppRoute.COURSE_VIEW && activeCourse && (
              <CourseView 
                course={activeCourse} 
                user={user} 
                onBack={() => setRoute(AppRoute.DASHBOARD)} 
                initialLessonId={initialLessonId}
                onQuizComplete={(lid, att) => {
                  const updated = { ...user, quizScores: { ...user.quizScores, [lid]: att } };
                  setUser(updated);
                  localStorage.setItem('eduworld_user', JSON.stringify(updated));
                }} 
              />
            )}
          </div>
        </main>

        {route !== AppRoute.COURSE_VIEW && (
          <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-slate-900/90 backdrop-blur-2xl border-t border-slate-800 flex justify-around items-center px-4 py-4 z-50 safe-area-bottom shadow-[0_-8px_40px_rgba(0,0,0,0.6)]">
            {navItems.map(item => (
              <button 
                key={item.id}
                onClick={() => navigate(item.id)}
                className={`flex flex-col items-center justify-center space-y-1.5 py-1 transition-all ${route === item.id ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}
              >
                <div className={`text-xl ${route === item.id ? 'scale-110' : 'scale-100'} transition-transform duration-300`}>
                  <i className={`fas ${item.icon}`}></i>
                </div>
                <span className="text-[8px] font-black uppercase tracking-widest">{item.label}</span>
              </button>
            ))}
          </nav>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit, Lesson } from '../types';

interface DashboardProps {
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
  selectedSubjectId: string | null;
  setSelectedSubjectId: (id: string | null) => void;
  selectedSubSubjectId: string | null;
  setSelectedSubSubjectId: (id: string | null) => void;
  selectedUnitId: string | null;
  setSelectedUnitId: (id: string | null) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse,
  selectedSubjectId,
  setSelectedSubjectId,
  selectedSubSubjectId,
  setSelectedSubSubjectId,
  selectedUnitId,
  setSelectedUnitId
}) => {
  const [showCoursePicker, setShowCoursePicker] = useState(false);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  const selectedSubject = useMemo(() => activeCourse?.subjects?.find(s => s.id === selectedSubjectId) || null, [activeCourse, selectedSubjectId]);
  const selectedSubSubject = useMemo(() => selectedSubject?.subSubjects?.find(ss => ss.id === selectedSubSubjectId) || null, [selectedSubject, selectedSubSubjectId]);
  const selectedUnit = useMemo(() => selectedSubSubject?.units?.find(u => u.id === selectedUnitId) || null, [selectedSubSubject, selectedUnitId]);

  const timeRemaining = useMemo(() => {
    if (!activeCourse?.expiryDate) return null;
    const now = new Date();
    const expiry = new Date(activeCourse.expiryDate);
    const diff = expiry.getTime() - now.getTime();
    const days = Math.ceil(diff / (1000 * 60 * 60 * 24));

    if (days < 0) return "Access Expired";
    if (days === 0) return "Expires Today";
    if (days === 1) return "1 day remaining";
    return `${days} days remaining`;
  }, [activeCourse]);

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-16 h-16 md:w-24 md:h-24 bg-slate-900 text-indigo-400 rounded-[30px] md:rounded-[40px] flex items-center justify-center mb-8 border border-slate-800 shadow-inner">
          <i className="fas fa-rocket text-2xl md:text-3xl"></i>
        </div>
        <h2 className="text-xl md:text-3xl font-black text-slate-100 mb-4 px-4">Initialize Your Journey</h2>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-600/20">Access Course Catalog</button>
      </div>
    );
  }

  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubjectId(subj.id);
    setSelectedSubSubjectId(null);
    setSelectedUnitId(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubjectId(ss.id);
    setSelectedUnitId(null);
  };

  const handleUnitClick = (unit: Unit) => {
    setSelectedUnitId(unit.id);
  };

  const handleBack = () => {
    if (selectedUnit) {
      setSelectedUnitId(null);
    } else if (selectedSubSubject) {
      setSelectedSubSubjectId(null);
    } else if (selectedSubject) {
      setSelectedSubjectId(null);
    }
  };

  const filteredLessons = useMemo(() => {
    if (!selectedUnit) return [];
    return activeCourse.lessons.filter(l => 
      l.subjectId === selectedSubjectId && 
      l.subSubjectId === selectedSubSubjectId &&
      l.unitId === selectedUnitId
    );
  }, [activeCourse.lessons, selectedSubjectId, selectedSubSubjectId, selectedUnitId]);

  const uncategorizedLessons = activeCourse.lessons.filter(l => !l.subjectId);

  const subHeader = (selectedSubject || selectedSubSubject || selectedUnit) 
    ? activeCourse.title 
    : 'Academic Curriculum';

  const mainTitle = useMemo(() => {
    if (selectedUnit) return `${selectedSubject?.name} • ${selectedSubSubject?.name} • ${selectedUnit.name}`;
    if (selectedSubSubject) return `${selectedSubject?.name} • ${selectedSubSubject.name}`;
    if (selectedSubject) return selectedSubject.name;
    return activeCourse.title;
  }, [selectedSubject, selectedSubSubject, selectedUnit, activeCourse.title]);

  const unitHasExams = (unitId: string) => {
    return activeCourse.lessons.some(l => l.unitId === unitId && l.isExamMode);
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-5xl mx-auto px-0">
      {courses.length > 1 && !selectedSubject && (
        <div className="flex justify-end px-4 md:px-0">
          <div className="relative">
            <button 
              onClick={() => setShowCoursePicker(!showCoursePicker)}
              className="flex items-center space-x-3 px-4 py-2 bg-slate-900 border border-slate-800 rounded-xl hover:border-indigo-500 transition-all group"
            >
              <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest group-hover:text-indigo-400">Switch Program</span>
              <i className={`fas fa-chevron-down text-[8px] text-slate-600 group-hover:text-indigo-400 transition-transform ${showCoursePicker ? 'rotate-180' : ''}`}></i>
            </button>
            {showCoursePicker && (
              <div className="absolute top-full right-0 mt-2 w-72 bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl z-[100] p-2 animate-in zoom-in-95 duration-200">
                {courses.map(c => (
                  <button 
                    key={c.id}
                    onClick={() => {
                      onSelectCourse(c.id);
                      setShowCoursePicker(false);
                    }}
                    className={`w-full text-left p-4 rounded-xl transition-all flex items-center space-x-3 group ${activeCourse.id === c.id ? 'bg-indigo-600/10 border border-indigo-500/20' : 'hover:bg-slate-800 border border-transparent'}`}
                  >
                    <img src={c.thumbnail} className="w-10 h-10 rounded-lg object-cover" alt="" />
                    <div className="min-w-0">
                      <p className={`text-xs font-black truncate ${activeCourse.id === c.id ? 'text-white' : 'text-slate-400'}`}>{c.title}</p>
                      {c.expiryDate && (
                        <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mt-0.5">
                          Expires: {new Date(c.expiryDate).toLocaleDateString()}
                        </p>
                      )}
                    </div>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      <div className="bg-slate-900/50 rounded-[32px] md:rounded-[48px] border border-slate-800/50 p-6 md:p-14 text-center shadow-2xl backdrop-blur-sm relative overflow-hidden group">
        {(selectedSubject || selectedSubSubject || selectedUnit) && (
          <button 
            onClick={handleBack}
            className="absolute left-4 md:left-10 top-6 md:top-1/2 md:-translate-y-1/2 w-9 h-9 md:w-12 md:h-12 bg-slate-950 border border-slate-800 rounded-full flex items-center justify-center text-slate-400 hover:text-white hover:border-indigo-500/50 transition-all z-10 shadow-xl"
          >
            <i className="fas fa-arrow-left text-xs"></i>
          </button>
        )}

        <div className="relative z-10 space-y-3 px-8 md:px-0">
          <p className="text-[9px] md:text-xs font-black text-slate-500 uppercase tracking-[0.3em] opacity-80 animate-in slide-in-from-top-2">
            {subHeader}
          </p>
          <h1 className="text-xl md:text-4xl font-black text-white tracking-tighter leading-tight drop-shadow-md break-words">
            {mainTitle}
          </h1>

          {!selectedSubject && activeCourse.expiryDate && (
            <div className="inline-flex items-center px-4 py-1.5 bg-indigo-600/10 rounded-full border border-indigo-500/20 animate-in fade-in duration-700 delay-200">
               <i className="fas fa-hourglass-half text-indigo-400 text-[10px] mr-2"></i>
               <span className="text-[9px] md:text-[10px] font-black text-indigo-400 uppercase tracking-[0.1em]">
                  {timeRemaining}
               </span>
            </div>
          )}
        </div>
        <div className="absolute -top-20 -right-20 w-80 h-80 bg-indigo-600/10 rounded-full blur-[100px] group-hover:bg-indigo-600/20 transition-all duration-1000"></div>
      </div>

      <div className="bg-slate-900/30 rounded-[32px] md:rounded-[40px] border border-slate-800/40 p-4 md:p-12 shadow-xl backdrop-blur-sm min-h-[400px] relative">
        {!selectedSubject ? (
          <div className="space-y-10 md:space-y-14">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8">
              {(activeCourse.subjects || []).map((subj) => (
                <button 
                  key={subj.id} 
                  onClick={() => handleSubjectClick(subj)}
                  className="flex items-center justify-between p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group relative overflow-hidden shadow-lg active:scale-95 text-left"
                >
                  <div className="flex items-center space-x-4 md:space-x-5">
                    <div className={`w-12 h-12 md:w-16 md:h-16 rounded-2xl flex items-center justify-center text-xl md:text-2xl shadow-inner border border-white/5 ${subj.color} group-hover:scale-105 transition-transform`}>
                      <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                    </div>
                    <div>
                      <span className="text-lg md:text-xl font-black text-slate-100 group-hover:text-white transition-colors block leading-tight">{subj.name}</span>
                      <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1 block">Explorer Units</span>
                    </div>
                  </div>
                  <div className="w-8 h-8 md:w-9 md:h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center transition-all group-hover:bg-indigo-600/10 shrink-0">
                    <i className="fas fa-chevron-right text-[10px] text-indigo-500"></i>
                  </div>
                </button>
              ))}
            </div>

            {uncategorizedLessons.length > 0 && (
              <div className="space-y-8 pt-10 border-t border-slate-800/50">
                <div className="flex items-center space-x-4">
                  <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-950 border border-slate-800 rounded-2xl flex items-center justify-center text-slate-600 shadow-inner">
                    <i className="fas fa-folder-open text-lg md:text-xl"></i>
                  </div>
                  <div>
                    <h3 className="text-[10px] md:text-sm font-black text-slate-200 uppercase tracking-[0.2em]">General Resources</h3>
                    <p className="text-[9px] md:text-[10px] font-black text-slate-600 uppercase mt-1">Foundation Modules</p>
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-5">
                  {uncategorizedLessons.map((lesson) => (
                    <button 
                      key={lesson.id} 
                      onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                      className="flex items-center p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-[24px] md:rounded-[28px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md"
                    >
                      <div className={`w-9 h-9 md:w-10 md:h-10 rounded-xl flex items-center justify-center mr-4 md:mr-5 transition-colors ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500' : 'bg-slate-900 text-slate-700 group-hover:text-indigo-400'}`}>
                        <i className={`fas ${lesson.isExamMode ? 'fa-file-signature' : 'fa-file-lines'}`}></i>
                      </div>
                      <div className="flex-1 text-left">
                        <div className="flex items-center space-x-2">
                          <h4 className="font-bold text-slate-100 group-hover:text-white transition-colors text-sm md:text-base">{lesson.title}</h4>
                          {lesson.isExamMode && <i className="fas fa-stopwatch text-rose-500 text-[10px] animate-pulse"></i>}
                        </div>
                        <span className="text-[9px] md:text-[10px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : !selectedSubSubject ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-8 duration-500">
            {selectedSubject.subSubjects.map((ss) => (
              <button 
                key={ss.id} 
                onClick={() => handleSubSubjectClick(ss)}
                className="flex items-center justify-between p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group shadow-lg active:scale-95 text-left"
              >
                <div className="flex items-center space-x-4 md:space-x-5">
                  <div className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl flex items-center justify-center text-base md:text-lg bg-slate-900 text-indigo-400 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm`}><i className="fas fa-layer-group"></i></div>
                  <span className="text-base md:text-lg font-black text-slate-100 group-hover:text-indigo-400 transition-colors leading-tight">{ss.name}</span>
