                >
                  <div className="flex items-center space-x-4 md:space-x-5">
                    <div className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl flex items-center justify-center text-base md:text-lg bg-slate-900 border border-slate-800 group-hover:text-white transition-all shadow-sm ${hasExam ? 'text-rose-400 group-hover:bg-rose-600' : 'text-emerald-400 group-hover:bg-emerald-600'}`}>
                      <i className={`fas ${hasExam ? 'fa-file-signature' : 'fa-cube'}`}></i>
                    </div>
                    <div>
                      <span className="text-base md:text-lg font-black text-slate-100 group-hover:text-white transition-colors leading-tight">{unit.name}</span>
                      {hasExam && <p className="text-[7px] font-black text-rose-500 uppercase tracking-widest mt-1">Exam Active</p>}
                    </div>
                  </div>
                  <div className={`w-8 h-8 md:w-9 md:h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center shrink-0 ${hasExam ? 'group-hover:border-rose-500/50' : 'group-hover:border-emerald-500/50'}`}>
                    <i className={`fas fa-chevron-right text-[10px] ${hasExam ? 'text-rose-500' : 'text-emerald-500'}`}></i>
                  </div>
                </button>
              );
            })}
            {(!selectedSubSubject.units || selectedSubSubject.units.length === 0) && (
              <div className="col-span-full py-20 md:py-28 flex flex-col items-center justify-center text-center opacity-40 px-6">
                <i className="fas fa-mountain-sun text-4xl md:text-5xl mb-6 text-slate-700"></i>
                <h3 className="text-xl md:text-2xl font-black text-white">Structure Pending</h3>
                <p className="text-[9px] md:text-xs font-bold text-slate-500 mt-2 uppercase tracking-widest">Awaiting admin initialization for this unit</p>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6 md:space-y-8 animate-in slide-in-from-right-8 duration-500">
            {filteredLessons.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-5">
                {filteredLessons.map((lesson, idx) => (
                  <button 
                    key={lesson.id} 
                    onClick={() => onCourseClick(activeCourse.id, lesson.id)}
                    className="flex items-center p-5 md:p-6 bg-slate-950 border border-slate-800/50 rounded-[28px] md:rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all group active:scale-98 shadow-md text-left"
                  >
                    <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center text-[10px] md:text-xs font-black border mr-4 md:mr-5 transition-all shadow-inner ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/30' : 'bg-slate-900 text-slate-500 border-slate-800 group-hover:text-indigo-400 group-hover:border-indigo-500/30'}`}>
                      {lesson.isExamMode ? <i className="fas fa-file-signature text-[10px]"></i> : (idx + 1)}
