import { Course, UserDocument } from '../types';

const DB_NAME = 'EduWorldDB';
const STORE_COURSES = 'courses';
const STORE_VAULT = 'vault';
const DB_VERSION = 2; // Incremented version for new store

export const initDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_COURSES)) {
        db.createObjectStore(STORE_COURSES, { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains(STORE_VAULT)) {
        db.createObjectStore(STORE_VAULT, { keyPath: 'id' });
      }
    };

    request.onsuccess = (event) => {
      resolve((event.target as IDBOpenDBRequest).result);
    };

    request.onerror = (event) => {
      reject('IndexedDB error: ' + (event.target as IDBOpenDBRequest).error);
    };
  });
};

export const saveCourseToDB = async (course: Course): Promise<void> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_COURSES], 'readwrite');
    const store = transaction.objectStore(STORE_COURSES);
    const request = store.put(course);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

export const getAllCoursesFromDB = async (): Promise<Course[]> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_COURSES], 'readonly');
    const store = transaction.objectStore(STORE_COURSES);
    const request = store.getAll();

    request.onsuccess = () => resolve(request.result || []);
    request.onerror = () => reject(request.error);
  });
};

export const deleteCourseFromDB = async (id: string): Promise<void> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_COURSES], 'readwrite');
    const store = transaction.objectStore(STORE_COURSES);
    const request = store.delete(id);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

// Vault Storage for large PDFs and User Documents
export const saveDocToVault = async (doc: UserDocument): Promise<void> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_VAULT], 'readwrite');
    const store = transaction.objectStore(STORE_VAULT);
    const request = store.put(doc);
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

export const getDocFromVault = async (id: string): Promise<UserDocument | undefined> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_VAULT], 'readonly');
    const store = transaction.objectStore(STORE_VAULT);
    const request = store.get(id);
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const getAllDocsFromVault = async (ids: string[]): Promise<UserDocument[]> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_VAULT], 'readonly');
    const store = transaction.objectStore(STORE_VAULT);
    const docs: UserDocument[] = [];

    // Efficiently get specific docs by IDs
    let count = 0;
    if (ids.length === 0) return resolve([]);

    ids.forEach(id => {
      const req = store.get(id);
      req.onsuccess = () => {
        if (req.result) docs.push(req.result);
        count++;
        if (count === ids.length) resolve(docs);
      };
      req.onerror = () => {
        count++;
        if (count === ids.length) resolve(docs);
      };
    });
  });
};

export const deleteDocFromVault = async (id: string): Promise<void> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([STORE_VAULT], 'readwrite');
    const store = transaction.objectStore(STORE_VAULT);
    const request = store.delete(id);
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

