  'fa-dna', 'fa-vial', 'fa-language', 'fa-earth-americas', 'fa-calculator', 'fa-square-root-variable', 
  'fa-code', 'fa-terminal', 'fa-laptop-code', 'fa-tower-broadcast', 'fa-brain', 'fa-palette', 
  'fa-music', 'fa-feather', 'fa-landmark', 'fa-scale-balanced', 'fa-briefcase', 'fa-heart-pulse', 
  'fa-volleyball', 'fa-person-running', 'fa-gears', 'fa-shield-halved', 'fa-chart-pie', 'fa-compass',
  'fa-star', 'fa-lightbulb', 'fa-magnifying-glass', 'fa-pencil', 'fa-user-graduate', 'fa-globe', 'fa-award', 'fa-certificate'
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [iconPickerOpenId, setIconPickerOpenId] = useState<string | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || [],
      expiryDate: currentCourse.expiryDate
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    // For thumbnails, Blobs are safer but since they are small, we store the File object
    // which IndexedDB handles perfectly.
    setCurrentCourse(prev => ({ ...prev, thumbnail: file }));
  };

  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    // Do NOT read as data URL. Store the File/Blob directly.
    if (editingLessonIdx !== null) {
      updateLesson(editingLessonIdx, { videoUrl: file });
    }
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      isExamMode: false,
      examDuration: 30,
      quiz: [],
      resources: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addQuizQuestion = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];

      const newQuestion: QuizQuestion = {
        id: Math.random().toString(36).substr(2, 9),
        question: 'New Question?',
        options: ['Option 1', 'Option 2', 'Option 3', 'Option 4'],
        correctAnswer: 0
      };

      lesson.quiz = [...currentQuiz, newQuestion];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateQuizQuestion = (qIdx: number, updates: Partial<QuizQuestion>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = [...(lesson.quiz || [])];
      currentQuiz[qIdx] = { ...currentQuiz[qIdx], ...updates };
      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeQuizQuestion = (qIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentQuiz = (lesson.quiz || []).filter((_, i) => i !== qIdx);
      lesson.quiz = currentQuiz;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const addResource = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];
      const newResource: Resource = {
        id: Math.random().toString(36).substr(2, 9),
        title: 'New Resource',
        url: '',
        type: 'link',
        description: ''
      };
      lesson.resources = [...currentResources, newResource];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateResource = (rIdx: number, updates: Partial<Resource>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];
      currentResources[rIdx] = { ...currentResources[rIdx], ...updates };
      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeResource = (rIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = (lesson.resources || []).filter((_, i) => i !== rIdx);
      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const addSubject = () => {
    const newSubj: SubjectGroup = { id: Math.random().toString(36).substr(2, 9), name: 'New Subject', icon: 'fa-book', color: COLOR_PRESETS[3], subSubjects: [] };
    setCurrentCourse(prev => ({ ...prev, subjects: [...(prev?.subjects || []), newSubj] }));
  };

  const addSubSubject = (subjectId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjectId ? { ...s, subSubjects: [...s.subSubjects, { id: Math.random().toString(36).substr(2, 9), name: 'New Sub-group', units: [] }] } : s)
    }));
  };

  const addUnit = (subjId: string, ssId: string) => {
    setCurrentCourse(prev => ({
      ...prev,
      subjects: (prev?.subjects || []).map(s => s.id === subjId ? { 
        ...s, 
        subSubjects: s.subSubjects.map(ss => ss.id === ssId ? { ...ss, units: [...(ss.units || []), { id: Math.random().toString(36).substr(2, 9), name: 'New Unit' }] } : ss) 
      } : s)
    }));
  };

  // Safe object URL generator for previews
  const thumbnailPreview = useMemo(() => {
    if (!currentCourse?.thumbnail) return null;
    if (typeof currentCourse.thumbnail === 'string') return currentCourse.thumbnail;
    return URL.createObjectURL(currentCourse.thumbnail);
  }, [currentCourse?.thumbnail]);

  const lessonVideoPreview = useMemo(() => {
    if (editingLessonIdx === null || !currentCourse?.lessons) return null;
    const url = currentCourse.lessons[editingLessonIdx].videoUrl;
    if (!url) return null;
    if (typeof url === 'string') return url;
    return URL.createObjectURL(url);
  }, [editingLessonIdx, currentCourse?.lessons]);

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-6 md:space-y-8 pb-24 animate-in fade-in duration-500">

        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto flex flex-col p-4 md:p-12 animate-in slide-in-from-right-8 duration-500">
            <div className="max-w-5xl mx-auto w-full space-y-6 md:space-y-8">
              <div className="flex flex-col md:flex-row md:items-center justify-between border-b border-slate-800 pb-6 md:pb-8 gap-4">
                <div className="flex items-center space-x-4 md:space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all shadow-xl"><i className="fas fa-arrow-left"></i></button>
                  <h2 className="text-xl md:text-3xl font-black text-white tracking-tight">Module Architect</h2>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="w-full md:w-auto px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Done & Close</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8">
                <div className="lg:col-span-8 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="md:col-span-2 space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Module Title</label>
                        <input type="text" value={currentLesson.title} onChange={e => updateLesson(editingLessonIdx!, { title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none transition-all text-sm" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Length (EST)</label>
                        <input type="text" value={currentLesson.duration} onChange={e => updateLesson(editingLessonIdx!, { duration: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none transition-all text-sm" />
                      </div>
                    </div>

                    <div className="space-y-4 pt-4 border-t border-slate-800">
                      <div className="flex items-center justify-between">
                        <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Video Resource</label>
                        <button onClick={() => videoInputRef.current?.click()} className="px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">
                          {isUploading ? 'Syncing...' : <><i className="fas fa-upload mr-2"></i>Upload Big Video</>}
                        </button>
                        <input type="file" ref={videoInputRef} onChange={handleVideoUpload} className="hidden" accept="video/*" />
                      </div>
                      {lessonVideoPreview && (
                        <div className="mt-4 rounded-xl overflow-hidden border border-slate-800 aspect-video bg-black">
                          <video src={lessonVideoPreview} controls className="w-full h-full" />
                        </div>
                      )}
                      <input type="text" value={typeof currentLesson.videoUrl === 'string' ? currentLesson.videoUrl : '(Binary Asset Stored)'} readOnly className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-slate-400 font-mono text-xs focus:border-indigo-500 outline-none transition-all" />
                    </div>
                  </div>

                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 ml-1">Academic Content (HTML)</h3>
                    <textarea rows={10} value={currentLesson.content} onChange={e => updateLesson(editingLessonIdx!, { content: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-300 font-mono text-xs leading-relaxed outline-none focus:border-indigo-500/30 transition-all" />
                  </div>

                  {/* Asset Library */}
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6 shadow-sm">
                    <div className="flex items-center justify-between">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Asset Library (Resources)</h3>
                       <button onClick={addResource} className="px-4 py-2 bg-indigo-600/20 text-indigo-400 border border-indigo-500/30 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600 hover:text-white transition-all">+ Add Asset</button>
                    </div>

                    <div className="space-y-4">
                      {(currentLesson.resources || []).map((res, rIdx) => (
                        <div key={res.id} className="p-5 bg-slate-950 border border-slate-800 rounded-2xl space-y-4 relative group animate-in slide-in-from-bottom-2">
                          <button onClick={() => removeResource(rIdx)} className="absolute top-4 right-4 text-slate-800 hover:text-rose-500 transition-colors p-2"><i className="fas fa-trash-alt text-xs"></i></button>

                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="space-y-1">
                               <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Resource Title</label>
                               <input type="text" value={res.title} onChange={e => updateResource(rIdx, { title: e.target.value })} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white text-xs font-bold focus:border-indigo-500 outline-none" />
                            </div>
                            <div className="space-y-1">
                               <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Resource Type</label>
                               <select value={res.type} onChange={e => updateResource(rIdx, { type: e.target.value as any })} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white text-[10px] font-black uppercase outline-none focus:border-indigo-500">
                                  <option value="link">External Link</option>
                                  <option value="pdf">PDF Document</option>
                                  <option value="video">Video Stream</option>
                                  <option value="zip">Archive (ZIP)</option>
                               </select>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 text-center md:text-left">Architectural Link</h3>
                    <div className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-[8px] font-black text-slate-700 uppercase tracking-widest ml-1">Parent Subject</label>
                        <select value={currentLesson.subjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value, subSubjectId: undefined, unitId: undefined })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 outline-none focus:border-indigo-500">
                          <option value="">Unassigned</option>
                          {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                      </div>

                      <div className="pt-4 border-t border-slate-800 space-y-4">
                        <div className="flex items-center justify-between">
                          <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Exam Mode</label>
                          <button 
                            onClick={() => updateLesson(editingLessonIdx!, { isExamMode: !currentLesson.isExamMode })}
                            className={`w-10 h-5 rounded-full relative transition-all ${currentLesson.isExamMode ? 'bg-rose-600' : 'bg-slate-800'}`}
                          >
                            <div className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow-md transition-all ${currentLesson.isExamMode ? 'left-[22px]' : 'left-[2px]'}`}></div>
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Action Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-4 md:px-0">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white text-[10px] font-black uppercase tracking-widest transition-colors self-start flex items-center"><i className="fas fa-arrow-left mr-2"></i> Registry Hub</button>
          <button onClick={handleSave} className="w-full md:w-auto px-10 py-4 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Commit Changes</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] md:rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="p-6 md:p-12">
            {activeTab === 'info' && (
              <div className="space-y-10 animate-in fade-in duration-300">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                      <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({ ...currentCourse!, title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none text-sm shadow-inner" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Category</label>
                      <input type="text" value={currentCourse.category || ''} onChange={e => setCurrentCourse({ ...currentCourse!, category: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold focus:border-indigo-500 outline-none text-sm shadow-inner" />
                    </div>
                  </div>
                  <div className="space-y-6">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Identity Visual</label>
                    <div className="aspect-video bg-slate-950 rounded-3xl border border-slate-800 overflow-hidden relative group shadow-inner">
                      {thumbnailPreview ? (
                        <img src={thumbnailPreview} className="w-full h-full object-cover" alt="preview" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-slate-700 font-black uppercase text-[10px]">Registry Thumbnail Pending</div>
                      )}
                      <div className="absolute inset-0 bg-slate-950/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                        <button onClick={() => thumbnailInputRef.current?.click()} className="px-6 py-2 bg-white text-slate-950 rounded-xl font-black text-[9px] uppercase shadow-xl transform scale-90 group-hover:scale-100 transition-transform">Replace Asset</button>
                      </div>
                    </div>
                    <input type="file" ref={thumbnailInputRef} className="hidden" accept="image/*" onChange={handleThumbnailUpload} />
                  </div>
                </div>
              </div>
            )}
            {/* Curriculum and Structure tabs follow standard pattern... */}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 px-4 md:px-0">
        <div>
          <h1 className="text-3xl md:text-5xl font-black text-white tracking-tight leading-none mb-2">Academic Registry</h1>
          <p className="text-slate-500 font-bold uppercase tracking-[0.2em] text-[10px]">Manage neural-linked expert programs</p>
        </div>
        <button onClick={() => { setCurrentCourse({ id: Math.random().toString(36).substr(2, 9), title: 'New Program', lessons: [], subjects: [], category: 'Academic', price: 0, roadmap: [] }); setIsEditing(true); }} className="w-full md:w-auto px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-xl shadow-indigo-600/20 tracking-widest active:scale-95 transition-all"><i className="fas fa-plus mr-3"></i> Initialize Program</button>
      </div>

      <div className="grid grid-cols-1 gap-4 px-4 md:px-0">
        {courses.map(course => (
          <div key={course.id} className="bg-slate-900 rounded-[28px] md:rounded-[40px] border border-slate-800 p-6 flex flex-col lg:flex-row lg:items-center justify-between gap-6 group hover:border-indigo-500/40 hover:bg-slate-900/50 transition-all shadow-xl">
             <div className="flex items-center space-x-6 min-w-0">
                <div className="w-20 md:w-32 h-14 md:h-20 overflow-hidden rounded-2xl border border-slate-800 shadow-inner shrink-0">
                  <img src={typeof course.thumbnail === 'string' ? course.thumbnail : URL.createObjectURL(course.thumbnail)} className="w-full h-full object-cover group-hover:scale-105 transition-transform" alt="" />
                </div>
                <div className="min-w-0">
                  <h4 className="font-black text-slate-100 text-lg md:text-2xl group-hover:text-indigo-400 transition-colors leading-tight truncate">{course.title}</h4>
                </div>
             </div>
             <div className="flex items-center justify-end space-x-3 lg:ml-6 border-t lg:border-t-0 border-slate-800 pt-5 lg:pt-0 shrink-0">
                <button onClick={() => { setCurrentCourse({ ...course }); setIsEditing(true); }} className="flex-1 lg:flex-none h-12 md:h-14 px-8 bg-slate-950 rounded-2xl text-slate-500 hover:text-white hover:bg-indigo-600 border border-slate-800 hover:border-indigo-500 transition-all shadow-sm text-[10px] font-black uppercase tracking-widest"><i className="fas fa-edit mr-3"></i> Architect</button>
                <button onClick={() => onDeleteCourse(course.id)} className="h-12 md:h-14 w-12 md:w-14 bg-slate-950 rounded-2xl text-slate-500 hover:text-rose-500 flex items-center justify-center border border-slate-800 transition-all shadow-sm transition-colors"><i className="fas fa-trash-alt text-sm"></i></button>
             </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useRef, useEffect } from 'react';
import { User, Course, UserDocument } from '../types';
import CourseCard from './CourseCard';
import { saveDocToVault, getAllDocsFromVault, deleteDocFromVault } from '../services/storage';

interface ProfileProps {
  user: User;
  courses: Course[];
  onCourseClick: (id: string) => void;
  onUpdateUser: (user: User) => void;
  onLogout: () => void;
}

const Profile: React.FC<ProfileProps> = ({ user, courses, onCourseClick, onUpdateUser, onLogout }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [isAvatarUploading, setIsAvatarUploading] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [vaultDocs, setVaultDocs] = useState<UserDocument[]>([]);

  // Settings Form State
  const [settingsName, setSettingsName] = useState(user.name);
  const [settingsError, setSettingsError] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const avatarInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadVault = async () => {
      const docs = await getAllDocsFromVault(user.documents || []);
      setVaultDocs(docs);
    };
    loadVault();
  }, [user.documents]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || file.type !== 'application/pdf') {
      alert('Please upload a valid PDF file.');
      return;
    }

    setIsUploading(true);
    try {
      // Store the File object directly as it is a Blob
      const newDoc: UserDocument = {
        id: Math.random().toString(36).substr(2, 9),
        title: file.name,
        data: file,
        uploadDate: new Date(),
      };

      await saveDocToVault(newDoc);

      // Update User object with the new document ID
      const updatedDocs = [...(user.documents || []), newDoc.id];
      onUpdateUser({
        ...user,
        documents: updatedDocs,
      });

      setVaultDocs(prev => [newDoc, ...prev]);
    } catch (err) {
      console.error("Vault Upload Error:", err);
      alert("Failed to secure document in vault.");
    } finally {
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !file.type.startsWith('image/')) return;

    setIsAvatarUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      onUpdateUser({ ...user, avatar: event.target?.result as string });
      setIsAvatarUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    if (!settingsName.trim()) {
      setSettingsError('Name cannot be empty.');
      return;
    }
    onUpdateUser({ ...user, name: settingsName });
    setIsSettingsOpen(false);
  };

  const removeDoc = async (id: string) => {
    if (window.confirm('Erase this record from vault?')) {
      await deleteDocFromVault(id);
      onUpdateUser({
        ...user,
        documents: (user.documents || []).filter(d => d !== id),
      });
      setVaultDocs(prev => prev.filter(d => d.id !== id));
    }
  };

  const downloadDoc = (doc: UserDocument) => {
    const url = typeof doc.data === 'string' ? doc.data : URL.createObjectURL(doc.data);
    const link = document.createElement('a');
    link.href = url;
    link.download = doc.title;
    link.click();
    // Cleanup if it was a Blob URL
    if (typeof doc.data !== 'string') {
      setTimeout(() => URL.revokeObjectURL(url), 100);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 md:space-y-12 pb-24 animate-in fade-in duration-500">

      {/* Settings Modal */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-lg rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
            <div className="p-8 border-b border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-black text-slate-100 uppercase tracking-widest">Settings</h3>
              <button onClick={() => setIsSettingsOpen(false)} className="text-slate-500"><i className="fas fa-times"></i></button>
            </div>
            <form onSubmit={handleSaveSettings} className="p-8 space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Display Name</label>
                <input type="text" value={settingsName} onChange={(e) => setSettingsName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white font-bold" />
              </div>
              {settingsError && <p className="text-xs text-rose-500 font-bold">{settingsError}</p>}
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs rounded-xl shadow-lg">Save Changes</button>
            </form>
          </div>
        </div>
      )}

      {/* Header */}
      <section className="bg-slate-900 rounded-[32px] md:rounded-[40px] border border-slate-800 p-6 md:p-14 shadow-2xl flex flex-col md:flex-row items-center md:items-start gap-8 md:gap-14">
        <div className="relative">
          <div className="w-28 h-28 md:w-36 md:h-36 rounded-3xl md:rounded-[48px] overflow-hidden border-4 border-slate-800 bg-slate-950 flex items-center justify-center">
            {isAvatarUploading ? <i className="fas fa-spinner fa-spin text-indigo-500 text-2xl"></i> : <img src={user.avatar} className="w-full h-full object-cover" alt={user.name} />}
          </div>
          <button onClick={() => avatarInputRef.current?.click()} className="absolute -bottom-2 -right-2 w-10 h-10 bg-indigo-600 text-white rounded-xl flex items-center justify-center border-4 border-slate-900"><i className="fas fa-camera text-xs"></i></button>
          <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={handleAvatarUpload} />
        </div>

        <div className="flex-1 text-center md:text-left">
          <h1 className="text-3xl md:text-5xl font-black text-slate-100 tracking-tighter mb-2">{user.name}</h1>
          <div className="flex flex-wrap items-center justify-center md:justify-start gap-3 mb-6">
             <span className="px-3 py-1 bg-indigo-500/10 text-indigo-400 font-black uppercase tracking-widest text-[9px] rounded-full border border-indigo-500/20">{user.role}</span>
          </div>
        </div>

        <div className="w-full md:w-auto flex flex-col space-y-3">
          <button onClick={() => setIsSettingsOpen(true)} className="w-full md:w-auto px-8 py-4 bg-slate-100 text-slate-950 font-black text-[10px] uppercase tracking-widest rounded-xl shadow-lg">Settings</button>
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 md:gap-12">
        <div className="lg:col-span-2 space-y-6">
          <h2 className="text-xl font-black text-white uppercase tracking-widest">Active Learning</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {courses.map(course => <CourseCard key={course.id} course={course} onClick={onCourseClick} showProgress />)}
          </div>
        </div>

        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-white uppercase tracking-widest">Neural Vault</h2>
            <button onClick={() => fileInputRef.current?.click()} disabled={isUploading} className="w-10 h-10 bg-indigo-600 text-white rounded-xl flex items-center justify-center shadow-lg"><i className={`fas ${isUploading ? 'fa-spinner fa-spin' : 'fa-plus'}`}></i></button>
            <input type="file" ref={fileInputRef} className="hidden" accept="application/pdf" onChange={handleFileUpload} />
          </div>

          <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-6 space-y-4">
            {vaultDocs.length > 0 ? vaultDocs.map(doc => (
              <div key={doc.id} className="flex items-center p-4 bg-slate-950 rounded-2xl border border-slate-800 group">
                <div className="w-10 h-10 bg-slate-900 rounded-lg flex items-center justify-center text-indigo-400 mr-4"><i className="fas fa-file-pdf"></i></div>
                <div className="flex-1 min-w-0">
                  <p className="text-xs font-black text-slate-200 truncate">{doc.title}</p>
                </div>
                <div className="flex space-x-2">
                  <button onClick={() => downloadDoc(doc)} className="text-slate-600 hover:text-indigo-400"><i className="fas fa-download text-xs"></i></button>
                  <button onClick={() => removeDoc(doc.id)} className="text-slate-600 hover:text-rose-500"><i className="fas fa-trash-alt text-xs"></i></button>
                </div>
              </div>
            )) : <p className="text-[9px] text-slate-600 font-black uppercase text-center py-10">Vault empty. Upload PDFs securely.</p>}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Course, QuizAttempt, User } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [videoSourceUrl, setVideoSourceUrl] = useState<string | null>(null);

  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Handle Binary Video Blobs and Object URL Lifecycle
  useEffect(() => {
    if (!activeLesson.videoUrl) {
      setVideoSourceUrl(null);
      return;
    }

    let url: string;
    if (typeof activeLesson.videoUrl === 'string') {
      url = activeLesson.videoUrl;
    } else {
      url = URL.createObjectURL(activeLesson.videoUrl);
    }

    setVideoSourceUrl(url);

    // Cleanup Object URL when lesson changes or component unmounts
    return () => {
      if (typeof activeLesson.videoUrl !== 'string' && url) {
        URL.revokeObjectURL(url);
      }
    };
  }, [activeLessonId, activeLesson.videoUrl]);

  const [timeLeft, setTimeLeft] = useState<number>(0);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (activeLesson.isExamMode && !quizState.complete) {
      setTimeLeft((activeLesson.examDuration || 30) * 60);
      setActiveTab('quiz');
      if (timerRef.current) clearInterval(timerRef.current);
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            if (timerRef.current) clearInterval(timerRef.current);
            handleSubmitExam();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [activeLessonId, activeLesson.isExamMode]);

  const formatTimeLeft = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const scopedLessons = useMemo(() => {
    return course.lessons.filter(l => 
      l.subjectId === activeLesson.subjectId && 
      l.subSubjectId === activeLesson.subSubjectId &&
      l.unitId === activeLesson.unitId
    );
  }, [course.lessons, activeLesson]);

  const scopedIndex = useMemo(() => 
    scopedLessons.findIndex(l => l.id === activeLessonId)
  , [scopedLessons, activeLessonId]);

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
    if (activeLesson.isExamMode) setIsAiOpen(false);
  }, [activeLessonId]);

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;
    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const handleSubmitExam = () => {
    setQuizState(prev => ({ ...prev, complete: true }));
    onQuizComplete(activeLesson.id, { score: quizState.score, total: activeLesson.quiz?.length || 0, date: new Date() });
    if (timerRef.current) clearInterval(timerRef.current);
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50 relative">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30 shadow-xl">
          <div className="flex items-center space-x-4">
            <button onClick={onBack} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{course.title}</h2>
              <p className="text-base font-black text-white truncate max-w-[250px]">{activeLesson.title}</p>
            </div>
          </div>
          {activeLesson.isExamMode && !quizState.complete && (
            <div className="bg-rose-500/10 border border-rose-500/30 px-6 py-2 rounded-xl text-rose-500 font-black text-sm">
              <i className="fas fa-stopwatch mr-2"></i> {formatTimeLeft(timeLeft)}
            </div>
          )}
        </nav>

        <div className="flex-1 p-6 md:p-14 max-w-5xl mx-auto w-full space-y-10">
          {videoSourceUrl ? (
            <div className="bg-black rounded-[32px] overflow-hidden aspect-video border border-slate-800 shadow-2xl relative">
              <video key={videoSourceUrl} ref={videoRef} src={videoSourceUrl} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-slate-900/40 rounded-[32px] border border-dashed border-slate-800/60 py-24 flex flex-col items-center justify-center text-center">
              <i className="fas fa-book-open text-3xl mb-4 text-indigo-400"></i>
              <h3 className="text-xl font-black text-white">Module Curriculum</h3>
            </div>
          )}

          {!activeLesson.isExamMode && (
            <div className="flex border-b border-slate-800 space-x-10 overflow-x-auto no-scrollbar">
              <button onClick={() => setActiveTab('overview')} className={`pb-4 text-[11px] font-black uppercase tracking-widest border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Overview</button>
              {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={() => setActiveTab('quiz')} className={`pb-4 text-[11px] font-black uppercase tracking-widest border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Quiz</button>}
            </div>
          )}

          <div className="min-h-[400px] pb-32">
            {activeTab === 'overview' && !activeLesson.isExamMode && (
              <div className="animate-in fade-in duration-500 prose prose-invert max-w-none text-slate-300" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />
            )}

            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-8 max-w-2xl mx-auto">
                {quizState.complete ? (
                  <div className="p-12 bg-slate-950 border border-slate-800 rounded-[40px] text-center shadow-2xl">
                    <i className="fas fa-award text-4xl mb-6 text-emerald-400"></i>
                    <h3 className="text-2xl font-black text-white mb-8">Performance Recorded</h3>
                    <button onClick={onBack} className="px-10 py-4 bg-indigo-600 text-white rounded-2xl text-[11px] font-black uppercase shadow-xl hover:bg-indigo-700 transition-all">Finish Module</button>
                  </div>
                ) : (
                  <div key={quizState.currentIdx} className="space-y-6">
                    <h4 className="text-2xl font-black text-white">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-4">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button key={i} onClick={() => handleQuizAnswer(i)} className="w-full p-6 bg-slate-900 border border-slate-800 rounded-3xl text-left hover:border-indigo-500 transition-all font-black text-slate-200">{opt}</button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="mt-auto p-8 border-t border-slate-800 bg-slate-950/80 backdrop-blur-xl flex justify-between items-center sticky bottom-0 z-30">
          <button disabled={scopedIndex <= 0} onClick={() => setActiveLessonId(scopedLessons[scopedIndex - 1].id)} className="px-6 py-3 bg-slate-900 border border-slate-800 rounded-2xl text-[11px] font-black uppercase text-slate-500 hover:text-white transition-all">Prev</button>
          <button disabled={scopedIndex === scopedLessons.length - 1} onClick={() => setActiveLessonId(scopedLessons[scopedIndex + 1].id)} className="px-8 py-3 bg-indigo-600 text-white rounded-2xl text-[11px] font-black uppercase shadow-xl hover:bg-indigo-700 transition-all">Next</button>
        </div>
      </div>
      <aside className={`fixed lg:relative bottom-0 right-0 w-full lg:w-[450px] h-[85vh] lg:h-full bg-slate-950 border-l border-slate-800 transition-transform ${isAiOpen ? 'translate-x-0' : 'translate-x-full lg:hidden'}`}>
        {!activeLesson.isExamMode && <AIAssistant course={course} lesson={activeLesson} user={user} />}
      </aside>
    </div>
  );
};

export default CourseView;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, QuizQuestion, Resource } from '../types';

