import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Course, QuizAttempt, User, Resource } from '../types';
import AIAssistant from './AIAssistant';

interface CourseViewProps {
  course: Course;
  user: User;
  onBack: () => void;
  initialLessonId?: string;
  onQuizComplete: (lessonId: string, attempt: QuizAttempt) => void;
}

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);

  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  useEffect(() => {
    if (!activeLesson.videoUrl) {
      setVideoUrl(null);
      return;
    }
    let url: string;
    if (typeof activeLesson.videoUrl === 'string') {
      url = activeLesson.videoUrl;
    } else {
      url = URL.createObjectURL(activeLesson.videoUrl);
    }
    setVideoUrl(url);
    return () => {
      if (typeof activeLesson.videoUrl !== 'string' && url) URL.revokeObjectURL(url);
    };
  }, [activeLessonId, activeLesson.videoUrl]);

  const [timeLeft, setTimeLeft] = useState<number>(0);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (activeLesson.isExamMode && !quizState.complete) {
      setTimeLeft((activeLesson.examDuration || 30) * 60);
      setActiveTab('quiz');
      if (timerRef.current) clearInterval(timerRef.current);
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            if (timerRef.current) clearInterval(timerRef.current);
            handleSubmitExam();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [activeLessonId, activeLesson.isExamMode]);

  const formatTimeLeft = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const scopedLessons = useMemo(() => {
    return course.lessons.filter(l => 
      l.subjectId === activeLesson.subjectId && 
      l.subSubjectId === activeLesson.subSubjectId &&
      l.unitId === activeLesson.unitId
    );
  }, [course.lessons, activeLesson]);

  const scopedIndex = useMemo(() => 
    scopedLessons.findIndex(l => l.id === activeLessonId)
  , [scopedLessons, activeLessonId]);

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
    if (activeLesson.isExamMode) setIsAiOpen(false);
  }, [activeLessonId]);

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;
    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const handleSubmitExam = () => {
    setQuizState(prev => ({ ...prev, complete: true }));
    onQuizComplete(activeLesson.id, { score: quizState.score, total: activeLesson.quiz?.length || 0, date: new Date() });
    if (timerRef.current) clearInterval(timerRef.current);
  };

  const handleResourceAction = (res: Resource) => {
    if (typeof res.url === 'string') {
      window.open(res.url, '_blank');
    } else {
      const url = URL.createObjectURL(res.url);
      const link = document.createElement('a');
      link.href = url;
      link.download = res.title;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      setTimeout(() => URL.revokeObjectURL(url), 100);
    }
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50 relative">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30 shadow-xl">
          <div className="flex items-center space-x-4">
            <button onClick={onBack} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all shadow-inner"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-widest leading-none mb-1">{course.title}</h2>
              <p className="text-base font-black text-white truncate max-w-[250px] leading-tight">{activeLesson.title}</p>
            </div>
          </div>
          {activeLesson.isExamMode && !quizState.complete && (
            <div className="bg-rose-500/10 border border-rose-500/30 px-6 py-2 rounded-xl text-rose-500 font-black text-sm">
              <i className="fas fa-stopwatch mr-2"></i> {formatTimeLeft(timeLeft)}
            </div>
          )}
        </nav>

        <div className="flex-1 p-6 md:p-14 max-w-5xl mx-auto w-full space-y-10">
          {videoUrl ? (
            <div className="bg-black rounded-[32px] md:rounded-[40px] overflow-hidden aspect-video border border-slate-800 shadow-2xl relative">
              <video key={activeLesson.id} ref={videoRef} src={videoUrl} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-slate-900/40 rounded-[32px] md:rounded-[40px] border border-dashed border-slate-800/60 py-24 flex flex-col items-center justify-center text-center">
              <i className="fas fa-book-open text-3xl mb-4 text-indigo-400"></i>
              <h3 className="text-2xl font-black text-white">Theory Module</h3>
            </div>
          )}

          {!activeLesson.isExamMode && (
            <div className="flex border-b border-slate-800 space-x-10 overflow-x-auto no-scrollbar">
              <button onClick={() => setActiveTab('overview')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-widest border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Overview</button>
              {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={() => setActiveTab('quiz')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-widest border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Assessment</button>}
            </div>
          )}

          <div className="min-h-[400px] pb-32">
            {activeTab === 'overview' && !activeLesson.isExamMode && (
              <div className="animate-in fade-in duration-500 space-y-10">
                <div className="prose prose-invert max-w-none text-slate-300 leading-relaxed text-lg" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                {activeLesson.resources && activeLesson.resources.length > 0 && (
                  <div className="pt-10 border-t border-slate-800">
                    <h4 className="text-[11px] font-black text-slate-500 uppercase tracking-widest mb-6">Asset Library</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {activeLesson.resources.map(res => (
                        <button 
                          key={res.id} 
                          onClick={() => handleResourceAction(res)}
                          className="flex items-center p-5 bg-slate-950 border border-slate-800 rounded-2xl hover:border-indigo-500/50 transition-all text-left group"
                        >
                          <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-indigo-400 mr-4 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner">
                            <i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play' : res.type === 'zip' ? 'fa-file-zipper' : 'fa-link'}`}></i>
                          </div>
                          <div>
                            <p className="text-sm font-black text-slate-100">{res.title}</p>
                            <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{res.type} format</p>
                          </div>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-8 max-w-2xl mx-auto">
                {quizState.complete ? (
                  <div className="p-12 bg-slate-950 border border-slate-800 rounded-[40px] text-center shadow-2xl">
                    <i className="fas fa-award text-4xl mb-6 text-emerald-400"></i>
                    <h3 className="text-3xl font-black text-white mb-8">Assessment Complete</h3>
                    <button onClick={onBack} className="px-10 py-4 bg-indigo-600 text-white rounded-2xl text-[11px] font-black uppercase shadow-xl hover:bg-indigo-700 transition-all">Continue Journey</button>
                  </div>
                ) : (
                  <div key={quizState.currentIdx} className="space-y-8 animate-in slide-in-from-right-8">
                    <h4 className="text-2xl font-black text-white">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-4">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button key={i} onClick={() => handleQuizAnswer(i)} className="w-full p-6 bg-slate-900 border border-slate-800 rounded-3xl text-left hover:border-indigo-500 hover:bg-slate-950 transition-all font-black text-slate-200 flex items-center shadow-lg">
                          <span className="w-8 h-8 rounded-lg bg-slate-950 flex items-center justify-center mr-5 border border-slate-800 text-[10px]">{String.fromCharCode(65 + i)}</span>
                          {opt}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="mt-auto p-8 border-t border-slate-800 bg-slate-950/80 backdrop-blur-xl flex justify-between items-center sticky bottom-0 z-30">
          <button disabled={scopedIndex <= 0} onClick={() => setActiveLessonId(scopedLessons[scopedIndex - 1].id)} className="px-6 py-3 bg-slate-900 border border-slate-800 rounded-2xl text-[11px] font-black uppercase text-slate-500 hover:text-white transition-all shadow-xl">Prev</button>
          <button disabled={scopedIndex === scopedLessons.length - 1} onClick={() => setActiveLessonId(scopedLessons[scopedIndex + 1].id)} className="px-8 py-3 bg-indigo-600 text-white rounded-2xl text-[11px] font-black uppercase shadow-xl hover:bg-indigo-700 transition-all active:scale-95">Next Module</button>
        </div>
      </div>
      <aside className={`fixed lg:relative bottom-0 right-0 w-full lg:w-[450px] h-[85vh] lg:h-full bg-slate-950 border-l border-slate-800 transition-transform ${isAiOpen ? 'translate-x-0' : 'translate-x-full lg:hidden'}`}>
        {!activeLesson.isExamMode && <AIAssistant course={course} lesson={activeLesson} user={user} />}
      </aside>
    </div>
  );
};

