const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'structure'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [activeResourceIdx, setActiveResourceIdx] = useState<number | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const resourceInputRef = useRef<HTMLInputElement>(null);
  const apkInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || [],
      expiryDate: currentCourse.expiryDate,
      appApk: currentCourse.appApk
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCurrentCourse(prev => ({ ...prev, thumbnail: file }));
  };

  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (editingLessonIdx !== null) {
      updateLesson(editingLessonIdx, { videoUrl: file });
    }
  };

  const handleApkUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCurrentCourse(prev => ({ ...prev, appApk: file }));
  };

  const handleResourceFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || editingLessonIdx === null || activeResourceIdx === null) return;

    let type: 'link' | 'pdf' | 'video' | 'zip' = 'link';
    if (file.type.includes('pdf')) type = 'pdf';
    else if (file.type.includes('video')) type = 'video';
    else if (file.name.match(/\.(zip|rar|7z)$/i)) type = 'zip';

    updateResource(activeResourceIdx, { 
      url: file, 
      title: file.name,
      type 
    });
    setActiveResourceIdx(null);
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      isExamMode: false,
      examDuration: 30,
      quiz: [],
      resources: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addResource = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];
      const newResource: Resource = {
        id: Math.random().toString(36).substr(2, 9),
        title: 'New Resource',
        url: '',
        type: 'link'
      };
      lesson.resources = [...currentResources, newResource];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateResource = (rIdx: number, updates: Partial<Resource>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];
      currentResources[rIdx] = { ...currentResources[rIdx], ...updates };
      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeResource = (rIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = (lesson.resources || []).filter((_, i) => i !== rIdx);
      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const thumbnailPreview = useMemo(() => {
    if (!currentCourse?.thumbnail) return null;
    if (typeof currentCourse.thumbnail === 'string') return currentCourse.thumbnail;
    return URL.createObjectURL(currentCourse.thumbnail);
  }, [currentCourse?.thumbnail]);

  const lessonVideoPreview = useMemo(() => {
    if (editingLessonIdx === null || !currentCourse?.lessons) return null;
    const url = currentCourse.lessons[editingLessonIdx].videoUrl;
    if (!url) return null;
    if (typeof url === 'string') return url;
    return URL.createObjectURL(url);
  }, [editingLessonIdx, currentCourse?.lessons]);

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-6 md:space-y-8 pb-24 animate-in fade-in duration-500">

        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto flex flex-col p-4 md:p-12 animate-in slide-in-from-right-8 duration-500">
            <div className="max-w-5xl mx-auto w-full space-y-6 md:space-y-8">
              <div className="flex flex-col md:flex-row md:items-center justify-between border-b border-slate-800 pb-6 md:pb-8 gap-4">
                <div className="flex items-center space-x-4 md:space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all shadow-xl"><i className="fas fa-arrow-left"></i></button>
                  <h2 className="text-xl md:text-3xl font-black text-white tracking-tight">Module Architect</h2>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="w-full md:w-auto px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Done & Close</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8">
                <div className="lg:col-span-8 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6">
                    <div className="flex items-center justify-between">
                       <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Lesson Video</label>
                       <button onClick={() => videoInputRef.current?.click()} className="px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">
                          Upload Binary Video
                       </button>
                       <input type="file" ref={videoInputRef} onChange={handleVideoUpload} className="hidden" accept="video/*" />
                    </div>
                    {lessonVideoPreview && (
                      <div className="mt-4 rounded-xl overflow-hidden border border-slate-800 aspect-video bg-black shadow-2xl">
                        <video src={lessonVideoPreview} controls className="w-full h-full" />
                      </div>
                    )}
                  </div>

                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6 shadow-sm">
                    <div className="flex items-center justify-between">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Asset Library</h3>
                       <button onClick={addResource} className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all">+ Add Asset</button>
                    </div>

                    <div className="space-y-4">
                      {(currentLesson.resources || []).map((res, rIdx) => (
                        <div key={res.id} className="p-5 bg-slate-950 border border-slate-800 rounded-2xl space-y-4 relative group animate-in slide-in-from-bottom-2">
                          <button onClick={() => removeResource(rIdx)} className="absolute top-4 right-4 text-slate-800 hover:text-rose-500 transition-colors p-2"><i className="fas fa-trash-alt text-xs"></i></button>
                          <div className="flex items-center space-x-3">
                             <input type="text" value={res.title} onChange={e => updateResource(rIdx, { title: e.target.value })} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white text-xs font-bold" placeholder="Asset Name" />
                             <button onClick={() => { setActiveResourceIdx(rIdx); resourceInputRef.current?.click(); }} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest">Upload File</button>
                          </div>
                        </div>
                      ))}
                      <input type="file" ref={resourceInputRef} onChange={handleResourceFileUpload} className="hidden" />
                    </div>
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Framework Sync</h3>
                    <div className="space-y-4">
                      <select value={currentLesson.subjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400">
                        <option value="">Unassigned</option>
                        {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                      </select>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-4 md:px-0">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white text-[10px] font-black uppercase tracking-widest transition-colors self-start flex items-center"><i className="fas fa-arrow-left mr-2"></i> Hub Registry</button>
          <button onClick={handleSave} className="w-full md:w-auto px-10 py-4 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Commit Changes</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] md:rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'mobile'].map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>
                {tab === 'info' ? 'Profile' : tab === 'curriculum' ? 'Modules' : 'Mobile Core'}
              </button>
            ))}
          </div>
          <div className="p-6 md:p-12">
            {activeTab === 'info' && (
              <div className="space-y-10 animate-in fade-in duration-300">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                    <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({ ...currentCourse!, title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold outline-none shadow-inner" />
                  </div>
                  <div className="space-y-6 text-center">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Identify Visual</label>
                    <div className="aspect-video bg-slate-950 rounded-3xl border border-slate-800 overflow-hidden relative group">
                      {thumbnailPreview ? <img src={thumbnailPreview} className="w-full h-full object-cover" alt="preview" /> : <div className="w-full h-full flex items-center justify-center text-slate-700 font-black text-[10px]">No Thumbnail</div>}
                      <button onClick={() => thumbnailInputRef.current?.click()} className="absolute inset-0 bg-slate-950/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-white font-black text-[10px] uppercase">Replace</button>
                    </div>
                    <input type="file" ref={thumbnailInputRef} className="hidden" accept="image/*" onChange={handleThumbnailUpload} />
                  </div>
                </div>
              </div>
            )}
            {activeTab === 'mobile' && (
              <div className="space-y-10 animate-in fade-in duration-300">
                <div className="max-w-xl mx-auto text-center space-y-6 py-10">
                  <div className="w-20 h-20 bg-indigo-600/10 text-indigo-400 rounded-3xl flex items-center justify-center mx-auto border border-indigo-500/20 text-3xl shadow-inner">
                    <i className="fas fa-mobile-screen"></i>
                  </div>
                  <h3 className="text-2xl font-black text-white">Neural Bridge APK</h3>
                  <p className="text-slate-500 text-xs font-bold leading-relaxed">Upload the native Android application package (.apk) for this course. Mobile users will see a download button on their dashboard.</p>

                  <div className="pt-8 flex flex-col items-center">
                    <button onClick={() => apkInputRef.current?.click()} className="px-12 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">
                      {currentCourse.appApk ? 'Update Bridge binary' : 'Upload APK Binary'}
                    </button>
                    <input type="file" ref={apkInputRef} className="hidden" accept=".apk" onChange={handleApkUpload} />
                    {currentCourse.appApk && (
                      <div className="mt-4 flex items-center space-x-2 text-emerald-400 font-black text-[9px] uppercase tracking-widest animate-in slide-in-from-top-2">
                        <i className="fas fa-check-circle"></i>
                        <span>Binary Synced: {typeof currentCourse.appApk === 'string' ? 'Cloud' : (currentCourse.appApk as File).name}</span>
                        <button onClick={() => setCurrentCourse(prev => ({ ...prev, appApk: undefined }))} className="ml-4 text-slate-700 hover:text-rose-500 transition-colors"><i className="fas fa-trash-alt"></i></button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useMemo, useEffect } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit } from '../types';

interface DashboardProps {
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
  selectedSubjectId: string | null;
  setSelectedSubjectId: (id: string | null) => void;
  selectedSubSubjectId: string | null;
  setSelectedSubSubjectId: (id: string | null) => void;
  selectedUnitId: string | null;
  setSelectedUnitId: (id: string | null) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse,
  selectedSubjectId,
  setSelectedSubjectId,
  selectedSubSubjectId,
  setSelectedSubSubjectId,
  selectedUnitId,
  setSelectedUnitId
}) => {
  const [showCoursePicker, setShowCoursePicker] = useState(false);
  const [isMobile, setIsMobile] = useState(false);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(/iPhone|iPad|iPod|Android/i.test(navigator.userAgent));
    };
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const selectedSubject = useMemo(() => activeCourse?.subjects?.find(s => s.id === selectedSubjectId) || null, [activeCourse, selectedSubjectId]);
  const selectedSubSubject = useMemo(() => selectedSubject?.subSubjects?.find(ss => ss.id === selectedSubSubjectId) || null, [selectedSubject, selectedSubSubjectId]);
  const selectedUnit = useMemo(() => selectedSubSubject?.units?.find(u => u.id === selectedUnitId) || null, [selectedSubSubject, selectedUnitId]);

  const handleDownloadApp = () => {
    if (!activeCourse?.appApk) return;
    const url = typeof activeCourse.appApk === 'string' ? activeCourse.appApk : URL.createObjectURL(activeCourse.appApk);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${activeCourse.title.replace(/\s+/g, '_')}_App.apk`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    if (typeof activeCourse.appApk !== 'string') {
      setTimeout(() => URL.revokeObjectURL(url), 100);
    }
  };

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-24 h-24 bg-slate-900 text-indigo-400 rounded-[40px] flex items-center justify-center mb-8 border border-slate-800 shadow-inner">
          <i className="fas fa-rocket text-3xl"></i>
        </div>
        <h2 className="text-3xl font-black text-slate-100 mb-4 px-4">Initialize Your Journey</h2>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Course Catalog</button>
      </div>
    );
  }

  const handleSubjectClick = (subj: SubjectGroup) => {
    setSelectedSubjectId(subj.id);
    setSelectedSubSubjectId(null);
    setSelectedUnitId(null);
  };

  const handleSubSubjectClick = (ss: SubSubject) => {
    setSelectedSubSubjectId(ss.id);
    setSelectedUnitId(null);
  };

  const handleUnitClick = (unit: Unit) => {
    setSelectedUnitId(unit.id);
  };

  const handleBack = () => {
    if (selectedUnit) setSelectedUnitId(null);
    else if (selectedSubSubject) setSelectedSubSubjectId(null);
    else if (selectedSubject) setSelectedSubjectId(null);
  };

  const filteredLessons = useMemo(() => {
    if (!selectedUnit) return [];
    return activeCourse.lessons.filter(l => 
      l.subjectId === selectedSubjectId && 
      l.subSubjectId === selectedSubSubjectId &&
      l.unitId === selectedUnitId
    );
  }, [activeCourse.lessons, selectedSubjectId, selectedSubSubjectId, selectedUnitId]);

  const uncategorizedLessons = activeCourse.lessons.filter(l => !l.subjectId);

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-5xl mx-auto px-0">

      {/* Mobile App Download Banner */}
      {isMobile && activeCourse.appApk && !selectedSubject && (
        <div className="mx-4 md:mx-0 p-6 bg-gradient-to-r from-indigo-900/40 to-indigo-600/20 border border-indigo-500/30 rounded-[32px] flex flex-col sm:flex-row items-center justify-between gap-6 animate-in slide-in-from-top-4 duration-700">
           <div className="flex items-center space-x-6 text-center sm:text-left">
              <div className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center text-xl shadow-lg shrink-0">
                <i className="fas fa-mobile-screen"></i>
              </div>
              <div>
                <h4 className="text-lg font-black text-white leading-tight">Neural Bridge APK</h4>
                <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mt-1">Native Mobile Experience Ready</p>
              </div>
           </div>
           <button onClick={handleDownloadApp} className="w-full sm:w-auto px-8 py-3.5 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-xl active:scale-95 transition-all">
             <i className="fas fa-download mr-3"></i> Download App
           </button>
        </div>
      )}

      {courses.length > 1 && !selectedSubject && (
        <div className="flex justify-end px-4 md:px-0">
          <button 
            onClick={() => setShowCoursePicker(!showCoursePicker)}
            className="flex items-center space-x-3 px-4 py-2 bg-slate-900 border border-slate-800 rounded-xl hover:border-indigo-500 transition-all group"
          >
            <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Switch Program</span>
            <i className={`fas fa-chevron-down text-[8px] transition-transform ${showCoursePicker ? 'rotate-180' : ''}`}></i>
          </button>
          {showCoursePicker && (
            <div className="absolute top-16 right-4 md:right-auto mt-2 w-72 bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl z-[100] p-2 animate-in zoom-in-95">
              {courses.map(c => (
                <button 
                  key={c.id}
                  onClick={() => { onSelectCourse(c.id); setShowCoursePicker(false); }}
                  className={`w-full text-left p-4 rounded-xl transition-all flex items-center space-x-3 ${activeCourse.id === c.id ? 'bg-indigo-600/10 border border-indigo-500/20' : 'hover:bg-slate-800 border border-transparent'}`}
                >
                  <img src={typeof c.thumbnail === 'string' ? c.thumbnail : URL.createObjectURL(c.thumbnail)} className="w-10 h-10 rounded-lg object-cover" alt="" />
                  <p className={`text-xs font-black truncate ${activeCourse.id === c.id ? 'text-white' : 'text-slate-400'}`}>{c.title}</p>
                </button>
              ))}
            </div>
          )}
        </div>
      )}

      <div className="bg-slate-900/50 rounded-[32px] md:rounded-[48px] border border-slate-800/50 p-6 md:p-14 text-center shadow-2xl backdrop-blur-sm relative overflow-hidden group">
        {(selectedSubject || selectedSubSubject || selectedUnit) && (
          <button onClick={handleBack} className="absolute left-4 md:left-10 top-6 md:top-1/2 md:-translate-y-1/2 w-10 h-10 bg-slate-950 border border-slate-800 rounded-full flex items-center justify-center text-slate-400 hover:text-white transition-all z-10">
            <i className="fas fa-arrow-left text-xs"></i>
          </button>
        )}
        <div className="relative z-10 space-y-3">
          <p className="text-[9px] md:text-xs font-black text-slate-500 uppercase tracking-[0.3em]">{selectedUnit ? 'Module Set' : selectedSubSubject ? 'Unit Group' : selectedSubject ? 'Subject Core' : 'Active Program'}</p>
          <h1 className="text-xl md:text-4xl font-black text-white tracking-tighter leading-tight">
            {selectedUnit ? selectedUnit.name : selectedSubSubject ? selectedSubSubject.name : selectedSubject ? selectedSubject.name : activeCourse.title}
          </h1>
        </div>
      </div>

      <div className="bg-slate-900/30 rounded-[32px] md:rounded-[40px] border border-slate-800/40 p-4 md:p-12 shadow-xl backdrop-blur-sm min-h-[400px]">
        {!selectedSubject ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8">
            {(activeCourse.subjects || []).map((subj) => (
              <button 
                key={subj.id} 
                onClick={() => handleSubjectClick(subj)}
                className="flex items-center justify-between p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all group shadow-lg text-left"
              >
                <div className="flex items-center space-x-5">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl border ${subj.color}`}>
                    <i className={`fas ${subj.icon || 'fa-book-open'}`}></i>
                  </div>
                  <span className="text-lg font-black text-slate-100">{subj.name}</span>
                </div>
                <i className="fas fa-chevron-right text-xs text-indigo-500"></i>
              </button>
            ))}
          </div>
        ) : !selectedSubSubject ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-8">
            {selectedSubject.subSubjects.map((ss) => (
              <button key={ss.id} onClick={() => handleSubSubjectClick(ss)} className="flex items-center justify-between p-6 bg-slate-950 border border-slate-800 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all text-left">
                <span className="text-lg font-black text-slate-100">{ss.name}</span>
                <i className="fas fa-chevron-right text-xs text-indigo-500"></i>
              </button>
            ))}
          </div>
        ) : !selectedUnit ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 animate-in slide-in-from-right-8">
            {selectedSubSubject.units?.map((unit) => (
              <button key={unit.id} onClick={() => handleUnitClick(unit)} className="flex items-center justify-between p-6 bg-slate-950 border border-slate-800 rounded-3xl hover:border-indigo-500/40 hover:bg-slate-900 transition-all text-left">
                <span className="text-lg font-black text-slate-100">{unit.name}</span>
                <i className="fas fa-chevron-right text-xs text-indigo-500"></i>
              </button>
            ))}
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5 animate-in slide-in-from-right-8">
            {filteredLessons.map((lesson, idx) => (
              <button key={lesson.id} onClick={() => onCourseClick(activeCourse.id, lesson.id)} className="flex items-center p-6 bg-slate-950 border border-slate-800/50 rounded-[32px] hover:border-indigo-500/40 hover:bg-slate-900 transition-all text-left group">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xs font-black border mr-5 ${lesson.isExamMode ? 'bg-rose-500/10 text-rose-500' : 'bg-slate-900 text-slate-500'}`}>
                  {idx + 1}
                </div>
                <div className="flex-1">
                  <h4 className="font-bold text-slate-100 text-base">{lesson.title}</h4>
                  <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                </div>
                <i className="fas fa-chevron-right text-[10px] text-indigo-400 opacity-0 group-hover:opacity-100 transition-opacity"></i>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, QuizQuestion, Resource } from '../types';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
  'bg-slate-500/10 text-slate-400 border-slate-500/20',
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse, onPreview }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  // Corrected activeTab type to include 'mobile' and match usage in the UI
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'mobile'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [activeResourceIdx, setActiveResourceIdx] = useState<number | null>(null);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const resourceInputRef = useRef<HTMLInputElement>(null);
  const apkInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || [],
      expiryDate: currentCourse.expiryDate,
      appApk: currentCourse.appApk
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const handleThumbnailUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCurrentCourse(prev => ({ ...prev, thumbnail: file }));
  };

  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (editingLessonIdx !== null) {
      updateLesson(editingLessonIdx, { videoUrl: file });
    }
  };

  const handleApkUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCurrentCourse(prev => ({ ...prev, appApk: file }));
  };

  const handleResourceFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || editingLessonIdx === null || activeResourceIdx === null) return;

    let type: 'link' | 'pdf' | 'video' | 'zip' = 'link';
    if (file.type.includes('pdf')) type = 'pdf';
    else if (file.type.includes('video')) type = 'video';
    else if (file.name.match(/\.(zip|rar|7z)$/i)) type = 'zip';

    updateResource(activeResourceIdx, { 
      url: file, 
      title: file.name,
      type 
    });
    setActiveResourceIdx(null);
  };

  const addLesson = (subjId?: string, ssId?: string, uId?: string) => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      subjectId: subjId,
      subSubjectId: ssId,
      unitId: uId,
      hasAiFeature: true,
      isExamMode: false,
      examDuration: 30,
      quiz: [],
      resources: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addResource = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];
      const newResource: Resource = {
        id: Math.random().toString(36).substr(2, 9),
        title: 'New Resource',
        url: '',
        type: 'link'
      };
      lesson.resources = [...currentResources, newResource];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateResource = (rIdx: number, updates: Partial<Resource>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];
      currentResources[rIdx] = { ...currentResources[rIdx], ...updates };
      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeResource = (rIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = (lesson.resources || []).filter((_, i) => i !== rIdx);
      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const thumbnailPreview = useMemo(() => {
    if (!currentCourse?.thumbnail) return null;
    if (typeof currentCourse.thumbnail === 'string') return currentCourse.thumbnail;
    return URL.createObjectURL(currentCourse.thumbnail);
  }, [currentCourse?.thumbnail]);

  const lessonVideoPreview = useMemo(() => {
    if (editingLessonIdx === null || !currentCourse?.lessons) return null;
    const url = currentCourse.lessons[editingLessonIdx].videoUrl;
    if (!url) return null;
    if (typeof url === 'string') return url;
    return URL.createObjectURL(url);
  }, [editingLessonIdx, currentCourse?.lessons]);

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-6 md:space-y-8 pb-24 animate-in fade-in duration-500">

        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto flex flex-col p-4 md:p-12 animate-in slide-in-from-right-8 duration-500">
            <div className="max-w-5xl mx-auto w-full space-y-6 md:space-y-8">
              <div className="flex flex-col md:flex-row md:items-center justify-between border-b border-slate-800 pb-6 md:pb-8 gap-4">
                <div className="flex items-center space-x-4 md:space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all shadow-xl"><i className="fas fa-arrow-left"></i></button>
                  <h2 className="text-xl md:text-3xl font-black text-white tracking-tight">Module Architect</h2>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="w-full md:w-auto px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Done & Close</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8">
                <div className="lg:col-span-8 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6">
                    <div className="flex items-center justify-between">
                       <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Lesson Video</label>
                       <button onClick={() => videoInputRef.current?.click()} className="px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">
                          Upload Binary Video
                       </button>
                       <input type="file" ref={videoInputRef} onChange={handleVideoUpload} className="hidden" accept="video/*" />
                    </div>
                    {lessonVideoPreview && (
                      <div className="mt-4 rounded-xl overflow-hidden border border-slate-800 aspect-video bg-black shadow-2xl">
                        <video src={lessonVideoPreview} controls className="w-full h-full" />
                      </div>
                    )}
                  </div>

                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6 shadow-sm">
                    <div className="flex items-center justify-between">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Asset Library</h3>
                       <button onClick={addResource} className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all">+ Add Asset</button>
                    </div>

                    <div className="space-y-4">
                      {(currentLesson.resources || []).map((res, rIdx) => (
                        <div key={res.id} className="p-5 bg-slate-950 border border-slate-800 rounded-2xl space-y-4 relative group animate-in slide-in-from-bottom-2">
                          <button onClick={() => removeResource(rIdx)} className="absolute top-4 right-4 text-slate-800 hover:text-rose-500 transition-colors p-2"><i className="fas fa-trash-alt text-xs"></i></button>
                          <div className="flex items-center space-x-3">
                             <input type="text" value={res.title} onChange={e => updateResource(rIdx, { title: e.target.value })} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white text-xs font-bold" placeholder="Asset Name" />
                             <button onClick={() => { setActiveResourceIdx(rIdx); resourceInputRef.current?.click(); }} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest">Upload File</button>
                          </div>
                        </div>
                      ))}
                      <input type="file" ref={resourceInputRef} onChange={handleResourceFileUpload} className="hidden" />
                    </div>
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Framework Sync</h3>
                    <div className="space-y-4">
                      <select value={currentLesson.subjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400">
                        <option value="">Unassigned</option>
                        {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                      </select>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-4 md:px-0">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white text-[10px] font-black uppercase tracking-widest transition-colors self-start flex items-center"><i className="fas fa-arrow-left mr-2"></i> Hub Registry</button>
          <button onClick={handleSave} className="w-full md:w-auto px-10 py-4 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Commit Changes</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] md:rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'mobile'].map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-indigo-400 border-indigo-500 bg-slate-900' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>
                {tab === 'info' ? 'Profile' : tab === 'curriculum' ? 'Modules' : 'Mobile Core'}
              </button>
            ))}
          </div>
          <div className="p-6 md:p-12">
            {activeTab === 'info' && (
              <div className="space-y-10 animate-in fade-in duration-300">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                    <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({ ...currentCourse!, title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold outline-none shadow-inner" />
                  </div>
                  <div className="space-y-6 text-center">
                    <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Identify Visual</label>
                    <div className="aspect-video bg-slate-950 rounded-3xl border border-slate-800 overflow-hidden relative group">
                      {thumbnailPreview ? <img src={thumbnailPreview} className="w-full h-full object-cover" alt="preview" /> : <div className="w-full h-full flex items-center justify-center text-slate-700 font-black text-[10px]">No Thumbnail</div>}
                      <button onClick={() => thumbnailInputRef.current?.click()} className="absolute inset-0 bg-slate-950/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-white font-black text-[10px] uppercase">Replace</button>
                    </div>
                    <input type="file" ref={thumbnailInputRef} className="hidden" accept="image/*" onChange={handleThumbnailUpload} />
                  </div>
                </div>
              </div>
            )}
            {activeTab === 'mobile' && (
              <div className="space-y-10 animate-in fade-in duration-300">
                <div className="max-w-xl mx-auto text-center space-y-6 py-10">
                  <div className="w-20 h-20 bg-indigo-600/10 text-indigo-400 rounded-3xl flex items-center justify-center mx-auto border border-indigo-500/20 text-3xl shadow-inner">
                    <i className="fas fa-mobile-screen"></i>
                  </div>
                  <h3 className="text-2xl font-black text-white">Neural Bridge APK</h3>
                  <p className="text-slate-500 text-xs font-bold leading-relaxed">Upload the native Android application package (.apk) for this course. Mobile users will see a download button on their dashboard.</p>

                  <div className="pt-8 flex flex-col items-center">
                    <button onClick={() => apkInputRef.current?.click()} className="px-12 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">
                      {currentCourse.appApk ? 'Update Bridge binary' : 'Upload APK Binary'}
                    </button>
                    <input type="file" ref={apkInputRef} className="hidden" accept=".apk" onChange={handleApkUpload} />
                    {currentCourse.appApk && (
                      <div className="mt-4 flex items-center space-x-2 text-emerald-400 font-black text-[9px] uppercase tracking-widest animate-in slide-in-from-top-2">
                        <i className="fas fa-check-circle"></i>
                        <span>Binary Synced: {typeof currentCourse.appApk === 'string' ? 'Cloud' : (currentCourse.appApk as File).name}</span>
                        <button onClick={() => setCurrentCourse(prev => ({ ...prev, appApk: undefined }))} className="ml-4 text-slate-700 hover:text-rose-500 transition-colors"><i className="fas fa-trash-alt"></i></button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  // Dashboard View (Course List) - Fixed missing return statement to resolve JSX parsing issues
  return (
    <div className="space-y-8 animate-in fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-white tracking-tight">Program Registry</h1>
          <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mt-2">Manage course syllabus and mobile binaries</p>
        </div>
        <button 
          onClick={() => {
            setCurrentCourse({
              id: Math.random().toString(36).substr(2, 9),
              title: '',
              lessons: [],
              subjects: [],
              roadmap: [],
              price: 0
            });
            setIsEditing(true);
            setActiveTab('info');
          }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all"
        >
          Create New Program
        </button>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {courses.map(course => (
          <div key={course.id} className="bg-slate-900 border border-slate-800 rounded-3xl p-6 flex flex-col md:flex-row items-center justify-between gap-6 group hover:border-indigo-500/50 transition-all">
            <div className="flex items-center space-x-6 w-full md:w-auto">
              <img src={typeof course.thumbnail === 'string' ? course.thumbnail : URL.createObjectURL(course.thumbnail)} className="w-16 h-16 rounded-2xl object-cover border border-slate-800" alt="" />
              <div>
                <h3 className="text-lg font-black text-white leading-tight">{course.title}</h3>
                <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1">{course.lessons.length} Modules • {course.instructor}</p>
              </div>
            </div>
            <div className="flex items-center space-x-3 w-full md:w-auto">
              <button 
                onClick={() => { setCurrentCourse({...course}); setIsEditing(true); setActiveTab('info'); }}
                className="flex-1 md:flex-none px-6 py-3 bg-slate-950 border border-slate-800 text-indigo-400 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600 hover:text-white transition-all"
              >
                Edit
              </button>
              <button 
                onClick={() => { if(window.confirm('Delete this course?')) onDeleteCourse(course.id); }}
                className="flex-1 md:flex-none px-6 py-3 bg-rose-600/10 border border-rose-900/30 text-rose-500 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-rose-600 hover:text-white transition-all"
              >
                Delete
              </button>
            </div>
          </div>
        ))}
        {courses.length === 0 && (
          <div className="py-20 bg-slate-900/50 rounded-3xl border-2 border-dashed border-slate-800 flex flex-col items-center justify-center text-center p-8 opacity-40">
            <i className="fas fa-folder-open text-4xl mb-4"></i>
            <p className="text-sm font-black uppercase tracking-widest">Registry Empty</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useRef } from 'react';
import { User, Course, UserDocument } from '../types';
import CourseCard from './CourseCard';

interface ProfileProps {
  user: User;
  courses: Course[];
  onCourseClick: (id: string) => void;
  onUpdateUser: (user: User) => void;
  onLogout: () => void;
}

const Profile: React.FC<ProfileProps> = ({ user, courses, onCourseClick, onUpdateUser, onLogout }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [isAvatarUploading, setIsAvatarUploading] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Settings Form State
  const [settingsName, setSettingsName] = useState(user.name);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [settingsError, setSettingsError] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const avatarInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || file.type !== 'application/pdf') {
      alert('Please upload a valid PDF file.');
      return;
    }

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      const newDoc: UserDocument = {
        id: Math.random().toString(36).substr(2, 9),
        title: file.name,
        data: base64,
        uploadDate: new Date(),
      };

      onUpdateUser({
        ...user,
        documents: [newDoc, ...user.documents],
      });
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.onerror = () => {
      alert("Failed to read file.");
      setIsUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !file.type.startsWith('image/')) {
      alert('Please upload a valid image file.');
      return;
    }

    setIsAvatarUploading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      onUpdateUser({
        ...user,
        avatar: base64,
      });
      setIsAvatarUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    setSettingsError('');

    if (!settingsName.trim()) {
      setSettingsError('Name cannot be empty.');
      return;
    }

    if (newPassword && newPassword !== confirmPassword) {
      setSettingsError('Passwords do not match.');
      return;
    }

    onUpdateUser({
      ...user,
      name: settingsName,
    });

    setIsSettingsOpen(false);
    setNewPassword('');
    setConfirmPassword('');
  };

  const removeDoc = (id: string) => {
    if (window.confirm('Delete this document?')) {
      onUpdateUser({
        ...user,
        documents: user.documents.filter(d => d.id !== id),
      });
    }
  };

  // Fixed: Ensure link.href is always a string by handling Blobs with URL.createObjectURL
  const downloadDoc = (doc: UserDocument) => {
    const link = document.createElement('a');
    let url = '';
    if (doc.data instanceof Blob) {
      url = URL.createObjectURL(doc.data);
    } else {
      url = doc.data;
    }
    link.href = url;
    link.download = doc.title;
    link.click();
    if (doc.data instanceof Blob) {
      URL.revokeObjectURL(url);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 md:space-y-12 pb-24 animate-in fade-in duration-500">

      {/* Settings Modal */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl">
          <div className="bg-slate-900 w-full max-w-lg rounded-[32px] border border-slate-800 overflow-hidden shadow-2xl">
            <div className="p-8 border-b border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-black text-slate-100 uppercase tracking-widest">Settings</h3>
              <button onClick={() => setIsSettingsOpen(false)} className="text-slate-500"><i className="fas fa-times"></i></button>
            </div>
            <form onSubmit={handleSaveSettings} className="p-8 space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Display Name</label>
                <input type="text" value={settingsName} onChange={(e) => setSettingsName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white font-bold" />
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">New Secret</label>
                  <input type="password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Confirm</label>
                  <input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-white" />
                </div>
              </div>
              {settingsError && <p className="text-xs text-rose-500 font-bold">{settingsError}</p>}
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white font-black uppercase text-xs rounded-xl shadow-lg">Save Changes</button>
            </form>
          </div>
        </div>
      )}

      {/* Header */}
      <section className="bg-slate-900 rounded-[32px] md:rounded-[40px] border border-slate-800 p-6 md:p-14 shadow-2xl flex flex-col md:flex-row items-center md:items-start gap-8 md:gap-14">
        <div className="relative">
          <div className="w-28 h-28 md:w-36 md:h-36 rounded-3xl md:rounded-[48px] overflow-hidden border-4 border-slate-800 bg-slate-950 flex items-center justify-center">
            {isAvatarUploading ? <i className="fas fa-spinner fa-spin text-indigo-500 text-2xl"></i> : <img src={user.avatar} className="w-full h-full object-cover" alt={user.name} />}
          </div>
          <button onClick={() => avatarInputRef.current?.click()} className="absolute -bottom-2 -right-2 w-10 h-10 bg-indigo-600 text-white rounded-xl flex items-center justify-center border-4 border-slate-900"><i className="fas fa-camera text-xs"></i></button>
          <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={handleAvatarUpload} />
        </div>

        <div className="flex-1 text-center md:text-left">
          <h1 className="text-3xl md:text-5xl font-black text-slate-100 tracking-tighter mb-2">{user.name}</h1>
          <div className="flex flex-wrap items-center justify-center md:justify-start gap-3 mb-6">
             <span className="px-3 py-1 bg-indigo-500/10 text-indigo-400 font-black uppercase tracking-widest text-[9px] rounded-full border border-indigo-500/20">{user.role}</span>
          </div>
          <div className="flex flex-wrap justify-center md:justify-start gap-3 md:gap-6">
            <div className="px-4 py-3 bg-slate-950 rounded-2xl border border-slate-800 min-w-[100px]">
              <p className="text-xl font-black text-white">{courses.length}</p>
              <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest">Courses</p>
            </div>
            <div className="px-4 py-3 bg-slate-950 rounded-2xl border border-slate-800 min-w-[100px]">
              <p className="text-xl font-black text-indigo-400">84%</p>
              <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest">Score</p>
            </div>
          </div>
        </div>

        <div className="w-full md:w-auto flex flex-col space-y-3">
          <button onClick={() => setIsSettingsOpen(true)} className="w-full md:w-auto px-8 py-4 bg-slate-100 text-slate-950 font-black text-[10px] uppercase tracking-widest rounded-xl shadow-lg">Settings</button>
          <button onClick={onLogout} className="w-full md:w-auto px-8 py-4 bg-rose-600/10 text-rose-500 border border-rose-900/30 font-black text-[10px] uppercase tracking-widest rounded-xl md:hidden">Logout Session</button>
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 md:gap-12">
        <div className="lg:col-span-2 space-y-6">
          <h2 className="text-xl font-black text-white uppercase tracking-widest">Active Learning</h2>
          {courses.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {courses.map(course => <CourseCard key={course.id} course={course} onClick={onCourseClick} showProgress />)}
            </div>
          ) : (
            <div className="py-20 bg-slate-900/50 rounded-3xl border-2 border-dashed border-slate-800 flex flex-col items-center justify-center text-center p-8">
              <i className="fas fa-ghost text-4xl text-slate-800 mb-4"></i>
              <p className="text-slate-500 font-bold text-sm">No active courses yet.</p>
            </div>
          )}
        </div>

        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-white uppercase tracking-widest">Study Vault</h2>
            <button onClick={() => fileInputRef.current?.click()} disabled={isUploading} className="w-10 h-10 bg-indigo-600 text-white rounded-xl flex items-center justify-center shadow-lg"><i className={`fas ${isUploading ? 'fa-spinner fa-spin' : 'fa-plus'}`}></i></button>
            <input type="file" ref={fileInputRef} className="hidden" accept="application/pdf" onChange={handleFileUpload} />
          </div>

          <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-6 space-y-4">
            {user.documents.length > 0 ? user.documents.map(doc => (
              <div key={doc.id} className="flex items-center p-4 bg-slate-950 rounded-2xl border border-slate-800 group">
                <div className="w-10 h-10 bg-slate-900 rounded-lg flex items-center justify-center text-indigo-400 mr-4"><i className="fas fa-file-pdf"></i></div>
                <div className="flex-1 min-w-0">
                  <p className="text-xs font-black text-slate-200 truncate">{doc.title}</p>
                  <p className="text-[8px] text-slate-600 font-bold uppercase">{new Date(doc.uploadDate).toLocaleDateString()}</p>
                </div>
                <div className="flex space-x-2">
                  <button onClick={() => downloadDoc(doc)} className="text-slate-600 hover:text-indigo-400"><i className="fas fa-download text-xs"></i></button>
                  <button onClick={() => removeDoc(doc.id)} className="text-slate-600 hover:text-rose-500"><i className="fas fa-trash-alt text-xs"></i></button>
                </div>
              </div>
            )) : <p className="text-[9px] text-slate-600 font-black uppercase text-center py-10">Vault empty. Upload PDFs to start.</p>}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, QuizQuestion, Resource, User } from '../types';
import { clearAllCoursesFromDB, getAllCoursesFromDB } from '../services/storage';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const COLOR_PRESETS = [
  'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
  'bg-blue-500/10 text-blue-500 border-blue-500/20',
  'bg-rose-500/10 text-rose-500 border-rose-500/20',
  'bg-indigo-500/10 text-indigo-400 border-indigo-500/20',
  'bg-orange-500/10 text-orange-500 border-orange-500/20',
  'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  'bg-purple-500/10 text-purple-500 border-purple-500/20',
  'bg-slate-500/10 text-slate-400 border-slate-500/20',
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse, onPreview }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'mobile' | 'system'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [activeResourceIdx, setActiveResourceIdx] = useState<number | null>(null);
  const [systemUsers, setSystemUsers] = useState<User[]>([]);

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const resourceInputRef = useRef<HTMLInputElement>(null);
  const apkInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  // Fetch users from local registry for system control
  const refreshUsers = () => {
    const usersStr = localStorage.getItem('eduworld_registered_users');
    if (usersStr) {
      setSystemUsers(JSON.parse(usersStr));
    }
  };

  useEffect(() => {
    if (activeTab === 'system') {
      refreshUsers();
    }
  }, [activeTab]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || [],
      expiryDate: currentCourse.expiryDate,
      appApk: currentCourse.appApk
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const deleteSystemUser = (userId: string) => {
    if (confirm('Permanently sever this identity from the neural network?')) {
      const users = systemUsers.filter(u => u.id !== userId);
      localStorage.setItem('eduworld_registered_users', JSON.stringify(users));
      setSystemUsers(users);
    }
  };

  const handlePurgeDatabase = async () => {
    if (confirm('CRITICAL: Purge ALL academic programs from local database? This cannot be undone.')) {
      await clearAllCoursesFromDB();
      window.location.reload();
    }
  };

  const handleThumbnailUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCurrentCourse(prev => ({ ...prev, thumbnail: file }));
  };

  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (editingLessonIdx !== null) {
      updateLesson(editingLessonIdx, { videoUrl: file });
    }
  };

  const handleApkUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setCurrentCourse(prev => ({ ...prev, appApk: file }));
  };

  const handleResourceFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || editingLessonIdx === null || activeResourceIdx === null) return;

    let type: 'link' | 'pdf' | 'video' | 'zip' = 'link';
    if (file.type.includes('pdf')) type = 'pdf';
    else if (file.type.includes('video')) type = 'video';
    else if (file.name.match(/\.(zip|rar|7z)$/i)) type = 'zip';

    updateResource(activeResourceIdx, { 
      url: file, 
      title: file.name,
      type 
    });
    setActiveResourceIdx(null);
  };

  const addLesson = () => {
    const newLesson: Lesson = { 
      id: Math.random().toString(36).substr(2, 9), 
      title: 'New Module', 
      content: '<p>Start creating content...</p>', 
      duration: '10:00',
      hasAiFeature: true,
      isExamMode: false,
      examDuration: 30,
      quiz: [],
      resources: []
    };
    setCurrentCourse(prev => {
      const lessons = [...(prev?.lessons || []), newLesson];
      setEditingLessonIdx(lessons.length - 1);
      return { ...prev, lessons };
    });
  };

  const updateLesson = (idx: number, updates: Partial<Lesson>) => {
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      lessons[idx] = { ...lessons[idx], ...updates };
      return { ...prev, lessons };
    });
  };

  const addResource = () => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];
      const newResource: Resource = {
        id: Math.random().toString(36).substr(2, 9),
        title: 'New Resource',
        url: '',
        type: 'link'
      };
      lesson.resources = [...currentResources, newResource];
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const updateResource = (rIdx: number, updates: Partial<Resource>) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = [...(lesson.resources || [])];
      currentResources[rIdx] = { ...currentResources[rIdx], ...updates };
      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const removeResource = (rIdx: number) => {
    if (editingLessonIdx === null) return;
    setCurrentCourse(prev => {
      if (!prev?.lessons) return prev;
      const lessons = [...prev.lessons];
      const lesson = { ...lessons[editingLessonIdx] };
      const currentResources = (lesson.resources || []).filter((_, i) => i !== rIdx);
      lesson.resources = currentResources;
      lessons[editingLessonIdx] = lesson;
      return { ...prev, lessons };
    });
  };

  const thumbnailPreview = useMemo(() => {
    if (!currentCourse?.thumbnail) return null;
    if (typeof currentCourse.thumbnail === 'string') return currentCourse.thumbnail;
    return URL.createObjectURL(currentCourse.thumbnail);
  }, [currentCourse?.thumbnail]);

  const lessonVideoPreview = useMemo(() => {
    if (editingLessonIdx === null || !currentCourse?.lessons) return null;
    const url = currentCourse.lessons[editingLessonIdx].videoUrl;
    if (!url) return null;
    if (typeof url === 'string') return url;
    return URL.createObjectURL(url);
  }, [editingLessonIdx, currentCourse?.lessons]);

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    const currentLesson = isEditingLesson ? currentCourse.lessons![editingLessonIdx!] : null;

    return (
      <div className="max-w-5xl mx-auto space-y-6 md:space-y-8 pb-24 animate-in fade-in duration-500">

        {isEditingLesson && currentLesson && (
          <div className="fixed inset-0 z-[150] bg-slate-950 overflow-y-auto flex flex-col p-4 md:p-12 animate-in slide-in-from-right-8 duration-500">
            <div className="max-w-5xl mx-auto w-full space-y-6 md:space-y-8">
              <div className="flex flex-col md:flex-row md:items-center justify-between border-b border-slate-800 pb-6 md:pb-8 gap-4">
                <div className="flex items-center space-x-4 md:space-x-6">
                  <button onClick={() => setEditingLessonIdx(null)} className="w-10 h-10 md:w-12 md:h-12 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white transition-all shadow-xl"><i className="fas fa-arrow-left"></i></button>
                  <h2 className="text-xl md:text-3xl font-black text-white tracking-tight uppercase">Module Architect</h2>
                </div>
                <button onClick={() => setEditingLessonIdx(null)} className="w-full md:w-auto px-8 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all">Done & Close</button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8">
                <div className="lg:col-span-8 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6 shadow-sm">
                    <div className="flex items-center justify-between">
                       <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Lesson Video</label>
                       <button onClick={() => videoInputRef.current?.click()} className="px-4 py-2 bg-indigo-600/10 text-indigo-400 border border-indigo-500/20 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-600/20 transition-all">
                          Upload Binary Video
                       </button>
                       <input type="file" ref={videoInputRef} onChange={handleVideoUpload} className="hidden" accept="video/*" />
                    </div>
                    {lessonVideoPreview && (
                      <div className="mt-4 rounded-xl overflow-hidden border border-slate-800 aspect-video bg-black shadow-2xl">
                        <video src={lessonVideoPreview} controls className="w-full h-full" />
                      </div>
                    )}
                  </div>

                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6 shadow-sm">
                    <div className="flex items-center justify-between">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Asset Library</h3>
                       <button onClick={addResource} className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all">+ Add Asset</button>
                    </div>

                    <div className="space-y-4">
                      {(currentLesson.resources || []).map((res, rIdx) => (
                        <div key={res.id} className="p-5 bg-slate-950 border border-slate-800 rounded-2xl space-y-4 relative group animate-in slide-in-from-bottom-2">
                          <button onClick={() => removeResource(rIdx)} className="absolute top-4 right-4 text-slate-800 hover:text-rose-500 transition-colors p-2"><i className="fas fa-trash-alt text-xs"></i></button>
                          <div className="flex items-center space-x-3">
                             <input type="text" value={res.title} onChange={e => updateResource(rIdx, { title: e.target.value })} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-2 text-white text-xs font-bold" placeholder="Asset Name" />
                             <button onClick={() => { setActiveResourceIdx(rIdx); resourceInputRef.current?.click(); }} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest">Upload File</button>
                          </div>
                        </div>
                      ))}
                      <input type="file" ref={resourceInputRef} onChange={handleResourceFileUpload} className="hidden" />
                    </div>
                  </div>
                </div>

                <div className="lg:col-span-4 space-y-6 md:space-y-8">
                  <div className="bg-slate-900 rounded-[24px] md:rounded-[32px] border border-slate-800 p-6 md:p-8 space-y-6 shadow-inner">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Framework Sync</h3>
                    <div className="space-y-4">
                      <select value={currentLesson.subjectId || ''} onChange={e => updateLesson(editingLessonIdx!, { subjectId: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-slate-400 outline-none focus:border-indigo-500 shadow-sm">
                        <option value="">Unassigned</option>
                        {currentCourse.subjects?.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                      </select>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-4 md:px-0">
