};

const CourseView: React.FC<CourseViewProps> = ({ course, user, onBack, initialLessonId, onQuizComplete }) => {
  const [activeLessonId, setActiveLessonId] = useState(initialLessonId || course.lessons[0]?.id);
  const [activeTab, setActiveTab] = useState<'overview' | 'quiz' | 'notes'>('overview');
  const [isAiOpen, setIsAiOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  // Find the current lesson in the full course list
  const activeLesson = useMemo(() => 
    course.lessons.find(l => l.id === activeLessonId) || course.lessons[0]
  , [course.lessons, activeLessonId]);

  // Exam Timer State
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (activeLesson.isExamMode && !quizState.complete) {
      setTimeLeft((activeLesson.examDuration || 30) * 60);
      setActiveTab('quiz'); // Force quiz view in exam mode

      if (timerRef.current) clearInterval(timerRef.current);

      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            if (timerRef.current) clearInterval(timerRef.current);
            handleSubmitExam();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [activeLessonId, activeLesson.isExamMode]);

  const formatTimeLeft = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Define Scoped Navigation: Filter lessons to only include those in the current unit/subject context
  const scopedLessons = useMemo(() => {
    return course.lessons.filter(l => 
      l.subjectId === activeLesson.subjectId && 
      l.subSubjectId === activeLesson.subSubjectId &&
      l.unitId === activeLesson.unitId
    );
  }, [course.lessons, activeLesson]);

  // Index within the unit-scoped lessons
  const scopedIndex = useMemo(() => 
    scopedLessons.findIndex(l => l.id === activeLessonId)
  , [scopedLessons, activeLessonId]);

  const [quizState, setQuizState] = useState({ currentIdx: 0, score: 0, complete: false });

  useEffect(() => {
    if (initialLessonId) {
      setActiveLessonId(initialLessonId);
    }
  }, [initialLessonId]);

  // Reset quiz state when active lesson changes
  useEffect(() => {
    resetQuiz();
    if (videoRef.current) videoRef.current.load();
    // If exam mode starts, ensure AI panel is closed
    if (activeLesson.isExamMode) {
      setIsAiOpen(false);
    }
  }, [activeLessonId, activeLesson.isExamMode]);

  const resetQuiz = () => {
    setQuizState({ currentIdx: 0, score: 0, complete: false });
  };

  const handleQuizAnswer = (idx: number) => {
    if (!activeLesson.quiz) return;
    const isCorrect = idx === activeLesson.quiz[quizState.currentIdx].correctAnswer;
    const newScore = isCorrect ? quizState.score + 1 : quizState.score;

    if (quizState.currentIdx < activeLesson.quiz.length - 1) {
      setQuizState(prev => ({ ...prev, currentIdx: prev.currentIdx + 1, score: newScore }));
    } else {
      setQuizState(prev => ({ ...prev, score: newScore, complete: true }));
      onQuizComplete(activeLesson.id, { score: newScore, total: activeLesson.quiz.length, date: new Date() });
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const handleSubmitExam = () => {
    setQuizState(prev => ({ ...prev, complete: true }));
    onQuizComplete(activeLesson.id, { score: quizState.score, total: activeLesson.quiz?.length || 0, date: new Date() });
    if (timerRef.current) clearInterval(timerRef.current);
  };

  const isAdmin = user.role === 'admin';

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-[#020617] overflow-hidden">
      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-y-auto border-r border-slate-800/50 relative">
        <nav className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/90 backdrop-blur-md sticky top-0 z-30 shadow-xl">
          <div className="flex items-center space-x-4">
            <button onClick={onBack} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-500 hover:text-white hover:border-indigo-500/50 transition-all shadow-inner"><i className="fas fa-arrow-left text-sm"></i></button>
            <div className="hidden sm:block">
              <div className="flex items-center space-x-2">
                <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">{course.title}</h2>
                {activeLesson.isExamMode && <span className="bg-rose-600 px-2 py-0.5 rounded text-[8px] font-black text-white uppercase tracking-widest animate-pulse">Timed Examination</span>}
              </div>
              <p className="text-base font-black text-white truncate max-w-[250px] leading-tight">{activeLesson.title}</p>
            </div>
          </div>

          {activeLesson.isExamMode && !quizState.complete ? (
            <div className="flex items-center space-x-4 bg-rose-500/10 border border-rose-500/30 px-6 py-2 rounded-xl">
              <i className="fas fa-stopwatch text-rose-500 text-sm"></i>
              <span className={`text-sm font-black tracking-widest ${timeLeft < 60 ? 'text-rose-500 animate-pulse' : 'text-white'}`}>
                {formatTimeLeft(timeLeft)}
              </span>
            </div>
          ) : (
            <button 
              disabled={activeLesson.isExamMode}
              onClick={() => !activeLesson.isExamMode && setIsAiOpen(!isAiOpen)} 
              className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeLesson.isExamMode ? 'bg-slate-950 text-slate-800 border border-slate-900 cursor-not-allowed' : isAiOpen ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'bg-slate-900 text-slate-500 border border-slate-800 hover:text-white'}`}
            >
              <i className={`fas ${activeLesson.isExamMode ? 'fa-lock' : 'fa-sparkles'} mr-2`}></i>
              {activeLesson.isExamMode ? 'AI Disabled' : 'AI Tutoring'}
            </button>
          )}
        </nav>

        <div className="flex-1 p-6 md:p-14 max-w-5xl mx-auto w-full space-y-10">
          {activeLesson.isExamMode ? (
            <div className="bg-slate-900/40 rounded-[32px] md:rounded-[40px] border border-dashed border-rose-500/30 py-16 flex flex-col items-center justify-center text-center backdrop-blur-sm animate-in fade-in duration-700">
              <div className="w-20 h-20 rounded-3xl flex items-center justify-center text-3xl mb-6 border shadow-inner bg-rose-500/10 text-rose-500 border-rose-500/20">
                <i className="fas fa-file-signature"></i>
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight uppercase">Formal Assessment</h3>
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-2">
                External aids, resources, and AI tools are restricted
              </p>
            </div>
          ) : activeLesson.videoUrl ? (
            <div className="bg-black rounded-[32px] md:rounded-[40px] overflow-hidden aspect-video border border-slate-800 shadow-2xl relative group ring-1 ring-white/5">
              <video key={activeLesson.id} ref={videoRef} src={getMediaUrl(activeLesson.videoUrl)} controls className="w-full h-full" />
            </div>
          ) : (
            <div className="bg-slate-900/40 rounded-[32px] md:rounded-[40px] border border-dashed border-slate-800/60 py-24 flex flex-col items-center justify-center text-center backdrop-blur-sm">
              <div className="w-20 h-20 rounded-3xl flex items-center justify-center text-3xl mb-6 border shadow-inner bg-indigo-600/10 text-indigo-400 border-indigo-600/20">
                <i className="fas fa-book-open"></i>
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight">Theory & Content</h3>
              <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-2">
                This module focuses on academic reading materials
              </p>
            </div>
          )}

          {!activeLesson.isExamMode && (
            <div className="flex border-b border-slate-800 space-x-10 overflow-x-auto no-scrollbar scroll-smooth">
              <button onClick={() => setActiveTab('overview')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'overview' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Content Overview</button>
              {activeLesson.quiz && activeLesson.quiz.length > 0 && <button onClick={() => setActiveTab('quiz')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'quiz' ? 'text-indigo-400 border-indigo-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Knowledge Check</button>}
              {isAdmin && <button onClick={() => setActiveTab('notes')} className={`pb-4 whitespace-nowrap text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all ${activeTab === 'notes' ? 'text-emerald-400 border-emerald-500' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>Instructor Desk</button>}
            </div>
          )}

          <div className="min-h-[400px] pb-32 md:pb-24">
            {activeTab === 'overview' && !activeLesson.isExamMode && (
              <div className="animate-in fade-in duration-500 space-y-8">
                <div className="prose prose-invert prose-slate max-w-none text-slate-300 leading-relaxed text-lg" dangerouslySetInnerHTML={{ __html: activeLesson.content }} />

                {activeLesson.resources && activeLesson.resources.length > 0 && (
                  <div className="mt-16 space-y-6 pt-12 border-t border-slate-800">
                    <h4 className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em]">Module Supplemental Assets</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {activeLesson.resources.map(res => (
                        <a key={res.id} href={getMediaUrl(res.url)} target="_blank" rel="noopener noreferrer" className="flex items-center p-5 bg-slate-900 border border-slate-800 rounded-2xl hover:border-indigo-500/50 hover:bg-slate-950 transition-all group shadow-sm">
                          <div className="w-10 h-10 rounded-xl bg-slate-950 flex items-center justify-center text-sm text-indigo-400 mr-4 border border-slate-800 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner">
                            <i className={`fas ${res.type === 'pdf' ? 'fa-file-pdf' : res.type === 'video' ? 'fa-play' : res.type === 'zip' ? 'fa-file-zipper' : 'fa-link'}`}></i>
                          </div>
                          <div>
                            <span className="text-sm font-black text-slate-200 block leading-tight">{res.title}</span>
                            <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1 block">{res.type} Format</span>
                          </div>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'quiz' && activeLesson.quiz && (
              <div className="space-y-8 max-w-2xl mx-auto animate-in fade-in slide-in-from-right-8 duration-500">
                {quizState.complete ? (
                  <div className="p-12 md:p-16 bg-slate-950 border border-slate-800 rounded-[40px] text-center shadow-2xl relative overflow-hidden">
                    <div className={`absolute top-0 left-0 w-full h-1 ${activeLesson.isExamMode ? 'bg-rose-500 shadow-[0_0_20px_rgba(244,63,94,0.5)]' : 'bg-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.5)]'}`}></div>
                    <div className={`w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-8 text-4xl border shadow-inner animate-in zoom-in ${activeLesson.isExamMode ? 'bg-rose-500/10 text-rose-500 border-rose-500/20' : 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'}`}>
                      <i className={`fas ${activeLesson.isExamMode ? 'fa-award' : 'fa-check-double'}`}></i>
                    </div>
                    <h3 className="text-3xl font-black text-white tracking-tight mb-3">{activeLesson.isExamMode ? 'Examination Complete' : 'Mastery Verified'}</h3>
                    <p className="text-slate-500 text-xs font-black uppercase tracking-[0.2em] mb-12">Performance Metric: {Math.round((quizState.score/activeLesson.quiz.length)*100)}% Proficiency achieved</p>

                    <div className="flex flex-col sm:flex-row items-center justify-center gap-5">
                      {!activeLesson.isExamMode && <button onClick={resetQuiz} className="w-full sm:w-auto px-10 py-4 bg-slate-900 border border-slate-800 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-md active:scale-95">Retake Assessment</button>}
                      <button onClick={onBack} className="w-full sm:w-auto px-10 py-4 bg-indigo-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-2xl shadow-indigo-600/30 hover:bg-indigo-700 transition-all active:scale-95">
                        {activeLesson.isExamMode ? 'Return to Dashboard' : 'Back to Content'}
                      </button>
                    </div>
                  </div>
                ) : (
                  <div key={quizState.currentIdx} className="space-y-8 animate-in slide-in-from-right-12 duration-500">
                    <div className="flex justify-between items-center mb-4">
                      <p className="text-[11px] text-slate-500 font-black uppercase tracking-widest">Question {quizState.currentIdx + 1} of {activeLesson.quiz.length}</p>
                      <div className="w-48 h-2 bg-slate-900 border border-slate-800 rounded-full overflow-hidden shadow-inner">
                        <div 
                          className={`h-full transition-all duration-700 ${activeLesson.isExamMode ? 'bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.4)]' : 'bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.4)]'}`}
                          style={{ width: `${((quizState.currentIdx + 1) / activeLesson.quiz.length) * 100}%` }}
                        ></div>
                      </div>
                    </div>
                    <h4 className="text-2xl md:text-3xl font-black text-white tracking-tight leading-snug">{activeLesson.quiz[quizState.currentIdx].question}</h4>
                    <div className="grid gap-4 pt-6">
                      {activeLesson.quiz[quizState.currentIdx].options.map((opt, i) => (
                        <button 
                          key={i} 
                          onClick={() => handleQuizAnswer(i)} 
                          className={`w-full p-6 bg-slate-900/50 border border-slate-800 rounded-3xl text-left transition-all font-black text-base text-slate-200 group flex items-center shadow-lg active:scale-[0.99] ${activeLesson.isExamMode ? 'hover:border-rose-500 hover:bg-rose-500/5' : 'hover:border-indigo-500 hover:bg-slate-900'}`}
                        >
                          <div className={`w-8 h-8 rounded-xl bg-slate-950 border border-slate-800 flex items-center justify-center mr-5 text-[10px] font-black transition-all shadow-inner ${activeLesson.isExamMode ? 'group-hover:bg-rose-600 group-hover:text-white' : 'group-hover:bg-indigo-600 group-hover:text-white'}`}>{String.fromCharCode(65 + i)}</div>
                          <span className="flex-1 leading-tight">{opt}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'notes' && isAdmin && !activeLesson.isExamMode && (
              <div className="animate-in slide-in-from-top-6 duration-500 p-10 bg-emerald-500/5 border border-emerald-500/20 rounded-[40px] shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl"></div>
                <div className="flex items-center space-x-4 mb-8">
                  <div className="w-12 h-12 bg-emerald-500/10 text-emerald-400 rounded-2xl flex items-center justify-center border border-emerald-500/20 shadow-inner text-xl">
                    <i className="fas fa-graduation-cap"></i>
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-emerald-400 uppercase tracking-widest">Instructor Desk</h3>
                    <p className="text-[10px] font-black text-emerald-600/60 uppercase tracking-widest mt-1">Teaching Guidelines & Context</p>
                  </div>
                </div>
                <div className="text-emerald-100/70 leading-relaxed text-base italic whitespace-pre-wrap font-medium">
                  {activeLesson.instructorNotes || 'Universal instructor guidance applies. Maintain consistent terminology and encourage AI-driven inquiry for deeper understanding.'}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer Navigation */}
        <div className="mt-auto p-4 md:p-8 border-t border-slate-800 bg-slate-950/80 backdrop-blur-xl flex justify-between items-center sticky bottom-0 z-30 shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
          {activeLesson.isExamMode && !quizState.complete ? (
            <button 
              onClick={handleSubmitExam}
              className="w-full flex items-center justify-center space-x-3 py-4 bg-rose-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-[0.3em] hover:bg-rose-700 transition-all shadow-xl shadow-rose-600/20 active:scale-95"
            >
              <span>Submit Examination</span>
              <i className="fas fa-paper-plane"></i>
            </button>
          ) : (
            <>
              <button 
                disabled={scopedIndex <= 0 || activeLesson.isExamMode} 
                onClick={() => setActiveLessonId(scopedLessons[scopedIndex - 1].id)} 
                className="flex items-center space-x-3 px-6 py-3.5 bg-slate-900 border border-slate-800 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-slate-500 disabled:opacity-20 hover:text-white hover:border-slate-700 transition-all shadow-xl active:scale-95"
              >
                <i className="fas fa-chevron-left"></i><span>Previous Module</span>
              </button>

              <div className="hidden md:flex space-x-3 overflow-x-auto px-4 max-w-[300px] no-scrollbar">
                {scopedLessons.map(l => (
                  <button 
                    key={l.id} 
                    onClick={() => setActiveLessonId(l.id)}
                    className={`w-2.5 h-2.5 rounded-full flex-shrink-0 transition-all duration-700 ${l.id === activeLessonId ? (activeLesson.isExamMode ? 'bg-rose-500 w-10 shadow-[0_0_15px_rgba(244,63,94,0.6)]' : 'bg-indigo-500 w-10 shadow-[0_0_15px_rgba(99,102,241,0.6)]') : 'bg-slate-800 hover:bg-slate-700'}`}
                  ></button>
                ))}
              </div>

              <button 
                disabled={scopedIndex === scopedLessons.length - 1 || activeLesson.isExamMode} 
                onClick={() => setActiveLessonId(scopedLessons[scopedIndex + 1].id)} 
                className={`flex items-center space-x-3 px-8 py-3.5 border rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white disabled:opacity-20 transition-all shadow-2xl active:scale-95 ${activeLesson.isExamMode ? 'bg-rose-600 border-rose-500 shadow-rose-600/30 hover:bg-rose-700' : 'bg-indigo-600 border-indigo-500/30 shadow-indigo-600/30 hover:bg-indigo-700'}`}
              >
                <span>Proceed Next</span><i className="fas fa-chevron-right"></i>
              </button>
            </>
          )}
        </div>
      </div>

      {/* AI Panel */}
      <aside className={`fixed lg:relative bottom-0 right-0 w-full lg:w-[450px] h-[85vh] lg:h-full bg-slate-950 border-t lg:border-t-0 lg:border-l border-slate-800 z-[40] transition-transform duration-500 ease-in-out transform ${isAiOpen && !activeLesson.isExamMode ? 'translate-y-0 lg:translate-x-0 shadow-2xl' : 'translate-y-full lg:translate-x-full lg:hidden'}`}>
        <div className="flex flex-col h-full relative ring-1 ring-white/5">
          <button onClick={() => setIsAiOpen(false)} className="lg:hidden absolute top-4 right-4 z-50 text-slate-500 text-xl p-3 bg-slate-900/50 rounded-full hover:text-white transition-all"><i className="fas fa-times"></i></button>
          {!activeLesson.isExamMode && <AIAssistant course={course} lesson={activeLesson} user={user} />}
        </div>
      </aside>
    </div>
  );
};

