import React, { useState } from 'react';
import { Course, Lesson } from '../types';

interface CourseDetailsProps {
  course: Course;
  isAdmin: boolean;
  isEnrolled: boolean;
  onEnroll: (courseId: string) => void;
  onAdminEdit: () => void;
  onBack: () => void;
}

/**
 * Helper to resolve media URLs from either strings or File objects.
 * Essential for rendering images that were uploaded locally via Admin Panel.
 */
const getMediaUrl = (media: string | File | undefined): string => {
  if (!media) return '';
  if (typeof media === 'string') return media;
  return URL.createObjectURL(media);
};

const CourseDetails: React.FC<CourseDetailsProps> = ({ course, isAdmin, isEnrolled, onEnroll, onAdminEdit, onBack }) => {
