                  <i className="fas fa-check"></i>
                </div>
                <h3 className="text-2xl font-black text-white mb-2">Payment Successful</h3>
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest">Enrolling you in the neural network...</p>
