                    <div className="flex items-center space-x-4 p-4 bg-slate-950 rounded-2xl border border-slate-800">
                      <img src={getMediaUrl(course.thumbnail)} className="w-16 h-16 object-cover rounded-xl" alt="" />
                      <div className="min-w-0">
                        <p className="text-sm font-black text-white truncate">{course.title}</p>
                        <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1">Instructor: {course.instructor}</p>
                      </div>
                    </div>
                  </div>
                  <div className="p-6 bg-indigo-600 rounded-2xl text-white shadow-xl">
                    <p className="text-[10px] font-black uppercase opacity-60 tracking-widest mb-1">Total Fee</p>
                    <p className="text-4xl font-black">${(course.price || 0).toFixed(2)}</p>
