               <div className="flex items-center text-[10px] text-amber-500 font-black"><i className="fas fa-star mr-1"></i> {course.rating}</div>
            </div>

            {/* Price Badge for Mobile - Highly prominent near title */}
            <div className="md:hidden inline-block bg-indigo-600 px-4 py-2 rounded-2xl text-white font-black text-sm shadow-xl shadow-indigo-600/20 mb-2">
               Full Access: ${(course.price || 0).toFixed(2)}
            </div>

            <h1 className="text-3xl md:text-6xl font-black text-white tracking-tighter leading-tight md:leading-none">{course.title}</h1>
            <p className="text-base md:text-lg text-slate-400 leading-relaxed max-w-3xl">{course.description}</p>
          </div>

          <div className="space-y-8 md:space-y-10">
            <h3 className="text-xl md:text-2xl font-black text-white tracking-tight flex items-center">
               <i className="fas fa-map-location-dot mr-4 text-indigo-500"></i> Curriculum Map
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
              {course.subjects.map((subject) => (
                <div key={subject.id} className="p-5 md:p-6 bg-slate-900/50 border border-slate-800 rounded-[28px] md:rounded-[32px] group hover:border-indigo-500/50 transition-all text-left">
                  <div className="flex items-center space-x-4">
                    <div className={`w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center text-xl md:text-2xl shadow-inner border group-hover:scale-105 transition-transform shrink-0 ${subject.color}`}>
                      <i className={`fas ${subject.icon}`}></i>
                    </div>
                    <div>
                       <h4 className="text-lg md:text-xl font-black text-slate-100 uppercase tracking-tight leading-tight">{subject.name}</h4>
                       <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1">{subject.subSubjects.length} Core Units</p>
                    </div>
                  </div>
                </div>
              ))}
              {course.subjects.length === 0 && (
                <p className="text-slate-500 font-bold italic py-8">No subjects mapped to this registry.</p>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-4 mt-10 lg:mt-0">
          <div className="lg:sticky lg:top-8 bg-slate-900 rounded-[32px] md:rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl relative">
            <img src={getMediaUrl(course.thumbnail)} className="w-full aspect-video object-cover" alt="" />
            <div className="absolute top-4 right-4 bg-slate-950/80 backdrop-blur-md px-3 py-1 rounded-full text-[10px] font-black text-indigo-400 border border-slate-800 uppercase tracking-widest">
               ${(course.price || 0).toFixed(2)}
            </div>

            <div className="p-8 md:p-10 space-y-8 md:space-y-10">
              <div className="space-y-4">
                 <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Program Benefits</h4>
                 <ul className="space-y-5">
                   {roadmapItems.map((item, i) => (
                     <li key={i} className="flex items-center text-[11px] font-bold text-slate-300">
                        <div className="w-8 h-8 rounded-xl bg-slate-950 border border-slate-800 flex items-center justify-center text-indigo-400 mr-4 shadow-sm shrink-0">
                           <i className={`fas ${item.icon}`}></i>
                        </div>
                        {item.text}
                     </li>
                   ))}
                 </ul>
              </div>

              {course.expiryDate && (
                <div className="space-y-2 pt-4 border-t border-slate-800/50">
                  <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest">
                    <span className="text-slate-600">Enrollment Ends</span>
                    <span className="text-rose-400">{new Date(course.expiryDate).toLocaleDateString()}</span>
                  </div>
                </div>
              )}

              <div className="space-y-4 pt-4 border-t border-slate-800/50">
                 <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest">
                    <span className="text-slate-600">Active Students</span>
                    <span className="text-slate-200">{course.studentsCount.toLocaleString()}</span>
                 </div>
                 <button 
                  onClick={() => setView('checkout')} 
                  disabled={isEnrolled} 
                  className={`w-full py-5 rounded-2xl font-black uppercase text-[11px] tracking-[0.25em] transition-all shadow-xl ${isEnrolled ? 'bg-slate-950 text-slate-700 border border-slate-800 cursor-not-allowed' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-600/20 active:scale-[0.98]'}`}
                >
                    {isEnrolled ? 'Enrolled Successfully' : 'Enroll Now'}
                 </button>
                 <p className="text-[9px] text-slate-600 font-bold uppercase text-center tracking-widest opacity-60">Lifetime Access Guaranteed</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CourseDetails;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Course, Lesson, SubjectGroup, SubSubject, Unit, QuizQuestion, Resource, User } from '../types';
import { clearAllCoursesFromDB, getAllCoursesFromDB } from '../services/storage';

interface AdminPanelProps {
  courses: Course[];
  initialEditCourseId?: string | null;
  onAddCourse: (course: Course) => void;
  onUpdateCourse: (course: Course) => void;
  onDeleteCourse: (id: string) => void;
  onPreview: () => void;
}

const THEME_OPTIONS = [
  { name: 'Neural Indigo', rgb: '79, 70, 229', colorClass: 'bg-indigo-600' },
  { name: 'Bionic Emerald', rgb: '16, 185, 129', colorClass: 'bg-emerald-600' },
  { name: 'Cyber Rose', rgb: '225, 29, 72', colorClass: 'bg-rose-600' },
  { name: 'Solar Amber', rgb: '217, 119, 6', colorClass: 'bg-amber-600' },
];

const AdminPanel: React.FC<AdminPanelProps> = ({ courses, initialEditCourseId, onAddCourse, onUpdateCourse, onDeleteCourse, onPreview }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [currentCourse, setCurrentCourse] = useState<Partial<Course> | null>(null);
  const [activeTab, setActiveTab] = useState<'info' | 'curriculum' | 'mobile' | 'system'>('info');
  const [editingLessonIdx, setEditingLessonIdx] = useState<number | null>(null);
  const [systemUsers, setSystemUsers] = useState<User[]>([]);

  // System Config States
  const [appName, setAppName] = useState(localStorage.getItem('eduworld_app_name') || 'Edu World');
  const [currentThemeRgb, setCurrentThemeRgb] = useState(localStorage.getItem('eduworld_theme_rgb') || '79, 70, 229');

  const thumbnailInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const resourceInputRef = useRef<HTMLInputElement>(null);
  const apkInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialEditCourseId) {
      const course = courses.find(c => c.id === initialEditCourseId);
      if (course) {
        setCurrentCourse({ ...course });
        setIsEditing(true);
      }
    }
  }, [initialEditCourseId, courses]);

  const refreshUsers = () => {
    const usersStr = localStorage.getItem('eduworld_registered_users');
    if (usersStr) setSystemUsers(JSON.parse(usersStr));
  };

  useEffect(() => {
    if (activeTab === 'system') refreshUsers();
  }, [activeTab]);

  const applyTheme = (rgb: string) => {
    setCurrentThemeRgb(rgb);
    localStorage.setItem('eduworld_theme_rgb', rgb);
    document.documentElement.style.setProperty('--brand-rgb', rgb);
  };

  const handleSaveSystemConfig = () => {
    localStorage.setItem('eduworld_app_name', appName);
    alert('System Configuration Latched.');
    window.location.reload(); // Reload to apply branding globally
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentCourse) return;

    const finalCourse: Course = {
      id: currentCourse.id || Math.random().toString(36).substr(2, 9),
      title: currentCourse.title || 'Untitled Program',
      description: currentCourse.description || '',
      instructor: currentCourse.instructor || 'Lead Instructor',
      instructorAvatar: currentCourse.instructorAvatar || 'https://api.dicebear.com/7.x/avataaars/svg?seed=edu',
      thumbnail: currentCourse.thumbnail || 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&q=80&w=800',
      category: currentCourse.category || 'Academic',
      rating: currentCourse.rating || 5.0,
      studentsCount: currentCourse.studentsCount || 0,
      price: currentCourse.price || 0,
      lessons: currentCourse.lessons || [],
      subjects: currentCourse.subjects || [],
      roadmap: currentCourse.roadmap || [],
      supplementalContent: currentCourse.supplementalContent || [],
      expiryDate: currentCourse.expiryDate,
      appApk: currentCourse.appApk
    };

    const isExisting = courses.some(c => c.id === finalCourse.id);
    if (isExisting) onUpdateCourse(finalCourse);
    else onAddCourse(finalCourse);

    setIsEditing(false);
    setCurrentCourse(null);
  };

  const deleteSystemUser = (userId: string) => {
    if (confirm('Permanently sever this identity from the neural network?')) {
      const users = systemUsers.filter(u => u.id !== userId);
      localStorage.setItem('eduworld_registered_users', JSON.stringify(users));
      setSystemUsers(users);
    }
  };

  const handleThumbnailUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) setCurrentCourse(prev => ({ ...prev, thumbnail: file }));
  };

  const handleApkUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) setCurrentCourse(prev => ({ ...prev, appApk: file }));
  };

  const thumbnailPreview = useMemo(() => {
    if (!currentCourse?.thumbnail) return null;
    if (typeof currentCourse.thumbnail === 'string') return currentCourse.thumbnail;
    return URL.createObjectURL(currentCourse.thumbnail);
  }, [currentCourse?.thumbnail]);

  if (isEditing && currentCourse) {
    const isEditingLesson = editingLessonIdx !== null;
    return (
      <div className="max-w-5xl mx-auto space-y-8 pb-24 animate-in fade-in duration-500">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white text-[10px] font-black uppercase tracking-widest flex items-center transition-colors"><i className="fas fa-arrow-left mr-2"></i> Registry Hub</button>
          <button onClick={handleSave} className="w-full md:w-auto px-10 py-4 bg-brand text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all">Commit Changes</button>
        </div>

        <div className="bg-slate-900 rounded-[32px] md:rounded-[40px] border border-slate-800 overflow-hidden shadow-2xl">
          <div className="flex border-b border-slate-800 bg-slate-950/50">
            {['info', 'curriculum', 'mobile'].map(tab => (
              <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 py-6 text-[9px] font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === tab ? 'text-brand border-brand bg-slate-900' : 'text-slate-600 border-transparent hover:text-slate-400'}`}>
                {tab === 'info' ? 'Course Profile' : tab === 'curriculum' ? 'Modules' : 'Mobile Bridge'}
              </button>
            ))}
          </div>
          <div className="p-8 md:p-12">
            {activeTab === 'info' && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10 animate-in fade-in">
                <div className="space-y-6">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Program Title</label>
                  <input type="text" value={currentCourse.title || ''} onChange={e => setCurrentCourse({ ...currentCourse!, title: e.target.value })} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 text-white font-bold outline-none shadow-inner" />
                </div>
                <div className="space-y-6 text-center">
                  <label className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Visual Identity</label>
                  <div className="aspect-video bg-slate-950 rounded-3xl border border-slate-800 overflow-hidden relative group">
                    {thumbnailPreview ? <img src={thumbnailPreview} className="w-full h-full object-cover" alt="" /> : <div className="w-full h-full flex items-center justify-center text-slate-700 font-black text-[10px]">No Thumbnail</div>}
                    <button onClick={() => thumbnailInputRef.current?.click()} className="absolute inset-0 bg-slate-950/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-white font-black text-[10px] uppercase">Upload Image</button>
                  </div>
                  <input type="file" ref={thumbnailInputRef} className="hidden" accept="image/*" onChange={handleThumbnailUpload} />
                </div>
              </div>
            )}
            {activeTab === 'mobile' && (
              <div className="max-w-xl mx-auto text-center space-y-6 py-10 animate-in fade-in">
                <div className="w-20 h-20 bg-brand/10 text-brand rounded-3xl flex items-center justify-center mx-auto border border-brand/20 text-3xl shadow-inner">
                  <i className="fas fa-mobile-screen"></i>
                </div>
                <h3 className="text-2xl font-black text-white">Neural Bridge APK</h3>
                <p className="text-slate-500 text-xs font-bold leading-relaxed italic">Supply the native Android binary for this program. Mobile explorers will see a priority download sync on their dashboard.</p>
                <button onClick={() => apkInputRef.current?.click()} className="px-12 py-4 bg-brand text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-brand/20 active:scale-95 transition-all">
                  {currentCourse.appApk ? 'Refresh Bridge Binary' : 'Initialize APK Upload'}
                </button>
                <input type="file" ref={apkInputRef} className="hidden" accept=".apk" onChange={handleApkUpload} />
                {currentCourse.appApk && <p className="text-emerald-400 text-[10px] font-black uppercase tracking-widest">Binary Synced: {typeof currentCourse.appApk === 'string' ? 'Active' : (currentCourse.appApk as File).name}</p>}
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (activeTab === 'system') {
    return (
      <div className="space-y-8 animate-in fade-in duration-500">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-8 space-y-6">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Neural Branding & Control</h3>
            <div className="bg-slate-900 rounded-[40px] border border-slate-800 p-8 md:p-12 space-y-12 shadow-2xl">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-4">
                  <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">System Identity</label>
                  <input type="text" value={appName} onChange={(e) => setAppName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-4 text-white font-black" />
                </div>
                <div className="space-y-4">
                  <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Neural Signature (Theme)</label>
                  <div className="grid grid-cols-4 gap-3">
                    {THEME_OPTIONS.map(theme => (
                      <button key={theme.name} onClick={() => applyTheme(theme.rgb)} className={`aspect-square rounded-xl ${theme.colorClass} border-4 transition-all ${currentThemeRgb === theme.rgb ? 'border-white scale-110 shadow-xl' : 'border-transparent opacity-50 hover:opacity-100'}`} title={theme.name}></button>
                    ))}
                  </div>
                </div>
              </div>
              <button onClick={handleSaveSystemConfig} className="w-full py-5 bg-brand text-white rounded-2xl font-black uppercase text-[11px] tracking-widest shadow-xl">Apply Global Parameters</button>
            </div>

            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 mt-10">Identity Registry</h3>
            <div className="bg-slate-900 rounded-[40px] border border-slate-800 overflow-hidden shadow-xl">
              <table className="w-full text-left">
                <thead className="bg-slate-950/50 border-b border-slate-800">
                  <tr>
                    <th className="px-8 py-5 text-[9px] font-black text-slate-500 uppercase tracking-widest">Identity</th>
                    <th className="px-8 py-5 text-[9px] font-black text-slate-500 uppercase tracking-widest">Clearance</th>
                    <th className="px-8 py-5 text-[9px] font-black text-slate-500 uppercase tracking-widest text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {systemUsers.map(u => (
                    <tr key={u.id} className="hover:bg-slate-800/20 transition-colors">
                      <td className="px-8 py-5 flex items-center space-x-4">
                        <img src={u.avatar} className="w-10 h-10 rounded-xl border border-slate-800" alt="" />
                        <div>
                          <p className="text-sm font-black text-white">{u.name}</p>
                          <p className="text-[10px] text-slate-600 font-bold uppercase tracking-widest">{u.enrolledCourses.length} Programs</p>
                        </div>
                      </td>
                      <td className="px-8 py-5">
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${u.role === 'admin' ? 'bg-brand/10 text-brand border-brand/30' : 'bg-slate-950 text-slate-600 border-slate-800'}`}>{u.role}</span>
                      </td>
                      <td className="px-8 py-5 text-right">
                        {u.role !== 'admin' && (
                          <button onClick={() => deleteSystemUser(u.id)} className="w-9 h-9 rounded-xl bg-slate-950 text-slate-700 hover:text-rose-500 transition-all flex items-center justify-center border border-transparent hover:border-rose-500/20 ml-auto"><i className="fas fa-user-slash text-xs"></i></button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="lg:col-span-4 space-y-8">
             <div className="bg-slate-900 rounded-[32px] border border-slate-800 p-8 space-y-6 shadow-xl">
                <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">System Vitality</h4>
                <div className="grid grid-cols-2 gap-4">
                   <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800">
                      <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mb-1">Programs</p>
                      <p className="text-3xl font-black text-white">{courses.length}</p>
                   </div>
                   <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800">
                      <p className="text-[8px] font-black text-slate-600 uppercase tracking-widest mb-1">Nodes</p>
                      <p className="text-3xl font-black text-white">{systemUsers.length}</p>
