                <div className="flex items-center space-x-3 mt-1">
                  <span className="px-2 py-0.5 bg-slate-950 text-slate-600 font-black uppercase text-[8px] rounded border border-slate-800">{course.category}</span>
                  {course.appApk && <span className="text-[9px] font-black text-brand uppercase"><i className="fas fa-mobile-screen mr-1"></i> APK Synced</span>}
                </div>
              </div>
            </div>
            <div className="flex items-center justify-end space-x-3 shrink-0">
              <button onClick={() => { setCurrentCourse({...course}); setIsEditing(true); setActiveTab('info'); }} className="h-12 px-8 bg-slate-950 rounded-2xl text-slate-500 hover:text-white hover:bg-brand transition-all text-[10px] font-black uppercase tracking-widest border border-slate-800">Edit</button>
              <button onClick={() => { if(confirm('Delete program?')) onDeleteCourse(course.id); }} className="h-12 w-12 bg-slate-950 rounded-2xl text-slate-500 hover:text-rose-500 flex items-center justify-center border border-slate-800 transition-all"><i className="fas fa-trash-alt text-sm"></i></button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useMemo, useEffect } from 'react';
import { AppRoute, Course, SubjectGroup, SubSubject, Unit, Lesson } from '../types';

interface DashboardProps {
  onCourseClick: (id: string, lessonId?: string) => void;
  setRoute: (route: AppRoute) => void;
  courses: Course[];
  selectedCourseId: string | null;
  onSelectCourse: (id: string) => void;
  selectedSubjectId: string | null;
  setSelectedSubjectId: (id: string | null) => void;
  selectedSubSubjectId: string | null;
  setSelectedSubSubjectId: (id: string | null) => void;
  selectedUnitId: string | null;
  setSelectedUnitId: (id: string | null) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  onCourseClick, 
  setRoute, 
  courses, 
  selectedCourseId, 
  onSelectCourse,
  selectedSubjectId,
  setSelectedSubjectId,
  selectedSubSubjectId,
  setSelectedSubSubjectId,
  selectedUnitId,
  setSelectedUnitId
}) => {
  const [showCoursePicker, setShowCoursePicker] = useState(false);
  const [isMobile, setIsMobile] = useState(false);

  const activeCourse = courses.find(c => c.id === selectedCourseId) || courses[0];

  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(/iPhone|iPad|iPod|Android/i.test(navigator.userAgent));
    };
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const handleDownloadApp = () => {
    if (!activeCourse?.appApk) return;
    const url = typeof activeCourse.appApk === 'string' ? activeCourse.appApk : URL.createObjectURL(activeCourse.appApk);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${activeCourse.title.replace(/\s+/g, '_')}_Neural_Bridge.apk`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    if (typeof activeCourse.appApk !== 'string') {
      setTimeout(() => URL.revokeObjectURL(url), 100);
    }
  };

  const selectedSubject = useMemo(() => activeCourse?.subjects?.find(s => s.id === selectedSubjectId) || null, [activeCourse, selectedSubjectId]);
  const selectedSubSubject = useMemo(() => selectedSubject?.subSubjects?.find(ss => ss.id === selectedSubSubjectId) || null, [selectedSubject, selectedSubSubjectId]);
  const selectedUnit = useMemo(() => selectedSubSubject?.units?.find(u => u.id === selectedUnitId) || null, [selectedSubSubject, selectedUnitId]);

  if (!activeCourse) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-[#020617] animate-in fade-in">
        <div className="w-16 h-16 md:w-24 md:h-24 bg-slate-900 text-brand rounded-[30px] md:rounded-[40px] flex items-center justify-center mb-8 border border-slate-800 shadow-inner">
          <i className="fas fa-rocket text-2xl md:text-3xl"></i>
        </div>
        <h2 className="text-xl md:text-3xl font-black text-slate-100 mb-4 px-4">Initialize Your Journey</h2>
        <button onClick={() => setRoute(AppRoute.COURSES)} className="px-8 py-4 bg-brand text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-brand/20">Access Course Catalog</button>
      </div>
    );
  }

  const handleBack = () => {
    if (selectedUnit) setSelectedUnitId(null);
    else if (selectedSubSubject) setSelectedSubSubjectId(null);
    else if (selectedSubject) setSelectedSubjectId(null);
  };

  const filteredLessons = useMemo(() => {
    if (!selectedUnit) return [];
    return activeCourse.lessons.filter(l => 
      l.subjectId === selectedSubjectId && 
      l.subSubjectId === selectedSubSubjectId &&
      l.unitId === selectedUnitId
    );
  }, [activeCourse.lessons, selectedSubjectId, selectedSubSubjectId, selectedUnitId]);

  const mainTitle = useMemo(() => {
    if (selectedUnit) return selectedUnit.name;
    if (selectedSubSubject) return selectedSubSubject.name;
    if (selectedSubject) return selectedSubject.name;
    return activeCourse.title;
  }, [selectedSubject, selectedSubSubject, selectedUnit, activeCourse.title]);

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-5xl mx-auto px-0">

      {/* Mobile Priority Download Banner */}
      {isMobile && activeCourse.appApk && !selectedSubject && (
        <div className="mx-4 md:mx-0 p-6 bg-brand/10 border border-brand/30 rounded-[32px] flex flex-col sm:flex-row items-center justify-between gap-6 animate-in slide-in-from-top-4 duration-700 shadow-xl relative overflow-hidden group">
           <div className="flex items-center space-x-5 text-center sm:text-left z-10">
              <div className="w-14 h-14 bg-brand text-white rounded-2xl flex items-center justify-center text-xl shadow-lg shrink-0">
                <i className="fas fa-mobile-screen"></i>
              </div>
              <div>
                <h4 className="text-lg font-black text-white leading-tight">Neural Bridge APK Available</h4>
                <p className="text-[10px] font-black text-brand uppercase tracking-widest mt-1">Enhance Your Learning Interface</p>
              </div>
           </div>
           <button onClick={handleDownloadApp} className="w-full sm:w-auto px-8 py-3.5 bg-brand text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-2xl active:scale-95 transition-all z-10">
             <i className="fas fa-download mr-3"></i> Download App
           </button>
           <div className="absolute top-0 right-0 w-32 h-32 bg-brand/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl group-hover:bg-brand/10 transition-all"></div>
        </div>
      )}

      {courses.length > 1 && !selectedSubject && (
        <div className="flex justify-end px-4 md:px-0">
          <button 
            onClick={() => setShowCoursePicker(!showCoursePicker)}
            className="flex items-center space-x-3 px-4 py-2 bg-slate-900 border border-slate-800 rounded-xl hover:border-brand transition-all group"
          >
            <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest group-hover:text-brand">Switch Program</span>
            <i className={`fas fa-chevron-down text-[8px] transition-transform ${showCoursePicker ? 'rotate-180' : ''}`}></i>
          </button>
          {showCoursePicker && (
            <div className="absolute top-full right-4 md:right-auto mt-2 w-72 bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl z-[100] p-2 animate-in zoom-in-95">
              {courses.map(c => (
                <button key={c.id} onClick={() => { onSelectCourse(c.id); setShowCoursePicker(false); }} className={`w-full text-left p-4 rounded-xl flex items-center space-x-3 group ${activeCourse.id === c.id ? 'bg-brand/10 border border-brand/20' : 'hover:bg-slate-800'}`}>
                  <img src={typeof c.thumbnail === 'string' ? c.thumbnail : URL.createObjectURL(c.thumbnail)} className="w-10 h-10 rounded-lg object-cover" alt="" />
                  <p className={`text-xs font-black truncate ${activeCourse.id === c.id ? 'text-white' : 'text-slate-400'}`}>{c.title}</p>
                </button>
              ))}
            </div>
          )}
        </div>
      )}

      <div className="bg-slate-900/50 rounded-[32px] md:rounded-[48px] border border-slate-800/50 p-6 md:p-14 text-center shadow-2xl backdrop-blur-sm relative overflow-hidden group">
        {(selectedSubject || selectedSubSubject || selectedUnit) && (
          <button onClick={handleBack} className="absolute left-4 md:left-10 top-6 md:top-1/2 md:-translate-y-1/2 w-10 h-10 bg-slate-950 border border-slate-800 rounded-full flex items-center justify-center text-slate-400 hover:text-white transition-all z-10">
            <i className="fas fa-arrow-left text-xs"></i>
          </button>
        )}
        <div className="relative z-10 space-y-3 px-8 md:px-0">
          <p className="text-[9px] md:text-xs font-black text-slate-500 uppercase tracking-[0.3em] opacity-80">{selectedUnit ? 'Active Unit' : selectedSubject ? 'Academic Core' : 'Your Learning Path'}</p>
          <h1 className="text-xl md:text-4xl font-black text-white tracking-tighter leading-tight">{mainTitle}</h1>
        </div>
        <div className="absolute -top-20 -right-20 w-80 h-80 bg-brand/5 rounded-full blur-[100px] group-hover:bg-brand/10 transition-all duration-1000"></div>
      </div>

      <div className="bg-slate-900/30 rounded-[32px] md:rounded-[40px] border border-slate-800/40 p-4 md:p-12 shadow-xl min-h-[400px]">
        {!selectedSubject ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8">
            {(activeCourse.subjects || []).map((subj) => (
              <button key={subj.id} onClick={() => { setSelectedSubjectId(subj.id); setSelectedSubSubjectId(null); }} className="flex items-center justify-between p-6 bg-slate-950 border border-slate-800/50 rounded-3xl hover:border-brand/40 hover:bg-slate-900 transition-all group shadow-lg text-left">
                <div className="flex items-center space-x-5">
                  <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl border ${subj.color} group-hover:scale-105 transition-transform`}><i className={`fas ${subj.icon || 'fa-book-open'}`}></i></div>
                  <span className="text-lg font-black text-slate-100 group-hover:text-white transition-colors">{subj.name}</span>
                </div>
                <i className="fas fa-chevron-right text-xs text-brand group-hover:translate-x-1 transition-transform"></i>
              </button>
            ))}
          </div>
        ) : !selectedSubSubject ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-right-8">
            {selectedSubject.subSubjects.map(ss => (
              <button key={ss.id} onClick={() => setSelectedSubSubjectId(ss.id)} className="flex items-center justify-between p-6 bg-slate-950 border border-slate-800 rounded-3xl hover:border-brand/40 hover:bg-slate-900 transition-all text-left group">
                <span className="text-lg font-black text-slate-100">{ss.name}</span>
                <i className="fas fa-chevron-right text-xs text-brand group-hover:translate-x-1 transition-transform"></i>
              </button>
            ))}
          </div>
        ) : !selectedUnit ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-right-8">
            {selectedSubSubject.units?.map(unit => (
              <button key={unit.id} onClick={() => setSelectedUnitId(unit.id)} className="flex items-center justify-between p-6 bg-slate-950 border border-slate-800 rounded-3xl hover:border-brand/40 hover:bg-slate-900 transition-all text-left group">
                <span className="text-lg font-black text-slate-100">{unit.name}</span>
                <i className="fas fa-chevron-right text-xs text-brand group-hover:translate-x-1 transition-transform"></i>
              </button>
            ))}
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5 animate-in slide-in-from-right-8">
            {filteredLessons.map((lesson, idx) => (
              <button key={lesson.id} onClick={() => onCourseClick(activeCourse.id, lesson.id)} className="flex items-center p-6 bg-slate-950 border border-slate-800/50 rounded-[32px] hover:border-brand/40 hover:bg-slate-900 transition-all text-left group">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xs font-black border border-slate-800 mr-5 bg-slate-900 text-slate-500 group-hover:text-brand group-hover:border-brand/30 transition-all shadow-inner`}>{idx + 1}</div>
                <div className="flex-1">
                  <h4 className="font-bold text-slate-100 text-base leading-tight">{lesson.title}</h4>
                  <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">{lesson.duration}</span>
                </div>
                <i className="fas fa-chevron-right text-[10px] text-brand opacity-0 group-hover:opacity-100 group-hover:translate-x-1 transition-all"></i>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

