            className={`w-full flex items-center px-5 py-4 text-sm font-bold rounded-2xl transition-all group ${
              currentRoute === item.id
                ? 'bg-brand/10 text-brand border border-brand/10'
                : 'text-slate-500 hover:bg-slate-900 hover:text-white'
            }`}
          >
            <i className={`fas ${item.icon} w-6 mr-3 text-lg transition-colors ${currentRoute === item.id ? 'text-brand' : 'text-slate-600 group-hover:text-brand'}`}></i>
            {item.label}
          </button>
        ))}

        {user.role === 'admin' && (
          <div className="mt-10">
            <p className="px-4 text-[9px] font-black text-slate-600 uppercase tracking-[0.3em] mb-4 opacity-50">SYSTEM CONTROL</p>
            <button
              onClick={() => setRoute(AppRoute.ADMIN)}
              className={`w-full flex items-center px-5 py-4 text-sm font-bold rounded-2xl transition-all ${
                currentRoute === AppRoute.ADMIN
                  ? 'bg-brand text-white shadow-2xl shadow-brand/30'
                  : 'text-slate-500 hover:bg-slate-900 hover:text-white'
              }`}
            >
              <i className={`fas fa-shield-halved w-6 mr-3 text-lg`}></i>
              Admin Panel
            </button>
          </div>
        )}
      </nav>

      {/* Footer / User Profile */}
      <div className="p-6 border-t border-slate-900 bg-slate-950/50">
        <div className="flex items-center p-4 space-x-4 bg-slate-900/50 rounded-2xl border border-slate-800 mb-6">
          <div className="relative">
            <img src={user.avatar} className="w-10 h-10 rounded-xl object-cover border border-slate-800 shadow-inner" alt="avatar" />
            <div className="absolute -bottom-1 -right-1 w-3 h-3 bg-emerald-500 rounded-full border-2 border-slate-900"></div>
          </div>
          <div className="flex-1 overflow-hidden">
            <p className="text-xs font-black text-white truncate">{user.name}</p>
            <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest leading-none mt-1">{user.role}</p>
          </div>
        </div>
        <button 
          onClick={onLogout} 
          className="w-full flex items-center justify-center px-4 py-3.5 text-[9px] font-black text-rose-500 hover:bg-rose-950/20 rounded-2xl transition-all uppercase tracking-[0.2em] border border-transparent hover:border-rose-900/30"
        >
          <i className="fas fa-right-from-bracket mr-3"></i>
          Logout Session
        </button>
      </div>
    </div>
  );
};

export default Sidebar;
